                  boxShadow: '0 8px 32px hsl(var(--primary) / 0.1)',
                }}
                formatter={(value: number, _name: string, props: any) => [
                  `${value}/5 (${props.payload.responses} ${t('orgDashboard.responses')})`,
                  t('orgDashboard.avgScore'),
                ]}
              />
