import { Award, Trophy, CheckCircle2 } from 'lucide-react';
import { toast } from 'sonner';

interface ShortlistEntry {
  ranking_id: string;
  rank: number;
  theme_name: string;
  cycle_name: string;
  cycle_id: string;
  require_acknowledgment: boolean;
  points_earned: number;
}

export function DashboardShortlistWidget() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const qc = useQueryClient();

  const { data: entries = [], isPending } = useQuery({
    queryKey: ['my-shortlist-acknowledgments', user?.id],
    queryFn: async () => {
      if (!user?.id) return [];

      // Get all nominee_rankings for this user where acknowledged_at is null
      const { data: rankings, error } = await supabase
        .from('nominee_rankings')
        .select(`
          id,
          rank,
          acknowledged_at,
          nomination_id,
          theme_results_id,
          theme_results:theme_results_id (
            cycle_id,
            theme_id,
            award_themes:theme_id ( name ),
            award_cycles:cycle_id ( name, shortlist_count, require_acknowledgment, points_config, status )
          ),
          nominations:nomination_id ( nominee_id )
        `)
        .is('deleted_at', null)
        .is('acknowledged_at', null);

      if (error) throw error;
      if (!rankings) return [];

      // Filter to only this user's nominations and announced cycles within shortlist range
      const results: ShortlistEntry[] = [];
      for (const r of rankings) {
        const nom = r.nominations as any;
        const tr = r.theme_results as any;
        if (!nom || !tr) continue;
        if (nom.nominee_id !== user.id) continue;

        const cycle = tr.award_cycles as any;
        const theme = tr.award_themes as any;
        if (!cycle || cycle.status !== 'announced') continue;

        const shortlistCount = cycle.shortlist_count ?? 3;
        if (r.rank > shortlistCount) continue;

        // Determine points earned for this rank
        const pc = (cycle.points_config || {}) as Record<string, number>;
        let points = pc[`place_${r.rank}`] ?? 0;
        if (points === 0) {
          if (r.rank === 1) points = pc.first_place ?? 5000;
          else if (r.rank === 2) points = pc.second_place ?? 2000;
          else if (r.rank === 3) points = pc.third_place ?? 1000;
        }

        results.push({
          ranking_id: r.id,
          rank: r.rank,
          theme_name: theme?.name || '',
          cycle_name: cycle?.name || '',
          cycle_id: tr.cycle_id,
          require_acknowledgment: cycle.require_acknowledgment ?? true,
          points_earned: points,
        });
      }

      return results.sort((a, b) => a.rank - b.rank);
    },
    enabled: !!user?.id,
  });

  const acknowledge = useMutation({
    mutationFn: async (rankingId: string) => {
      const { error } = await supabase
        .from('nominee_rankings')
        .update({ acknowledged_at: new Date().toISOString() } as any)
        .eq('id', rankingId);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['my-shortlist-acknowledgments'] });
      toast.success(t('recognition.shortlist.acknowledged'));
    },
    onError: () => toast.error(t('recognition.shortlist.acknowledgeError')),
  });

  if (isPending) {
    return <Skeleton className="h-24" />;
  }

  if (!entries.length) return null;

  const getRankIcon = (rank: number) => {
    if (rank === 1) return <Trophy className="h-7 w-7 text-chart-1" />;
    return <Award className="h-7 w-7 text-chart-2" />;
  };

  const getRankLabel = (rank: number) => {
    if (rank === 1) return '🥇';
    if (rank === 2) return '🥈';
    if (rank === 3) return '🥉';
    return `#${rank}`;
  };

  return (
    <div className="space-y-3">
      {entries.map((entry) => (
        <Card key={entry.ranking_id} className="glass-card border-0 ring-1 ring-chart-1/30 overflow-hidden">
          <CardContent className="flex items-center gap-4 p-6">
            <div className="flex h-14 w-14 shrink-0 items-center justify-center rounded-lg bg-chart-1/10">
              {getRankIcon(entry.rank)}
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 flex-wrap">
                <h3 className="font-semibold text-base">
                  {getRankLabel(entry.rank)} {t('recognition.shortlist.youPlaced', { rank: entry.rank })}
                </h3>
                {entry.points_earned > 0 && (
                  <Badge variant="secondary" className="text-xs">
                    +{entry.points_earned.toLocaleString()} {t('home.points')}
                  </Badge>
                )}
              </div>
              <p className="text-muted-foreground text-sm mt-0.5">
                {entry.theme_name} — {entry.cycle_name}
              </p>
            </div>
            {entry.require_acknowledgment ? (
              <Button
                size="sm"
                onClick={() => acknowledge.mutate(entry.ranking_id)}
                disabled={acknowledge.isPending}
                className="shrink-0"
              >
                <CheckCircle2 className="h-4 w-4 me-1" />
                {t('recognition.shortlist.acknowledge')}
              </Button>
            ) : (
              <CheckCircle2 className="h-6 w-6 text-chart-1 shrink-0" />
            )}
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Link } from 'react-router-dom';
import { isAfter, isBefore, format, addDays } from 'date-fns';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { useUnifiedTasks } from '@/features/workload/hooks/useUnifiedTasks';
import { useApprovalQueue } from '@/features/tasks/hooks/useApprovalQueue';
import {
  ClipboardList, ChevronRight, CheckCircle2, AlertTriangle,
  Clock, SquareCheckBig,
} from 'lucide-react';

const PRIORITY_COLORS: Record<number, string> = {
  1: 'bg-destructive',     // critical
  2: 'bg-chart-4',         // high
  3: 'bg-chart-2',         // medium
  4: 'bg-chart-1',         // low
};

interface Props {
  employeeId: string;
}

export function DashboardWorkloadWidget({ employeeId }: Props) {
  const { t } = useTranslation();
  const { tasks, isPending } = useUnifiedTasks(employeeId);
  const { pendingTasks } = useApprovalQueue();

  const now = new Date();

  const stats = useMemo(() => {
    const active = tasks.filter(tk => tk.status !== 'completed' && tk.status !== 'cancelled').length;
    const completed = tasks.filter(tk => tk.status === 'completed').length;
    const overdue = tasks.filter(tk =>
      tk.due_date && isAfter(now, new Date(tk.due_date)) && tk.status !== 'completed' && tk.status !== 'cancelled'
    ).length;
    const total = tasks.length;
    const rate = total > 0 ? Math.round((completed / total) * 100) : 0;
    return { active, completed, overdue, pending: pendingTasks.length, rate };
  }, [tasks, pendingTasks, now]);

  const upcoming = useMemo(() => {
    return tasks
      .filter(tk => tk.status !== 'completed' && tk.status !== 'cancelled' && tk.due_date)
      .sort((a, b) => new Date(a.due_date!).getTime() - new Date(b.due_date!).getTime())
      .slice(0, 3);
  }, [tasks]);

  if (isPending) {
    return <Skeleton className="h-48 w-full rounded-xl" />;
  }

  const statItems = [
    { label: t('common.active'), value: stats.active, icon: Clock, color: 'text-primary' },
    { label: t('common.done'), value: stats.completed, icon: CheckCircle2, color: 'text-chart-1' },
    { label: t('common.overdue'), value: stats.overdue, icon: AlertTriangle, color: 'text-destructive' },
    { label: t('dashboard.workloadWidget.pendingApprovals'), value: stats.pending, icon: SquareCheckBig, color: 'text-chart-2' },
  ];

  return (
    <Card className="glass-card border-0 ring-1 ring-primary/10">
      {/* Header */}
      <div className="flex items-center justify-between p-6 pb-0">
        <div className="flex items-center gap-2">
          <ClipboardList className="h-5 w-5 text-primary" />
          <h3 className="font-semibold text-base">{t('dashboard.workloadWidget.title')}</h3>
        </div>
        <Link
          to="/my-workload"
          className="flex items-center gap-1 text-sm text-muted-foreground hover:text-primary transition-colors"
        >
          {t('dashboard.workloadWidget.viewAll')}
          <ChevronRight className="h-4 w-4 rtl:rotate-180" />
        </Link>
      </div>

      <CardContent className="space-y-4 pt-4">
        {/* Stats Grid */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
          {statItems.map(item => (
            <div key={item.label} className="flex flex-col items-center gap-1 rounded-lg bg-muted/50 p-2">
              <item.icon className={`h-4 w-4 ${item.color}`} />
              <span className="text-lg font-bold">{item.value}</span>
              <span className="text-2xs text-muted-foreground text-center leading-tight">{item.label}</span>
            </div>
          ))}
        </div>

        {/* Progress */}
        <div className="space-y-1.5">
          <div className="flex items-center justify-between text-xs text-muted-foreground">
            <span>{t('dashboard.workloadWidget.completionRate')}</span>
            <span className="font-medium">{stats.rate}%</span>
          </div>
          <Progress value={stats.rate} className="h-2" />
        </div>

        {/* Upcoming Tasks */}
        {upcoming.length > 0 && (
          <div className="space-y-2">
            <p className="text-xs font-medium text-muted-foreground">{t('dashboard.workloadWidget.upcoming')}</p>
            <div className="space-y-1.5">
              {upcoming.map(task => (
                <div key={task.id} className="flex items-center gap-2 rounded-md bg-muted/30 px-3 py-2">
                  <span className={`h-2 w-2 shrink-0 rounded-full ${PRIORITY_COLORS[task.priority] ?? 'bg-muted-foreground'}`} />
                  <span className="flex-1 truncate text-sm">{task.title}</span>
                  {task.due_date && (
                    <Badge variant="outline" className="text-2xs shrink-0">
                      {format(new Date(task.due_date), 'MMM d')}
                    </Badge>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { AlertTriangle, TrendingDown, Zap, Users, RotateCcw } from 'lucide-react';
import type { EarlyWarning } from '@/shared/utils/analytics/types';

interface Props {
  warnings: EarlyWarning[];
  isLoading: boolean;
}

const TYPE_CONFIG: Record<string, { icon: React.ComponentType<any>; label: string }> = {
  declining_trend: { icon: TrendingDown, label: 'orgDashboard.warningDeclining' },
  spike_detected: { icon: Zap, label: 'orgDashboard.warningSpike' },
  low_engagement: { icon: Users, label: 'orgDashboard.warningLowEngagement' },
  recurring_risk: { icon: RotateCcw, label: 'orgDashboard.warningRecurring' },
};

export function EarlyWarningPanel({ warnings, isLoading }: Props) {
  const { t } = useTranslation();

  if (isLoading) {
    return (
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-base flex items-center gap-2">
            <AlertTriangle className="h-4 w-4" />
            {t('orgDashboard.earlyWarnings')}
          </CardTitle>
        </CardHeader>
        <CardContent><Skeleton className="h-[200px] w-full" /></CardContent>
      </Card>
    );
  }

  return (
    <Card className="glass-card border-0">
      <CardHeader className="pb-2">
        <CardTitle className="text-base flex items-center gap-2">
          <AlertTriangle className="h-4 w-4 text-chart-4" />
          {t('orgDashboard.earlyWarnings')}
          {warnings.length > 0 && (
            <Badge variant="secondary" className="text-2xs">{warnings.length}</Badge>
          )}
        </CardTitle>
      </CardHeader>
      <CardContent>
        {warnings.length === 0 ? (
          <div className="text-center py-8">
            <p className="text-sm text-muted-foreground">{t('orgDashboard.noAlerts')}</p>
          </div>
        ) : (
          <div className="space-y-3">
            {warnings.map(w => {
              const config = TYPE_CONFIG[w.type] ?? TYPE_CONFIG.declining_trend;
              const Icon = config.icon;

              return (
                <div key={w.id} className="flex items-start gap-3 p-3 rounded-lg glass-badge">
                  <div className={`mt-0.5 p-1.5 rounded ${w.severity === 'high' ? 'bg-destructive/10 text-destructive' : 'bg-chart-4/10 text-chart-4'}`}>
                    <Icon className="h-3.5 w-3.5" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-0.5">
                      <Badge variant={w.severity === 'high' ? 'destructive' : 'secondary'} className="text-2xs">
                        {t(`orgDashboard.severity.${w.severity}`)}
                      </Badge>
                      <span className="text-2xs text-muted-foreground">{t(config.label)}</span>
                    </div>
                    <p className="text-sm">{w.message}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Skeleton } from '@/shared/components/ui/skeleton';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Cell,
} from 'recharts';
import type { SubcategoryScore } from '@/hooks/analytics/useOrgAnalytics';
import { CHART_AXIS_TICK, CHART_TOOLTIP_STYLE, CHART_GRID_STROKE } from '@/config/chart-styles';

interface SubcategoryChartProps {
  data: SubcategoryScore[];
  isLoading: boolean;
}

export function SubcategoryChart({ data, isLoading }: SubcategoryChartProps) {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.dir() === 'rtl';

  if (!isLoading && data.length === 0) return null;

  const chartData = data.map(d => ({
    name: isRTL && d.nameAr ? d.nameAr : d.name,
    category: isRTL && d.categoryNameAr ? d.categoryNameAr : d.categoryName,
    score: d.avgScore,
    color: d.color,
    responses: d.responseCount,
  }));

  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="text-base">{t('orgDashboard.subcategoryDrilldown')}</CardTitle>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <Skeleton className="h-[280px] w-full" />
        ) : (
          <ResponsiveContainer width="100%" height={Math.max(280, chartData.length * 36)}>
            <BarChart data={chartData} layout="vertical" margin={{ top: 0, right: 30, left: 10, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke={CHART_GRID_STROKE} horizontal={false} />
              <XAxis
                type="number"
                domain={[0, 5]}
                tick={CHART_AXIS_TICK}
                axisLine={false}
                tickLine={false}
              />
              <YAxis
                type="category"
                dataKey="name"
                tick={CHART_AXIS_TICK}
                axisLine={false}
                tickLine={false}
                width={140}
              />
              <Tooltip
                contentStyle={CHART_TOOLTIP_STYLE}
                formatter={(value: number, _name: string, props: any) => [
                  `${value}/5 (${props.payload.responses} ${t('orgDashboard.responses')})`,
                  props.payload.category,
                ]}
              />
              <Bar dataKey="score" radius={[0, 4, 4, 0]} barSize={20}>
                {chartData.map((entry, index) => (
                  <Cell key={index} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        )}
      </CardContent>
    </Card>
  );
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { ResponsiveContainer, ScatterChart, Scatter, XAxis, YAxis, CartesianGrid, Tooltip, ZAxis } from 'recharts';
import type { SubcategoryScore } from '@/hooks/analytics/useOrgAnalytics';
import { CHART_AXIS_TICK, CHART_AXIS_LABEL, CHART_TOOLTIP_STYLE, CHART_GRID_STROKE } from '@/config/chart-styles';

interface SubcategoryBubble extends SubcategoryScore {
  declineRate: number;
}

interface Props {
  data: SubcategoryBubble[];
  isLoading: boolean;
}

export function SubcategoryRiskBubble({ data, isLoading }: Props) {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.dir() === 'rtl';

  if (isLoading) {
    return (
      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-base">{t('orgDashboard.subcategoryRiskMatrix')}</CardTitle></CardHeader>
        <CardContent><Skeleton className="h-[300px] w-full" /></CardContent>
      </Card>
    );
  }

  if (data.length === 0) {
    return (
      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-base">{t('orgDashboard.subcategoryRiskMatrix')}</CardTitle></CardHeader>
        <CardContent><p className="text-muted-foreground text-sm text-center py-10">{t('orgDashboard.noSurveyData')}</p></CardContent>
      </Card>
    );
  }

  const chartData = data.map(d => ({
    x: d.avgScore,
    y: d.responseCount,
    z: Math.max(50, d.declineRate * 100 + 50),
    name: isRTL && d.nameAr ? d.nameAr : d.name,
    category: isRTL && d.categoryNameAr ? d.categoryNameAr : d.categoryName,
    color: d.color,
    avgScore: d.avgScore,
    responses: d.responseCount,
    decline: d.declineRate,
  }));

  return (
    <Card>
      <CardHeader className="pb-2">
        <CardTitle className="text-base">{t('orgDashboard.subcategoryRiskMatrix')}</CardTitle>
        <p className="text-xs text-muted-foreground">{t('orgDashboard.bubbleHint')}</p>
      </CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={300}>
          <ScatterChart margin={{ top: 10, right: 20, bottom: 10, left: 10 }}>
            <CartesianGrid strokeDasharray="3 3" stroke={CHART_GRID_STROKE} />
            <XAxis
              dataKey="x" type="number" domain={[0, 5]}
              name={t('orgDashboard.avgScore')}
              tick={CHART_AXIS_TICK}
              axisLine={false} tickLine={false}
              label={{ value: t('orgDashboard.avgScore'), position: 'bottom', ...CHART_AXIS_LABEL }}
            />
            <YAxis
              dataKey="y" type="number"
              name={t('orgDashboard.responses')}
              tick={CHART_AXIS_TICK}
              axisLine={false} tickLine={false}
              label={{ value: t('orgDashboard.responses'), angle: -90, position: 'insideLeft', ...CHART_AXIS_LABEL }}
            />
            <ZAxis dataKey="z" range={[40, 400]} />
            <Tooltip
              contentStyle={CHART_TOOLTIP_STYLE}
              formatter={(_val: any, _name: string, props: any) => {
                const d = props.payload;
                return [
                  <div key="tip" className="space-y-1">
                    <p className="font-medium">{d.name}</p>
                    <p className="text-muted-foreground">{d.category}</p>
                    <p>{t('orgDashboard.avgScore')}: {d.avgScore}/5</p>
                    <p>{t('orgDashboard.responses')}: {d.responses}</p>
                  </div>,
                  '',
                ];
              }}
            />
            <Scatter data={chartData} fill="hsl(var(--primary) / 0.6)" />
          </ScatterChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Switch } from '@/shared/components/ui/switch';
import { Textarea } from '@/shared/components/ui/textarea';
import { Button } from '@/shared/components/ui/button';
import { Label } from '@/shared/components/ui/label';
import { Save, RotateCcw, Link2, Plus, X, ChevronUp, ChevronDown } from 'lucide-react';
import type { MoodQuestionConfig } from '@/hooks/wellness/useMoodQuestionConfig';
import type { MoodDefinition } from '@/hooks/wellness/useMoodDefinitions';

interface TaggedQuestion {
  id: string;
  text?: string;
  text_ar?: string | null;
  [key: string]: any;
}

interface MoodConfigCardProps {
  moodDef: MoodDefinition;
  config: MoodQuestionConfig | undefined;
  taggedQuestions: TaggedQuestion[];
  isRTL: boolean;
  isSaving: boolean;
  onUpdateField: (moodLevel: string, field: keyof MoodQuestionConfig, value: any) => void;
  onSave: (moodLevel: string) => void;
  onOpenPicker: (moodLevel: string) => void;
  onUnlinkQuestion: (questionId: string, moodLevel: string) => void;
}

export function MoodConfigCard({
  moodDef, config, taggedQuestions, isRTL, isSaving,
  onUpdateField, onSave, onOpenPicker, onUnlinkQuestion,
}: MoodConfigCardProps) {
  const { t } = useTranslation();
  const moodLevel = moodDef.key;
  const moodLabel = isRTL ? moodDef.label_ar : moodDef.label_en;
  const isEnabled = config?.is_enabled ?? true;

  return (
    <Card className="glass-card border-0 rounded-xl overflow-hidden">
      <CardHeader className="pb-3 border-b">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <span className="text-2xl">{moodDef.emoji}</span>
            <div>
              <CardTitle className={`text-base ${moodDef.color}`}>{moodLabel}</CardTitle>
              <CardDescription className="text-xs mt-0.5">
                {t('moodPathway.linkedQuestionsCount', { count: taggedQuestions.length })}
              </CardDescription>
            </div>
          </div>
        </div>
      </CardHeader>

      <CardContent className="pt-4 space-y-4">
        {/* Enable toggle */}
        <div className="flex items-center justify-between">
          <Label className="text-sm font-medium">{t('moodPathway.enablePathway')}</Label>
          <Switch checked={isEnabled} onCheckedChange={v => onUpdateField(moodLevel, 'is_enabled', v)} />
        </div>

        {/* Enable free-text */}
        <div className="flex items-center justify-between">
          <Label className="text-sm font-medium">{t('moodPathway.enableFreeText')}</Label>
          <Switch
            checked={config?.enable_free_text ?? false}
            onCheckedChange={v => onUpdateField(moodLevel, 'enable_free_text', v)}
            disabled={!isEnabled}
          />
        </div>

        {/* Questions per mood */}
        <div className="flex items-center justify-between">
          <Label className="text-sm font-medium">{t('moodPathway.questionsPerMood')}</Label>
          <div className="flex items-center gap-1">
            <Button
              variant="outline" size="icon" className="h-8 w-8"
              onClick={() => onUpdateField(moodLevel, 'max_questions', Math.max(1, (config?.max_questions ?? 2) - 1))}
              disabled={!isEnabled || (config?.max_questions ?? 2) <= 1}
            >
              <ChevronDown className="h-4 w-4" />
            </Button>
            <span className="w-8 text-center text-sm font-semibold tabular-nums">
              {config?.max_questions ?? 2}
            </span>
            <Button
              variant="outline" size="icon" className="h-8 w-8"
              onClick={() => onUpdateField(moodLevel, 'max_questions', Math.min(10, (config?.max_questions ?? 2) + 1))}
              disabled={!isEnabled || (config?.max_questions ?? 2) >= 10}
            >
              <ChevronUp className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Linked questions */}
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <Label className="text-sm font-medium">{t('moodPathway.linkedQuestions')}</Label>
            <Button
              variant="outline" size="sm" className="h-7 text-xs gap-1.5"
              onClick={() => onOpenPicker(moodLevel)} disabled={!isEnabled}
            >
              <Plus className="h-3.5 w-3.5" />
              {t('moodPathway.browseQuestions')}
            </Button>
          </div>
          {taggedQuestions.length === 0 ? (
            <div className="rounded-lg border border-dashed p-4 text-center">
              <Link2 className="h-4 w-4 text-muted-foreground inline-block mb-1" />
              <p className="text-xs text-muted-foreground">{t('moodPathway.noLinkedQuestions')}</p>
            </div>
          ) : (
            <div className="space-y-2">
              {taggedQuestions.map(q => {
                const text = isRTL && q.text_ar ? q.text_ar : q.text;
                return (
                  <div key={q.id} className="flex items-start gap-2 rounded-lg border bg-muted/30 p-2.5">
                    <p className="text-sm flex-1 line-clamp-2" dir="auto">{text}</p>
                    <Button
                      variant="ghost" size="icon"
                      className="h-6 w-6 shrink-0 text-muted-foreground hover:text-destructive"
                      onClick={() => onUnlinkQuestion(q.id, moodLevel)}
                    >
                      <X className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* AI Recommendation Hint */}
        {isEnabled && (
          <div className="space-y-1.5">
            <Label className="text-sm font-medium">{t('moodPathway.aiRecommendationHint')}</Label>
            <Textarea
              value={config?.custom_prompt_context || ''}
              onChange={e => onUpdateField(moodLevel, 'custom_prompt_context', e.target.value || null)}
              placeholder={t('moodPathway.aiRecommendationHintPlaceholder')}
              rows={2} className="resize-none text-sm rounded-xl" dir="auto"
            />
            <p className="text-xs text-muted-foreground">{t('moodPathway.aiRecommendationHintDesc')}</p>
          </div>
        )}

        {/* Save button */}
        <div className="flex justify-end">
          <Button
            size="sm" onClick={() => onSave(moodLevel)} disabled={isSaving}
            className="gap-1.5 h-8 px-4 rounded-lg text-xs"
          >
            {isSaving ? <RotateCcw className="h-3 w-3 animate-spin" /> : <Save className="h-3 w-3" />}
            {t('moodPathway.saveSettings')}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useTranslation } from 'react-i18next';
import { Pencil, Trash2, Users } from 'lucide-react';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/shared/components/ui/table';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/shared/components/ui/alert-dialog';
import type { Site } from '@/hooks/org/useSites';
import type { Branch } from '@/hooks/org/useBranches';
import type { Department } from '@/hooks/org/useDepartments';
import type { Division } from '@/hooks/org/useDivisions';
import type { Employee } from '@/hooks/org/useEmployees';

interface SiteTableProps {
  sites: Site[];
  branches: Branch[];
  departments: Department[];
  divisions: Division[];
  employees: Employee[];
  onEdit: (site: Site) => void;
  onDelete: (id: string) => void;
}

export function SiteTable({ sites, branches, departments, divisions, employees, onEdit, onDelete }: SiteTableProps) {
  const { t, i18n } = useTranslation();

  if (sites.length === 0) {
    return <p className="text-muted-foreground text-center py-8">{t('common.noData')}</p>;
  }

  const branchMap = new Map(branches.map(b => [b.id, b]));
  const deptMap = new Map(departments.map(d => [d.id, d]));
  const divisionMap = new Map(divisions.map(d => [d.id, d]));

  return (
    <Table>
      <TableHeader>
        <TableRow>
          <TableHead>{t('sections.name')}</TableHead>
          <TableHead>{t('sections.department')}</TableHead>
          <TableHead className="hidden md:table-cell">{t('organization.head')}</TableHead>
          <TableHead>{t('organization.members')}</TableHead>
          <TableHead className="hidden md:table-cell">{t('sections.address')}</TableHead>
          <TableHead>{t('common.status')}</TableHead>
          <TableHead>{t('common.actions')}</TableHead>
        </TableRow>
      </TableHeader>
      <TableBody>
        {sites.map(site => {
          const dept = site.department_id ? deptMap.get(site.department_id) : null;
          const division = dept?.division_id ? divisionMap.get(dept.division_id) : null;
          const effectiveColor = site.color && site.color !== '#3B82F6' ? site.color : (dept?.color && dept.color !== '#3B82F6' ? dept.color : (division?.color || '#3B82F6'));
          const displayName = i18n.language === 'ar' && site.name_ar ? site.name_ar : site.name;
          const displayAddress = i18n.language === 'ar' && site.address_ar ? site.address_ar : site.address;
          const deptName = dept ? (i18n.language === 'ar' && dept.name_ar ? dept.name_ar : dept.name) : '—';
          const headEmployee = site.head_employee_id
            ? employees.find(e => e.id === site.head_employee_id)
            : null;
          const directMembers = employees.filter(e => (e as any).section_id === site.id).length;
          const headIsAlreadyCounted = site.head_employee_id ? employees.some(e => (e as any).section_id === site.id && e.id === site.head_employee_id) : true;
          const memberCount = directMembers + (site.head_employee_id && !headIsAlreadyCounted ? 1 : 0);
          return (
            <TableRow key={site.id}>
              <TableCell className="font-medium">
                <div className="flex items-center gap-2">
                  <div
                    className="h-3 w-3 rounded-full shrink-0"
                    style={{ backgroundColor: effectiveColor }}
                  />
                  {displayName}
                </div>
              </TableCell>
              <TableCell>{deptName}</TableCell>
              <TableCell className="hidden md:table-cell">
                {headEmployee?.full_name || '—'}
              </TableCell>
              <TableCell>
                <Badge variant="secondary" className="gap-1">
                  <Users className="h-3 w-3" /> {memberCount}
                </Badge>
              </TableCell>
              <TableCell className="hidden md:table-cell">{displayAddress || '—'}</TableCell>
              <TableCell>
                <Badge variant={site.is_active ? 'default' : 'secondary'}>
                  {site.is_active ? t('common.active') : t('common.inactive')}
                </Badge>
              </TableCell>
              <TableCell>
                <div className="flex gap-1">
                  <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => onEdit(site)}>
                    <Pencil className="h-4 w-4" />
                  </Button>
                  <AlertDialog>
                    <AlertDialogTrigger asChild>
                      <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive">
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent>
                      <AlertDialogHeader>
                        <AlertDialogTitle>{t('sections.deleteSection')}</AlertDialogTitle>
                        <AlertDialogDescription>{t('sections.confirmDelete')}</AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
                        <AlertDialogAction onClick={() => onDelete(site.id)}>{t('common.delete')}</AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                </div>
              </TableCell>
            </TableRow>
          );
        })}
      </TableBody>
    </Table>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Plus, Building2 } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { useDepartments, type Department, type DepartmentInput } from '@/hooks/org/useDepartments';
import { useDivisions } from '@/hooks/org/useDivisions';
import { useSites } from '@/hooks/org/useSites';
import { useEmployees } from '@/hooks/org/useEmployees';
import { DepartmentTable } from '@/components/org/DepartmentTable';
import { DepartmentSheet } from '@/components/org/DepartmentSheet';

interface Props {
  tenantId: string;
  isLoading: boolean;
}

export function DepartmentsTab({ tenantId, isLoading }: Props) {
  const { t } = useTranslation();
  const { departments, createDepartment, updateDepartment, deleteDepartment } = useDepartments();
  const { divisions } = useDivisions();
  const { sites } = useSites();
  const { employees } = useEmployees();
  const [sheetOpen, setSheetOpen] = useState(false);
  const [editing, setEditing] = useState<Department | null>(null);

  const handleSubmit = (data: DepartmentInput) => {
    if (editing) {
      updateDepartment.mutate({ id: editing.id, ...data });
    } else {
      createDepartment.mutate(data);
    }
  };

  const loadingSkeleton = (
    <div className="space-y-3">
      {[1, 2, 3].map(i => <Skeleton key={i} className="h-10 w-full" />)}
    </div>
  );

  return (
    <>
      <Card className="glass-card border-0 rounded-xl">
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>{t('organization.departments')}</CardTitle>
          <Button onClick={() => { setEditing(null); setSheetOpen(true); }}>
            <Plus className="me-2 h-4 w-4" /> {t('organization.addDepartment')}
          </Button>
        </CardHeader>
        <CardContent>
          {isLoading ? loadingSkeleton : (
            <DepartmentTable
              departments={departments}
              divisions={divisions}
              sites={sites}
              employees={employees as any}
              onEdit={(dept) => { setEditing(dept); setSheetOpen(true); }}
              onDelete={(id) => deleteDepartment.mutate(id)}
            />
          )}
        </CardContent>
      </Card>
      <DepartmentSheet
        open={sheetOpen}
        onOpenChange={setSheetOpen}
        department={editing}
        divisions={divisions}
        employees={employees as any}
        tenantId={tenantId}
        onSubmit={handleSubmit}
      />
    </>
  );
}

