import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useEffect } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/shared/components/ui/dialog';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  FormDescription,
} from '@/shared/components/ui/form';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Button } from '@/shared/components/ui/button';
import { Switch } from '@/shared/components/ui/switch';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/shared/components/ui/select';
import type { Plan } from '@/hooks/org/usePlans';

const planSchema = z.object({
  name: z.string().min(1, 'Name is required').max(100),
  description: z.string().max(500).optional().or(z.literal('')),
  price: z.coerce.number().min(0, 'Price must be 0 or greater'),
  billing_period: z.enum(['monthly', 'yearly']),
  max_users: z.coerce.number().int().min(-1, 'Use -1 for unlimited'),
  max_storage_gb: z.coerce.number().int().min(0),
  is_active: z.boolean(),
});

type PlanFormValues = z.infer<typeof planSchema>;

interface PlanDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  plan?: Plan | null;
  onSubmit: (data: PlanFormValues) => void;
  isSubmitting: boolean;
}

export function PlanDialog({
  open,
  onOpenChange,
  plan,
  onSubmit,
  isSubmitting,
}: PlanDialogProps) {
  const { t } = useTranslation();
  const isEditing = !!plan;

  const form = useForm<PlanFormValues>({
    resolver: zodResolver(planSchema),
    defaultValues: {
      name: '',
      description: '',
      price: 0,
      billing_period: 'monthly',
      max_users: 5,
      max_storage_gb: 10,
      is_active: true,
    },
  });

  useEffect(() => {
    if (plan) {
      form.reset({
        name: plan.name,
        description: plan.description || '',
        price: Number(plan.price),
        billing_period: plan.billing_period as 'monthly' | 'yearly',
        max_users: plan.max_users ?? 5,
        max_storage_gb: plan.max_storage_gb ?? 10,
        is_active: plan.is_active,
      });
    } else {
      form.reset({
        name: '',
        description: '',
        price: 0,
        billing_period: 'monthly',
        max_users: 5,
        max_storage_gb: 10,
        is_active: true,
      });
    }
  }, [plan, form]);

  const handleSubmit = (data: PlanFormValues) => {
    onSubmit({
      ...data,
      description: data.description || null,
    } as any);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>
            {isEditing ? t('plans.editPlan') : t('plans.addPlan')}
          </DialogTitle>
          <DialogDescription>
            {isEditing
              ? t('plans.editPlanDescription')
              : t('plans.addPlanDescription')}
          </DialogDescription>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-4">
            <FormField
              control={form.control}
              name="name"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>{t('plans.name')}</FormLabel>
                  <FormControl>
                    <Input {...field} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="description"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>{t('plans.description')}</FormLabel>
                  <FormControl>
                    <Textarea {...field} rows={3} />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="price"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('plans.price')}</FormLabel>
                    <FormControl>
                      <Input type="number" step="0.01" min="0" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="billing_period"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('plans.billingPeriod')}</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="monthly">{t('plans.monthly')}</SelectItem>
                        <SelectItem value="yearly">{t('plans.yearly')}</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="max_users"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('plans.maxUsers')}</FormLabel>
                    <FormControl>
                      <Input type="number" min="-1" {...field} />
                    </FormControl>
                    <FormDescription className="text-xs">
                      {t('plans.unlimitedHint')}
                    </FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="max_storage_gb"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('plans.maxStorage')}</FormLabel>
                    <FormControl>
                      <Input type="number" min="0" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <FormField
              control={form.control}
              name="is_active"
              render={({ field }) => (
                <FormItem className="flex flex-row items-center justify-between rounded-lg border p-3">
                  <div className="space-y-0.5">
                    <FormLabel>{t('plans.isActive')}</FormLabel>
                    <FormDescription className="text-xs">
                      {t('plans.isActiveHint')}
                    </FormDescription>
                  </div>
                  <FormControl>
                    <Switch
                      checked={field.value}
                      onCheckedChange={field.onChange}
                    />
                  </FormControl>
                </FormItem>
              )}
            />

            <DialogFooter>
              <Button
                type="button"
                variant="outline"
                onClick={() => onOpenChange(false)}
              >
                {t('common.cancel')}
              </Button>
              <Button type="submit" disabled={isSubmitting}>
                {isSubmitting ? t('common.loading') : t('common.save')}
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/shared/components/ui/dialog';
import type { BatchQuestion } from '@/hooks/questions/useQuestionBatches';

interface QuestionDetailDialogProps {
  question: BatchQuestion | null;
  onClose: () => void;
  statusColor: (status: string) => string;
  statusLabel: (status: string) => string;
  typeLabel: (type: string) => string;
}

export function QuestionDetailDialog({ question, onClose, statusColor, statusLabel, typeLabel }: QuestionDetailDialogProps) {
  const { t } = useTranslation();

  return (
    <Dialog open={!!question} onOpenChange={() => onClose()}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{t('questions.questionDetails')}</DialogTitle>
          <DialogDescription>{t('questions.viewQuestion')}</DialogDescription>
        </DialogHeader>

        {question && (
          <div className="space-y-4">
            <div className="space-y-2">
              <p className="text-sm font-medium text-muted-foreground">{t('batches.questionText')}</p>
              <p className="text-sm bg-muted/50 rounded-md p-3">{question.question_text}</p>
            </div>

            <div className="space-y-2">
              <p className="text-sm font-medium text-muted-foreground">{t('batches.questionTextAr')}</p>
              <p className="text-sm bg-muted/50 rounded-md p-3" dir="rtl">
                {question.question_text_ar || '—'}
              </p>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">{t('batches.type')}:</span>
                <Badge variant="outline">{typeLabel(question.type)}</Badge>
              </div>
              {question.confidence_score != null && (
                <div className="flex items-center gap-2">
                  <span className="text-sm text-muted-foreground">{t('batches.confidence')}:</span>
                  <Badge variant="outline">{question.confidence_score}%</Badge>
                </div>
              )}
              <div className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">{t('common.status')}:</span>
                <Badge variant="outline" className={statusColor(question.validation_status || 'pending')}>
                  {statusLabel(question.validation_status || 'pending')}
                </Badge>
              </div>
            </div>

            {question.options && Array.isArray(question.options) && question.options.length > 0 && (
              <div className="space-y-2">
                <p className="text-sm font-medium text-muted-foreground">{t('questions.options')}</p>
                <ol className="list-decimal list-inside space-y-1 bg-muted/50 rounded-md p-3">
                  {question.options.map((opt: any, i: number) => (
                    <li key={i} className="text-sm">{typeof opt === 'string' ? opt : JSON.stringify(opt)}</li>
                  ))}
                </ol>
              </div>
            )}
          </div>
        )}

        <DialogFooter>
          <Button variant="outline" onClick={onClose}>
            {t('common.close')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

/**
 * ScheduleForm — name, description, schedule type, generation period, batches.
 * Extracted from ScheduleManagement.tsx dialog body. ZERO behaviour change.
 */

import { useTranslation } from 'react-i18next';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Textarea } from '@/shared/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { RadioGroup, RadioGroupItem } from '@/shared/components/ui/radio-group';
import { Popover, PopoverContent, PopoverTrigger } from '@/shared/components/ui/popover';
import { Checkbox } from '@/shared/components/ui/checkbox';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { CalendarClock, Package } from 'lucide-react';
import type { ScheduleFormState } from '@/features/admin/hooks/admin/useScheduleReducer';

interface ScheduleFormProps {
  state: ScheduleFormState;
  dispatch: React.Dispatch<any>;
  setField: <K extends keyof ScheduleFormState>(field: K, value: ScheduleFormState[K]) => void;
  batches: any[];
  periods: any[];
}

export default function ScheduleForm({ state, dispatch, setField, batches, periods }: ScheduleFormProps) {
  const { t } = useTranslation();

  const linkedPeriod = state.linkedPeriodId ? periods.find((p: any) => p.id === state.linkedPeriodId) : null;

  const filteredBatches = batches.filter((b: any) => {
    const matchesPurpose = state.scheduleType === 'daily_checkin' ? b.purpose === 'wellness' : b.purpose === 'survey';
    return matchesPurpose && b.status === 'published';
  });

  return (
    <>
      <div className="space-y-2">
        <Label>{t('schedules.name')}</Label>
        <Input
          value={state.name}
          onChange={e => setField('name', e.target.value)}
          placeholder={t('schedules.namePlaceholder')}
        />
      </div>
      <div className="space-y-2">
        <Label>{t('schedules.description')}</Label>
        <Textarea
          value={state.description}
          onChange={e => setField('description', e.target.value)}
          placeholder={t('schedules.descriptionPlaceholder')}
          rows={2}
        />
      </div>

      {/* Schedule Type Selector */}
      <div className="space-y-2">
        <Label>{t('schedules.scheduleType')}</Label>
        <RadioGroup
          value={state.scheduleType}
          onValueChange={(val) => dispatch({ type: 'CHANGE_SCHEDULE_TYPE', scheduleType: val })}
          className="flex gap-4"
        >
          <div className="flex items-center gap-2">
            <RadioGroupItem value="daily_checkin" id="type-checkin" />
            <Label htmlFor="type-checkin" className="font-normal cursor-pointer">
              {t('schedules.dailyCheckin')}
            </Label>
          </div>
          <div className="flex items-center gap-2">
            <RadioGroupItem value="survey" id="type-survey" />
            <Label htmlFor="type-survey" className="font-normal cursor-pointer">
              {t('schedules.survey')}
            </Label>
          </div>
        </RadioGroup>
      </div>

      {/* Link to Generation Period */}
      <div className="space-y-2">
        <Label className="flex items-center gap-2">
          <CalendarClock className="h-4 w-4" />
          {t('aiGenerator.generationPeriod')}
        </Label>
        <Select
          value={state.linkedPeriodId || '__none__'}
          onValueChange={(v) => {
            if (v === '__none__') {
              setField('linkedPeriodId', null);
            } else {
              setField('linkedPeriodId', v);
              const period = periods.find((p: any) => p.id === v);
              if (period) {
                setField('startDate', period.start_date.includes('T') ? period.start_date : `${period.start_date}T00:00`);
                setField('endDate', period.end_date.includes('T') ? period.end_date : `${period.end_date}T23:59`);
              }
            }
          }}
        >
          <SelectTrigger><SelectValue /></SelectTrigger>
          <SelectContent>
            <SelectItem value="__none__">{t('common.none')}</SelectItem>
            {periods.filter((p: any) => p.status === 'active' && p.purpose === (state.scheduleType === 'daily_checkin' ? 'wellness' : 'survey')).map((p: any) => (
              <SelectItem key={p.id} value={p.id}>
                {p.start_date} → {p.end_date}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {linkedPeriod && (
          <Badge variant="secondary" className="text-xs">
            {t('aiGenerator.periodLinked')}: {linkedPeriod.start_date} → {linkedPeriod.end_date}
          </Badge>
        )}
      </div>

      {/* Question Batches Multi-Select */}
      <div className="space-y-2">
        <Label>{t('schedules.questionBatches')}</Label>
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="outline" className="w-full justify-start font-normal">
              <Package className="h-4 w-4 me-2" />
              {state.selectedBatchIds.length > 0
                ? t('schedules.batchesSelected', { count: state.selectedBatchIds.length })
                : t('schedules.selectBatches')}
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-80 max-h-60 overflow-y-auto" align="start">
            {filteredBatches.length === 0 ? (
              <p className="text-sm text-muted-foreground py-2">{t('schedules.noBatchesAvailable')}</p>
            ) : (
              <div className="space-y-2">
                {filteredBatches.map((batch: any) => {
                  const isSelected = state.selectedBatchIds.includes(batch.id);
                  const isDisabled = !isSelected && state.selectedBatchIds.length >= 3;
                  return (
                    <label
                      key={batch.id}
                      className={`flex items-center gap-2 p-2 rounded-md hover:bg-accent cursor-pointer ${isDisabled ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                      <Checkbox
                        checked={isSelected}
                        disabled={isDisabled}
                        onCheckedChange={(checked) => {
                          if (checked) {
                            setField('selectedBatchIds', [...state.selectedBatchIds, batch.id]);
                          } else {
                            setField('selectedBatchIds', state.selectedBatchIds.filter((id: string) => id !== batch.id));
                          }
                        }}
                      />
                      <div className="flex-1 min-w-0">
                        <span className="text-sm truncate block">{batch.name || 'Unnamed Batch'}</span>
                      </div>
                      <Badge variant="outline" className="text-xs shrink-0">
                        {batch.question_count}
                      </Badge>
                    </label>
                  );
                })}
                {state.selectedBatchIds.length >= 3 && (
                  <p className="text-xs text-muted-foreground pt-1">{t('schedules.maxBatchesReached')}</p>
                )}
              </div>
            )}
          </PopoverContent>
        </Popover>
      </div>
    </>
  );
}

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/shared/components/ui/dialog';
import { Tooltip as UiTooltip, TooltipContent, TooltipTrigger } from '@/shared/components/ui/tooltip';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/shared/components/ui/table';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/shared/components/ui/collapsible';
import { Checkbox } from '@/shared/components/ui/checkbox';
import { Popover, PopoverContent, PopoverTrigger } from '@/shared/components/ui/popover';
import { Calendar, Loader2, BarChart3, ChevronDown, Filter, X, Building2, GitBranch, MapPin } from 'lucide-react';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface PreviewQuestion {
  id: string;
  status: string;
  scheduled_delivery: string;
  actual_delivery?: string;
  question_id: string;
  question_source?: string;
  employee?: {
    id?: string;
    full_name?: string;
    email?: string;
    department?: string | null;
    department_id?: string | null;
    branch_id?: string | null;
    section_id?: string | null;
    branch?: { id?: string; name?: string; name_ar?: string } | any;
    dept?: { id?: string; name?: string; name_ar?: string } | any;
    section?: { id?: string; name?: string; name_ar?: string } | any;
  } | null;
  question?: { id?: string; text?: string; text_ar?: string; type?: string } | null;
}

interface SchedulePreviewDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  previewQuestions: PreviewQuestion[];
  previewLoading: boolean;
}

const STATUS_OPTIONS = ['pending', 'delivered', 'answered', 'skipped', 'expired', 'failed'];

const STATUS_COLORS: Record<string, string> = {
  pending: 'hsl(var(--muted-foreground))',
  delivered: 'hsl(var(--primary))',
  answered: 'hsl(142, 71%, 45%)',
  skipped: 'hsl(0, 84%, 60%)',
  expired: 'hsl(25, 95%, 53%)',
  failed: 'hsl(0, 72%, 51%)',
};

const PIE_COLORS = ['hsl(var(--primary))', 'hsl(142, 71%, 45%)', 'hsl(var(--muted-foreground))', 'hsl(0, 84%, 60%)', 'hsl(25, 95%, 53%)', 'hsl(0, 72%, 51%)'];

export default function SchedulePreviewDialog({ open, onOpenChange, previewQuestions, previewLoading }: SchedulePreviewDialogProps) {
  const { t } = useTranslation();

  // View question detail state
  const [viewSq, setViewSq] = useState<PreviewQuestion | null>(null);

  // Filter state
  const [filterDateFrom, setFilterDateFrom] = useState('');
  const [filterDateTo, setFilterDateTo] = useState('');
  const [filterStatuses, setFilterStatuses] = useState<string[]>([]);
  const [filterEmployee, setFilterEmployee] = useState('');
  const [filterBranch, setFilterBranch] = useState('');
  const [filterDepartment, setFilterDepartment] = useState('');
  const [filterSection, setFilterSection] = useState('');
  const [showAnalytics, setShowAnalytics] = useState(false);

  // Helper to unwrap array joins
  const getEmpBranch = (sq: PreviewQuestion) => {
    const b = sq.employee?.branch;
    return Array.isArray(b) ? b[0] : b;
  };
  const getEmpDept = (sq: PreviewQuestion): { id?: string; name?: string; name_ar?: string } | null => {
    // Use FK join first, fallback to text department field
    const d = sq.employee?.dept;
    const resolved = Array.isArray(d) ? d[0] : d;
    if (resolved?.id) return resolved;
    // Fallback: use text department field as name
    if (sq.employee?.department) {
      return { name: sq.employee.department };
    }
    return null;
  };
  const getEmpSection = (sq: PreviewQuestion): { id?: string; name?: string; name_ar?: string } | null => {
    const s = sq.employee?.section;
    return Array.isArray(s) ? s[0] : s;
  };

  // Unique employees from data
  const uniqueEmployees = useMemo(() => {
    const map = new Map<string, string>();
    previewQuestions.forEach(sq => {
      const emp = sq.employee;
      if (emp?.id && emp?.full_name) map.set(emp.id, emp.full_name);
    });
    return Array.from(map.entries()).map(([id, name]) => ({ id, name }));
  }, [previewQuestions]);

  // Unique branches
  const uniqueBranches = useMemo(() => {
    const map = new Map<string, string>();
    previewQuestions.forEach(sq => {
      const b = getEmpBranch(sq);
      if (b?.id && b?.name) map.set(b.id, b.name);
    });
    return Array.from(map.entries()).map(([id, name]) => ({ id, name }));
  }, [previewQuestions]);

  // Unique departments (from FK or text fallback)
  const uniqueDepartments = useMemo(() => {
    const map = new Map<string, string>();
    previewQuestions.forEach(sq => {
      const d = getEmpDept(sq);
      if (d?.name) {
        const key = d.id || `text:${d.name}`;
        map.set(key, d.name);
      }
    });
    return Array.from(map.entries()).map(([id, name]) => ({ id, name }));
  }, [previewQuestions]);

  // Unique sections
  const uniqueSections = useMemo(() => {
    const map = new Map<string, string>();
    previewQuestions.forEach(sq => {
      const s = getEmpSection(sq);
      if (s?.id && s?.name) map.set(s.id, s.name);
    });
    return Array.from(map.entries()).map(([id, name]) => ({ id, name }));
  }, [previewQuestions]);

  // Filtered data
  const filteredPreview = useMemo(() => {
    return previewQuestions.filter(sq => {
      if (filterDateFrom && sq.scheduled_delivery < filterDateFrom) return false;
      if (filterDateTo && sq.scheduled_delivery > filterDateTo + 'T23:59:59') return false;
      if (filterStatuses.length > 0 && !filterStatuses.includes(sq.status)) return false;
      if (filterEmployee && filterEmployee !== 'all' && sq.employee?.id !== filterEmployee) return false;
      if (filterBranch && filterBranch !== 'all') {
        const b = getEmpBranch(sq);
        if (b?.id !== filterBranch) return false;
      }
      if (filterDepartment && filterDepartment !== 'all') {
        const d = getEmpDept(sq);
        const dKey = d?.id || (d?.name ? `text:${d.name}` : '');
        if (dKey !== filterDepartment) return false;
      }
      if (filterSection && filterSection !== 'all') {
        const s = getEmpSection(sq);
        if (s?.id !== filterSection) return false;
      }
      return true;
    });
  }, [previewQuestions, filterDateFrom, filterDateTo, filterStatuses, filterEmployee, filterBranch, filterDepartment, filterSection]);

  // Chart data
  const statusChartData = useMemo(() => {
    const counts: Record<string, number> = {};
    filteredPreview.forEach(sq => { counts[sq.status] = (counts[sq.status] || 0) + 1; });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [filteredPreview]);

  const timelineChartData = useMemo(() => {
    const byDate: Record<string, number> = {};
    filteredPreview.forEach(sq => {
      const d = sq.scheduled_delivery ? new Date(sq.scheduled_delivery).toLocaleDateString() : 'Unknown';
      byDate[d] = (byDate[d] || 0) + 1;
    });
    return Object.entries(byDate)
      .map(([date, count]) => ({ date, count }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [filteredPreview]);

  // Status by Branch
  const statusByBranchData = useMemo(() => {
    const map: Record<string, Record<string, number>> = {};
    filteredPreview.forEach(sq => {
      const b = getEmpBranch(sq);
      const bName = b?.name || t('common.unassigned');
      if (!map[bName]) map[bName] = {};
      map[bName][sq.status] = (map[bName][sq.status] || 0) + 1;
    });
    return Object.entries(map).map(([name, statuses]) => ({ name, ...statuses }));
  }, [filteredPreview, t]);

  // Status by Department
  const statusByDeptData = useMemo(() => {
    const map: Record<string, Record<string, number>> = {};
    filteredPreview.forEach(sq => {
      const d = getEmpDept(sq);
      const dName = d?.name || t('common.unassigned');
      if (!map[dName]) map[dName] = {};
      map[dName][sq.status] = (map[dName][sq.status] || 0) + 1;
    });
    return Object.entries(map).map(([name, statuses]) => ({ name, ...statuses }));
  }, [filteredPreview, t]);

  // Status by Section
  const statusBySectionData = useMemo(() => {
    const map: Record<string, Record<string, number>> = {};
    filteredPreview.forEach(sq => {
      const s = getEmpSection(sq);
      const sName = s?.name || t('common.unassigned');
      if (!map[sName]) map[sName] = {};
      map[sName][sq.status] = (map[sName][sq.status] || 0) + 1;
    });
    return Object.entries(map).map(([name, statuses]) => ({ name, ...statuses }));
  }, [filteredPreview, t]);

  // All unique statuses for stacked bars
  const allStatuses = useMemo(() => {
    const s = new Set<string>();
    filteredPreview.forEach(sq => s.add(sq.status));
    return Array.from(s);
  }, [filteredPreview]);

  // Summary stats
  const totalCount = filteredPreview.length;
  const answeredCount = filteredPreview.filter(sq => sq.status === 'answered').length;
  const pendingCount = filteredPreview.filter(sq => sq.status === 'pending').length;
  const answeredRate = totalCount > 0 ? Math.round((answeredCount / totalCount) * 100) : 0;

  const hasActiveFilters = filterDateFrom || filterDateTo || filterStatuses.length > 0 || filterEmployee || filterBranch || filterDepartment || filterSection;

  const clearFilters = () => {
    setFilterDateFrom('');
    setFilterDateTo('');
    setFilterStatuses([]);
    setFilterEmployee('');
    setFilterBranch('');
    setFilterDepartment('');
    setFilterSection('');
  };

  const toggleStatusFilter = (status: string) => {
    setFilterStatuses(prev =>
      prev.includes(status) ? prev.filter(s => s !== status) : [...prev, status]
    );
  };

  const getSqStatusBadge = (status: string) => {
    const map: Record<string, string> = {
      pending: 'outline',
      delivered: 'secondary',
      answered: 'default',
      skipped: 'destructive',
    };
    return <Badge variant={(map[status] || 'outline') as any}>{status}</Badge>;
  };

  const handleClose = (openState: boolean) => {
    if (!openState) {
      clearFilters();
      setShowAnalytics(false);
    }
    onOpenChange(openState);
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-[900px] max-h-[85vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <div>
              <DialogTitle>{t('schedules.viewScheduled')}</DialogTitle>
              <DialogDescription>
                {t('schedules.scheduledQuestionsDescription')}
                {previewQuestions.length > 0 && (
                  <span className="ms-1">({previewQuestions.length} total)</span>
                )}
              </DialogDescription>
            </div>
          </div>
        </DialogHeader>

        {previewLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : previewQuestions.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <Calendar className="h-10 w-10 mx-auto mb-3 opacity-50" />
            <p>{t('schedules.noScheduledQuestions')}</p>
            <p className="text-sm mt-1">{t('schedules.runToGenerate')}</p>
          </div>
        ) : (
          <div className="space-y-4">
            {/* Filter Bar */}
            <div className="flex flex-wrap items-end gap-3 p-3 border rounded-lg bg-muted/30">
              <div className="space-y-1">
                <Label className="text-xs">{t('common.from')}</Label>
                <Input
                  type="date"
                  value={filterDateFrom}
                  onChange={e => setFilterDateFrom(e.target.value)}
                  className="h-9 w-[140px]"
                />
              </div>
              <div className="space-y-1">
                <Label className="text-xs">{t('common.to')}</Label>
                <Input
                  type="date"
                  value={filterDateTo}
                  onChange={e => setFilterDateTo(e.target.value)}
                  className="h-9 w-[140px]"
                />
              </div>
              <div className="space-y-1">
                <Label className="text-xs">{t('common.status')}</Label>
                <Popover>
                  <PopoverTrigger asChild>
                    <Button variant="outline" size="sm" className="h-9 min-w-[120px] justify-start">
                      <Filter className="h-3.5 w-3.5 me-1.5" />
                      {filterStatuses.length > 0
                        ? `${filterStatuses.length} ${t('common.selected')}`
                        : t('common.all')}
                      <ChevronDown className="h-3.5 w-3.5 ms-auto" />
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-48 p-2" align="start">
                    <div className="space-y-1">
                      {STATUS_OPTIONS.map(status => (
                        <label key={status} className="flex items-center gap-2 p-1.5 rounded hover:bg-accent cursor-pointer">
                          <Checkbox
                            checked={filterStatuses.includes(status)}
                            onCheckedChange={() => toggleStatusFilter(status)}
                          />
                          <span className="text-sm capitalize">{status}</span>
                        </label>
                      ))}
                    </div>
                  </PopoverContent>
                </Popover>
              </div>
              <div className="space-y-1">
                <Label className="text-xs">{t('schedules.employee')}</Label>
                <Select value={filterEmployee} onValueChange={setFilterEmployee}>
                  <SelectTrigger className="h-9 w-[160px]">
                    <SelectValue placeholder="All" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">{t('common.all')}</SelectItem>
                    {uniqueEmployees.map(emp => (
                      <SelectItem key={emp.id} value={emp.id}>{emp.name}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              {uniqueBranches.length > 0 && (
                <div className="space-y-1">
                  <Label className="text-xs">{t('branches.title')}</Label>
                  <Select value={filterBranch} onValueChange={setFilterBranch}>
                    <SelectTrigger className="h-9 w-[150px]">
                      <SelectValue placeholder={t('common.all')} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">{t('common.all')}</SelectItem>
                      {uniqueBranches.map(b => (
                        <SelectItem key={b.id} value={b.id}>{b.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )}
              {uniqueDepartments.length > 0 && (
                <div className="space-y-1">
                  <Label className="text-xs">{t('users.department')}</Label>
                  <Select value={filterDepartment} onValueChange={setFilterDepartment}>
                    <SelectTrigger className="h-9 w-[150px]">
                      <SelectValue placeholder={t('common.all')} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">{t('common.all')}</SelectItem>
                      {uniqueDepartments.map(d => (
                        <SelectItem key={d.id} value={d.id}>{d.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )}
              {uniqueSections.length > 0 && (
                <div className="space-y-1">
                  <Label className="text-xs">{t('sections.title')}</Label>
                  <Select value={filterSection} onValueChange={setFilterSection}>
                    <SelectTrigger className="h-9 w-[150px]">
                      <SelectValue placeholder={t('common.all')} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">{t('common.all')}</SelectItem>
                      {uniqueSections.map(s => (
                        <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )}
              <div className="flex items-end gap-2 ms-auto">
                {hasActiveFilters && (
                  <Button variant="ghost" size="sm" className="h-9" onClick={clearFilters}>
                    <X className="h-3.5 w-3.5 me-1" />
                    {t('common.clear')}
                  </Button>
                )}
                <Button
                  variant={showAnalytics ? 'default' : 'outline'}
                  size="sm"
                  className="h-9"
                  onClick={() => setShowAnalytics(prev => !prev)}
                >
                  <BarChart3 className="h-3.5 w-3.5 me-1.5" />
                  {t('common.analytics')}
                </Button>
              </div>
            </div>

            {/* Analytics Section */}
            <Collapsible open={showAnalytics}>
              <CollapsibleContent>
                <div className="space-y-4 pb-2">
                  {/* Summary Cards */}
                  <div className="grid grid-cols-3 gap-3">
                    <Card>
                      <CardContent className="p-4 text-center">
                        <p className="text-2xl font-bold">{totalCount}</p>
                        <p className="text-xs text-muted-foreground">{t('common.totalQuestions')}</p>
