                      </CardContent>
                    </Card>
                    <Card>
                      <CardContent className="p-4 text-center">
                        <p className="text-2xl font-bold">{pendingCount}</p>
                        <p className="text-xs text-muted-foreground">{t('common.pending')}</p>
                      </CardContent>
                    </Card>
                  </div>

                  {/* Charts */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Status Distribution Pie */}
                    <Card>
                      <CardContent className="p-4">
                        <p className="text-sm font-medium mb-3">{t('common.statusDistribution')}</p>
                        {statusChartData.length > 0 ? (
                          <ResponsiveContainer width="100%" height={200}>
                            <PieChart>
                              <Pie
                                data={statusChartData}
                                cx="50%"
                                cy="50%"
                                innerRadius={50}
                                outerRadius={80}
                                paddingAngle={2}
                                dataKey="value"
                                nameKey="name"
                              >
                                {statusChartData.map((entry, index) => (
                                  <Cell
                                    key={entry.name}
                                    fill={STATUS_COLORS[entry.name] || PIE_COLORS[index % PIE_COLORS.length]}
                                  />
                                ))}
                              </Pie>
                              <Tooltip />
                              <Legend />
                            </PieChart>
                          </ResponsiveContainer>
                        ) : (
                          <p className="text-sm text-muted-foreground text-center py-8">{t('common.noData')}</p>
                        )}
                      </CardContent>
                    </Card>

                    {/* Delivery Timeline Bar */}
                    <Card>
                      <CardContent className="p-4">
                        <p className="text-sm font-medium mb-3">{t('common.deliveryTimeline')}</p>
                        {timelineChartData.length > 0 ? (
                          <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={timelineChartData}>
                              <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                              <YAxis allowDecimals={false} tick={{ fontSize: 11 }} />
                              <Tooltip />
                              <Bar dataKey="count" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                            </BarChart>
                          </ResponsiveContainer>
                        ) : (
                          <p className="text-sm text-muted-foreground text-center py-8">{t('common.noData')}</p>
                        )}
                      </CardContent>
                    </Card>
                  </div>

                  {/* Org-Level Status Distribution */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Status by Branch */}
                    {statusByBranchData.length > 0 && (
                      <Card>
                        <CardContent className="p-4">
                          <div className="flex items-center gap-2 mb-3">
                            <Building2 className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm font-medium">{t('branches.title')} — {t('common.statusDistribution')}</p>
                          </div>
                          <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={statusByBranchData} layout="vertical">
                              <XAxis type="number" allowDecimals={false} tick={{ fontSize: 11 }} />
                              <YAxis type="category" dataKey="name" tick={{ fontSize: 11 }} width={80} />
                              <Tooltip />
                              <Legend />
                              {allStatuses.map((status, i) => (
                                <Bar key={status} dataKey={status} stackId="a" fill={STATUS_COLORS[status] || PIE_COLORS[i % PIE_COLORS.length]} />
                              ))}
                            </BarChart>
                          </ResponsiveContainer>
                        </CardContent>
                      </Card>
                    )}

                    {/* Status by Department */}
                    {statusByDeptData.length > 0 && (
                      <Card>
                        <CardContent className="p-4">
                          <div className="flex items-center gap-2 mb-3">
                            <GitBranch className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm font-medium">{t('users.department')} — {t('common.statusDistribution')}</p>
                          </div>
                          <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={statusByDeptData} layout="vertical">
                              <XAxis type="number" allowDecimals={false} tick={{ fontSize: 11 }} />
                              <YAxis type="category" dataKey="name" tick={{ fontSize: 11 }} width={80} />
                              <Tooltip />
                              <Legend />
                              {allStatuses.map((status, i) => (
                                <Bar key={status} dataKey={status} stackId="a" fill={STATUS_COLORS[status] || PIE_COLORS[i % PIE_COLORS.length]} />
                              ))}
                            </BarChart>
                          </ResponsiveContainer>
                        </CardContent>
                      </Card>
                    )}

                    {/* Status by Section */}
                    {statusBySectionData.length > 0 && (
                      <Card>
                        <CardContent className="p-4">
                          <div className="flex items-center gap-2 mb-3">
                            <MapPin className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm font-medium">{t('sections.title')} — {t('common.statusDistribution')}</p>
                          </div>
                          <ResponsiveContainer width="100%" height={200}>
                            <BarChart data={statusBySectionData} layout="vertical">
                              <XAxis type="number" allowDecimals={false} tick={{ fontSize: 11 }} />
                              <YAxis type="category" dataKey="name" tick={{ fontSize: 11 }} width={80} />
                              <Tooltip />
                              <Legend />
                              {allStatuses.map((status, i) => (
                                <Bar key={status} dataKey={status} stackId="a" fill={STATUS_COLORS[status] || PIE_COLORS[i % PIE_COLORS.length]} />
                              ))}
                            </BarChart>
                          </ResponsiveContainer>
                        </CardContent>
                      </Card>
                    )}
                  </div>
                </div>
              </CollapsibleContent>
            </Collapsible>

            {/* Results count */}
            {hasActiveFilters && (
              <p className="text-sm text-muted-foreground">
                {t('common.showingOf', { shown: filteredPreview.length, total: previewQuestions.length })}
              </p>
            )}

            {/* Table */}
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>{t('schedules.employee')}</TableHead>
                  <TableHead>{t('branches.title')}</TableHead>
                  <TableHead>{t('users.department')}</TableHead>
                  <TableHead>{t('sections.title')}</TableHead>
                  <TableHead>{t('questions.questionTextEn')}</TableHead>
                  <TableHead>{t('schedules.delivery')}</TableHead>
                  <TableHead>{t('common.status')}</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredPreview.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center text-muted-foreground py-6">
                      {t('common.noMatchingQuestions')}
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredPreview.map(sq => (
                    <TableRow key={sq.id}>
                      <TableCell className="text-sm">
                        {sq.employee?.full_name || '-'}
                      </TableCell>
                      <TableCell className="text-sm">
                        {getEmpBranch(sq)?.name || '-'}
                      </TableCell>
                      <TableCell className="text-sm">
                        {getEmpDept(sq)?.name || '-'}
                      </TableCell>
                      <TableCell className="text-sm">
                        {getEmpSection(sq)?.name || '-'}
                      </TableCell>
                      <TableCell
                        className="text-sm max-w-[220px] cursor-pointer hover:bg-muted/50"
                        onClick={() => setViewSq(sq)}
                      >
                        {(() => {
                          const text = sq.question?.text || '-';
                          if (text === '-' || text.length <= 45) return <span>{text}</span>;
                          return (
                            <UiTooltip>
                              <TooltipTrigger asChild>
                                <p className="line-clamp-2 cursor-help">{text}</p>
                              </TooltipTrigger>
                              <TooltipContent side="bottom" className="max-w-sm whitespace-pre-wrap">
                                <p className="text-sm">{text}</p>
                              </TooltipContent>
                            </UiTooltip>
                          );
                        })()}
                      </TableCell>
                      <TableCell className="text-sm">
                        {sq.scheduled_delivery
                          ? new Date(sq.scheduled_delivery).toLocaleDateString()
                          : '-'}
                      </TableCell>
                      <TableCell>{getSqStatusBadge(sq.status)}</TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        )}
      </DialogContent>

      {/* Question Detail Dialog */}
      <Dialog open={!!viewSq} onOpenChange={() => setViewSq(null)}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{t('questions.questionDetails')}</DialogTitle>
            <DialogDescription>{t('questions.viewQuestion')}</DialogDescription>
          </DialogHeader>
          {viewSq && (
            <div className="space-y-4">
              <div className="space-y-2">
                <p className="text-sm font-medium text-muted-foreground">{t('questions.questionTextEn')}</p>
                <p className="text-sm bg-muted/50 rounded-md p-3">{viewSq.question?.text || '-'}</p>
              </div>
              <div className="space-y-2">
                <p className="text-sm font-medium text-muted-foreground">{t('questions.questionTextAr')}</p>
                <p className="text-sm bg-muted/50 rounded-md p-3" dir="rtl">{viewSq.question?.text_ar || '-'}</p>
              </div>
              <div className="flex flex-wrap items-center gap-3">
                {viewSq.question?.type && (
                  <div className="flex items-center gap-2">
                    <span className="text-sm text-muted-foreground">{t('questions.type')}:</span>
                    <Badge variant="outline">{viewSq.question.type}</Badge>
                  </div>
                )}
                <div className="flex items-center gap-2">
                  <span className="text-sm text-muted-foreground">{t('common.status')}:</span>
                  {getSqStatusBadge(viewSq.status)}
                </div>
                {viewSq.employee?.full_name && (
                  <div className="flex items-center gap-2">
                    <span className="text-sm text-muted-foreground">{t('schedules.employee')}:</span>
                    <Badge variant="secondary">{viewSq.employee.full_name}</Badge>
                  </div>
                )}
              </div>
              {viewSq.scheduled_delivery && (
                <div className="flex items-center gap-2">
                  <span className="text-sm text-muted-foreground">{t('schedules.delivery')}:</span>
                  <span className="text-sm">{new Date(viewSq.scheduled_delivery).toLocaleDateString()}</span>
                </div>
              )}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setViewSq(null)}>{t('common.close')}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </Dialog>
  );
}

/**
 * ScheduleTimingConfig — frequency, preferred time, questions-per-delivery,
 * mood overrides, survey dates, weekend day picker.
 * Extracted from ScheduleManagement.tsx dialog body. ZERO behaviour change.
 */

import { useTranslation } from 'react-i18next';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { Switch } from '@/shared/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/shared/components/ui/collapsible';
import { ChevronDown, ChevronUp, Settings2 } from 'lucide-react';
import type { ScheduleFormState } from '@/features/admin/hooks/admin/useScheduleReducer';

interface MoodDef {
  key: string;
  emoji: string;
  label_en: string;
}

interface ScheduleTimingConfigProps {
  state: ScheduleFormState;
  dispatch: React.Dispatch<any>;
  setField: <K extends keyof ScheduleFormState>(field: K, value: ScheduleFormState[K]) => void;
  activeMoods: MoodDef[];
  linkedPeriod: any;
}

export default function ScheduleTimingConfig({
  state,
  dispatch,
  setField,
  activeMoods,
  linkedPeriod,
}: ScheduleTimingConfigProps) {
  const { t } = useTranslation();

  return (
    <>
      {/* Frequency - only for daily_checkin */}
      {state.scheduleType === 'daily_checkin' && (
        <div className="space-y-2">
          <Label>{t('schedules.frequency')}</Label>
          <Select value={state.frequency} onValueChange={v => setField('frequency', v)}>
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="1_per_day">{t('schedules.frequencies.daily')}</SelectItem>
              <SelectItem value="2_per_day">{t('schedules.frequencies.twiceDaily')}</SelectItem>
              <SelectItem value="3_days_per_week">{t('schedules.frequencies.threePerWeek')}</SelectItem>
              <SelectItem value="weekly">{t('schedules.frequencies.weekly')}</SelectItem>
              <SelectItem value="custom">{t('schedules.frequencies.custom')}</SelectItem>
            </SelectContent>
          </Select>
        </div>
      )}

      {/* Start/End Date — only for survey */}
      {state.scheduleType === 'survey' && (
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label>{t('schedules.startDate')}</Label>
            <Input
              type="datetime-local"
              value={state.startDate}
              onChange={e => setField('startDate', e.target.value)}
              readOnly={!!linkedPeriod}
            />
          </div>
          <div className="space-y-2">
            <Label>{t('schedules.endDate')}</Label>
            <Input
              type="datetime-local"
              value={state.endDate}
              onChange={e => setField('endDate', e.target.value)}
              min={state.startDate}
              readOnly={!!linkedPeriod}
            />
          </div>
        </div>
      )}

      {/* Preferred Time + Questions Per Delivery — only for daily_checkin */}
      {state.scheduleType === 'daily_checkin' && (
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <Label>{t('schedules.preferredTime')}</Label>
            <Input
              type="time"
              value={state.preferredTime}
              onChange={e => setField('preferredTime', e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <Label>{t('schedules.questionsPerDelivery')}</Label>
            <div className="flex items-center gap-1">
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-10 w-10"
                onClick={() => {
                  const newVal = Math.max(1, state.questionsPerDelivery - 1);
                  setField('questionsPerDelivery', newVal);
                  dispatch({ type: 'CLAMP_MOOD_OVERRIDES', maxValue: newVal });
                }}
                disabled={state.questionsPerDelivery <= 1}
              >
                <ChevronDown className="h-4 w-4" />
              </Button>
              <span className="w-10 text-center text-sm font-semibold tabular-nums">
                {state.questionsPerDelivery}
              </span>
              <Button
                type="button"
                variant="outline"
                size="icon"
                className="h-10 w-10"
                onClick={() => setField('questionsPerDelivery', Math.min(10, state.questionsPerDelivery + 1))}
                disabled={state.questionsPerDelivery >= 10}
              >
                <ChevronUp className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>
      )}

      {/* Questions Per Mood Configuration */}
      {state.scheduleType === 'daily_checkin' && activeMoods.length > 0 && (
        <Collapsible open={state.moodConfigOpen} onOpenChange={v => setField('moodConfigOpen', v)}>
          <CollapsibleTrigger asChild>
            <Button variant="outline" type="button" className="w-full justify-between">
              <span className="flex items-center gap-2">
                <Settings2 className="h-4 w-4" />
                {t('schedules.questionsPerMood', 'Questions Per Mood')}
              </span>
              <div className="flex items-center gap-2">
                {Object.values(state.moodOverrides).some(o => o.enabled) && (
                  <Badge variant="default" className="text-xs">
                    {Object.values(state.moodOverrides).filter(o => o.enabled).length} {t('schedules.customized', 'customized')}
                  </Badge>
                )}
                {state.moodConfigOpen ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
              </div>
            </Button>
          </CollapsibleTrigger>
          <CollapsibleContent>
            <div className="border rounded-md p-3 mt-2 space-y-3">
              <p className="text-xs text-muted-foreground">
                {t('schedules.moodInheritHint', 'Moods inherit the global Questions Per Delivery value unless overridden.')}
              </p>
              {activeMoods.map(mood => {
                const override = state.moodOverrides[mood.key];
                const isOverridden = override?.enabled === true;
                const displayValue = isOverridden ? Math.min(override.value, state.questionsPerDelivery) : state.questionsPerDelivery;
                return (
                  <div key={mood.key} className="flex items-center justify-between gap-2 py-1.5 border-b last:border-b-0">
                    <div className="flex items-center gap-2 min-w-0">
                      <span className="text-lg">{mood.emoji}</span>
                      <span className="text-sm font-medium truncate">{mood.label_en}</span>
                      <Badge variant={isOverridden ? 'default' : 'secondary'} className="text-xs shrink-0">
                        {isOverridden ? t('schedules.customizedBadge', 'Customized') : t('schedules.defaultBadge', 'Default')}
                      </Badge>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <Switch
                        checked={isOverridden}
                        onCheckedChange={(checked) => {
                          dispatch({
                            type: 'SET_MOOD_OVERRIDE',
                            key: mood.key,
                            enabled: checked,
                            value: state.moodOverrides[mood.key]?.value || state.questionsPerDelivery,
                          });
                        }}
                      />
                      {isOverridden ? (
                        <div className="flex items-center gap-1">
                          <Button
                            type="button"
                            variant="outline"
                            size="icon"
                            className="h-7 w-7"
                            onClick={() => {
                              dispatch({
                                type: 'SET_MOOD_OVERRIDE',
                                key: mood.key,
                                enabled: true,
                                value: Math.max(1, (state.moodOverrides[mood.key]?.value || 1) - 1),
                              });
                            }}
                            disabled={displayValue <= 1}
                          >
                            <ChevronDown className="h-3 w-3" />
                          </Button>
                          <span className="w-6 text-center text-sm font-semibold tabular-nums">{displayValue}</span>
                          <Button
                            type="button"
                            variant="outline"
                            size="icon"
                            className="h-7 w-7"
                            onClick={() => {
                              dispatch({
                                type: 'SET_MOOD_OVERRIDE',
                                key: mood.key,
                                enabled: true,
                                value: Math.min(state.questionsPerDelivery, (state.moodOverrides[mood.key]?.value || 1) + 1),
                              });
                            }}
                            disabled={displayValue >= state.questionsPerDelivery}
                          >
                            <ChevronUp className="h-3 w-3" />
                          </Button>
                        </div>
                      ) : (
                        <span className="w-[76px] text-center text-sm text-muted-foreground tabular-nums">{displayValue}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </CollapsibleContent>
        </Collapsible>
      )}

      {/* Weekend Days — only for daily_checkin */}
      {state.scheduleType === 'daily_checkin' && (
        <div className="space-y-2">
          <Label>{t('schedules.weekendDays')}</Label>
          <p className="text-xs text-muted-foreground">{t('schedules.weekendDaysHint')}</p>
          <div className="flex flex-wrap gap-2">
            {[
              { value: 0, label: t('schedules.days.sunday') },
              { value: 1, label: t('schedules.days.monday') },
              { value: 2, label: t('schedules.days.tuesday') },
              { value: 3, label: t('schedules.days.wednesday') },
              { value: 4, label: t('schedules.days.thursday') },
              { value: 5, label: t('schedules.days.friday') },
              { value: 6, label: t('schedules.days.saturday') },
            ].map(day => {
              const isSelected = state.weekendDays.includes(day.value);
              return (
                <Button
                  key={day.value}
                  type="button"
                  variant={isSelected ? 'default' : 'outline'}
                  size="sm"
                  className="min-w-[70px]"
                  onClick={() => {
                    setField(
                      'weekendDays',
                      isSelected
                        ? state.weekendDays.filter(d => d !== day.value)
                        : [...state.weekendDays, day.value],
                    );
                  }}
                >
                  {day.label}
                </Button>
              );
            })}
          </div>
        </div>
      )}
    </>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { format } from 'date-fns';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/shared/components/ui/dialog';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { Badge } from '@/shared/components/ui/badge';
import { TenantStatusBadge } from './TenantStatusBadge';
import { TenantTrialControl } from './TenantTrialControl';
import { TenantSecurityControl, type SecuritySettings, DEFAULT_SECURITY_SETTINGS } from './TenantSecurityControl';
import { InvitationManagement } from './InvitationManagement';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Building2, Calendar, Users, Globe, Mail, Phone, FileText } from 'lucide-react';
import type { Tenant } from '@/hooks/org/useTenants';

interface TenantDetailDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  tenant: Tenant | null;
  onUpdateTrial: (tenantId: string, action: 'start' | 'extend' | 'end', params?: any) => void;
  onUpdateSecurity: (tenantId: string, settings: SecuritySettings) => void;
  isUpdating: boolean;
}

export function TenantDetailDialog({
  open,
  onOpenChange,
  tenant,
  onUpdateTrial,
  onUpdateSecurity,
  isUpdating,
}: TenantDetailDialogProps) {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState('overview');

  if (!tenant) return null;

  const trialData = {
    subscription_status: tenant.subscription_status || 'inactive',
    trial_start_date: tenant.trial_start_date || null,
    trial_end_date: tenant.trial_end_date || null,
  };

  const securitySettings: SecuritySettings = {
    mfa_trust_duration_days: tenant.mfa_trust_duration_days ?? DEFAULT_SECURITY_SETTINGS.mfa_trust_duration_days,
    session_timeout_minutes: tenant.session_timeout_minutes ?? DEFAULT_SECURITY_SETTINGS.session_timeout_minutes,
    max_concurrent_sessions: tenant.max_concurrent_sessions ?? DEFAULT_SECURITY_SETTINGS.max_concurrent_sessions,
    glass_break_active: tenant.glass_break_active ?? DEFAULT_SECURITY_SETTINGS.glass_break_active,
  };

  const handleStartTrial = (days: number) => {
    onUpdateTrial(tenant.id, 'start', { days });
  };

  const handleExtendTrial = (params: { days?: number; endDate?: string }) => {
    onUpdateTrial(tenant.id, 'extend', params);
  };

  const handleEndTrial = () => {
    onUpdateTrial(tenant.id, 'end');
  };

  const handleSecurityChange = (settings: SecuritySettings) => {
    onUpdateSecurity(tenant.id, settings);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center gap-3">
            <DialogTitle className="text-xl">{tenant.name}</DialogTitle>
            <TenantStatusBadge status={tenant.status} />
          </div>
          <DialogDescription>
            {tenant.slug && <span className="font-mono">{tenant.slug}</span>}
            {tenant.domain && (
              <>
                <span className="mx-2">•</span>
                <span>{tenant.domain}</span>
              </>
            )}
          </DialogDescription>
        </DialogHeader>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="mt-4">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="overview">{t('tenants.tabs.overview')}</TabsTrigger>
            <TabsTrigger value="subscription">{t('tenants.tabs.subscription')}</TabsTrigger>
            <TabsTrigger value="security">{t('tenants.tabs.security')}</TabsTrigger>
            <TabsTrigger value="invitations">{t('tenants.tabs.invitations')}</TabsTrigger>
          </TabsList>

          <TabsContent value="overview" className="mt-4 space-y-4">
            {/* Quick Stats */}
            <div className="grid grid-cols-4 gap-4">
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Calendar className="h-4 w-4" />
                    <span className="text-xs">{t('tenants.createdAt')}</span>
                  </div>
                  <p className="mt-1 font-medium">{format(new Date(tenant.created_at), 'PP')}</p>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <FileText className="h-4 w-4" />
                    <span className="text-xs">{t('tenants.plan')}</span>
                  </div>
                  <p className="mt-1 font-medium">
                    {tenant.plan?.name || t('tenants.noPlan')}
                  </p>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Building2 className="h-4 w-4" />
                    <span className="text-xs">{t('tenants.industry')}</span>
                  </div>
                  <p className="mt-1 font-medium">
                    {tenant.industry ? t(`tenants.industries.${tenant.industry}`) : '-'}
                  </p>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <Users className="h-4 w-4" />
                    <span className="text-xs">{t('tenants.employeeCount')}</span>
                  </div>
                  <p className="mt-1 font-medium">{tenant.employee_count || '-'}</p>
                </CardContent>
              </Card>
            </div>

            {/* Contact & Business Info */}
            <div className="grid grid-cols-2 gap-4">
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm">{t('tenants.contactInfo')}</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm">
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground w-24">{t('tenants.contactPerson')}:</span>
                    <span>{tenant.contact_person || '-'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Mail className="h-3 w-3 text-muted-foreground" />
                    <span>{tenant.contact_email || '-'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Phone className="h-3 w-3 text-muted-foreground" />
                    <span dir="ltr">{tenant.contact_phone || '-'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Globe className="h-3 w-3 text-muted-foreground" />
                    <span>{tenant.country ? `${tenant.city || ''}, ${tenant.country}` : '-'}</span>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm">{t('tenants.businessInfo')}</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm">
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground w-24">{t('tenants.crNumber')}:</span>
                    <span dir="ltr">{tenant.cr_number || '-'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground w-24">{t('tenants.vatNumber')}:</span>
                    <span dir="ltr">{tenant.vat_number || '-'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground w-24">{t('tenants.currency')}:</span>
                    <span>{tenant.preferred_currency || 'SAR'}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-muted-foreground w-24">{t('tenants.billingEmail')}:</span>
                    <span>{tenant.billing_email || '-'}</span>
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Notes */}
            {tenant.notes && (
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm">{t('tenants.notes')}</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-muted-foreground whitespace-pre-wrap">{tenant.notes}</p>
                </CardContent>
              </Card>
            )}
          </TabsContent>

          <TabsContent value="subscription" className="mt-4">
            <TenantTrialControl
              tenantId={tenant.id}
              trialData={trialData}
              onStartTrial={handleStartTrial}
              onExtendTrial={handleExtendTrial}
              onEndTrial={handleEndTrial}
              isUpdating={isUpdating}
            />
          </TabsContent>

          <TabsContent value="security" className="mt-4">
            <TenantSecurityControl
              settings={securitySettings}
              onChange={handleSecurityChange}
            />
          </TabsContent>

          <TabsContent value="invitations" className="mt-4">
            <InvitationManagement tenantId={tenant.id} />
          </TabsContent>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { Label } from '@/shared/components/ui/label';
import { Switch } from '@/shared/components/ui/switch';
import { Input } from '@/shared/components/ui/input';
import { Users, CreditCard, Headphones, Building2, FileText, Shield, UserPlus } from 'lucide-react';

export interface TenantSettings {
  allow_signup: boolean;
  mfa_required: boolean;
  max_users: number;
  modules: {
    user_management: boolean;
    billing: boolean;
    support: boolean;
    org_structure: boolean;
    documents: boolean;
  };
}

export const DEFAULT_SETTINGS: TenantSettings = {
  allow_signup: true,
  mfa_required: false,
  max_users: 10,
  modules: {
    user_management: true,
    billing: true,
    support: true,
    org_structure: true,
    documents: true,
  },
};

interface TenantModuleControlProps {
  settings: TenantSettings;
  onChange: (settings: TenantSettings) => void;
}

const MODULE_ICONS = {
  user_management: Users,
  billing: CreditCard,
  support: Headphones,
  org_structure: Building2,
  documents: FileText,
};

export function TenantModuleControl({ settings, onChange }: TenantModuleControlProps) {
  const { t } = useTranslation();

  const handleModuleToggle = (module: keyof TenantSettings['modules']) => {
    onChange({
      ...settings,
      modules: {
        ...settings.modules,
        [module]: !settings.modules[module],
      },
    });
  };

  const handleSettingToggle = (key: 'allow_signup' | 'mfa_required') => {
    onChange({
      ...settings,
      [key]: !settings[key],
    });
  };

  const handleMaxUsersChange = (value: string) => {
    const num = parseInt(value, 10);
    onChange({
      ...settings,
      max_users: isNaN(num) ? -1 : num,
    });
  };

  const moduleKeys = Object.keys(settings.modules) as (keyof TenantSettings['modules'])[];

  return (
    <div className="space-y-6">
      {/* Access Settings */}
      <div className="space-y-4">
        <h4 className="text-sm font-medium">{t('tenants.accessSettings')}</h4>
        <p className="text-xs text-muted-foreground">{t('tenants.accessSettingsDescription')}</p>
        
        <div className="space-y-4">
          <div className="flex items-center justify-between rounded-lg border p-4">
            <div className="flex items-center gap-3">
              <UserPlus className="h-5 w-5 text-muted-foreground" />
              <div>
                <Label className="text-sm font-medium">{t('tenants.allowSignup')}</Label>
                <p className="text-xs text-muted-foreground">{t('tenants.allowSignupDescription')}</p>
              </div>
            </div>
            <Switch
              checked={settings.allow_signup}
              onCheckedChange={() => handleSettingToggle('allow_signup')}
            />
          </div>

          <div className="flex items-center justify-between rounded-lg border p-4">
            <div className="flex items-center gap-3">
              <Shield className="h-5 w-5 text-muted-foreground" />
              <div>
                <Label className="text-sm font-medium">{t('tenants.mfaRequired')}</Label>
                <p className="text-xs text-muted-foreground">{t('tenants.mfaRequiredDescription')}</p>
              </div>
            </div>
            <Switch
              checked={settings.mfa_required}
              onCheckedChange={() => handleSettingToggle('mfa_required')}
            />
          </div>

          <div className="flex items-center justify-between rounded-lg border p-4">
            <div className="flex items-center gap-3">
              <Users className="h-5 w-5 text-muted-foreground" />
              <div>
                <Label className="text-sm font-medium">{t('tenants.maxUsers')}</Label>
                <p className="text-xs text-muted-foreground">{t('tenants.maxUsersDescription')}</p>
              </div>
            </div>
            <Input
              type="number"
              value={settings.max_users === -1 ? '' : settings.max_users}
              onChange={(e) => handleMaxUsersChange(e.target.value)}
              placeholder={t('plans.unlimited')}
              className="w-24 text-end"
              min={-1}
            />
          </div>
        </div>
      </div>

      {/* Module Toggles */}
      <div className="space-y-4">
        <h4 className="text-sm font-medium">{t('tenants.moduleAccess')}</h4>
        <p className="text-xs text-muted-foreground">{t('tenants.moduleAccessDescription')}</p>
        
        <div className="space-y-3">
          {moduleKeys.map((module) => {
            const Icon = MODULE_ICONS[module];
            return (
              <div
                key={module}
                className="flex items-center justify-between rounded-lg border p-4"
              >
                <div className="flex items-center gap-3">
                  <Icon className="h-5 w-5 text-muted-foreground" />
                  <div>
                    <Label className="text-sm font-medium">
                      {t(`tenants.modules.${module}`)}
                    </Label>
                    <p className="text-xs text-muted-foreground">
                      {t(`tenants.modules.${module}Description`)}
                    </p>
                  </div>
                </div>
                <Switch
                  checked={settings.modules[module]}
                  onCheckedChange={() => handleModuleToggle(module)}
                />
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { Shield, Clock, Users, AlertTriangle } from 'lucide-react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Label } from '@/shared/components/ui/label';
import { Input } from '@/shared/components/ui/input';
import { Switch } from '@/shared/components/ui/switch';
import { Slider } from '@/shared/components/ui/slider';
import { Badge } from '@/shared/components/ui/badge';
export type { SecuritySettings } from '@/shared/types/common.types/tenant';
export { DEFAULT_SECURITY_SETTINGS } from '@/shared/types/common.types/tenant';
import type { SecuritySettings } from '@/shared/types/common.types/tenant';

interface TenantSecurityControlProps {
  settings: SecuritySettings;
  onChange: (settings: SecuritySettings) => void;
}

export function TenantSecurityControl({ settings, onChange }: TenantSecurityControlProps) {
  const { t } = useTranslation();

  const handleChange = <K extends keyof SecuritySettings>(key: K, value: SecuritySettings[K]) => {
    onChange({ ...settings, [key]: value });
  };

  return (
    <div className="space-y-6">
      {/* MFA Settings */}
      <Card>
        <CardHeader className="pb-3">
          <div className="flex items-center gap-2">
            <Shield className="h-4 w-4 text-primary" />
            <CardTitle className="text-base">{t('tenants.security.mfaSettings')}</CardTitle>
          </div>
          <CardDescription>{t('tenants.security.mfaSettingsDescription')}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label>{t('tenants.security.mfaTrustDuration')}</Label>
              <span className="text-sm text-muted-foreground">
                {t('tenants.daysCount', { count: settings.mfa_trust_duration_days })}
              </span>
            </div>
            <Slider
              value={[settings.mfa_trust_duration_days]}
              onValueChange={([value]) => handleChange('mfa_trust_duration_days', value)}
              min={1}
              max={365}
              step={1}
              className="w-full"
            />
            <p className="text-xs text-muted-foreground">
              {t('tenants.security.mfaTrustDurationHint')}
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Session Settings */}
      <Card>
        <CardHeader className="pb-3">
          <div className="flex items-center gap-2">
            <Clock className="h-4 w-4 text-primary" />
            <CardTitle className="text-base">{t('tenants.security.sessionSettings')}</CardTitle>
          </div>
          <CardDescription>{t('tenants.security.sessionSettingsDescription')}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label>{t('tenants.security.sessionTimeout')}</Label>
            <div className="flex items-center gap-2">
              <Input
                type="number"
                value={settings.session_timeout_minutes}
                onChange={(e) => handleChange('session_timeout_minutes', parseInt(e.target.value) || 15)}
                min={5}
                max={120}
                className="w-24"
              />
              <span className="text-sm text-muted-foreground">{t('tenants.security.minutes')}</span>
            </div>
            <p className="text-xs text-muted-foreground">
              {t('tenants.security.sessionTimeoutHint')}
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Concurrent Sessions */}
      <Card>
        <CardHeader className="pb-3">
          <div className="flex items-center gap-2">
            <Users className="h-4 w-4 text-primary" />
            <CardTitle className="text-base">{t('tenants.security.concurrentSessions')}</CardTitle>
          </div>
          <CardDescription>{t('tenants.security.concurrentSessionsDescription')}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label>{t('tenants.security.maxConcurrent')}</Label>
            <div className="flex items-center gap-2">
              <Input
                type="number"
                value={settings.max_concurrent_sessions}
                onChange={(e) => handleChange('max_concurrent_sessions', parseInt(e.target.value) || 1)}
                min={1}
                max={10}
                className="w-24"
              />
              <span className="text-sm text-muted-foreground">{t('tenants.security.sessions')}</span>
            </div>
            <p className="text-xs text-muted-foreground">
              {t('tenants.security.maxConcurrentHint')}
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Emergency Access */}
      <Card className={settings.glass_break_active ? 'border-destructive' : ''}>
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <AlertTriangle className={`h-4 w-4 ${settings.glass_break_active ? 'text-destructive' : 'text-muted-foreground'}`} />
              <CardTitle className="text-base">{t('tenants.security.glassBreak')}</CardTitle>
            </div>
            {settings.glass_break_active && (
              <Badge variant="destructive">{t('common.active')}</Badge>
            )}
          </div>
          <CardDescription>{t('tenants.security.glassBreakDescription')}</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <Label>{t('tenants.security.enableGlassBreak')}</Label>
              <p className="text-xs text-muted-foreground">
                {t('tenants.security.glassBreakWarning')}
