            </div>
            <Switch
              checked={settings.glass_break_active}
              onCheckedChange={(checked) => handleChange('glass_break_active', checked)}
            />
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useEffect, useState } from 'react';
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetFooter,
} from '@/shared/components/ui/sheet';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/shared/components/ui/form';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/shared/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { TenantBrandingTab } from './TenantBrandingTab';
import { TenantModuleControl, DEFAULT_SETTINGS, type TenantSettings } from './TenantModuleControl';
import { TenantContactTab } from './TenantContactTab';
import { TenantSecurityControl, DEFAULT_SECURITY_SETTINGS, type SecuritySettings } from './TenantSecurityControl';
import { usePlansManagement } from '@/hooks/org/usePlans';
import type { Tenant } from '@/hooks/org/useTenants';

const TENANT_STATUSES = ['active', 'trial', 'suspended', 'inactive'] as const;

const tenantSchema = z.object({
  name: z.string().min(1, 'Name is required').max(100),
  slug: z.string().max(100).optional().or(z.literal('')),
  domain: z.string().max(255).optional().or(z.literal('')),
  status: z.enum(TENANT_STATUSES),
  plan_id: z.string().optional().or(z.literal('')),
  // Contact fields
  industry: z.string().optional().or(z.literal('')),
  country: z.string().optional().or(z.literal('')),
  city: z.string().optional().or(z.literal('')),
  contact_email: z.string().email('Primary Admin Email is required'),
  contact_phone: z.string().optional().or(z.literal('')),
  contact_person: z.string().optional().or(z.literal('')),
  notes: z.string().optional().or(z.literal('')),
  cr_number: z.string().optional().or(z.literal('')),
  vat_number: z.string().optional().or(z.literal('')),
  employee_count: z.number().nullable().optional(),
  preferred_currency: z.string().optional(),
  billing_email: z.string().email().optional().or(z.literal('')),
  default_language: z.enum(['en', 'ar'], { required_error: 'Default language is required' }),
  terms_accepted: z.boolean().refine(val => val === true, {
    message: 'You must accept the terms and conditions',
  }),
});

type TenantFormValues = z.infer<typeof tenantSchema>;

interface BrandingConfig {
  primary_hsl?: string;
  secondary_hsl?: string;
  accent_hsl?: string;
  logo_url?: string | null;
  favicon_url?: string | null;
}

interface TenantSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  tenant?: Tenant | null;
  onSubmit: (data: any) => void;
  isSubmitting: boolean;
}

export function TenantSheet({
  open,
  onOpenChange,
  tenant,
  onSubmit,
  isSubmitting,
}: TenantSheetProps) {
  const { t } = useTranslation();
  const { plans } = usePlansManagement();
  const isEditing = !!tenant;
  const [branding, setBranding] = useState<BrandingConfig>({});
  const [settings, setSettings] = useState<TenantSettings>(DEFAULT_SETTINGS);
  const [security, setSecurity] = useState<SecuritySettings>(DEFAULT_SECURITY_SETTINGS);

  // Wizard navigation state
  const TAB_ORDER = ['general', 'contact', 'security', 'modules', 'branding'] as const;
  const [activeTab, setActiveTab] = useState<string>(TAB_ORDER[0]);
  const currentIndex = TAB_ORDER.indexOf(activeTab as typeof TAB_ORDER[number]);
  const isFirstTab = currentIndex === 0;
  const isLastTab = currentIndex === TAB_ORDER.length - 1;

  const handleNext = () => {
    if (!isLastTab) {
      setActiveTab(TAB_ORDER[currentIndex + 1]);
    }
  };

  const handlePrevious = () => {
    if (!isFirstTab) {
      setActiveTab(TAB_ORDER[currentIndex - 1]);
    }
  };

  const form = useForm<TenantFormValues>({
    resolver: zodResolver(tenantSchema),
    defaultValues: {
      name: '',
      slug: '',
      domain: '',
      status: 'trial',
      plan_id: '',
      industry: '',
      country: '',
      city: '',
      contact_email: '',
      contact_phone: '',
      contact_person: '',
      notes: '',
      cr_number: '',
      vat_number: '',
      employee_count: null,
      preferred_currency: 'SAR',
      billing_email: '',
      default_language: 'en',
      terms_accepted: false,
    },
  });

  useEffect(() => {
    if (tenant) {
      const t = tenant as any;
      form.reset({
        name: tenant.name,
        slug: t.slug || '',
        domain: tenant.domain || '',
        status: tenant.status,
        plan_id: t.plan_id || '',
        industry: t.industry || '',
        country: t.country || '',
        city: t.city || '',
        contact_email: t.contact_email || '',
        contact_phone: t.contact_phone || '',
        contact_person: t.contact_person || '',
        notes: t.notes || '',
        cr_number: t.cr_number || '',
        vat_number: t.vat_number || '',
        employee_count: t.employee_count || null,
        preferred_currency: t.preferred_currency || 'SAR',
        billing_email: t.billing_email || '',
        default_language: t.default_language || 'en',
        terms_accepted: true, // Editing existing tenant implies terms were accepted
      });
      setBranding((tenant.branding_config as BrandingConfig) || {});
      setSettings(t.settings || DEFAULT_SETTINGS);
      setSecurity({
        mfa_trust_duration_days: t.mfa_trust_duration_days ?? DEFAULT_SECURITY_SETTINGS.mfa_trust_duration_days,
        session_timeout_minutes: t.session_timeout_minutes ?? DEFAULT_SECURITY_SETTINGS.session_timeout_minutes,
        max_concurrent_sessions: t.max_concurrent_sessions ?? DEFAULT_SECURITY_SETTINGS.max_concurrent_sessions,
        glass_break_active: t.glass_break_active ?? DEFAULT_SECURITY_SETTINGS.glass_break_active,
      });
    } else {
      form.reset({
        name: '',
        slug: '',
        domain: '',
        status: 'trial',
        plan_id: '',
        industry: '',
        country: '',
        city: '',
        contact_email: '',
        contact_phone: '',
        contact_person: '',
        notes: '',
        cr_number: '',
        vat_number: '',
        employee_count: null,
        preferred_currency: 'SAR',
        billing_email: '',
        default_language: 'en',
        terms_accepted: false,
      });
      setBranding({});
      setSettings(DEFAULT_SETTINGS);
      setSecurity(DEFAULT_SECURITY_SETTINGS);
    }
  }, [tenant, form]);

  const handleSubmit = (data: TenantFormValues) => {
    // Extract terms_accepted (form-only field) and exclude from database submission
    const { terms_accepted, ...tenantData } = data;
    onSubmit({
      ...tenantData,
      slug: tenantData.slug || null,
      domain: tenantData.domain || null,
      plan_id: tenantData.plan_id || null,
      branding_config: branding,
      settings,
      ...security,
    });
  };

  const activePlans = plans.filter(p => p.is_active);

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent className="sm:max-w-2xl overflow-y-auto">
        <SheetHeader>
          <SheetTitle>
            {isEditing ? t('tenants.editTenant') : t('tenants.addTenant')}
          </SheetTitle>
          <SheetDescription>
            {isEditing
              ? t('tenants.editTenantDescription')
              : t('tenants.addTenantDescription')}
          </SheetDescription>
        </SheetHeader>

        <Form {...form}>
