                      <FormControl>
                        <Input {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="slug"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('tenants.slug')}</FormLabel>
                      <FormControl>
                        <Input {...field} placeholder="company-name" />
                      </FormControl>
                      <p className="text-xs text-muted-foreground">{t('tenants.slugDescription')}</p>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="domain"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('tenants.domain')}</FormLabel>
                      <FormControl>
                        <Input {...field} placeholder="example.com" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="plan_id"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('tenants.plan')}</FormLabel>
                      <Select
                        onValueChange={(val) => field.onChange(val === '_none' ? '' : val)}
                        value={field.value || '_none'}
                      >
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder={t('tenants.selectPlan')} />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="_none">{t('tenants.noPlan')}</SelectItem>
                          {activePlans.map((plan) => (
                            <SelectItem key={plan.id} value={plan.id}>
                              {plan.name}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="status"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('common.status')} <span className="text-destructive">*</span></FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {TENANT_STATUSES.map((status) => (
                            <SelectItem key={status} value={status}>
                              {t(`common.${status}`)}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}

                />

                <FormField
                  control={form.control}
                  name="contact_email"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('tenants.contactEmail')} <span className="text-destructive">*</span></FormLabel>
                      <FormControl>
                        <Input {...field} type="email" placeholder="admin@company.com" />
                      </FormControl>
                      <p className="text-xs text-muted-foreground">{t('tenants.adminEmailHint')}</p>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="default_language"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('tenants.defaultLanguage')} <span className="text-destructive">*</span></FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="en">English</SelectItem>
                          <SelectItem value="ar">العربية</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

              </TabsContent>

              <TabsContent value="contact" className="mt-4">
                <TenantContactTab form={form} />
              </TabsContent>

              <TabsContent value="security" className="mt-4">
                <TenantSecurityControl settings={security} onChange={setSecurity} />
              </TabsContent>

              <TabsContent value="modules" className="mt-4">
                <TenantModuleControl settings={settings} onChange={setSettings} />
              </TabsContent>

              <TabsContent value="branding" className="mt-4 space-y-4">
                <TenantBrandingTab branding={branding} onChange={setBranding} />
                
                {!isEditing && (
                  <FormField
                    control={form.control}
                    name="terms_accepted"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start gap-3 space-y-0 rounded-md border p-4">
                        <FormControl>
                          <input
                            type="checkbox"
                            className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary mt-1"
                            checked={field.value}
                            onChange={(e) => field.onChange(e.target.checked)}
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>
                            {t('tenants.acceptTerms')} <span className="text-destructive">*</span>
                          </FormLabel>
                          <p className="text-sm text-muted-foreground">
                            {t('tenants.acceptTermsDescription')}
                          </p>
                        </div>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}
              </TabsContent>
            </Tabs>
          </form>
        </Form>

        <SheetFooter className="mt-6 flex justify-between gap-2">
          {isFirstTab ? (
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
            >
              {t('common.cancel')}
            </Button>
          ) : (
            <Button
              type="button"
              variant="outline"
              onClick={handlePrevious}
            >
              {t('common.previous')}
            </Button>
          )}
          
          {isLastTab ? (
            <Button
              type="submit"
              form="tenant-form"
              disabled={isSubmitting}
            >
              {isSubmitting ? t('common.loading') : t('common.save')}
            </Button>
          ) : (
            <Button type="button" onClick={handleNext}>
              {t('common.next')}
            </Button>
          )}
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/shared/components/ui/dialog';
import { Button } from '@/shared/components/ui/button';
import { Checkbox } from '@/shared/components/ui/checkbox';
import { Label } from '@/shared/components/ui/label';
import { ScrollArea } from '@/shared/components/ui/scroll-area';
import { Badge } from '@/shared/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Separator } from '@/shared/components/ui/separator';
import { useRoles, Role } from '@/features/auth/hooks/auth/useRoles';
import { useUserRoles } from '@/hooks/org/useUsers';
import { useHasRole } from '@/features/auth/hooks/auth/useUserPermissions';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import type { UserWithRoles } from '@/hooks/org/useUsers';
import { Shield, Loader2, AlertTriangle } from 'lucide-react';

interface UserRoleDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  user: UserWithRoles | null;
  tenantId?: string;
}

const SYSTEM_ROLES = ['super_admin', 'tenant_admin', 'manager', 'user'] as const;
type SystemRole = typeof SYSTEM_ROLES[number];

const SYSTEM_ROLE_COLORS: Record<SystemRole, string> = {
  super_admin: '#dc2626',
  tenant_admin: '#ea580c',
  manager: '#2563eb',
  user: '#16a34a',
};

export function UserRoleDialog({ open, onOpenChange, user, tenantId }: UserRoleDialogProps) {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.language === 'ar';
  const { roles, isPending: rolesLoading } = useRoles(tenantId);
  const { userRoles, assignRole, removeRole, updateUserRole } = useUserRoles(user?.user_id);
  const { hasRole: isSuperAdmin } = useHasRole('super_admin');
  const { user: currentUser } = useAuth();
  
  const [selectedRoles, setSelectedRoles] = useState<string[]>([]);
  const [selectedSystemRole, setSelectedSystemRole] = useState<SystemRole>('user');
  const [isSaving, setIsSaving] = useState(false);

  // Get current system role from user_roles
  const currentSystemRole = userRoles.length > 0 ? userRoles[0]?.role as SystemRole : 'user';
  const isEditingSelf = currentUser?.id === user?.user_id;

  const userRoleIds = userRoles
    ?.filter(ur => ur.custom_role_id)
    .map(ur => ur.custom_role_id as string)
    .sort()
    .join(',') || '';

  useEffect(() => {
    if (user && open) {
      setSelectedRoles(userRoleIds ? userRoleIds.split(',') : []);
      setSelectedSystemRole(currentSystemRole);
    }
  }, [user?.user_id, open, userRoleIds, currentSystemRole]);

  const handleRoleToggle = (roleId: string, checked: boolean) => {
    if (checked) {
      setSelectedRoles(prev => [...prev, roleId]);
    } else {
      setSelectedRoles(prev => prev.filter(id => id !== roleId));
    }
  };

  // Determine the effective system role: if custom roles are selected, use the highest base_role
  const getEffectiveSystemRole = (): SystemRole => {
    if (selectedRoles.length === 0) return selectedSystemRole;
    
    const priority: Record<SystemRole, number> = { super_admin: 4, tenant_admin: 3, manager: 2, user: 1 };
    let highest: SystemRole = selectedSystemRole;
    
    for (const roleId of selectedRoles) {
      const roleObj = roles.find(r => r.id === roleId);
      if (roleObj?.base_role) {
        const br = roleObj.base_role as SystemRole;
        if (priority[br] > priority[highest]) {
          highest = br;
        }
      }
    }
    
    return highest;
  };

  const handleSave = async () => {
    if (!user) return;
    
    setIsSaving(true);
    try {
      const currentRoleIds = userRoles
        .filter(ur => ur.custom_role_id)
        .map(ur => ur.custom_role_id as string);
      
      const rolesToAdd = selectedRoles.filter(id => !currentRoleIds.includes(id));
      const rolesToRemove = userRoles.filter(
        ur => ur.custom_role_id && !selectedRoles.includes(ur.custom_role_id)
      );

      // Remove custom role assignments
      for (const userRole of rolesToRemove) {
        await removeRole.mutateAsync(userRole.id);
      }

      // Add custom role assignments
      for (const roleId of rolesToAdd) {
        const roleObj = roles.find(r => r.id === roleId);
        const baseRole = (roleObj?.base_role as SystemRole) || 'user';
        
        // Check if user already has a user_roles row with this same system role value
        const existingRow = userRoles.find(ur => ur.role === baseRole && !ur.custom_role_id);
        
        if (existingRow) {
          await updateUserRole.mutateAsync({
            userRoleId: existingRow.id,
            customRoleId: roleId,
          });
        } else {
          await assignRole.mutateAsync({ 
            userId: user.user_id, 
            customRoleId: roleId,
            role: baseRole,
          });
        }
      }

      // Handle system role change (only if super_admin is making the change)
      const effectiveRole = getEffectiveSystemRole();
      if (effectiveRole !== currentSystemRole && isSuperAdmin) {
        // Update the primary user_roles row's system role
        const primaryRow = userRoles[0];
        if (primaryRow) {
          // We need to delete the old row and insert a new one since 'role' might conflict
          await removeRole.mutateAsync(primaryRow.id);
          await assignRole.mutateAsync({
            userId: user.user_id,
            customRoleId: primaryRow.custom_role_id || undefined,
            role: effectiveRole,
          });
        }
      }

      onOpenChange(false);
    } catch (error) {
      console.error('Error saving roles:', error);
    } finally {
      setIsSaving(false);
    }
  };

  // Can current user change system roles?
  const canEditSystemRole = isSuperAdmin && !isEditingSelf;
  // Available system roles for the selector (super_admins shouldn't be demoted by non-super_admins)
  const availableSystemRoles = SYSTEM_ROLES.filter(r => {
    // Only super_admins can assign super_admin
    if (r === 'super_admin' && !isSuperAdmin) return false;
    return true;
  });

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Shield className="h-5 w-5" />
            {t('users.manageRoles')}
          </DialogTitle>
          <DialogDescription>
            {user?.full_name || t('users.unnamed')}
          </DialogDescription>
        </DialogHeader>

        <ScrollArea className="max-h-[400px] pe-4">
          {/* System Role Section */}
          <div className="space-y-3 mb-4">
            <div className="flex items-center gap-2">
              <Label className="font-semibold text-sm">{t('roles.systemRole', 'System Role')}</Label>
              <Badge
                style={{ backgroundColor: SYSTEM_ROLE_COLORS[currentSystemRole] + '20', color: SYSTEM_ROLE_COLORS[currentSystemRole] }}
                variant="outline"
                className="text-xs"
              >
                {currentSystemRole}
              </Badge>
            </div>

            {canEditSystemRole ? (
              <Select value={selectedSystemRole} onValueChange={(v) => setSelectedSystemRole(v as SystemRole)}>
                <SelectTrigger className="w-full">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {availableSystemRoles.map(role => (
                    <SelectItem key={role} value={role}>
                      <div className="flex items-center gap-2">
                        <span
                          className="h-2 w-2 rounded-full"
                          style={{ backgroundColor: SYSTEM_ROLE_COLORS[role] }}
                        />
                        {role.replace('_', ' ')}
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            ) : (
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <AlertTriangle className="h-3 w-3" />
                {isEditingSelf
                  ? t('roles.cannotEditOwnSystemRole', 'You cannot change your own system role')
                  : t('roles.onlySuperAdminCanEdit', 'Only super admins can change system roles')
                }
              </div>
            )}
          </div>

          <Separator className="my-4" />

          {/* Custom Roles Section */}
          <div className="space-y-3">
            <Label className="font-semibold text-sm">{t('roles.customRoles', 'Custom Roles')}</Label>
            
            {rolesLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
              </div>
            ) : roles.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                {t('roles.noRoles')}
              </div>
            ) : (
              <div className="space-y-3">
                {roles.map((role) => (
                  <div
                    key={role.id}
                    className="flex items-start gap-3 p-3 rounded-lg border hover:bg-muted/50 transition-colors"
                  >
                    <Checkbox
                      id={`role-${role.id}`}
                      checked={selectedRoles.includes(role.id)}
                      onCheckedChange={(checked) => handleRoleToggle(role.id, checked as boolean)}
                    />
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-2">
                        <Label
                          htmlFor={`role-${role.id}`}
                          className="font-medium cursor-pointer"
                        >
                          {isRTL && role.name_ar ? role.name_ar : role.name}
                        </Label>
                        <Badge
                          style={{ backgroundColor: role.color + '20', color: role.color }}
                          variant="outline"
                          className="text-xs"
                        >
                          {role.base_role}
                        </Badge>
                        {role.is_system_role && (
                          <Badge variant="secondary" className="text-xs">
                            {t('roles.system')}
                          </Badge>
                        )}
                      </div>
                      {(isRTL ? role.description_ar : role.description) && (
                        <p className="text-sm text-muted-foreground">
                          {isRTL && role.description_ar ? role.description_ar : role.description}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </ScrollArea>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            {t('common.cancel')}
          </Button>
          <Button onClick={handleSave} disabled={isSaving}>
            {isSaving && <Loader2 className="me-2 h-4 w-4 animate-spin" />}
            {t('common.save')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/shared/components/ui/alert-dialog';
import { UserX, Ban, Trash2, UserCheck } from 'lucide-react';
import type { UserWithRoles } from '@/hooks/org/useUsers';

export type StatusAction = 'deactivate' | 'suspend' | 'reactivate' | 'delete';

interface UserStatusDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  user: UserWithRoles | null;
  action: StatusAction;
  onConfirm: () => Promise<void>;
  isLoading: boolean;
}

export function UserStatusDialog({
  open,
  onOpenChange,
  user,
  action,
  onConfirm,
  isLoading,
}: UserStatusDialogProps) {
  const { t } = useTranslation();

  const getActionConfig = () => {
    switch (action) {
      case 'deactivate':
        return {
          title: t('users.deactivateUser'),
          description: t('users.confirmDeactivate'),
          icon: UserX,
          variant: 'default' as const,
          buttonText: t('users.deactivateUser'),
        };
      case 'suspend':
        return {
          title: t('users.suspendUser'),
          description: t('users.confirmSuspend'),
          icon: Ban,
          variant: 'destructive' as const,
          buttonText: t('users.suspendUser'),
        };
      case 'reactivate':
        return {
          title: t('users.reactivateUser'),
          description: t('users.confirmReactivate'),
          icon: UserCheck,
          variant: 'default' as const,
          buttonText: t('users.reactivateUser'),
        };
      case 'delete':
        return {
          title: t('users.deleteUser'),
          description: t('users.confirmDelete'),
          icon: Trash2,
          variant: 'destructive' as const,
          buttonText: t('users.deleteUser'),
        };
    }
  };

  const config = getActionConfig();
  const Icon = config.icon;

  if (!user) return null;

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-full ${config.variant === 'destructive' ? 'bg-destructive/10' : 'bg-primary/10'}`}>
              <Icon className={`h-5 w-5 ${config.variant === 'destructive' ? 'text-destructive' : 'text-primary'}`} />
            </div>
            <AlertDialogTitle>{config.title}</AlertDialogTitle>
          </div>
          <AlertDialogDescription className="pt-2">
            {config.description}
            <div className="mt-2 p-3 bg-muted rounded-lg">
              <div className="font-medium">{user.full_name || t('users.unnamed')}</div>
              <div className="text-sm text-muted-foreground">{(user as any).email || user.user_id}</div>
            </div>
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel disabled={isLoading}>{t('common.cancel')}</AlertDialogCancel>
          <AlertDialogAction
            onClick={(e) => {
              e.preventDefault();
              onConfirm();
            }}
            disabled={isLoading}
            className={config.variant === 'destructive' ? 'bg-destructive text-destructive-foreground hover:bg-destructive/90' : ''}
          >
            {isLoading ? t('common.loading') : config.buttonText}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

import { useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { updateMoodTags, unlinkQuestionFromMood } from '@/features/mental-toolkit/services/moodTaggingService';

export function useMoodTagging(questions: { id: string; mood_levels?: string[]; [key: string]: any }[]) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [isSaving, setIsSaving] = useState(false);

  const getTaggedQuestions = (moodLevel: string) => {
    return questions.filter(q => {
      const levels = (q as any).mood_levels;
      return Array.isArray(levels) && levels.includes(moodLevel);
    });
  };

  const saveTags = async (selectedIds: string[], moodLevel: string) => {
    setIsSaving(true);
    try {
      const wasTagged = getTaggedQuestions(moodLevel).map(q => q.id);
      const toUntagIds = wasTagged.filter(id => !selectedIds.includes(id));
      const toTagIds = selectedIds.filter(id => !wasTagged.includes(id));

      const toUntag = toUntagIds.map(id => {
        const q = questions.find(q => q.id === id);
        return { id, currentLevels: ((q as any)?.mood_levels || []) as string[] };
      }).filter(item => item !== null);

      const toTag = toTagIds.map(id => {
        const q = questions.find(q => q.id === id);
        return { id, currentLevels: ((q as any)?.mood_levels || []) as string[] };
      }).filter(item => item !== null);

      await updateMoodTags(moodLevel, toTag, toUntag);

      queryClient.invalidateQueries({ queryKey: ['questions'] });
      queryClient.invalidateQueries({ queryKey: ['mood-pathway-questions'] });
      toast.success(t('moodPathway.tagsSaved'));
    } catch {
      toast.error(t('moodPathway.tagsFailed'));
    } finally {
      setIsSaving(false);
    }
  };

  const unlinkQuestion = async (questionId: string, moodLevel: string) => {
    const q = questions.find(q => q.id === questionId);
    if (!q) return;
    const currentLevels = ((q as any).mood_levels || []) as string[];

    await unlinkQuestionFromMood(questionId, moodLevel, currentLevels);
    queryClient.invalidateQueries({ queryKey: ['questions'] });
    queryClient.invalidateQueries({ queryKey: ['mood-pathway-questions'] });
    toast.success(t('moodPathway.questionUnlinked'));
  };

  return { getTaggedQuestions, saveTags, unlinkQuestion, isSaving };
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { runScheduleNow, fetchSchedulePreview } from '@/features/admin/services/scheduleService';

export function useScheduleActions() {
  const { t } = useTranslation();
  const [runningId, setRunningId] = useState<string | null>(null);
  const [previewId, setPreviewId] = useState<string | null>(null);
  const [previewQuestions, setPreviewQuestions] = useState<any[]>([]);
  const [previewLoading, setPreviewLoading] = useState(false);

  const handleRunNow = async (scheduleId: string) => {
    setRunningId(scheduleId);
    try {
      const message = await runScheduleNow(scheduleId);
      toast.success(message || t('schedules.runSuccess'));
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : t('schedules.runError');
      toast.error(message);
    } finally {
      setRunningId(null);
    }
  };

  const handlePreview = async (scheduleId: string) => {
    setPreviewId(scheduleId);
    setPreviewLoading(true);
    try {
      const merged = await fetchSchedulePreview(scheduleId);
      setPreviewQuestions(merged);
    } catch {
      toast.error(t('common.error'));
      setPreviewQuestions([]);
    } finally {
      setPreviewLoading(false);
    }
  };

  const closePreview = () => {
    setPreviewId(null);
    setPreviewQuestions([]);
  };

  return {
    runningId,
    previewId,
    previewQuestions,
    previewLoading,
    handleRunNow,
    handlePreview,
    closePreview,
  };
}

/**
 * useScheduleReducer — centralises all form + dialog state for ScheduleManagement.
 * Extracted from ScheduleManagement.tsx with ZERO behaviour change.
 */

import { useReducer, useCallback } from 'react';
import type { QuestionSchedule } from '@/hooks/questions/useQuestionSchedules';

// ── State shape ──────────────────────────────────────────────────────────────

export interface ScheduleFormState {
  // Dialog control
  dialogOpen: boolean;
  editingSchedule: QuestionSchedule | null;
  deleteId: string | null;
  audienceViewSchedule: QuestionSchedule | null;
  audienceSearch: string;

  // Form fields
  name: string;
  description: string;
  frequency: string;
  preferredTime: string;
  questionsPerDelivery: number;
  weekendDays: number[];
  selectedBatchIds: string[];
  audienceType: 'all' | 'departments' | 'specific';
  selectedDepartments: string[];
  selectedEmployees: string[];
  employeeSearch: string;
  scheduleType: 'daily_checkin' | 'survey';
  startDate: string;
  endDate: string;
  linkedPeriodId: string | null;
  moodOverrides: Record<string, { enabled: boolean; value: number }>;
  moodConfigOpen: boolean;
}

const INITIAL_STATE: ScheduleFormState = {
  dialogOpen: false,
  editingSchedule: null,
  deleteId: null,
  audienceViewSchedule: null,
  audienceSearch: '',

  name: '',
  description: '',
  frequency: '1_per_day',
  preferredTime: '09:00',
  questionsPerDelivery: 1,
  weekendDays: [5, 6],
  selectedBatchIds: [],
  audienceType: 'all',
  selectedDepartments: [],
  selectedEmployees: [],
  employeeSearch: '',
  scheduleType: 'daily_checkin',
  startDate: '',
  endDate: '',
  linkedPeriodId: null,
  moodOverrides: {},
  moodConfigOpen: false,
};

// ── Actions ──────────────────────────────────────────────────────────────────

type Action =
  | { type: 'SET_FIELD'; field: keyof ScheduleFormState; value: any }
  | { type: 'RESET_FORM' }
  | { type: 'OPEN_CREATE' }
  | { type: 'OPEN_EDIT'; schedule: QuestionSchedule; moodConfigs: any[] }
  | { type: 'CLOSE_DIALOG' }
  | { type: 'SET_DELETE_ID'; id: string | null }
  | { type: 'SET_AUDIENCE_VIEW'; schedule: QuestionSchedule | null }
  | { type: 'CHANGE_SCHEDULE_TYPE'; scheduleType: 'daily_checkin' | 'survey' }
  | { type: 'SET_MOOD_OVERRIDE'; key: string; enabled: boolean; value: number }
  | { type: 'CLAMP_MOOD_OVERRIDES'; maxValue: number };

function reducer(state: ScheduleFormState, action: Action): ScheduleFormState {
  switch (action.type) {
    case 'SET_FIELD':
      return { ...state, [action.field]: action.value };

    case 'RESET_FORM':
      return {
        ...state,
        ...INITIAL_STATE,
        // Keep dialog-level booleans controlled separately
        dialogOpen: false,
        deleteId: null,
        audienceViewSchedule: null,
      };

    case 'OPEN_CREATE':
      return { ...INITIAL_STATE, dialogOpen: true };

    case 'OPEN_EDIT': {
      const s = action.schedule;
      const ta = s.target_audience;
      let audienceType: 'all' | 'departments' | 'specific' = 'all';
      let selectedDepartments: string[] = [];
      let selectedEmployees: string[] = [];

      if (ta?.departments && ta.departments.length > 0) {
        audienceType = 'departments';
        selectedDepartments = ta.departments;
      } else if (ta?.specific_employees && ta.specific_employees.length > 0) {
        audienceType = 'specific';
        selectedEmployees = ta.specific_employees;
      }

      const overrides: Record<string, { enabled: boolean; value: number }> = {};
      for (const cfg of action.moodConfigs) {
        if ((cfg as any).is_custom_override) {
          overrides[cfg.mood_level] = { enabled: true, value: cfg.max_questions };
        }
      }

      return {
        ...state,
        dialogOpen: true,
        editingSchedule: s,
        name: s.name,
        description: s.description || '',
        frequency: s.frequency,
        preferredTime: s.preferred_time || '09:00',
        questionsPerDelivery: s.questions_per_delivery || 1,
        weekendDays: (s as any).weekend_days || (s.avoid_weekends ? [5, 6] : []),
        selectedBatchIds: s.batch_ids || [],
        audienceType,
        selectedDepartments,
        selectedEmployees,
        employeeSearch: '',
        scheduleType: s.schedule_type || 'daily_checkin',
        startDate: s.start_date || '',
        endDate: s.end_date || '',
        linkedPeriodId: s.generation_period_id || null,
        moodOverrides: overrides,
        moodConfigOpen: Object.keys(overrides).length > 0,
      };
    }

    case 'CLOSE_DIALOG':
      return { ...INITIAL_STATE, dialogOpen: false };

    case 'SET_DELETE_ID':
      return { ...state, deleteId: action.id };

    case 'SET_AUDIENCE_VIEW':
      return { ...state, audienceViewSchedule: action.schedule, audienceSearch: '' };

    case 'CHANGE_SCHEDULE_TYPE':
      return {
        ...state,
        scheduleType: action.scheduleType,
        selectedBatchIds: [],
        linkedPeriodId: null,
        startDate: '',
        endDate: '',
      };

    case 'SET_MOOD_OVERRIDE':
      return {
        ...state,
        moodOverrides: {
          ...state.moodOverrides,
          [action.key]: { enabled: action.enabled, value: action.value },
        },
      };

    case 'CLAMP_MOOD_OVERRIDES': {
      const updated = { ...state.moodOverrides };
      for (const key of Object.keys(updated)) {
        if (updated[key].enabled && updated[key].value > action.maxValue) {
          updated[key] = { ...updated[key], value: action.maxValue };
        }
      }
      return { ...state, moodOverrides: updated };
    }

    default:
      return state;
  }
}

// ── Hook ─────────────────────────────────────────────────────────────────────

export function useScheduleReducer() {
  const [state, dispatch] = useReducer(reducer, INITIAL_STATE);

  const setField = useCallback(
    <K extends keyof ScheduleFormState>(field: K, value: ScheduleFormState[K]) =>
      dispatch({ type: 'SET_FIELD', field, value }),
    [],
  );

  return { state, dispatch, setField };
}

