import { ToggleGroup, ToggleGroupItem } from '@/shared/components/ui/toggle-group';
import { KnowledgeBasePanel } from './KnowledgeBasePanel';
import { FrameworkSelector } from './FrameworkSelector';
import { CreatePeriodDialog } from './CreatePeriodDialog';
import { DistributionPreview } from './DistributionPreview';
import { useQuestionCategories } from '@/hooks/questions/useQuestionCategories';
import { useQuestionSubcategories } from '@/hooks/questions/useQuestionSubcategories';
import { useState } from 'react';
import { useGeneratorContext } from '@/features/ai-generator';

export type QuestionPurpose = 'survey' | 'wellness';

const MOOD_LEVELS_META = [
  { value: 'great', label: '😄 Great', label_ar: '😄 ممتاز' },
  { value: 'good', label: '🙂 Good', label_ar: '🙂 جيد' },
  { value: 'okay', label: '😐 Okay', label_ar: '😐 عادي' },
  { value: 'struggling', label: '😟 Struggling', label_ar: '😟 أعاني' },
  { value: 'need_help', label: '😢 Need Help', label_ar: '😢 بحاجة للمساعدة' },
];

export function ConfigPanel() {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.dir() === 'rtl';
  const [advancedOpen, setAdvancedOpen] = useState(false);
  const [createPeriodOpen, setCreatePeriodOpen] = useState(false);
  const [categorySearch, setCategorySearch] = useState('');
  const [subcategorySearch, setSubcategorySearch] = useState('');

  const g = useGeneratorContext();

  const { categories = [] } = useQuestionCategories();
  const { subcategories: allSubcategories = [] } = useQuestionSubcategories();
  const activeCategories = (categories || []).filter(c => c.is_active);

  // When a period is selected, lock to its categories/subcategories
  const selectedPeriod = g.periods.find(p => p.id === g.selectedPeriodId) || null;
  const isPeriodLocked = !!selectedPeriod;
  const isGenerationLocked = !!g.activePeriodForPurpose && g.activePeriodForPurpose.id !== g.selectedPeriodId;

  // Filter periods by current purpose
  const purposePeriods = g.periods.filter(p => p.purpose === g.purpose);

  // Filter subcategories by selected categories
  const effectiveCategoryIds = isPeriodLocked ? (selectedPeriod.locked_category_ids || []) as string[] : g.selectedCategoryIds;
  const effectiveSubcategoryIds = isPeriodLocked ? (selectedPeriod.locked_subcategory_ids || []) as string[] : g.selectedSubcategoryIds;
  const filteredSubcategories = allSubcategories.filter(
    s => s.is_active && effectiveCategoryIds.includes(s.category_id)
  );
  const selectedSubsForPreview = filteredSubcategories.filter(s => effectiveSubcategoryIds.includes(s.id));

  // Prerequisites check
  const prerequisitesMet = activeCategories.length >= 3;
  const hasCategorySelected = effectiveCategoryIds.length > 0;

  // Auto question count from period
  const periodDays = selectedPeriod
    ? Math.max(1, differenceInDays(parseISO(selectedPeriod.end_date), parseISO(selectedPeriod.start_date)))
    : 0;
  const autoQuestionCount = selectedPeriod ? periodDays * g.questionsPerDay : 0;

  // Sync auto-calculated count to parent when period is selected
  if (selectedPeriod && autoQuestionCount !== g.questionCount) {
    g.setQuestionCount(autoQuestionCount);
  }

  // Search filtering
  const searchedCategories = activeCategories.filter(c => {
    if (!categorySearch) return true;
    const search = categorySearch.toLowerCase();
    return c.name.toLowerCase().includes(search) || (c.name_ar && c.name_ar.toLowerCase().includes(search));
  });

  const searchedSubcategories = filteredSubcategories.filter(s => {
    if (!subcategorySearch) return true;
    const search = subcategorySearch.toLowerCase();
    return s.name.toLowerCase().includes(search) || (s.name_ar && s.name_ar.toLowerCase().includes(search));
  });

  const toggleCategory = (categoryId: string) => {
    const isSelected = g.selectedCategoryIds.includes(categoryId);
    let nextIds: string[];
    if (isSelected) {
      nextIds = g.selectedCategoryIds.filter(id => id !== categoryId);
      const orphanedSubIds = allSubcategories
        .filter(s => s.category_id === categoryId)
        .map(s => s.id);
      if (orphanedSubIds.length > 0) {
        g.setSelectedSubcategoryIds(
          g.selectedSubcategoryIds.filter(sid => !orphanedSubIds.includes(sid))
        );
      }
    } else {
      nextIds = [...g.selectedCategoryIds, categoryId];
    }
    g.setSelectedCategoryIds(nextIds);
  };

  const toggleSubcategory = (subcategoryId: string) => {
    if (g.selectedSubcategoryIds.includes(subcategoryId)) {
      g.setSelectedSubcategoryIds(g.selectedSubcategoryIds.filter(id => id !== subcategoryId));
    } else {
      g.setSelectedSubcategoryIds([...g.selectedSubcategoryIds, subcategoryId]);
    }
  };

  const updateAdvanced = (key: keyof AdvancedSettings, value: any) => {
    g.setAdvancedSettings({ ...g.advancedSettings, [key]: value });
  };

  const getCategoryLabel = (c: any) => isRTL && c.name_ar ? c.name_ar : c.name;
  const getSubcategoryLabel = (s: any) => isRTL && s.name_ar ? s.name_ar : s.name;

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Sparkles className="h-5 w-5 text-primary" />
            {t('aiGenerator.configTitle')}
          </CardTitle>
          <CardDescription>{t('aiGenerator.configDescription')}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-5">
          {/* Purpose Selector */}
          <div className="space-y-2">
            <Label className="text-sm font-medium">{t('aiGenerator.purpose')}</Label>
            <p className="text-xs text-muted-foreground">{t('aiGenerator.purposeDescription')}</p>
            <ToggleGroup
              type="single"
              value={g.purpose}
              onValueChange={(v) => { if (v) g.setPurpose(v as QuestionPurpose); }}
              className="grid grid-cols-2 gap-2"
              variant="outline"
            >
              <ToggleGroupItem
                value="survey"
                className="flex flex-col items-center gap-1 py-3 px-2 data-[state=on]:bg-primary/10 data-[state=on]:border-primary"
              >
                <ClipboardList className="h-5 w-5" />
                <span className="text-xs font-medium">{t('aiGenerator.purposeSurvey')}</span>
              </ToggleGroupItem>
              <ToggleGroupItem
                value="wellness"
                className="flex flex-col items-center gap-1 py-3 px-2 data-[state=on]:bg-primary/10 data-[state=on]:border-primary"
              >
                <Heart className="h-5 w-5" />
                <span className="text-xs font-medium">{t('aiGenerator.purposeWellness')}</span>
              </ToggleGroupItem>
            </ToggleGroup>
          </div>

          {/* Mood Level Tags — only shown when purpose is wellness */}
          {g.purpose === 'wellness' && (
            <div className="space-y-2">
              <Label className="text-sm font-medium">{t('aiGenerator.moodLevelTags')}</Label>
              <p className="text-xs text-muted-foreground">{t('aiGenerator.moodLevelTagsDesc')}</p>
              <div className="flex flex-wrap gap-3">
                {MOOD_LEVELS_META.map(mood => (
                  <label key={mood.value} className="flex items-center gap-2 cursor-pointer">
                    <Checkbox
                      checked={g.selectedMoodLevels.includes(mood.value)}
                      onCheckedChange={(checked) => {
                        if (checked) {
                          g.setSelectedMoodLevels([...g.selectedMoodLevels, mood.value]);
                        } else {
                          g.setSelectedMoodLevels(g.selectedMoodLevels.filter(l => l !== mood.value));
                        }
                      }}
                    />
                    <span className="text-sm">{isRTL ? mood.label_ar : mood.label}</span>
                  </label>
                ))}
              </div>
            </div>
          )}

          {/* Generation Period Selector */}
          <div className="space-y-2">
            <Label className="flex items-center gap-2 text-sm font-medium">
              <CalendarClock className="h-4 w-4" />
              {t('aiGenerator.generationPeriod')}
            </Label>
            <div className="flex gap-2">
              <Select
                value={g.selectedPeriodId || '__freeform__'}
                onValueChange={(v) => {
                  if (v === '__freeform__') {
                    g.setSelectedPeriodId(null);
                  } else {
                    g.setSelectedPeriodId(v);
                    const period = g.periods.find(p => p.id === v);
                    if (period) {
                      g.setSelectedCategoryIds((period.locked_category_ids || []) as string[]);
                      g.setSelectedSubcategoryIds((period.locked_subcategory_ids || []) as string[]);
                    }
                  }
                }}
              >
                <SelectTrigger className="flex-1"><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="__freeform__">{t('aiGenerator.freeformMode')}</SelectItem>
                  {purposePeriods.filter(p => p.status === 'active').map(p => (
                    <SelectItem key={p.id} value={p.id}>
                      {t(`aiGenerator.period${p.period_type.charAt(0).toUpperCase() + p.period_type.slice(1)}`)} — {p.start_date} → {p.end_date}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Button variant="outline" size="icon" onClick={() => setCreatePeriodOpen(true)} title={t('aiGenerator.createPeriod')}>
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            {isPeriodLocked && (
              <p className="text-xs text-muted-foreground flex items-center gap-1">
                <Lock className="h-3 w-3" />
                {t('aiGenerator.periodLocked')}
              </p>
            )}
            {/* Active period management */}
            {g.activePeriodForPurpose && (
              <Alert className="py-2">
                <AlertTriangle className="h-4 w-4" />
                <AlertDescription className="flex items-center justify-between">
                  <span className="text-xs">
                    {t('aiGenerator.periodActiveInfo', {
                      start: g.activePeriodForPurpose.start_date,
                      end: g.activePeriodForPurpose.end_date,
                    })}
                  </span>
                  <div className="flex gap-1 ms-2">
                    <Button variant="ghost" size="sm" className="h-6 px-2 text-xs" onClick={() => g.handleExpirePeriod(g.activePeriodForPurpose.id)}>
                      <TimerOff className="h-3 w-3 me-1" />
                      {t('aiGenerator.periodExpire')}
                    </Button>
                    <Button variant="ghost" size="sm" className="h-6 px-2 text-xs text-destructive" onClick={() => g.handleDeletePeriod(g.activePeriodForPurpose.id)}>
                      <Trash2 className="h-3 w-3 me-1" />
                      {t('aiGenerator.periodDelete')}
                    </Button>
                  </div>
                </AlertDescription>
              </Alert>
            )}
          </div>

          {/* Category & Subcategory Multi-Select */}
          <div className="grid grid-cols-2 gap-4">
            {/* Categories Multi-Select */}
            <div className="space-y-2">
              <Label>{t('aiGenerator.category')}</Label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" className="w-full justify-between font-normal" disabled={isPeriodLocked}>
                    <span className="truncate">
                      {effectiveCategoryIds.length === 0
                        ? t('aiGenerator.selectCategories')
                        : t('aiGenerator.categoriesSelected', { count: effectiveCategoryIds.length })}
                    </span>
                    <ChevronsUpDown className="h-4 w-4 shrink-0 opacity-50" />
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-[260px] p-0" align="start">
                  <div className="p-2">
                    <Input
                      placeholder={t('aiGenerator.searchCategories')}
                      value={categorySearch}
                      onChange={e => setCategorySearch(e.target.value)}
                      className="h-8 text-sm"
                    />
                  </div>
                  <ScrollArea className="h-[200px] px-2 pb-2">
                    {searchedCategories.map(c => (
                      <label
                        key={c.id}
                        className="flex items-center gap-2 rounded-sm px-2 py-1.5 text-sm cursor-pointer hover:bg-accent"
                      >
                        <Checkbox
                          checked={g.selectedCategoryIds.includes(c.id)}
                          onCheckedChange={() => toggleCategory(c.id)}
                        />
                        <span
                          className="h-2.5 w-2.5 rounded-full shrink-0"
                          style={{ backgroundColor: c.color || '#3B82F6' }}
                        />
                        <span className="truncate">{getCategoryLabel(c)}</span>
                      </label>
                    ))}
                    {searchedCategories.length === 0 && (
                      <p className="text-xs text-muted-foreground text-center py-4">{t('common.noData')}</p>
                    )}
                  </ScrollArea>
                </PopoverContent>
              </Popover>
            </div>

            {/* Subcategories Multi-Select */}
            <div className="space-y-2">
              <Label>{t('aiGenerator.subcategory')}</Label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    className="w-full justify-between font-normal"
                    disabled={isPeriodLocked || effectiveCategoryIds.length === 0}
                  >
                    <span className="truncate">
                      {effectiveCategoryIds.length === 0
                        ? t('aiGenerator.selectSubcategories')
                        : effectiveSubcategoryIds.length === 0
                          ? t('aiGenerator.selectSubcategories')
                          : t('aiGenerator.categoriesSelected', { count: effectiveSubcategoryIds.length })}
                    </span>
                    <ChevronsUpDown className="h-4 w-4 shrink-0 opacity-50" />
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-[260px] p-0" align="start">
                  <div className="p-2">
                    <Input
                      placeholder={t('aiGenerator.searchSubcategories')}
                      value={subcategorySearch}
                      onChange={e => setSubcategorySearch(e.target.value)}
                      className="h-8 text-sm"
                    />
                  </div>
                  <ScrollArea className="h-[200px] px-2 pb-2">
                    {searchedSubcategories.map(s => {
                      const parentCat = activeCategories.find(c => c.id === s.category_id);
                      return (
                        <label
                          key={s.id}
                          className="flex items-center gap-2 rounded-sm px-2 py-1.5 text-sm cursor-pointer hover:bg-accent"
                        >
                          <Checkbox
                            checked={g.selectedSubcategoryIds.includes(s.id)}
                            onCheckedChange={() => toggleSubcategory(s.id)}
                          />
                          <span
                            className="h-2.5 w-2.5 rounded-full shrink-0"
                            style={{ backgroundColor: s.color || '#6366F1' }}
                          />
                          <span className="truncate">
                            {getSubcategoryLabel(s)}
                            {parentCat && (
                              <span className="text-muted-foreground text-xs ms-1">
                                ({getCategoryLabel(parentCat)})
                              </span>
                            )}
                          </span>
                        </label>
                      );
                    })}
                    {searchedSubcategories.length === 0 && (
                      <p className="text-xs text-muted-foreground text-center py-4">{t('common.noData')}</p>
                    )}
                  </ScrollArea>
                </PopoverContent>
              </Popover>
            </div>
          </div>

          {/* Distribution Preview */}
          {selectedSubsForPreview.length > 0 && (
            <DistributionPreview subcategories={selectedSubsForPreview} questionCount={g.questionCount} />
          )}

          {/* Question Type Multi-Select */}
          <div className="space-y-2">
            <Label>{t('aiGenerator.questionType')}</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full justify-between font-normal">
                  <span className="truncate">
                    {g.questionTypes.length === 0
                      ? t('aiGenerator.typeMixed')
                      : t('aiGenerator.typesSelected', { count: g.questionTypes.length })}
                  </span>
                  <ChevronsUpDown className="h-4 w-4 shrink-0 opacity-50" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-[260px] p-0" align="start">
                <ScrollArea className="max-h-[240px] px-2 py-2">
                  {(g.purpose === 'wellness'
                    ? [
                        { value: 'likert_5', emoji: '📊', label: t('aiGenerator.typeScale') },
                        { value: 'multiple_choice', emoji: '☑️', label: t('aiGenerator.typeMCQ') },
                        { value: 'open_ended', emoji: '💬', label: t('aiGenerator.typeOpen') },
                        { value: 'numeric_scale', emoji: '🔢', label: t('aiGenerator.typeNumeric') },
                        { value: 'yes_no', emoji: '✅', label: t('aiGenerator.typeYesNo') },
                        { value: 'slider', emoji: '🎚️', label: t('aiGenerator.typeSlider') },
                        { value: 'emoji_rating', emoji: '😀', label: t('aiGenerator.typeEmojiRating') },
                      ]
                    : [
                        { value: 'likert_5', emoji: '📊', label: t('aiGenerator.typeLikert') },
                        { value: 'multiple_choice', emoji: '☑️', label: t('aiGenerator.typeMCQ') },
                        { value: 'open_ended', emoji: '💬', label: t('aiGenerator.typeOpen') },
                        { value: 'numeric_scale', emoji: '🔢', label: t('aiGenerator.typeNumeric') },
                        { value: 'yes_no', emoji: '✅', label: t('aiGenerator.typeYesNo') },
                        { value: 'ranking', emoji: '🏆', label: t('aiGenerator.typeRanking') },
                        { value: 'matrix', emoji: '📋', label: t('aiGenerator.typeMatrix') },
                      ]
                  ).map(opt => (
                    <label
                      key={opt.value}
                      className="flex items-center gap-2 rounded-sm px-2 py-1.5 text-sm cursor-pointer hover:bg-accent"
                    >
                      <Checkbox
                        checked={g.questionTypes.includes(opt.value)}
                        onCheckedChange={() => {
                          if (g.questionTypes.includes(opt.value)) {
                            g.setQuestionTypes(g.questionTypes.filter(v => v !== opt.value));
                          } else {
                            g.setQuestionTypes([...g.questionTypes, opt.value]);
                          }
                        }}
                      />
                      <span>{opt.emoji} {opt.label}</span>
                    </label>
                  ))}
                </ScrollArea>
              </PopoverContent>
            </Popover>
            <p className="text-xs text-muted-foreground">{t('aiGenerator.typeMultiSelectHint')}</p>
          </div>

          {/* Question Count — auto-calc when period selected */}
          {selectedPeriod ? (
            <div className="space-y-3">
              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <Calculator className="h-4 w-4" />
                  {t('aiGenerator.questionsPerDay')}
                </Label>
                <p className="text-xs text-muted-foreground">{t('aiGenerator.questionsPerDayDesc')}</p>
                <ToggleGroup
                  type="single"
                  value={String(g.questionsPerDay)}
                  onValueChange={(v) => { if (v) g.setQuestionsPerDay(Number(v)); }}
                  className="justify-start"
                >
                  {[1, 2, 3].map(n => (
                    <ToggleGroupItem key={n} value={String(n)} className="px-4">
                      {n}
                    </ToggleGroupItem>
                  ))}
                </ToggleGroup>
              </div>
              <div className="bg-muted/50 rounded-lg p-3 text-sm">
                <p className="font-medium">{t('aiGenerator.questionCount')}: {autoQuestionCount}</p>
                <p className="text-xs text-muted-foreground mt-1">
                  {t('aiGenerator.totalQuestionsCalc', { days: periodDays, perDay: g.questionsPerDay, total: autoQuestionCount })}
                </p>
              </div>
            </div>
          ) : (
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>{t('aiGenerator.questionCount')}</Label>
              {g.purpose === 'survey' ? (
                <div className="flex items-center gap-1">
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 shrink-0"
                    disabled={g.questionCount <= 1}
                    onClick={() => g.setQuestionCount(Math.max(1, g.questionCount - 1))}
                  >
                    <Minus className="h-4 w-4" />
                  </Button>
                  <Input
                    type="number"
                    min={1}
                    max={200}
                    value={g.questionCount}
                    onChange={(e) => {
                      const val = parseInt(e.target.value, 10);
                      if (!isNaN(val)) g.setQuestionCount(Math.min(200, Math.max(1, val)));
                    }}
                    onBlur={(e) => {
                      const val = parseInt(e.target.value, 10);
                      if (isNaN(val) || val < 1) g.setQuestionCount(1);
                    }}
                    className="h-9 text-center [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                  />
                  <Button
                    type="button"
                    variant="outline"
                    size="icon"
                    className="h-9 w-9 shrink-0"
                    disabled={g.questionCount >= 200}
                    onClick={() => g.setQuestionCount(Math.min(200, g.questionCount + 1))}
                  >
                    <Plus className="h-4 w-4" />
                  </Button>
                </div>
              ) : (
                <Select value={String(g.questionCount)} onValueChange={v => g.setQuestionCount(Number(v))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {Array.from({ length: 20 }, (_, i) => i + 1).map(n => (
                      <SelectItem key={n} value={String(n)}>{n}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              )}
            </div>
            <div className="space-y-2">
              <Label>{t('aiGenerator.complexity')}</Label>
              <Select value={g.complexity} onValueChange={g.setComplexity}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="simple">{t('aiGenerator.simple')}</SelectItem>
                  <SelectItem value="moderate">{t('aiGenerator.moderate')}</SelectItem>
                  <SelectItem value="advanced">{t('aiGenerator.advanced')}</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          )}

          {/* Complexity - always shown once */}
          {selectedPeriod && (
            <div className="space-y-2">
              <Label>{t('aiGenerator.complexity')}</Label>
              <Select value={g.complexity} onValueChange={g.setComplexity}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="simple">{t('aiGenerator.simple')}</SelectItem>
                  <SelectItem value="moderate">{t('aiGenerator.moderate')}</SelectItem>
                  <SelectItem value="advanced">{t('aiGenerator.advanced')}</SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}

          <div className="space-y-2">
            <Label>{t('aiGenerator.tone')}</Label>
            <Select value={g.tone} onValueChange={g.setTone}>
              <SelectTrigger><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="neutral">{t('aiGenerator.neutral')}</SelectItem>
                <SelectItem value="formal">{t('aiGenerator.formal')}</SelectItem>
                <SelectItem value="analytical">{t('aiGenerator.toneAnalytical')}</SelectItem>
                <SelectItem value="supportive">{t('aiGenerator.toneSupportive')}</SelectItem>
                <SelectItem value="direct">{t('aiGenerator.toneDirect')}</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {/* Advanced Settings */}
          <Collapsible open={advancedOpen} onOpenChange={setAdvancedOpen}>
            <CollapsibleTrigger asChild>
              <Button variant="ghost" className="w-full justify-between" size="sm">
                <span className="flex items-center gap-2">
                  <Settings2 className="h-4 w-4" />
                  {t('aiGenerator.advancedSettings')}
                </span>
                <ChevronDown className={`h-4 w-4 transition-transform ${advancedOpen ? 'rotate-180' : ''}`} />
              </Button>
            </CollapsibleTrigger>
            <CollapsibleContent className="space-y-4 pt-3">
              <div className="flex items-center justify-between">
                <Label className="text-sm">{t('aiGenerator.requireExplanation')}</Label>
                <Switch checked={g.advancedSettings.requireExplanation} onCheckedChange={v => updateAdvanced('requireExplanation', v)} />
              </div>
              <div className="flex items-center justify-between">
                <Label className="text-sm">{t('aiGenerator.biasDetection')}</Label>
                <Switch checked={g.advancedSettings.enableBiasDetection} onCheckedChange={v => updateAdvanced('enableBiasDetection', v)} />
              </div>
              <div className="flex items-center justify-between">
                <Label className="text-sm">{t('aiGenerator.ambiguityDetection')}</Label>
                <Switch checked={g.advancedSettings.enableAmbiguityDetection} onCheckedChange={v => updateAdvanced('enableAmbiguityDetection', v)} />
              </div>
              <div className="flex items-center justify-between">
                <Label className="text-sm">{t('aiGenerator.duplicateDetection')}</Label>
                <Switch checked={g.advancedSettings.enableDuplicateDetection} onCheckedChange={v => updateAdvanced('enableDuplicateDetection', v)} />
              </div>
              <div className="flex items-center justify-between">
                <Label className="text-sm">{t('aiGenerator.criticPass')}</Label>
                <Switch checked={g.advancedSettings.enableCriticPass} onCheckedChange={v => updateAdvanced('enableCriticPass', v)} />
              </div>
              <div className="space-y-1">
                <Label className="text-sm">{t('aiGenerator.minWordLength')}</Label>
                <Input
                  type="number" min={1} max={50}
                  value={g.advancedSettings.minWordLength}
                  onChange={e => updateAdvanced('minWordLength', parseInt(e.target.value) || 5)}
                  className="w-24"
                />
              </div>
            </CollapsibleContent>
          </Collapsible>

          {/* Prerequisites Check */}
          {!prerequisitesMet && (
            <Alert variant="destructive" className="py-2">
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription className="text-xs">
                <p className="font-medium mb-1">{t('aiGenerator.prerequisitesNotMet')}</p>
                <ul className="space-y-1">
                  <li className="flex items-center gap-1.5">
                    {activeCategories.length >= 3 ? <CheckCircle2 className="h-3 w-3 text-chart-2" /> : <XCircle className="h-3 w-3" />}
                    {t('aiGenerator.prerequisiteMinCategories')}
                  </li>
                </ul>
              </AlertDescription>
            </Alert>
          )}

          {/* Generate Button */}
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <span className="w-full">
                  <Button
                    onClick={g.handleGenerate}
                    disabled={g.isGenerating || !hasCategorySelected || isGenerationLocked || !prerequisitesMet}
                    className="w-full"
                    size="lg"
                  >
                    {g.isGenerating ? (
                      <>
                        <Loader2 className="h-5 w-5 animate-spin me-2" />
                        {t('aiGenerator.generating')}
                      </>
                    ) : isGenerationLocked ? (
                      <>
                        <Lock className="h-5 w-5 me-2" />
                        {t('aiGenerator.generate')}
                      </>
                    ) : (
                      <>
                        <Sparkles className="h-5 w-5 me-2" />
                        {t('aiGenerator.generate')}
                      </>
                    )}
                  </Button>
                </span>
              </TooltipTrigger>
              {isGenerationLocked && (
                <TooltipContent>
                  <p>{t('aiGenerator.periodLockedGenerate')}</p>
                </TooltipContent>
              )}
            </Tooltip>
          </TooltipProvider>
        </CardContent>
      </Card>

      {/* Reference Frameworks (separate card) */}
      <FrameworkSelector
        frameworks={g.referenceFrameworks}
        selectedFrameworkIds={g.selectedFrameworkIds}
        onSelectedChange={g.setSelectedFrameworkIds}
        onAdd={g.addFramework}
        onUpdate={g.updateFramework}
        onDelete={g.deleteFramework}
        isLoading={g.frameworksLoading}
        currentUserId={g.currentUserId}
      />

      {/* Knowledge Base (custom prompt + documents) */}
      <KnowledgeBasePanel
        documents={g.documents}
        onUpload={g.uploadDocument}
        onToggleDocument={g.toggleDocument}
        onDeleteDocument={g.deleteDocument}
        isUploading={g.isUploading}
        customPrompt={g.customPrompt}
        onCustomPromptChange={g.setCustomPrompt}
        onRewritePrompt={g.handleRewritePrompt}
        isRewriting={g.isRewriting}
      />

      {/* Create Period Dialog */}
      <CreatePeriodDialog
        open={createPeriodOpen}
        onOpenChange={setCreatePeriodOpen}
        categories={activeCategories}
        subcategories={allSubcategories.filter(s => s.is_active)}
        onConfirm={(params) => {
          g.handleCreatePeriod(params);
          setCreatePeriodOpen(false);
        }}
        isCreating={g.isCreatingPeriod}
        purpose={g.purpose}
        activePeriodForPurpose={g.activePeriodForPurpose}
      />
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/shared/components/ui/dialog';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Label } from '@/shared/components/ui/label';
import { Badge } from '@/shared/components/ui/badge';
import { Separator } from '@/shared/components/ui/separator';
import { Upload, FileText, X } from 'lucide-react';
import { ReferenceFramework } from '@/hooks/questions/useReferenceFrameworks';

interface FrameworkDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  framework?: ReferenceFramework | null;
  onSave: (data: { id?: string; name: string; name_ar?: string; description?: string; description_ar?: string; icon?: string; framework_key: string; files?: File[] }) => void;
}

export function FrameworkDialog({ open, onOpenChange, framework, onSave }: FrameworkDialogProps) {
  const { t } = useTranslation();
  const [name, setName] = useState('');
  const [nameAr, setNameAr] = useState('');
  const [description, setDescription] = useState('');
  const [descriptionAr, setDescriptionAr] = useState('');
  const [icon, setIcon] = useState('📋');
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (framework) {
      setName(framework.name);
      setNameAr(framework.name_ar || '');
      setDescription(framework.description || '');
      setDescriptionAr(framework.description_ar || '');
      setIcon(framework.icon || '📋');
    } else {
      setName('');
      setNameAr('');
      setDescription('');
      setDescriptionAr('');
      setIcon('📋');
    }
    setPendingFiles([]);
  }, [framework, open]);

  const handleSubmit = () => {
    if (!name.trim()) return;
    const key = framework?.framework_key || name.trim().replace(/[^a-zA-Z0-9]/g, '_').toUpperCase();
    onSave({
      ...(framework ? { id: framework.id } : {}),
      name: name.trim(),
      name_ar: nameAr.trim() || undefined,
      description: description.trim() || undefined,
      description_ar: descriptionAr.trim() || undefined,
      icon: icon || '📋',
      framework_key: key,
      files: pendingFiles.length > 0 ? pendingFiles : undefined,
    });
    onOpenChange(false);
  };

  const allowed = ['.pdf', '.docx', '.doc', '.txt', '.md'];

  const addFiles = useCallback((fileList: FileList | File[]) => {
    const files = Array.from(fileList);
    const valid = files.filter(f => {
      const ext = '.' + f.name.split('.').pop()?.toLowerCase();
      return allowed.includes(ext);
    });
    setPendingFiles(prev => [...prev, ...valid]);
  }, []);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    addFiles(files);
    if (fileRef.current) fileRef.current.value = '';
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files.length) {
      addFiles(e.dataTransfer.files);
    }
  }, [addFiles]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const removeFile = (index: number) => {
    setPendingFiles(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>{framework ? t('aiGenerator.editFramework') : t('aiGenerator.addFramework')}</DialogTitle>
          <DialogDescription>{framework ? t('aiGenerator.editFrameworkDesc') : t('aiGenerator.addFrameworkDesc')}</DialogDescription>
        </DialogHeader>
        <div className="space-y-4">
          {/* Icon + Name row with icon preview */}
          <div className="grid grid-cols-[auto_1fr] gap-3">
            <div className="space-y-1">
              <Label className="text-xs">{t('aiGenerator.frameworkIcon')}</Label>
              <div className="flex flex-col items-center gap-1.5">
                <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-2xl">
                  {icon || '📋'}
                </div>
                <Input value={icon} onChange={e => setIcon(e.target.value)} className="w-14 text-center text-sm h-8" maxLength={2} />
              </div>
            </div>
            <div className="space-y-1">
              <Label className="text-xs">{t('aiGenerator.frameworkName')}</Label>
              <Input value={name} onChange={e => setName(e.target.value)} placeholder="e.g., ISO 45003" />
            </div>
          </div>

          <Separator className="my-1" />

          {/* Arabic name */}
          <div className="space-y-1">
            <Label className="text-xs">{t('aiGenerator.frameworkNameAr')}</Label>
            <Input value={nameAr} onChange={e => setNameAr(e.target.value)} dir="rtl" placeholder="الاسم بالعربية" />
          </div>

          <Separator className="my-1" />

          {/* Description EN */}
          <div className="space-y-1">
            <Label className="text-xs">{t('aiGenerator.frameworkDescription')}</Label>
            <Textarea value={description} onChange={e => setDescription(e.target.value)} className="min-h-[60px] text-xs" placeholder="Describe how this framework guides question generation..." />
          </div>

          {/* Description AR */}
          <div className="space-y-1">
            <Label className="text-xs">{t('aiGenerator.frameworkDescriptionAr')}</Label>
            <Textarea value={descriptionAr} onChange={e => setDescriptionAr(e.target.value)} className="min-h-[60px] text-xs" dir="rtl" placeholder="وصف الإطار المرجعي بالعربية..." />
          </div>

          <Separator className="my-1" />

          {/* File upload drop zone */}
          <div className="space-y-1.5">
            <Label className="text-xs">{t('aiGenerator.frameworkDocuments')}</Label>
            <div
              onDrop={handleDrop}
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onClick={() => fileRef.current?.click()}
              className={`flex flex-col items-center justify-center gap-1.5 p-4 rounded-lg border-2 border-dashed cursor-pointer transition-colors ${
                isDragging
                  ? 'border-primary bg-primary/5'
                  : 'border-border/60 hover:border-primary/40 hover:bg-muted/30'
              }`}
            >
              <Upload className={`h-5 w-5 ${isDragging ? 'text-primary' : 'text-muted-foreground'}`} />
              <span className="text-xs text-muted-foreground">{t('aiGenerator.dragOrClick')}</span>
              <span className="text-2xs text-muted-foreground/70">PDF, DOCX, DOC, TXT, MD</span>
            </div>
            <input
              ref={fileRef}
              type="file"
              className="hidden"
              accept=".pdf,.docx,.doc,.txt,.md"
              multiple
              onChange={handleFileSelect}
            />
            {pendingFiles.length > 0 && (
              <div className="space-y-1 mt-1.5">
                {pendingFiles.map((f, i) => (
                  <div key={i} className="flex items-center gap-1.5 p-1.5 rounded-md bg-muted/30 border border-border/30 text-xs">
                    <FileText className="h-3.5 w-3.5 text-primary shrink-0" />
                    <span className="flex-1 truncate">{f.name}</span>
                    <Badge variant="outline" className="text-2xs px-1 py-0 h-4">{(f.size / 1024).toFixed(0)}KB</Badge>
                    <button type="button" onClick={() => removeFile(i)} className="p-1 hover:bg-destructive/10 rounded">
                      <X className="h-3.5 w-3.5 text-destructive" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>{t('common.cancel')}</Button>
          <Button onClick={handleSubmit} disabled={!name.trim()}>{t('common.save')}</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import i18n from '@/shared/utils/i18n';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';

import { BookOpen, ChevronDown, Plus, Pencil, Trash2, Check, Search, CheckCheck, XCircle, FileText } from 'lucide-react';
import { ReferenceFramework } from '@/hooks/questions/useReferenceFrameworks';
import { FrameworkDialog } from './FrameworkDialog';
import { FrameworkDocuments } from './FrameworkDocuments';
import { useFrameworkDocuments } from '@/hooks/questions/useFrameworkDocuments';

interface FrameworkSelectorProps {
  frameworks: ReferenceFramework[];
  selectedFrameworkIds: string[];
  onSelectedChange: (ids: string[]) => void;
  onAdd: (data: { name: string; name_ar?: string; description?: string; description_ar?: string; icon?: string; framework_key: string }) => void;
  onUpdate: (data: { id: string; name: string; name_ar?: string; description?: string; description_ar?: string; icon?: string }) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
  currentUserId?: string;
}

function FrameworkDocCount({ frameworkId }: { frameworkId: string }) {
  const { documents } = useFrameworkDocuments(frameworkId);
  if (!documents || documents.length === 0) return null;
  return (
    <Badge variant="secondary" className="text-2xs px-1.5 py-0 h-4 gap-0.5">
      <FileText className="h-2.5 w-2.5" />
      {documents.length}
    </Badge>
  );
}

export function FrameworkSelector({
  frameworks,
  selectedFrameworkIds,
  onSelectedChange,
  onAdd,
  onUpdate,
  onDelete,
  isLoading,
  currentUserId,
}: FrameworkSelectorProps) {
  const { t } = useTranslation();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingFramework, setEditingFramework] = useState<ReferenceFramework | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const isAr = i18n.language === 'ar';

  const toggleFramework = (id: string) => {
    onSelectedChange(
      selectedFrameworkIds.includes(id)
        ? selectedFrameworkIds.filter(f => f !== id)
        : [...selectedFrameworkIds, id]
    );
  };

  const selectAll = () => onSelectedChange(frameworks.map(f => f.id));
  const deselectAll = () => onSelectedChange([]);

  const { uploadDocument } = useFrameworkDocuments();

  const handleSave = async (data: any) => {
    const { files, ...frameworkData } = data;
    if (frameworkData.id) {
      onUpdate(frameworkData);
      if (files?.length) {
        for (const file of files) {
          uploadDocument({ frameworkId: frameworkData.id, file });
        }
      }
    } else {
      onAdd(frameworkData);
      if (files?.length) {
        setTimeout(async () => {
          const { supabase } = await import('@/integrations/supabase/client');
          const { data: newFw } = await supabase
            .from('reference_frameworks')
            .select('id')
            .eq('framework_key', frameworkData.framework_key)
            .is('deleted_at', null)
            .order('created_at', { ascending: false })
            .limit(1)
            .single();
          if (newFw?.id) {
            for (const file of files) {
              uploadDocument({ frameworkId: newFw.id, file });
            }
          }
        }, 1500);
      }
    }
  };

  const filteredFrameworks = searchQuery.trim()
    ? frameworks.filter(fw => {
        const q = searchQuery.toLowerCase();
        const name = (isAr && fw.name_ar ? fw.name_ar : fw.name).toLowerCase();
        return name.includes(q);
      })
    : frameworks;

  const showSearch = frameworks.length > 5;

  return (
    <>
      <Card className="border-primary/20">
        <CardHeader className="pb-2">
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2 text-base">
              <BookOpen className="h-5 w-5 text-primary" />
              {t('aiGenerator.referenceFrameworks')}
            </CardTitle>
            {selectedFrameworkIds.length > 0 && (
              <Badge variant="default" className="text-xs">
                {t('aiGenerator.frameworksSelected', { count: selectedFrameworkIds.length })}
              </Badge>
            )}
          </div>
          <CardDescription className="text-xs">{t('aiGenerator.referenceFrameworksDesc')}</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          {/* Header actions: Select All / Deselect All */}
          {frameworks.length > 0 && (
            <div className="flex items-center gap-1.5">
              <Button
                variant="ghost"
                size="sm"
                className="h-7 text-xs px-2 gap-1"
                onClick={selectAll}
                disabled={selectedFrameworkIds.length === frameworks.length}
              >
                <CheckCheck className="h-3.5 w-3.5" />
                {t('aiGenerator.selectAll')}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                className="h-7 text-xs px-2 gap-1"
                onClick={deselectAll}
                disabled={selectedFrameworkIds.length === 0}
              >
                <XCircle className="h-3.5 w-3.5" />
                {t('aiGenerator.deselectAll')}
              </Button>
            </div>
          )}

          {/* Search */}
          {showSearch && (
            <div className="relative">
              <Search className="absolute start-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
              <Input
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                placeholder={t('aiGenerator.searchFrameworks')}
                className="h-8 text-xs ps-8"
              />
            </div>
          )}

          {/* Framework cards */}
          {isLoading ? (
            <p className="text-xs text-muted-foreground py-4 text-center">{t('common.loading')}</p>
          ) : frameworks.length === 0 ? (
            /* Empty state */
            <div className="flex flex-col items-center justify-center py-8 text-center space-y-3">
              <div className="w-14 h-14 rounded-lg bg-primary/10 flex items-center justify-center">
                <BookOpen className="h-7 w-7 text-primary/60" />
              </div>
              <div className="space-y-1">
                <p className="text-sm font-medium text-foreground">{t('aiGenerator.noFrameworksYet')}</p>
                <p className="text-xs text-muted-foreground max-w-[240px]">{t('aiGenerator.noFrameworksDesc')}</p>
              </div>
              <Button
                size="sm"
                onClick={() => { setEditingFramework(null); setDialogOpen(true); }}
                className="gap-1.5"
              >
                <Plus className="h-4 w-4" />
                {t('aiGenerator.addFramework')}
              </Button>
            </div>
          ) : (
            <div className="space-y-2">
              {filteredFrameworks.map(fw => {
                const selected = selectedFrameworkIds.includes(fw.id);
                const isExpanded = expandedId === fw.id;
                const canEdit = !fw.is_default && (fw.created_by === currentUserId);
                const displayName = isAr && fw.name_ar ? fw.name_ar : fw.name;
                const displayDesc = isAr && fw.description_ar ? fw.description_ar : fw.description;

                return (
                  <div key={fw.id} className="group">
                    {/* Card */}
                    <div
                      role="button"
                      tabIndex={0}
                      onClick={() => toggleFramework(fw.id)}
                      onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleFramework(fw.id); } }}
                      className={`relative p-3 rounded-xl border cursor-pointer transition-all duration-200 ${
                        selected
                          ? 'bg-primary/5 border-primary/30 border-s-[3px] border-s-primary shadow-sm'
                          : 'bg-card border-border/50 hover:border-border hover:shadow-md'
                      }`}
                    >
                      <div className="flex items-start gap-3">
                        {/* Icon circle */}
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shrink-0 ${
                          selected ? 'bg-primary/15' : 'bg-primary/10'
                        }`}>
                          {fw.icon || '📋'}
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0 space-y-1">
                          <div className="flex items-center gap-1.5 flex-wrap">
                            <span className="text-sm font-medium text-foreground truncate">{displayName}</span>
                            {fw.is_default && (
                              <Badge variant="outline" className="text-2xs px-1.5 py-0 h-4 shrink-0">
                                {t('aiGenerator.defaultArea')}
                              </Badge>
                            )}
                            {selected && (
                              <Badge variant="default" className="text-2xs px-1.5 py-0 h-4 shrink-0 gap-0.5">
                                <Check className="h-2.5 w-2.5" />
                                {t('common.selected')}
                              </Badge>
                            )}
                            <FrameworkDocCount frameworkId={fw.id} />
                          </div>
                          {displayDesc && (
                            <p className="text-xs text-muted-foreground line-clamp-2">{displayDesc}</p>
                          )}
                        </div>

                        {/* Action buttons - visible on hover */}
                        <div className="flex items-center gap-0.5 shrink-0" onClick={e => e.stopPropagation()}>
                          {canEdit && (
                            <>
                              <Button
                                variant="ghost"
                                size="sm"
                                className="h-7 w-7 p-0 opacity-0 group-hover:opacity-100 transition-opacity"
                                onClick={() => { setEditingFramework(fw); setDialogOpen(true); }}
                              >
                                <Pencil className="h-3.5 w-3.5 text-muted-foreground" />
                              </Button>
                              <Button
                                variant="ghost"
                                size="sm"
                                className="h-7 w-7 p-0 opacity-0 group-hover:opacity-100 transition-opacity"
                                onClick={() => onDelete(fw.id)}
                              >
                                <Trash2 className="h-3.5 w-3.5 text-destructive" />
                              </Button>
                            </>
                          )}
                          <Button
                            variant="ghost"
                            size="sm"
                            className="h-7 w-7 p-0"
                            onClick={() => setExpandedId(isExpanded ? null : fw.id)}
                          >
                            <ChevronDown className={`h-3.5 w-3.5 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                          </Button>
                        </div>
                      </div>
                    </div>

                    {/* Expanded details */}
                    {isExpanded && (
                      <div className="ms-5 mt-1 p-3 rounded-lg bg-muted/30 border border-border/40 space-y-3 animate-in slide-in-from-top-1 duration-200">
                        {displayDesc && (
                          <p className="text-xs text-muted-foreground leading-relaxed">{displayDesc}</p>
                        )}
                        <FrameworkDocuments frameworkId={fw.id} />
                        {canEdit && (
                          <div className="flex gap-1.5 pt-1 border-t border-border/30">
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-7 text-xs px-2.5 gap-1"
                              onClick={() => { setEditingFramework(fw); setDialogOpen(true); }}
                            >
                              <Pencil className="h-3 w-3" />{t('common.edit')}
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              className="h-7 text-xs px-2.5 gap-1 text-destructive border-destructive/30 hover:bg-destructive/10"
                              onClick={() => onDelete(fw.id)}
                            >
                              <Trash2 className="h-3 w-3" />{t('common.delete')}
                            </Button>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}

              {/* Add Framework button */}
              <Button
                variant="outline"
                size="sm"
                className="w-full text-xs mt-1 gap-1.5 border-dashed"
                onClick={() => { setEditingFramework(null); setDialogOpen(true); }}
              >
                <Plus className="h-3.5 w-3.5" />
                {t('aiGenerator.addFramework')}
              </Button>
            </div>
          )}
        </CardContent>
      </Card>

      <FrameworkDialog
        open={dialogOpen}
        onOpenChange={setDialogOpen}
        framework={editingFramework}
        onSave={handleSave}
      />
    </>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Textarea } from '@/shared/components/ui/textarea';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/shared/components/ui/collapsible';
import { Progress } from '@/shared/components/ui/progress';
import {
  RefreshCw, Edit2, Copy, ChevronDown, Check, X,
  AlertTriangle, CheckCircle, XCircle, Info, Sparkles, Loader2, Plus
} from 'lucide-react';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/shared/components/ui/tooltip';
import { Popover, PopoverContent, PopoverTrigger } from '@/shared/components/ui/popover';
import { EnhancedGeneratedQuestion } from '@/hooks/questions/useEnhancedAIGeneration';
import { toast } from 'sonner';
import { useQuestionRewrite } from '@/features/admin/hooks/admin/useQuestionRewrite';
import type { QuestionPurpose } from './ConfigPanel';
import type { MoodDefinition } from '@/hooks/wellness/useMoodDefinitions';
import { DEFAULT_MOOD_META } from '@/config/moods';

interface QuestionCardProps {
  question: EnhancedGeneratedQuestion;
  index: number;
  onRemove: (index: number) => void;
  onUpdate: (index: number, updates: Partial<EnhancedGeneratedQuestion>) => void;
  onRegenerate?: (index: number) => void;
  selectedModel?: string;
  purpose?: QuestionPurpose;
  moodDefinitions?: MoodDefinition[];
  isRegenerating?: boolean;
}

const typeLabels: Record<string, string> = {
  likert_5: 'aiGenerator.typeLikert',
  numeric_scale: 'aiGenerator.typeNumeric',
  yes_no: 'aiGenerator.typeYesNo',
  open_ended: 'aiGenerator.typeOpen',
  multiple_choice: 'aiGenerator.typeMCQ',
};

const statusIcons: Record<string, React.ReactNode> = {
  passed: <CheckCircle className="h-4 w-4 text-primary" />,
  warning: <AlertTriangle className="h-4 w-4 text-chart-4" />,
  failed: <XCircle className="h-4 w-4 text-destructive" />,
  pending: <Info className="h-4 w-4 text-muted-foreground" />,
};

const issueLabels: Record<string, string> = {
  incomplete_structure: 'aiGenerator.issue_incomplete_structure',
  bias_detected: 'aiGenerator.issue_bias_detected',
  ambiguity_detected: 'aiGenerator.issue_ambiguity_detected',
  low_confidence: 'aiGenerator.issue_low_confidence',
  moderate_confidence: 'aiGenerator.issue_moderate_confidence',
  missing_framework_reference: 'aiGenerator.issue_missing_framework',
  missing_arabic: 'aiGenerator.issue_missing_arabic',
  missing_options: 'aiGenerator.issue_missing_options',
  too_short: 'aiGenerator.issue_too_short',
  duplicate: 'aiGenerator.issue_duplicate',
};

export function QuestionCard({ question, index, onRemove, onUpdate, onRegenerate, selectedModel, purpose, moodDefinitions, isRegenerating }: QuestionCardProps) {
  const { t } = useTranslation();
  const { rewriteQuestion, isRewriting } = useQuestionRewrite();
  const [isEditing, setIsEditing] = useState(false);
  const [editText, setEditText] = useState(question.question_text);
  const [editTextAr, setEditTextAr] = useState(question.question_text_ar);
  const [explanationOpen, setExplanationOpen] = useState(false);
  const [rewriteOpen, setRewriteOpen] = useState(false);
  const [rewritePrompt, setRewritePrompt] = useState('');

  const handleSaveEdit = () => {
    onUpdate(index, { question_text: editText, question_text_ar: editTextAr });
    setIsEditing(false);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(question.question_text);
    toast.success(t('aiGenerator.copied'));
  };

  const handleRewrite = async () => {
    if (!rewritePrompt.trim()) return;
    const result = await rewriteQuestion({
      question_text: question.question_text,
      question_text_ar: question.question_text_ar,
      type: question.type,
      prompt: rewritePrompt.trim(),
      model: selectedModel,
    });

    if (result) {
      onUpdate(index, {
        question_text: result.question_text,
        question_text_ar: result.question_text_ar,
      });
      setRewritePrompt('');
      setRewriteOpen(false);
    }
  };

  const validationIssues: string[] = (question.validation_details as any)?.issues || [];
  const hasAlerts = question.bias_flag || question.ambiguity_flag || validationIssues.length > 0;

  const borderClass = question.validation_status === 'failed'
    ? 'border-destructive'
    : question.validation_status === 'warning'
      ? 'border-chart-4'
      : '';

  const bgClass = hasAlerts ? 'bg-amber-50 dark:bg-amber-950/30' : '';

  return (
    <Card className={`${borderClass} ${bgClass} relative overflow-hidden`} id={`question-card-${index}`}>
      {isRegenerating && (
        <div className="absolute inset-0 z-10 flex items-center justify-center bg-background/60 backdrop-blur-[1px] rounded-lg">
          <Loader2 className="h-6 w-6 animate-spin text-primary" />
        </div>
      )}
      <CardContent className="pt-4 space-y-3">
        {/* Header row */}
        <div className="flex items-start justify-between gap-3">
          <div className="flex items-center gap-2 flex-wrap">
            <Badge variant="secondary">{t(typeLabels[question.type] || 'aiGenerator.typeLikert')}</Badge>
            <Badge variant="outline">{question.complexity}</Badge>
            <Badge variant="outline" className="text-xs">{question.tone}</Badge>
            <Tooltip>
              <TooltipTrigger>{statusIcons[question.validation_status]}</TooltipTrigger>
              <TooltipContent>{t(`aiGenerator.status_${question.validation_status}`)}</TooltipContent>
            </Tooltip>
          </div>
          <div className="flex items-center gap-1">
            <Tooltip>
              <TooltipTrigger asChild>
                <div className="flex items-center gap-1 text-xs text-muted-foreground">
                  <span>{question.confidence_score}%</span>
                </div>
              </TooltipTrigger>
              <TooltipContent>{t('aiGenerator.confidenceScore')}</TooltipContent>
            </Tooltip>
          </div>
        </div>

        {/* Confidence bar */}
        <Progress value={question.confidence_score} className="h-1.5" />

        {/* Question text */}
        {isEditing ? (
          <div className="space-y-2">
            <Textarea value={editText} onChange={e => setEditText(e.target.value)} className="text-sm" rows={2} />
            <Textarea value={editTextAr} onChange={e => setEditTextAr(e.target.value)} className="text-sm" dir="rtl" rows={2} />
            <div className="flex gap-2">
              <Button size="sm" onClick={handleSaveEdit}>
                <Check className="h-3 w-3 me-1" />{t('common.save')}
              </Button>
              <Button size="sm" variant="ghost" onClick={() => setIsEditing(false)}>
                <X className="h-3 w-3 me-1" />{t('common.cancel')}
              </Button>
            </div>
          </div>
        ) : (
          <>
            <p className="font-medium text-sm">{question.question_text}</p>
            {question.question_text_ar && (
              <p className="text-muted-foreground text-sm" dir="rtl">{question.question_text_ar}</p>
            )}
          </>
         )}

        {/* Per-question Mood Level Tags (wellness only) */}
        {purpose === 'wellness' && (() => {
          const MOOD_META = moodDefinitions && moodDefinitions.length > 0
            ? moodDefinitions.map(m => ({ key: m.key, emoji: m.emoji, label: m.label_en }))
            : DEFAULT_MOOD_META.map(m => ({ key: m.key, emoji: m.emoji, label: t(m.labelKey) as string }));

          return (
            <div className="space-y-1.5">
              <p className="text-xs text-muted-foreground">{t('aiGenerator.moodTags')}</p>
              <div className="flex flex-wrap items-center gap-1.5">
                {(question.mood_levels || []).map(mood => {
                  const meta = MOOD_META.find(m => m.key === mood);
                  return (
                    <Badge key={mood} variant="secondary" className="text-xs gap-1 pe-1">
                      <span>{meta?.emoji ?? '•'}</span>
                      <span>{meta?.label ?? mood}</span>
                      <button
                        type="button"
                        className="ms-0.5 rounded-full hover:bg-muted-foreground/20 p-0.5"
                        onClick={() => {
                          const newLevels = (question.mood_levels || []).filter(m => m !== mood);
                          onUpdate(index, { mood_levels: newLevels });
                        }}
                      >
                        <X className="h-3 w-3" />
                      </button>
                    </Badge>
                  );
                })}
                <Popover>
                  <PopoverTrigger asChild>
                    <Button variant="outline" size="sm" className="h-6 text-xs px-2 gap-1">
                      <Plus className="h-3 w-3" />
                      {t('aiGenerator.addMood')}
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-48 p-2" align="start">
                    <div className="space-y-1">
                      {MOOD_META.filter(m => !(question.mood_levels || []).includes(m.key)).map(m => (
                        <Button
                          key={m.key}
                          variant="ghost"
                          size="sm"
                          className="w-full justify-start text-xs gap-2"
                          onClick={() => {
                            const newLevels = [...(question.mood_levels || []), m.key];
                            onUpdate(index, { mood_levels: newLevels });
                          }}
                        >
                          <span>{m.emoji}</span>
                          <span>{m.label}</span>
                        </Button>
                      ))}
                      {MOOD_META.filter(m => !(question.mood_levels || []).includes(m.key)).length === 0 && (
                        <p className="text-xs text-muted-foreground text-center py-2">{t('common.all')}</p>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              </div>
              {(question.mood_levels || []).length === 0 && (
                <p className="text-xs text-muted-foreground/70 italic">{t('aiGenerator.noMoodTags')}</p>
              )}
            </div>
          );
        })()}

        {/* Affective State & Mood Score Badges (NEW) */}
        {(question.affective_state || question.mood_score) && (
          <div className="flex flex-wrap gap-1.5">
            {question.affective_state && (
              <Badge
                variant="outline"
                className={`text-xs ${
                  question.affective_state === 'positive' ? 'border-primary text-primary' :
                  question.affective_state === 'negative' ? 'border-destructive text-destructive' :
                  'border-muted-foreground text-muted-foreground'
                }`}
              >
                {question.affective_state === 'positive' ? '🟢' : question.affective_state === 'negative' ? '🔴' : '⚪'}
                {' '}{t(`aiGenerator.affective_${question.affective_state}`)}
              </Badge>
            )}
            {typeof question.mood_score === 'number' && (
              <Badge variant="secondary" className="text-xs">
                {t('aiGenerator.moodScoreLabel')}: {question.mood_score}/5
              </Badge>
            )}
            {question.category_name && (
              <Badge variant="outline" className="text-xs">
                {question.category_name}
              </Badge>
            )}
            {question.subcategory_name && (
              <Badge variant="outline" className="text-xs text-muted-foreground">
                {question.subcategory_name}
              </Badge>
            )}
          </div>
        )}

        {/* Expert Knowledge Badges */}
        {(question.framework_reference || question.psychological_construct || question.scoring_mechanism) && (
          <div className="flex flex-wrap gap-1.5">
            {question.framework_reference && (
              <Badge variant="default" className="text-xs">
                {t('aiGenerator.frameworkReference')}: {question.framework_reference}
              </Badge>
            )}
            {question.psychological_construct && (
              <Badge variant="secondary" className="text-xs">
                {t('aiGenerator.psychologicalConstruct')}: {question.psychological_construct}
              </Badge>
            )}
            {question.scoring_mechanism && (
              <Badge variant="outline" className="text-xs">
                {t('aiGenerator.scoringMechanism')}: {question.scoring_mechanism}
              </Badge>
            )}
          </div>
        )}

        {/* Flags */}
        {(question.bias_flag || question.ambiguity_flag) && (
          <div className="flex gap-2">
            {question.bias_flag && (
              <Badge variant="destructive" className="text-xs">
                <AlertTriangle className="h-3 w-3 me-1" />{t('aiGenerator.biasDetected')}
              </Badge>
            )}
            {question.ambiguity_flag && (
              <Badge variant="outline" className="text-xs border-chart-4 text-chart-4">
                <AlertTriangle className="h-3 w-3 me-1" />{t('aiGenerator.ambiguityDetected')}
              </Badge>
            )}
          </div>
        )}

        {/* Per-Question Validation Issues */}
        {validationIssues.length > 0 && (
          <div className="flex flex-wrap gap-1.5">
            {validationIssues.map((issue, idx) => (
              <Badge key={idx} variant={question.validation_status === 'failed' ? 'destructive' : 'outline'} className="text-xs">
                {t(issueLabels[issue] || issue)}
              </Badge>
            ))}
          </div>
        )}

        {/* Explanation */}
        {question.explanation && (
          <Collapsible open={explanationOpen} onOpenChange={setExplanationOpen}>
            <CollapsibleTrigger asChild>
              <Button variant="ghost" size="sm" className="w-full justify-between text-xs">
                {t('aiGenerator.explanation')}
                <ChevronDown className={`h-3 w-3 transition-transform ${explanationOpen ? 'rotate-180' : ''}`} />
              </Button>
            </CollapsibleTrigger>
            <CollapsibleContent>
              <p className="text-xs text-muted-foreground p-2 bg-muted rounded-md">{question.explanation}</p>
            </CollapsibleContent>
          </Collapsible>
        )}

        {/* AI Rewrite Prompt Area */}
        {rewriteOpen && (
          <div className="space-y-2 p-3 bg-muted/50 rounded-md border">
            <Textarea
              value={rewritePrompt}
              onChange={e => setRewritePrompt(e.target.value)}
              placeholder={t('aiGenerator.rewritePrompt')}
              className="text-sm min-h-[60px]"
              rows={2}
              disabled={isRewriting}
            />
            <div className="flex items-center justify-end gap-2">
              <Button size="sm" variant="ghost" onClick={() => { setRewriteOpen(false); setRewritePrompt(''); }} disabled={isRewriting}>
                {t('common.cancel')}
              </Button>
              <Button size="sm" onClick={handleRewrite} disabled={!rewritePrompt.trim() || isRewriting}>
                {isRewriting ? (
                  <><Loader2 className="h-3 w-3 me-1 animate-spin" />{t('aiGenerator.rewriting')}</>
                ) : (
                  <><Sparkles className="h-3 w-3 me-1" />{t('aiGenerator.aiRewrite')}</>
                )}
              </Button>
            </div>
          </div>
        )}

        {/* Actions */}
        <div className={`flex items-center justify-end gap-1 pt-1 border-t ${isRegenerating ? 'pointer-events-none opacity-50' : ''}`}>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={handleCopy}>
            <Copy className="h-3.5 w-3.5" />
          </Button>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => { setEditText(question.question_text); setEditTextAr(question.question_text_ar); setIsEditing(true); }}>
            <Edit2 className="h-3.5 w-3.5" />
          </Button>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => setRewriteOpen(!rewriteOpen)}>
                {isRewriting ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Sparkles className="h-3.5 w-3.5" />}
              </Button>
            </TooltipTrigger>
            <TooltipContent>{t('aiGenerator.aiRewrite')}</TooltipContent>
          </Tooltip>
          {onRegenerate && (
            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => onRegenerate(index)}>
              <RefreshCw className="h-3.5 w-3.5" />
            </Button>
          )}
          <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => onRemove(index)}>
            <X className="h-3.5 w-3.5" />
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

/**
 * QuestionGeneratorContext — provides all AI generator config state to the subtree.
 * Eliminates prop drilling through ConfigPanel (48 → 0 props).
 *
 * The context value is memoized to prevent cascade re-renders when
 * unrelated parent state changes.
 */

import { createContext, useContext, useMemo, type ReactNode } from 'react';
import type { AIGeneratorState } from '../types';

const GeneratorContext = createContext<AIGeneratorState | null>(null);

export function GeneratorProvider({ state, children }: { state: AIGeneratorState; children: ReactNode }) {
  // Memoize the context value so consumers only re-render when state identity changes.
  // useAIGenerator returns a new object each render, but the individual fields are stable
  // thanks to useState identity. We rely on the parent hook's memoization.
  const value = useMemo(() => state, [
    // Config state
    state.accuracyMode, state.selectedModel, state.questionTypes,
    state.questionCount, state.complexity, state.tone,
    state.advancedSettings, state.customPrompt,
    state.selectedFrameworkIds, state.selectedCategoryIds,
    state.selectedSubcategoryIds, state.selectedMoodLevels,
    state.selectedPeriodId, state.purpose, state.questionsPerDay,
    state.batchDialogOpen, state.wellnessPreviewOpen,
    // Derived
    state.isStrict, state.hasFailures, state.canSave, state.canExport,
    // Data (reference equality from React Query)
    state.models, state.documents, state.referenceFrameworks,
    state.questions, state.validationReport, state.generationMeta,
    state.availableBatches, state.availableWellnessBatches,
    state.moodDefinitions, state.periods, state.tenantId,
    // Loading
    state.isGenerating, state.regeneratingIndex, state.isValidating,
    state.isSaving, state.isSavingWellness, state.isUploading,
    state.isRewriting, state.isCreatingPeriod,
  ]);

  return <GeneratorContext.Provider value={value}>{children}</GeneratorContext.Provider>;
}

export function useGeneratorContext(): AIGeneratorState {
  const ctx = useContext(GeneratorContext);
  if (!ctx) throw new Error('useGeneratorContext must be used within <GeneratorProvider>');
  return ctx;
}

/**
 * useAIGenerator — single orchestrator hook for the AI Question Generator feature.
 * Owns all state, delegates to existing service hooks. Zero Supabase calls.
 */

import { useState, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { DEFAULT_AI_MODEL, DEFAULT_ACCURACY_MODE, DEFAULT_AI_SETTINGS } from '@/config/ai';
import { useEnhancedAIGeneration, type AdvancedSettings } from '@/hooks/questions/useEnhancedAIGeneration';
import { useMoodDefinitions } from '@/hooks/wellness/useMoodDefinitions';
import { useAIModels } from '@/hooks/questions/useAIModels';
import { useAIKnowledge } from '@/hooks/questions/useAIKnowledge';
import { useReferenceFrameworks } from '@/hooks/questions/useReferenceFrameworks';
import { useQuestionBatches } from '@/hooks/questions/useQuestionBatches';
import { useGenerationPeriods } from '@/hooks/questions/useGenerationPeriods';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { usePromptRewrite } from '@/features/admin/hooks/admin/usePromptRewrite';
import type { QuestionPurpose } from '../components/ConfigPanel';
import type { AIGeneratorState } from '../types';

export function useAIGenerator(): AIGeneratorState {
  const { t } = useTranslation();
  const { user } = useAuth();

  // ─── Service hooks ───────────────────────────────────
  const { models } = useAIModels();
  const {
    documents, uploadDocument, toggleDocument, deleteDocument, deleteAllDocuments, isUploading,
  } = useAIKnowledge();
  const {
    frameworks: referenceFrameworks, isPending: frameworksLoading,
    addFramework, updateFramework, deleteFramework,
  } = useReferenceFrameworks();
  const {
    questions, validationReport, generationMeta,
    generate, validate, saveSet, saveWellness, removeQuestion, updateQuestion, clearAll,
    isGenerating, regeneratingIndex, isValidating, isSaving, isSavingWellness,
  } = useEnhancedAIGeneration();

  const { tenantId } = useTenantId();
  const { rewritePrompt: rewritePromptFn, isRewriting } = usePromptRewrite();

  const { availableBatches, availableWellnessBatches, MAX_BATCH_SIZE } = useQuestionBatches(tenantId || null);
  const { moods: moodDefinitions } = useMoodDefinitions(tenantId || null);
  const {
    periods, createPeriodAsync, isCreating: isCreatingPeriod,
    getActivePeriodForPurpose, expirePeriod, softDeletePeriod,
  } = useGenerationPeriods(tenantId || null);

  // ─── Local state ─────────────────────────────────────
  const [accuracyMode, setAccuracyMode] = useState<string>(DEFAULT_ACCURACY_MODE);
  const [selectedModel, setSelectedModel] = useState<string>(DEFAULT_AI_MODEL);
  const [questionTypes, setQuestionTypes] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState<number>(DEFAULT_AI_SETTINGS.questionCount);
  const [complexity, setComplexity] = useState<string>(DEFAULT_AI_SETTINGS.complexity);
  const [tone, setTone] = useState<string>(DEFAULT_AI_SETTINGS.tone);
  const [advancedSettings, setAdvancedSettings] = useState<AdvancedSettings>({
    requireExplanation: DEFAULT_AI_SETTINGS.requireExplanation,
    enableBiasDetection: DEFAULT_AI_SETTINGS.enableBiasDetection,
    enableAmbiguityDetection: DEFAULT_AI_SETTINGS.enableAmbiguityDetection,
    enableDuplicateDetection: DEFAULT_AI_SETTINGS.enableDuplicateDetection,
    enableCriticPass: DEFAULT_AI_SETTINGS.enableCriticPass,
    minWordLength: DEFAULT_AI_SETTINGS.minWordLength,
  });
  const [customPrompt, setCustomPrompt] = useState('');
  const [selectedFrameworkIds, setSelectedFrameworkIds] = useState<string[]>([]);
  const [selectedCategoryIds, setSelectedCategoryIds] = useState<string[]>([]);
  const [selectedSubcategoryIds, setSelectedSubcategoryIds] = useState<string[]>([]);
  const [selectedMoodLevels, setSelectedMoodLevels] = useState<string[]>([]);
  const [batchDialogOpen, setBatchDialogOpen] = useState(false);
  const [wellnessPreviewOpen, setWellnessPreviewOpen] = useState(false);
  const [selectedPeriodId, setSelectedPeriodId] = useState<string | null>(null);
  const [purpose, setPurpose] = useState<QuestionPurpose>('survey');
  const [questionsPerDay, setQuestionsPerDay] = useState(1);

  // ─── Derived (memoized) ──────────────────────────────
  const isStrict = accuracyMode === 'strict';
  const hasFailures = validationReport?.overall_result === 'failed';
  const canSave = questions.length > 0 && !(isStrict && hasFailures);
  const canExport = canSave;

  // ─── Helpers (memoized) ─────────────────────────────
  const activeDocIds = useMemo(() => documents.filter(d => d.is_active).map(d => d.id), [documents]);
  const resolvedType = useMemo(() => questionTypes.length === 0 ? 'mixed' : questionTypes.join(', '), [questionTypes]);

  // ─── Actions (stabilized with useCallback) ──────────
  const handleGenerate = useCallback(() => {
    if (selectedCategoryIds.length === 0) {
      toast.error(t('aiGenerator.selectAtLeastOneCategory'));
      return;
    }
    if (!selectedModel) {
      toast.error(t('aiGenerator.selectModel'));
      return;
    }
    generate({
      questionCount, complexity, tone, questionType: resolvedType,
      model: selectedModel, accuracyMode, advancedSettings, language: 'both',
      useExpertKnowledge: selectedFrameworkIds.length > 0,
      knowledgeDocumentIds: activeDocIds,
      customPrompt: customPrompt.trim() || undefined,
      selectedFrameworks: selectedFrameworkIds.length > 0 ? selectedFrameworkIds : undefined,
      categoryIds: selectedCategoryIds,
      subcategoryIds: selectedSubcategoryIds.length > 0 ? selectedSubcategoryIds : undefined,
      moodLevels: purpose === 'wellness' ? selectedMoodLevels : undefined,
      periodId: selectedPeriodId || undefined,
    });
  }, [selectedCategoryIds, selectedModel, generate, questionCount, complexity, tone, resolvedType, accuracyMode, advancedSettings, activeDocIds, customPrompt, selectedFrameworkIds, selectedSubcategoryIds, purpose, selectedMoodLevels, selectedPeriodId, t]);

  const handleRewritePrompt = useCallback(async () => {
    if (customPrompt.trim().length < 10) return;
    const activeDocs = documents.filter(d => d.is_active && d.content_text);
    const documentSummaries = activeDocs
      .map(d => `[${d.file_name}]: ${(d.content_text || '').substring(0, 400)}`)
      .join('\n')
      .substring(0, 2000);
    const result = await rewritePromptFn({
      prompt: customPrompt,
      model: selectedModel,
      useExpertKnowledge: selectedFrameworkIds.length > 0,
      selectedFrameworkIds: selectedFrameworkIds.length > 0 ? selectedFrameworkIds : undefined,
      documentSummaries: documentSummaries || undefined,
    });
    if (result) setCustomPrompt(result);
  }, [customPrompt, documents, selectedModel, selectedFrameworkIds, rewritePromptFn]);

  const handleValidate = useCallback(() => {
    validate({
      questions, accuracyMode,
      model: selectedModel,
      enableCriticPass: advancedSettings.enableCriticPass,
      minWordLength: advancedSettings.minWordLength,
      selectedFrameworkIds: selectedFrameworkIds.length > 0 ? selectedFrameworkIds : undefined,
      knowledgeDocumentIds: activeDocIds.length > 0 ? activeDocIds : undefined,
      hasDocuments: documents.length > 0,
      periodId: selectedPeriodId || undefined,
    });
  }, [validate, questions, accuracyMode, selectedModel, advancedSettings, selectedFrameworkIds, activeDocIds, documents, selectedPeriodId]);

  const handleSaveClick = useCallback(() => {
    if (purpose === 'wellness') {
      setWellnessPreviewOpen(true);
    } else {
      setBatchDialogOpen(true);
    }
  }, [purpose]);

  const handleWellnessConfirm = useCallback((targetBatchId?: string) => {
    saveWellness({ questions, targetBatchId }, {
      onSuccess: () => {
        setWellnessPreviewOpen(false);
        clearAll();
        if (documents.length > 0) deleteAllDocuments();
      },
    });
  }, [saveWellness, questions, clearAll, documents, deleteAllDocuments]);

  const handleBatchConfirm = useCallback((targetBatchId?: string) => {
    saveSet({
      questions, model: selectedModel, accuracyMode,
      settings: {
        questionCount, complexity, tone, questionTypes, advancedSettings,
        selected_framework_ids: selectedFrameworkIds,
        custom_prompt: customPrompt,
        categoryIds: selectedCategoryIds,
        subcategoryIds: selectedSubcategoryIds,
      },
      validationReport,
      targetBatchId,
    }, {
      onSuccess: () => {
        setBatchDialogOpen(false);
        clearAll();
        if (documents.length > 0) deleteAllDocuments();
      },
    });
  }, [saveSet, questions, selectedModel, accuracyMode, questionCount, complexity, tone, questionTypes, advancedSettings, selectedFrameworkIds, customPrompt, selectedCategoryIds, selectedSubcategoryIds, validationReport, clearAll, documents, deleteAllDocuments]);

  const handleExport = useCallback((format: 'json' | 'pdf') => {
    const exportData = {
      metadata: {
        model: selectedModel, accuracyMode, generatedAt: new Date().toISOString(),
        settings: { questionCount, complexity, tone, questionTypes, selectedFrameworkIds, selectedCategoryIds, selectedSubcategoryIds },
        validation: validationReport ? { overall: validationReport.overall_result, avgConfidence: validationReport.avg_confidence } : null,
      },
      questions: questions.map(q => ({
        question_text: q.question_text, question_text_ar: q.question_text_ar,
        type: q.type, complexity: q.complexity, tone: q.tone,
        confidence_score: q.confidence_score, explanation: q.explanation,
        framework_reference: q.framework_reference,
        category_id: q.category_id || null,
        subcategory_id: q.subcategory_id || null,
        category_name: q.category_name || null,
        subcategory_name: q.subcategory_name || null,
        mood_score: q.mood_score || null,
        affective_state: q.affective_state || null,
        generation_period_id: q.generation_period_id || null,
      })),
    };

    if (format === 'json') {
      const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `question-set-${new Date().toISOString().split('T')[0]}.json`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success(t('aiGenerator.exportSuccess'));
    } else {
      const printWindow = window.open('', '_blank');
      if (printWindow) {
        const html = `<html><head><title>Question Set</title><style>body{font-family:sans-serif;padding:2rem;} .q{margin:1rem 0;padding:1rem;border:1px solid #ddd;border-radius:8px;} .badge{display:inline-block;padding:2px 8px;border-radius:4px;background:#f0f0f0;font-size:12px;margin-inline-end:4px;} .ar{direction:rtl;color:#666;margin-top:4px;}</style></head><body>
          <h1>${t('aiGenerator.title')}</h1>
          <p>Model: ${selectedModel} | Accuracy: ${accuracyMode} | ${new Date().toLocaleDateString()}</p>
          ${questions.map((q, i) => `<div class="q"><span class="badge">${q.type}</span><span class="badge">${q.complexity}</span><span class="badge">${q.confidence_score}%</span>${q.framework_reference ? `<span class="badge">${q.framework_reference}</span>` : ''}<p><strong>${i + 1}. ${q.question_text}</strong></p><p class="ar">${q.question_text_ar}</p>${q.explanation ? `<p style="font-size:12px;color:#888;">${q.explanation}</p>` : ''}</div>`).join('')}
        </body></html>`;
        printWindow.document.write(html);
        printWindow.document.close();
        printWindow.print();
      }
    }
  }, [selectedModel, accuracyMode, questionCount, complexity, tone, questionTypes, selectedFrameworkIds, selectedCategoryIds, selectedSubcategoryIds, validationReport, questions, t]);

  const handleRegenerateFailedOnly = useCallback(() => {
    const failedCount = questions.filter(q => q.validation_status === 'failed').length;
    if (failedCount === 0) return;
    generate({
      questionCount: failedCount, complexity, tone, questionType: resolvedType,
      model: selectedModel, accuracyMode, advancedSettings, language: 'both',
      useExpertKnowledge: selectedFrameworkIds.length > 0,
      knowledgeDocumentIds: activeDocIds.length > 0 ? activeDocIds : undefined,
      selectedFrameworks: selectedFrameworkIds.length > 0 ? selectedFrameworkIds : undefined,
      categoryIds: selectedCategoryIds,
      subcategoryIds: selectedSubcategoryIds.length > 0 ? selectedSubcategoryIds : undefined,
      moodLevels: purpose === 'wellness' ? selectedMoodLevels : undefined,
      periodId: selectedPeriodId || undefined,
    });
  }, [questions, generate, complexity, tone, resolvedType, selectedModel, accuracyMode, advancedSettings, selectedFrameworkIds, activeDocIds, selectedCategoryIds, selectedSubcategoryIds, purpose, selectedMoodLevels, selectedPeriodId]);

  const handleRegenerateSingle = useCallback((index: number) => {
    const q = questions[index];
    const singleType = q.type || resolvedType;
    generate({
      questionCount: 1, complexity: q.complexity || complexity, tone: q.tone || tone, questionType: singleType,
      model: selectedModel, accuracyMode, advancedSettings, language: 'both',
      useExpertKnowledge: selectedFrameworkIds.length > 0,
      knowledgeDocumentIds: activeDocIds.length > 0 ? activeDocIds : undefined,
      selectedFrameworks: selectedFrameworkIds.length > 0 ? selectedFrameworkIds : undefined,
      categoryIds: selectedCategoryIds,
      subcategoryIds: selectedSubcategoryIds.length > 0 ? selectedSubcategoryIds : undefined,
      moodLevels: purpose === 'wellness' ? (q.mood_levels?.length ? q.mood_levels : selectedMoodLevels) : undefined,
      periodId: selectedPeriodId || undefined,
      _replaceAtIndex: index,
    } as any);
  }, [questions, generate, resolvedType, complexity, tone, selectedModel, accuracyMode, advancedSettings, selectedFrameworkIds, activeDocIds, selectedCategoryIds, selectedSubcategoryIds, purpose, selectedMoodLevels, selectedPeriodId]);

  const handleClearAll = useCallback(() => {
    clearAll();
    if (documents.length > 0) deleteAllDocuments();
  }, [clearAll, documents, deleteAllDocuments]);

  const handleCreatePeriod = useCallback(async (params: any) => {
    if (!tenantId) return;
    try {
      const newPeriod = await createPeriodAsync({
        tenantId,
        periodType: params.periodType,
        startDate: params.startDate,
        endDate: params.endDate,
        lockedCategoryIds: params.lockedCategoryIds,
        lockedSubcategoryIds: params.lockedSubcategoryIds,
        purpose: params.purpose || purpose,
        createdBy: user?.id,
      });
      if (newPeriod?.id) {
        setSelectedPeriodId(newPeriod.id);
        const catIds = (newPeriod.locked_category_ids as string[]) || [];
        const subIds = (newPeriod.locked_subcategory_ids as string[]) || [];
        setSelectedCategoryIds(catIds);
        setSelectedSubcategoryIds(subIds);
      }
    } catch {
      // Error already handled by mutation onError
    }
  }, [tenantId, createPeriodAsync, purpose, user?.id]);

  const handleExpirePeriod = useCallback((periodId: string) => {
    expirePeriod(periodId);
    if (selectedPeriodId === periodId) setSelectedPeriodId(null);
  }, [expirePeriod, selectedPeriodId]);

  const handleDeletePeriod = useCallback((periodId: string) => {
    softDeletePeriod(periodId);
    if (selectedPeriodId === periodId) setSelectedPeriodId(null);
  }, [softDeletePeriod, selectedPeriodId]);

  return {
    // Config state
    accuracyMode, setAccuracyMode,
    selectedModel, setSelectedModel,
    questionTypes, setQuestionTypes,
    questionCount, setQuestionCount,
    complexity, setComplexity,
    tone, setTone,
    advancedSettings, setAdvancedSettings,
    customPrompt, setCustomPrompt,
    selectedFrameworkIds, setSelectedFrameworkIds,
    selectedCategoryIds, setSelectedCategoryIds,
    selectedSubcategoryIds, setSelectedSubcategoryIds,
    selectedMoodLevels, setSelectedMoodLevels,
    selectedPeriodId, setSelectedPeriodId,
    purpose, setPurpose,
    questionsPerDay, setQuestionsPerDay,
    batchDialogOpen, setBatchDialogOpen,
    wellnessPreviewOpen, setWellnessPreviewOpen,

    // Derived
    isStrict, hasFailures, canSave, canExport,

    // Data
    models, documents, referenceFrameworks, frameworksLoading,
    questions, validationReport, generationMeta,
    availableBatches, availableWellnessBatches, MAX_BATCH_SIZE,
    moodDefinitions, periods,
    tenantId: tenantId || null,
    currentUserId: user?.id,

    // Loading
    isGenerating, regeneratingIndex, isValidating, isSaving, isSavingWellness, isUploading, isRewriting, isCreatingPeriod,

    // Actions
    handleGenerate, handleRewritePrompt, handleValidate,
    handleSaveClick, handleWellnessConfirm, handleBatchConfirm,
    handleExport, handleRegenerateFailedOnly, handleRegenerateSingle,
    handleClearAll, removeQuestion, updateQuestion,
    uploadDocument, toggleDocument, deleteDocument,
    addFramework, updateFramework, deleteFramework,
    activePeriodForPurpose: getActivePeriodForPurpose(purpose),
    handleExpirePeriod, handleDeletePeriod, handleCreatePeriod,
  };
}

/**
 * AI Question Generator feature types.
