  // Data
  models: import('@/hooks/questions/useAIModels').AIModel[];
  documents: any[];
  referenceFrameworks: import('@/hooks/questions/useReferenceFrameworks').ReferenceFramework[];
  frameworksLoading: boolean;
  questions: import('@/hooks/questions/useEnhancedAIGeneration').EnhancedGeneratedQuestion[];
  validationReport: import('@/hooks/questions/useEnhancedAIGeneration').ValidationReport | null;
  generationMeta: { model: string; duration_ms: number } | null;
  availableBatches: any[];
  availableWellnessBatches: any[];
  MAX_BATCH_SIZE: number;
  moodDefinitions: any[];
  periods: any[];
  tenantId: string | null;
  currentUserId: string | undefined;

  // Loading
  isGenerating: boolean;
  regeneratingIndex: number | null;
  isValidating: boolean;
  isSaving: boolean;
  isSavingWellness: boolean;
  isUploading: boolean;
  isRewriting: boolean;
  isCreatingPeriod: boolean;

  // Actions
  handleGenerate: () => void;
  handleRewritePrompt: () => Promise<void>;
  handleValidate: () => void;
  handleSaveClick: () => void;
  handleWellnessConfirm: (targetBatchId?: string) => void;
  handleBatchConfirm: (targetBatchId?: string) => void;
  handleExport: (format: 'json' | 'pdf') => void;
  handleRegenerateFailedOnly: () => void;
  handleRegenerateSingle: (index: number) => void;
  handleClearAll: () => void;
  removeQuestion: (index: number) => void;
  updateQuestion: (index: number, updates: any) => void;
  uploadDocument: any;
  toggleDocument: any;
  deleteDocument: any;
  addFramework: any;
  updateFramework: any;
  deleteFramework: any;
  activePeriodForPurpose: any;
  handleExpirePeriod: (periodId: string) => void;
  handleDeletePeriod: (periodId: string) => void;
  handleCreatePeriod: (params: any) => Promise<void>;
}

import { useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { useTranslation } from 'react-i18next';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import type { PerformanceDailyRow } from '@/features/ai-governance/hooks/usePerformanceTrend';

interface Props {
  performanceData: PerformanceDailyRow[];
  penalties: any[];
  isLoading: boolean;
}

export function RiskDashboard({ performanceData, penalties, isLoading }: Props) {
  const { t } = useTranslation();

  const trendData = useMemo(() => {
    const byDate: Record<string, { latency: number; errorRate: number; count: number }> = {};
    performanceData.forEach(r => {
      if (!byDate[r.date]) byDate[r.date] = { latency: 0, errorRate: 0, count: 0 };
      byDate[r.date].latency += r.avg_latency ?? 0;
      byDate[r.date].errorRate += r.error_rate ?? 0;
      byDate[r.date].count += 1;
    });
    return Object.entries(byDate).sort(([a], [b]) => a.localeCompare(b)).map(([date, v]) => ({
      date,
      latency: Number((v.latency / v.count).toFixed(0)),
      errorRate: Number(((v.errorRate / v.count) * 100).toFixed(2)),
    }));
  }, [performanceData]);

  // Filter expired penalties client-side
  const activePenalties = useMemo(() => {
    const now = new Date();
    return penalties.filter((p: any) => new Date(p.penalty_expires_at) > now);
  }, [penalties]);

  if (isLoading) {
    return <div className="space-y-4">{Array.from({ length: 3 }).map((_, i) => <Card key={i}><CardContent className="pt-6"><Skeleton className="h-48 w-full" /></CardContent></Card>)}</div>;
  }

  return (
    <div className="space-y-6">
      <div className="grid gap-4 md:grid-cols-2">
        <Card>
          <CardHeader><CardTitle>{t('aiGovernance.latencyTrend')}</CardTitle></CardHeader>
          <CardContent>
            {trendData.length > 0 ? (
              <ResponsiveContainer width="100%" height={250}>
                <LineChart data={trendData}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                  <YAxis tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ backgroundColor: 'hsl(var(--popover))', border: '1px solid hsl(var(--border))', color: 'hsl(var(--popover-foreground))' }} />
                  <Line type="monotone" dataKey="latency" stroke="hsl(var(--chart-4))" strokeWidth={2} dot={false} name={t('aiGovernance.avgLatencyMs')} />
                </LineChart>
              </ResponsiveContainer>
            ) : <p className="text-muted-foreground">{t('common.noData')}</p>}
          </CardContent>
        </Card>
        <Card>
          <CardHeader><CardTitle>{t('aiGovernance.errorRateTrend')}</CardTitle></CardHeader>
          <CardContent>
            {trendData.length > 0 ? (
              <ResponsiveContainer width="100%" height={250}>
                <LineChart data={trendData}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis dataKey="date" tick={{ fontSize: 11 }} />
                  <YAxis tick={{ fontSize: 11 }} />
                  <Tooltip contentStyle={{ backgroundColor: 'hsl(var(--popover))', border: '1px solid hsl(var(--border))', color: 'hsl(var(--popover-foreground))' }} />
                  <Line type="monotone" dataKey="errorRate" stroke="hsl(var(--destructive))" strokeWidth={2} dot={false} name={t('aiGovernance.errorRatePct')} />
                </LineChart>
