          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader><CardTitle>{t('aiGovernance.activePenalties')}</CardTitle></CardHeader>
        <CardContent>
          {activePenalties.length === 0 ? (
            <p className="text-muted-foreground">{t('aiGovernance.noPenalties')}</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b border-border">
                    <th className="text-start py-2 pe-4 font-medium text-muted-foreground">{t('aiGovernance.provider')}</th>
                    <th className="text-start py-2 pe-4 font-medium text-muted-foreground">{t('aiGovernance.feature')}</th>
                    <th className="text-start py-2 pe-4 font-medium text-muted-foreground">{t('aiGovernance.multiplier')}</th>
                    <th className="text-start py-2 font-medium text-muted-foreground">{t('aiGovernance.expires')}</th>
                  </tr>
                </thead>
                <tbody>
                  {activePenalties.map((p: any) => (
                    <tr key={p.id} className="border-b border-border/50">
                      <td className="py-2 pe-4">{p.provider}</td>
                      <td className="py-2 pe-4">{p.feature}</td>
                      <td className="py-2 pe-4">{p.penalty_multiplier}x</td>
                      <td className="py-2 text-muted-foreground">{new Date(p.penalty_expires_at).toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from './useAuth';
import { logger } from '@/shared/utils/logger';

export function useUserPermissions() {
  const { user, loading: authLoading } = useAuth();

  const permissionsQuery = useQuery({
    queryKey: ['user-permissions', user?.id],
    queryFn: async () => {
      if (!user?.id) return [];

      // Get all permissions for the user through their roles
      const { data, error } = await supabase
        .from('user_roles')
        .select(`
          custom_role_id,
          role,
          roles:custom_role_id (
            id,
            role_permissions (
              permissions (
                code
              )
            )
          )
        `)
        .eq('user_id', user.id);

      if (error) throw error;

      // Extract unique permission codes
      const permissionCodes = new Set<string>();
      
      // Check if user has super_admin role - they have all permissions
      const isSuperAdmin = data?.some(ur => ur.role === 'super_admin');
      if (isSuperAdmin) {
        // Return a special marker for super admin
        return ['*'];
      }

      data?.forEach(userRole => {
        const role = userRole.roles as any;
        if (role?.role_permissions) {
          role.role_permissions.forEach((rp: any) => {
            if (rp.permissions?.code) {
              permissionCodes.add(rp.permissions.code);
            }
          });
        }
      });

      return Array.from(permissionCodes);
    },
    enabled: !!user?.id && !authLoading,
  });

  const permissions = permissionsQuery.data ?? [];

  const hasPermission = (code: string): boolean => {
    if (permissions.includes('*')) return true; // Super admin
    return permissions.includes(code);
  };

  const hasAnyPermission = (codes: string[]): boolean => {
    if (permissions.includes('*')) return true; // Super admin
    return codes.some(code => permissions.includes(code));
  };

  const hasAllPermissions = (codes: string[]): boolean => {
    if (permissions.includes('*')) return true; // Super admin
    return codes.every(code => permissions.includes(code));
  };

  return {
    permissions,
    hasPermission,
    hasAnyPermission,
    hasAllPermissions,
    // CRITICAL: isLoading must be true while auth is initializing OR while the
    // query is pending. TanStack Query v5 isPending captures the "idle" state
    // (when enabled=false) unlike isLoading which returns false when idle.
    isPending: authLoading || permissionsQuery.isPending,
    isSuperAdmin: permissions.includes('*'),
  };
}

export function useHasRole(role: 'super_admin' | 'tenant_admin' | 'manager' | 'user') {
  const { user, loading: authLoading } = useAuth();

  const { data: hasRole = false, isPending } = useQuery({
    queryKey: ['has-role', user?.id, role],
    queryFn: async () => {
      if (!user?.id) return false;

      const { data, error } = await supabase
        .from('user_roles')
        .select('role')
        .eq('user_id', user.id)
        .eq('role', role)
        .maybeSingle();

      if (error) {
        logger.error('useHasRole', 'Error checking role', error);
        return false;
      }

      return !!data;
    },
    enabled: !!user?.id && !authLoading,
  });

  return {
    hasRole,
    // CRITICAL: must stay true while auth is loading OR query is pending (idle)
    isPending: authLoading || isPending,
  };
}

import { useState, useEffect } from "react";
import { useSearchParams } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { z } from "zod";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/shared/components/ui/card";
import { Input } from "@/shared/components/ui/input";
import { Button } from "@/shared/components/ui/button";
import { Label } from "@/shared/components/ui/label";
import { ThemeToggle } from "@/shared/components/ThemeToggle";
import { LanguageSelector } from "@/shared/components/LanguageSelector";
import { CheckCircle, AlertCircle, Loader2 } from "lucide-react";
import { useAcceptInvite } from "@/features/auth/hooks/auth/useAcceptInvite";

export default function AcceptInvite() {
  const { t } = useTranslation();
  const [searchParams] = useSearchParams();

  const {
    step,
    invitation,
    isVerifying,
    isSubmitting,
    codeError,
    verifyCode,
    handleSignup,
    goToLogin,
  } = useAcceptInvite();

  const [code, setCode] = useState(searchParams.get("code") || "");
  const [fullName, setFullName] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Auto-verify if code is in URL
  useEffect(() => {
    const urlCode = searchParams.get("code");
    if (urlCode && urlCode.length === 8) {
      verifyCode(urlCode);
    }
  }, []);

  // Sync invitation name
  useEffect(() => {
    if (invitation?.full_name) setFullName(invitation.full_name);
  }, [invitation]);

  const handleVerifyCode = (e: React.FormEvent) => {
    e.preventDefault();
    if (code.length < 8) return;
    verifyCode(code);
  };

  const validateSignup = () => {
    const newErrors: Record<string, string> = {};
    if (!fullName.trim()) newErrors.fullName = t("profile.fullNameRequired");
    if (password.length < 6) newErrors.password = t("validation.passwordMinLength");
    if (password !== confirmPassword) newErrors.confirmPassword = t("auth.passwordMismatch");
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const onSubmitSignup = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateSignup()) return;
    handleSignup(fullName, password);
  };

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <div className="flex justify-end gap-2 p-4">
        <LanguageSelector />
        <ThemeToggle />
      </div>

      <div className="flex-1 flex items-center justify-center px-4">
        {step === "code" && (
          <Card className="w-full max-w-md">
            <CardHeader className="text-center">
              <CardTitle className="text-2xl">{t("acceptInvite.title")}</CardTitle>
              <CardDescription>{t("acceptInvite.enterCode")}</CardDescription>
            </CardHeader>
            <CardContent>
              <form onSubmit={handleVerifyCode} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="code">{t("invitations.code")}</Label>
                  <Input
                    id="code"
                    value={code}
                    onChange={(e) => { setCode(e.target.value.toUpperCase()); }}
                    placeholder={t("acceptInvite.codePlaceholder")}
                    maxLength={8}
                    className="text-center text-lg tracking-widest font-mono"
                    dir="ltr"
                  />
                  {codeError && (
                    <p className="text-sm text-destructive flex items-center gap-1">
                      <AlertCircle className="h-4 w-4" />
                      {codeError}
                    </p>
                  )}
                </div>
                <Button type="submit" className="w-full" disabled={code.length < 8 || isVerifying}>
                  {isVerifying ? <Loader2 className="h-4 w-4 animate-spin me-2" /> : null}
                  {t("acceptInvite.verifyCode")}
                </Button>
              </form>
              <div className="mt-4 text-center text-sm">
                <button type="button" onClick={goToLogin} className="text-primary hover:underline">
                  {t("auth.hasAccount")} {t("auth.login")}
                </button>
              </div>
            </CardContent>
          </Card>
        )}

        {step === "signup" && invitation && (
          <Card className="w-full max-w-md">
            <CardHeader className="text-center">
              <CardTitle className="text-2xl">{t("acceptInvite.createAccount")}</CardTitle>
              <CardDescription>{invitation.tenants?.name || t("acceptInvite.title")}</CardDescription>
            </CardHeader>
            <CardContent>
              <form onSubmit={onSubmitSignup} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="email">{t("auth.email")}</Label>
                  <Input id="email" type="email" value={invitation.email} disabled className="bg-muted" dir="ltr" />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="fullName">{t("employees.name")}</Label>
                  <Input id="fullName" value={fullName} onChange={(e) => setFullName(e.target.value)} placeholder={t("profile.fullNamePlaceholder")} required />
                  {errors.fullName && <p className="text-sm text-destructive">{errors.fullName}</p>}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="password">{t("auth.password")}</Label>
                  <Input id="password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
                  {errors.password && <p className="text-sm text-destructive">{errors.password}</p>}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="confirmPassword">{t("auth.confirmPassword")}</Label>
                  <Input id="confirmPassword" type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required />
                  {errors.confirmPassword && <p className="text-sm text-destructive">{errors.confirmPassword}</p>}
                </div>
                <Button type="submit" className="w-full" disabled={isSubmitting}>
                  {isSubmitting ? <Loader2 className="h-4 w-4 animate-spin me-2" /> : null}
                  {t("acceptInvite.createAccount")}
                </Button>
              </form>
            </CardContent>
          </Card>
        )}

        {step === "success" && (
          <Card className="w-full max-w-md">
            <CardContent className="pt-6 text-center space-y-4">
              <CheckCircle className="h-16 w-16 text-primary mx-auto" />
              <h2 className="text-2xl font-bold">{t("acceptInvite.accountCreated")}</h2>
              <p className="text-muted-foreground">{t("acceptInvite.verifyEmailNote")}</p>
              <Button onClick={goToLogin} className="w-full">{t("auth.login")}</Button>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Switch } from '@/shared/components/ui/switch';
import { Label } from '@/shared/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/shared/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/shared/components/ui/table';
import { useEmergencyContacts, type EmergencyContact } from '@/features/crisis/hooks/crisis/useCrisisSupport';
import { useProfile } from '@/features/auth/hooks/auth/useProfile';
import { Plus, Trash2, Edit } from 'lucide-react';
import { toast } from 'sonner';

export default function EmergencyContactsTab() {
  const { t } = useTranslation();
  const { profile } = useProfile();
  const tenantId = profile?.tenant_id;
  const { contacts, isPending, createContact, updateContact, deleteContact } = useEmergencyContacts();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editing, setEditing] = useState<EmergencyContact | null>(null);
  const [form, setForm] = useState({ title: '', phone: '', description: '', available_24_7: false, country: 'SA' });

  const openCreate = () => {
    setEditing(null);
    setForm({ title: '', phone: '', description: '', available_24_7: false, country: 'SA' });
    setDialogOpen(true);
  };

  const openEdit = (c: EmergencyContact) => {
    setEditing(c);
    setForm({ title: c.title, phone: c.phone || '', description: c.description || '', available_24_7: c.available_24_7, country: c.country });
    setDialogOpen(true);
  };

  const handleSave = async () => {
    if (!form.title.trim()) {
      toast.error(t('crisisSupport.admin.nameRequired'));
      return;
    }

    try {
      if (editing) {
        await updateContact.mutateAsync({ id: editing.id, ...form });
      } else {
        if (!tenantId) {
          toast.error(t('crisisSupport.admin.tenantRequired'));
          return;
        }
        await createContact.mutateAsync({ tenant_id: tenantId, ...form } as any);
      }
      toast.success(t('common.success'));
      setDialogOpen(false);
    } catch {
      toast.error(t('common.error'));
    }
  };

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>{t('crisisSupport.admin.emergencyContacts')}</CardTitle>
          <CardDescription>{t('crisisSupport.admin.emergencyContactsDesc')}</CardDescription>
        </div>
        <Button onClick={openCreate} size="sm">
          <Plus className="h-4 w-4 me-1" />
          {t('crisisSupport.admin.addContact')}
        </Button>
      </CardHeader>
      <CardContent>
        {isPending ? (
          <p className="text-muted-foreground">{t('common.loading')}</p>
        ) : contacts.length === 0 ? (
          <p className="text-muted-foreground text-center py-8">{t('crisisSupport.admin.noContacts')}</p>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t('crisisSupport.admin.contactTitle')}</TableHead>
                <TableHead>{t('crisisSupport.admin.contactPhone')}</TableHead>
                <TableHead>{t('crisisSupport.admin.availability')}</TableHead>
                <TableHead>{t('common.actions')}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {contacts.map(c => (
                <TableRow key={c.id}>
                  <TableCell className="font-medium">{c.title}</TableCell>
                  <TableCell>{c.phone || '—'}</TableCell>
                  <TableCell>
                    <Badge variant={c.available_24_7 ? 'default' : 'secondary'}>{c.available_24_7 ? '24/7' : t('crisisSupport.admin.limited')}</Badge>
                  </TableCell>
                  <TableCell>
                    <div className="flex gap-1">
                      <Button variant="ghost" size="icon" onClick={() => openEdit(c)}>
                        <Edit className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon" onClick={() => deleteContact.mutate(c.id)}>
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editing ? t('crisisSupport.admin.editContact') : t('crisisSupport.admin.addContact')}</DialogTitle>
            <DialogDescription>{t('crisisSupport.admin.contactFormDesc')}</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>{t('crisisSupport.admin.contactTitle')}</Label>
              <Input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.contactPhone')}</Label>
              <Input value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.contactDescription')}</Label>
              <Textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
            </div>
            <div className="flex items-center justify-between">
              <Label>{t('crisisSupport.admin.available247')}</Label>
              <Switch checked={form.available_24_7} onCheckedChange={v => setForm(f => ({ ...f, available_24_7: v }))} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>{t('common.cancel')}</Button>
            <Button onClick={handleSave}>{t('common.save')}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { useSessionScheduling, BookableSlot } from '@/features/crisis/hooks/crisis/useSessionScheduling';
import { Calendar, Clock, Loader2, Check, ChevronLeft, ChevronRight } from 'lucide-react';
import { format, addDays, startOfDay } from 'date-fns';
import { toast } from 'sonner';

interface Props {
  firstAiderId: string;
  tenantId: string;
  caseId?: string;
  displayName: string;
  communicationChannel: string;
  onBooked?: () => void;
  onCancel?: () => void;
}

export default function EmployeeBookingWidget({ firstAiderId, tenantId, caseId, displayName, communicationChannel, onBooked, onCancel }: Props) {
  const { t } = useTranslation();
  const { getAvailableSlots, bookSession } = useSessionScheduling();

  const [slots, setSlots] = useState<BookableSlot[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedSlot, setSelectedSlot] = useState<BookableSlot | null>(null);
  const [booking, setBooking] = useState(false);
  const [weekOffset, setWeekOffset] = useState(0);
  const [dayIndex, setDayIndex] = useState(0);

  const today = startOfDay(new Date());
  const weekStart = addDays(today, weekOffset * 7);
  const weekEnd = addDays(weekStart, 6);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    getAvailableSlots(
      firstAiderId,
      format(weekStart, 'yyyy-MM-dd'),
      format(weekEnd, 'yyyy-MM-dd'),
      tenantId
    ).then(result => {
      if (!cancelled) {
        setSlots(result);
        setLoading(false);
        setDayIndex(0);
      }
    }).catch(() => {
      if (!cancelled) setLoading(false);
    });
    return () => { cancelled = true; };
  }, [firstAiderId, weekOffset]);

  // Group slots by date
  const slotsByDate = slots.reduce<Record<string, BookableSlot[]>>((acc, slot) => {
    if (!acc[slot.date]) acc[slot.date] = [];
    acc[slot.date].push(slot);
    return acc;
  }, {});

  const sortedDates = Object.keys(slotsByDate).sort();
  const currentDate = sortedDates[dayIndex] || null;
  const currentSlots = currentDate ? slotsByDate[currentDate] : [];

  const handleBook = async () => {
    if (!selectedSlot) return;
    setBooking(true);
    try {
      await bookSession.mutateAsync({
        tenant_id: tenantId,
        first_aider_id: firstAiderId,
        case_id: caseId,
        date: selectedSlot.date,
        start_time: selectedSlot.start,
        end_time: selectedSlot.end,
        communication_channel: communicationChannel,
      });
      toast.success(t('crisisSupport.scheduling.booked'));
      onBooked?.();
    } catch {
      toast.error(t('common.error'));
    } finally {
      setBooking(false);
    }
  };

  const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;

  return (
    <Card className="glass-card border-0 rounded-xl">
      <CardHeader>
        <CardTitle className="text-lg flex items-center gap-2">
          <Calendar className="h-5 w-5 text-primary" />
          {t('crisisSupport.scheduling.bookSession')}
        </CardTitle>
        <CardDescription>
          {t('crisisSupport.scheduling.bookWithName', { name: displayName })}
          <span className="block text-xs mt-1">🌐 {timezone}</span>
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {loading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          </div>
        ) : sortedDates.length === 0 ? (
          <div className="text-center py-6 space-y-2">
            <p className="text-sm text-muted-foreground">{t('crisisSupport.scheduling.noSlots')}</p>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.scheduling.tryNextWeek')}</p>
            <div className="flex justify-center gap-2 pt-2">
              <Button variant="outline" size="sm" onClick={() => setWeekOffset(Math.max(0, weekOffset - 1))} disabled={weekOffset === 0}>
                <ChevronLeft className="h-4 w-4 rtl:rotate-180" />
                {t('common.previous', 'Previous Week')}
              </Button>
              <Button variant="outline" size="sm" onClick={() => { setWeekOffset(weekOffset + 1); }} disabled={weekOffset >= 3}>
                {t('common.next', 'Next Week')}
                <ChevronRight className="h-4 w-4 rtl:rotate-180" />
              </Button>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            {/* Day navigation */}
            <div className="flex items-center justify-between">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  if (dayIndex > 0) {
                    setDayIndex(dayIndex - 1);
                  } else if (weekOffset > 0) {
                    setWeekOffset(weekOffset - 1);
                    // dayIndex will reset to 0 via useEffect
                  }
                }}
                disabled={dayIndex === 0 && weekOffset === 0}
              >
                <ChevronLeft className="h-4 w-4 rtl:rotate-180" />
              </Button>
              <div className="text-center">
                <p className="text-sm font-semibold">
                  {currentDate && format(new Date(currentDate + 'T12:00:00'), 'EEEE, MMM d')}
                </p>
                <p className="text-xs text-muted-foreground">
                  {currentSlots.length} {t('crisisSupport.scheduling.slotsAvailable', 'slots available')}
                </p>
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  if (dayIndex < sortedDates.length - 1) {
                    setDayIndex(dayIndex + 1);
                  } else if (weekOffset < 3) {
                    setWeekOffset(weekOffset + 1);
                    // dayIndex will reset to 0 via useEffect
                  }
                }}
                disabled={dayIndex >= sortedDates.length - 1 && weekOffset >= 3}
              >
                <ChevronRight className="h-4 w-4 rtl:rotate-180" />
              </Button>
            </div>

            {/* Time slots grid */}
            <div className="flex flex-wrap gap-2">
              {currentSlots.map((slot, idx) => {
                const isSelected = selectedSlot?.date === slot.date && selectedSlot?.start === slot.start;
                return (
                  <button
                    key={idx}
                    onClick={() => setSelectedSlot(isSelected ? null : slot)}
                    className={`flex items-center gap-1.5 px-3 py-2 rounded-xl border text-sm transition-colors ${
                      isSelected
                        ? 'border-primary bg-primary/10 text-primary font-medium'
                        : 'border-border bg-background text-foreground hover:bg-muted'
                    }`}
                  >
                    <Clock className="h-3 w-3" />
                    {slot.start} – {slot.end}
                    {isSelected && <Check className="h-3 w-3" />}
                  </button>
                );
              })}
            </div>

            {/* Day dots indicator */}
            <div className="flex justify-center gap-1">
              {sortedDates.map((_, i) => (
                <button
                  key={i}
                  onClick={() => setDayIndex(i)}
                  className={`h-1.5 rounded-full transition-all ${
                    i === dayIndex ? 'w-4 bg-primary' : 'w-1.5 bg-muted-foreground/30'
                  }`}
                />
              ))}
            </div>
          </div>
        )}

        {/* Confirmation */}
        {selectedSlot && (
          <div className="rounded-xl border border-primary/20 bg-primary/5 p-4 space-y-2">
            <p className="text-sm font-medium">{t('crisisSupport.scheduling.confirmBooking')}</p>
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Calendar className="h-4 w-4" />
              {format(new Date(selectedSlot.date + 'T12:00:00'), 'EEEE, MMMM d, yyyy')}
            </div>
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Clock className="h-4 w-4" />
              {selectedSlot.start} – {selectedSlot.end}
            </div>
            <Badge variant="secondary" className="text-xs">{communicationChannel}</Badge>
          </div>
        )}

        {/* Actions */}
        <div className="flex gap-2">
          {onCancel && (
            <Button variant="outline" onClick={onCancel} className="flex-1">
              {t('common.cancel')}
            </Button>
          )}
          <Button onClick={handleBook} disabled={!selectedSlot || booking} className="flex-1">
            {booking ? <Loader2 className="h-4 w-4 animate-spin me-1" /> : null}
            {t('crisisSupport.scheduling.confirmBook')}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Switch } from '@/shared/components/ui/switch';
import { Badge } from '@/shared/components/ui/badge';
import { Slider } from '@/shared/components/ui/slider';
import { useFirstAiderSchedule } from '@/features/crisis/hooks/crisis/useCrisisSupport';
import { toast } from 'sonner';
import { Clock, Calendar, Shield, AlertTriangle } from 'lucide-react';

const DAY_KEYS = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'] as const;

const DEFAULT_WEEKLY_RULES: Record<string, { from: string; to: string }[]> = {
  sun: [{ from: '09:00', to: '17:00' }],
  mon: [{ from: '09:00', to: '17:00' }],
  tue: [{ from: '09:00', to: '17:00' }],
  wed: [{ from: '09:00', to: '17:00' }],
  thu: [{ from: '09:00', to: '17:00' }],
  fri: [],
  sat: [],
};

interface Props {
  firstAiderId: string;
  tenantId: string;
  availabilityConfig?: Record<string, any> | null;
  onConfigUpdate?: (config: Record<string, any>) => void;
}

export default function FirstAiderAvailabilityManager({ firstAiderId, tenantId, availabilityConfig, onConfigUpdate }: Props) {
  const { t } = useTranslation();
  const { schedule, upsertSchedule } = useFirstAiderSchedule(firstAiderId);

  const [rules, setRules] = useState<Record<string, { from: string; to: string }[]>>(DEFAULT_WEEKLY_RULES);
  const [sla, setSla] = useState(60);
  const [isEnabled, setIsEnabled] = useState(true);
  const [tempUnavailable, setTempUnavailable] = useState(false);
  const [maxDailySessions, setMaxDailySessions] = useState(6);
  const [minNoticeHours, setMinNoticeHours] = useState(4);
  const [advanceBookingDays, setAdvanceBookingDays] = useState(14);
  const [emergencyOverride, setEmergencyOverride] = useState(true);

  useEffect(() => {
    if (schedule) {
      setRules(schedule.weekly_rules || DEFAULT_WEEKLY_RULES);
      setSla(schedule.response_sla_minutes);
      setIsEnabled(schedule.is_enabled);
      setTempUnavailable(schedule.temp_unavailable);
    }
    if (availabilityConfig) {
      setMaxDailySessions(availabilityConfig.max_daily_sessions ?? 6);
      setMinNoticeHours(availabilityConfig.min_notice_hours ?? 4);
      setAdvanceBookingDays(availabilityConfig.advance_booking_days ?? 14);
      setEmergencyOverride(availabilityConfig.emergency_override ?? true);
    }
  }, [schedule, availabilityConfig]);

  const handleSave = async () => {
    try {
      await upsertSchedule.mutateAsync({
        first_aider_id: firstAiderId,
        tenant_id: tenantId,
        weekly_rules: rules as any,
        response_sla_minutes: sla,
        is_enabled: isEnabled,
        temp_unavailable: tempUnavailable,
      });

      const config = { max_daily_sessions: maxDailySessions, min_notice_hours: minNoticeHours, advance_booking_days: advanceBookingDays, emergency_override: emergencyOverride };
      onConfigUpdate?.(config);

      toast.success(t('common.success'));
    } catch {
      toast.error(t('common.error'));
    }
  };

  const toggleDay = (day: string) => {
    const newRules = { ...rules };
    if ((newRules[day] || []).length > 0) {
      newRules[day] = [];
    } else {
      newRules[day] = [{ from: '09:00', to: '17:00' }];
    }
    setRules(newRules);
  };

  const addSlot = (day: string) => {
    const newRules = { ...rules };
    const existing = newRules[day] || [];
    const lastEnd = existing.length > 0 ? existing[existing.length - 1].to : '09:00';
    newRules[day] = [...existing, { from: lastEnd, to: '17:00' }];
    setRules(newRules);
  };

  const removeSlot = (day: string, idx: number) => {
    const newRules = { ...rules };
    newRules[day] = newRules[day].filter((_, i) => i !== idx);
    setRules(newRules);
  };

  const updateSlot = (day: string, idx: number, field: 'from' | 'to', value: string) => {
    const newRules = { ...rules };
    newRules[day] = [...newRules[day]];
    newRules[day][idx] = { ...newRules[day][idx], [field]: value };
    setRules(newRules);
  };

  return (
    <div className="space-y-6">
      {/* Status & Quick Controls */}
      <Card className="glass-card border-0 rounded-xl">
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="bg-primary/10 rounded-lg p-2"><Calendar className="h-5 w-5 text-primary" /></div>
              <div>
                <CardTitle className="text-lg">{t('crisisSupport.scheduling.availability')}</CardTitle>
                <CardDescription>{t('crisisSupport.scheduling.availabilityDesc')}</CardDescription>
              </div>
            </div>
            <Badge variant={isEnabled && !tempUnavailable ? 'default' : 'secondary'}>
              {tempUnavailable ? t('crisisSupport.firstAider.tempUnavailable') : isEnabled ? t('crisisSupport.status.online') : t('crisisSupport.status.offline')}
            </Badge>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <Label>{t('crisisSupport.scheduling.enabled')}</Label>
            <Switch checked={isEnabled} onCheckedChange={setIsEnabled} />
          </div>
          <div className="flex items-center justify-between">
            <div>
              <Label>{t('crisisSupport.firstAider.tempUnavailable')}</Label>
              <p className="text-xs text-muted-foreground">{t('crisisSupport.scheduling.tempUnavailableDesc')}</p>
            </div>
            <Switch checked={tempUnavailable} onCheckedChange={setTempUnavailable} />
          </div>
          <div className="flex items-center justify-between">
            <div>
              <Label>{t('crisisSupport.scheduling.emergencyOverride')}</Label>
              <p className="text-xs text-muted-foreground">{t('crisisSupport.scheduling.emergencyOverrideDesc')}</p>
            </div>
            <Switch checked={emergencyOverride} onCheckedChange={setEmergencyOverride} />
          </div>
        </CardContent>
      </Card>

      {/* Weekly Schedule Grid */}
      <Card className="glass-card border-0 rounded-xl">
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Clock className="h-4 w-4" />
            {t('crisisSupport.scheduling.weeklySchedule')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {DAY_KEYS.map(day => {
            const slots = rules[day] || [];
            const isOff = slots.length === 0;
            return (
              <div key={day} className="flex items-start gap-3 py-2 border-b border-border last:border-0">
                <button
                  onClick={() => toggleDay(day)}
                  className={`w-12 text-sm font-medium capitalize shrink-0 mt-1 ${isOff ? 'text-muted-foreground' : 'text-foreground'}`}
                >
                  {t(`orgDashboard.days.${day}`)}
                </button>
                <div className="flex-1">
                  {isOff ? (
                    <span className="text-sm text-muted-foreground italic">{t('crisisSupport.admin.dayOff')}</span>
                  ) : (
                    <div className="space-y-2">
                      {slots.map((slot, i) => (
                        <div key={i} className="flex items-center gap-2">
                          <Input type="time" value={slot.from} className="w-28" onChange={e => updateSlot(day, i, 'from', e.target.value)} />
                          <span className="text-muted-foreground">–</span>
                          <Input type="time" value={slot.to} className="w-28" onChange={e => updateSlot(day, i, 'to', e.target.value)} />
                          {slots.length > 1 && (
                            <Button variant="ghost" size="sm" onClick={() => removeSlot(day, i)} className="text-xs text-destructive">✕</Button>
                          )}
                        </div>
                      ))}
                      <Button variant="ghost" size="sm" onClick={() => addSlot(day)} className="text-xs">
                        + {t('crisisSupport.admin.addSlot')}
                      </Button>
                    </div>
                  )}
                </div>
                <Button variant="ghost" size="sm" onClick={() => toggleDay(day)} className="text-xs shrink-0">
                  {isOff ? t('crisisSupport.admin.addSlot') : t('crisisSupport.admin.markOff')}
                </Button>
              </div>
            );
          })}
        </CardContent>
      </Card>

      {/* Session Limits & SLA */}
      <Card className="glass-card border-0 rounded-xl">
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Shield className="h-4 w-4" />
            {t('crisisSupport.scheduling.sessionLimits')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-5">
          <div className="space-y-2">
            <Label>{t('crisisSupport.scheduling.maxDailySessions')}</Label>
            <div className="flex items-center gap-3">
              <Slider value={[maxDailySessions]} onValueChange={v => setMaxDailySessions(v[0])} min={1} max={12} step={1} className="flex-1" />
              <span className="text-sm font-medium w-8 text-end">{maxDailySessions}</span>
            </div>
          </div>

          <div className="space-y-2">
            <Label>{t('crisisSupport.scheduling.minNotice')}</Label>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.scheduling.minNoticeDesc')}</p>
            <div className="flex items-center gap-3">
              <Slider value={[minNoticeHours]} onValueChange={v => setMinNoticeHours(v[0])} min={0} max={24} step={1} className="flex-1" />
              <span className="text-sm font-medium w-10 text-end">{minNoticeHours}h</span>
            </div>
          </div>

          <div className="space-y-2">
            <Label>{t('crisisSupport.scheduling.advanceBooking')}</Label>
            <div className="flex items-center gap-3">
              <Slider value={[advanceBookingDays]} onValueChange={v => setAdvanceBookingDays(v[0])} min={1} max={30} step={1} className="flex-1" />
              <span className="text-sm font-medium w-10 text-end">{advanceBookingDays}d</span>
            </div>
          </div>

          <div>
            <Label>{t('crisisSupport.admin.slaMinutes')}</Label>
            <Input type="number" min={5} max={480} value={sla} onChange={e => setSla(parseInt(e.target.value) || 60)} className="w-32 mt-1" />
          </div>
        </CardContent>
      </Card>

      <Button onClick={handleSave} className="w-full">{t('common.save')}</Button>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Switch } from '@/shared/components/ui/switch';
import { Label } from '@/shared/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/shared/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/shared/components/ui/table';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { useFirstAiders, type FirstAider } from '@/features/crisis/hooks/crisis/useCrisisSupport';
import { useProfile } from '@/features/auth/hooks/auth/useProfile';
import { useEmployees } from '@/hooks/org/useEmployees';
import { Plus, Trash2, Edit } from 'lucide-react';
import { toast } from 'sonner';

export default function FirstAidersTab() {
  const { t } = useTranslation();
  const { profile } = useProfile();
  const tenantId = profile?.tenant_id;
  const { firstAiders, isPending, createFirstAider, updateFirstAider, deleteFirstAider } = useFirstAiders();
  const { employees } = useEmployees({ status: 'active' });
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingFA, setEditingFA] = useState<FirstAider | null>(null);
  const [form, setForm] = useState({
    user_id: '',
    display_name: '',
    department: '',
    role_title: '',
    bio: '',
    max_active_cases: 3,
    allow_anonymous_requests: true,
  });

  // Filter out employees who are already first aiders
  const availableEmployees = useMemo(() => {
    const existingUserIds = new Set(firstAiders.map(fa => fa.user_id));
    return employees.filter(emp => emp.user_id && !existingUserIds.has(emp.user_id));
  }, [employees, firstAiders]);

  const openCreate = () => {
    setEditingFA(null);
    setForm({ user_id: '', display_name: '', department: '', role_title: '', bio: '', max_active_cases: 3, allow_anonymous_requests: true });
    setDialogOpen(true);
  };

  const openEdit = (fa: FirstAider) => {
    setEditingFA(fa);
    setForm({
      user_id: fa.user_id,
      display_name: fa.display_name,
      department: fa.department || '',
      role_title: fa.role_title || '',
      bio: fa.bio || '',
      max_active_cases: fa.max_active_cases,
      allow_anonymous_requests: fa.allow_anonymous_requests,
    });
    setDialogOpen(true);
  };

  const handleEmployeeSelect = (employeeId: string) => {
    const emp = employees.find(e => e.id === employeeId);
    if (emp) {
      setForm(f => ({
        ...f,
        user_id: emp.user_id || '',
        display_name: emp.full_name,
        department: emp.department || '',
        role_title: emp.role_title || '',
      }));
    }
  };

  const handleSave = async () => {
    if (!form.display_name.trim()) {
      toast.error(t('crisisSupport.admin.nameRequired'));
      return;
    }

    try {
      if (editingFA) {
        await updateFirstAider.mutateAsync({
          id: editingFA.id,
          display_name: form.display_name,
          department: form.department || null,
          role_title: form.role_title || null,
          bio: form.bio || null,
          max_active_cases: form.max_active_cases,
          allow_anonymous_requests: form.allow_anonymous_requests,
        } as any);
      } else {
        if (!tenantId) {
          toast.error(t('crisisSupport.admin.tenantRequired'));
          return;
        }
        if (!form.user_id) {
          toast.error(t('crisisSupport.admin.selectEmployee'));
          return;
        }
        await createFirstAider.mutateAsync({
          tenant_id: tenantId,
          user_id: form.user_id,
          display_name: form.display_name,
          department: form.department || null,
          role_title: form.role_title || null,
          bio: form.bio || null,
          max_active_cases: form.max_active_cases,
          allow_anonymous_requests: form.allow_anonymous_requests,
        } as any);
      }
      toast.success(t('common.success'));
      setDialogOpen(false);
    } catch {
      toast.error(t('common.error'));
    }
  };

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <div>
          <CardTitle>{t('crisisSupport.admin.firstAiders')}</CardTitle>
          <CardDescription>{t('crisisSupport.admin.firstAidersDesc')}</CardDescription>
        </div>
        <Button onClick={openCreate} size="sm">
          <Plus className="h-4 w-4 me-1" />
          {t('crisisSupport.admin.addFirstAider')}
        </Button>
      </CardHeader>
      <CardContent>
        {isPending ? (
          <p className="text-muted-foreground">{t('common.loading')}</p>
        ) : firstAiders.length === 0 ? (
          <p className="text-muted-foreground text-center py-8">{t('crisisSupport.admin.noFirstAiders')}</p>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t('crisisSupport.admin.name')}</TableHead>
                <TableHead>{t('crisisSupport.admin.department')}</TableHead>
                <TableHead>{t('crisisSupport.admin.statusLabel')}</TableHead>
                <TableHead>{t('crisisSupport.admin.activeCases')}</TableHead>
                <TableHead>{t('common.actions')}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {firstAiders.map(fa => (
                <TableRow key={fa.id}>
                  <TableCell className="font-medium">{fa.display_name}</TableCell>
                  <TableCell>{fa.department || '—'}</TableCell>
                  <TableCell>
                    {(() => {
                      const statusMap: Record<string, { emoji: string; key: string; variant: 'default' | 'secondary' | 'destructive' | 'outline' }> = {
                        available: { emoji: '🟢', key: 'crisisSupport.status.available', variant: 'default' },
                        busy: { emoji: '🟡', key: 'crisisSupport.status.busy', variant: 'secondary' },
                        outside_hours: { emoji: '🔵', key: 'crisisSupport.status.outside_hours', variant: 'outline' },
                        temporarily_unavailable: { emoji: '🟠', key: 'crisisSupport.status.temporarily_unavailable', variant: 'destructive' },
                        offline: { emoji: '⚫', key: 'crisisSupport.status.offline', variant: 'secondary' },
                      };
                      const info = statusMap[fa.statusLabel] || statusMap.offline;
                      return (
                        <Badge variant={info.variant} className="text-xs">
                          {info.emoji} {t(info.key)}
                        </Badge>
                      );
                    })()}
                  </TableCell>
                  <TableCell>{fa.max_active_cases}</TableCell>
                  <TableCell>
                    <div className="flex gap-1">
                      <Button variant="ghost" size="icon" onClick={() => openEdit(fa)}>
                        <Edit className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon" onClick={() => deleteFirstAider.mutate(fa.id)}>
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </CardContent>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingFA ? t('crisisSupport.admin.editFirstAider') : t('crisisSupport.admin.addFirstAider')}</DialogTitle>
            <DialogDescription>{t('crisisSupport.admin.firstAiderFormDesc')}</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {/* Employee picker — only for create */}
            {!editingFA && (
              <div>
                <Label>{t('crisisSupport.admin.selectEmployee')}</Label>
                <Select onValueChange={handleEmployeeSelect}>
                  <SelectTrigger>
                    <SelectValue placeholder={t('crisisSupport.admin.selectEmployee')} />
                  </SelectTrigger>
                  <SelectContent>
                    {availableEmployees.length === 0 ? (
                      <SelectItem value="__none" disabled>{t('crisisSupport.admin.noAvailableEmployees')}</SelectItem>
                    ) : (
                      availableEmployees.map(emp => (
                        <SelectItem key={emp.id} value={emp.id}>
                          {emp.full_name} {emp.department ? `(${emp.department})` : ''}
                        </SelectItem>
                      ))
                    )}
                  </SelectContent>
                </Select>
              </div>
            )}
            <div>
              <Label>{t('crisisSupport.admin.name')}</Label>
              <Input value={form.display_name} onChange={e => setForm(f => ({ ...f, display_name: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.department')}</Label>
              <Input value={form.department} onChange={e => setForm(f => ({ ...f, department: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.roleTitle')}</Label>
              <Input value={form.role_title} onChange={e => setForm(f => ({ ...f, role_title: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.bio')}</Label>
              <Textarea value={form.bio} onChange={e => setForm(f => ({ ...f, bio: e.target.value }))} />
            </div>
            <div>
              <Label>{t('crisisSupport.admin.maxCases')}</Label>
              <Input type="number" min={1} max={10} value={form.max_active_cases} onChange={e => setForm(f => ({ ...f, max_active_cases: parseInt(e.target.value) || 3 }))} />
            </div>
            <div className="flex items-center justify-between">
              <Label>{t('crisisSupport.admin.allowAnonymous')}</Label>
              <Switch checked={form.allow_anonymous_requests} onCheckedChange={v => setForm(f => ({ ...f, allow_anonymous_requests: v }))} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>{t('common.cancel')}</Button>
            <Button onClick={handleSave}>{t('common.save')}</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </Card>
  );
}

import { useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/shared/components/ui/dialog';
import { Form, FormField, FormItem, FormLabel, FormControl, FormMessage } from '@/shared/components/ui/form';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Button } from '@/shared/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import type { RiskMapping } from '@/features/crisis/hooks/crisis/useRiskMappings';

const schema = z.object({
  intent: z.string().min(1, 'Intent is required'),
  risk_level: z.enum(['high', 'moderate', 'low']),
  action_description: z.string().optional(),
});

type FormValues = z.infer<typeof schema>;

interface Props {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  mapping?: RiskMapping | null;
  onSubmit: (values: { intent: string; risk_level: string; action_description?: string }) => void;
