import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';

export interface SecureAttachment {
  id: string;
  tenant_id: string;
  context: string;
  context_id: string | null;
  uploader_user_id: string;
  filename: string;
  mime_type: string;
  size_bytes: number;
  storage_path: string;
  expires_at: string;
  watermark_text: string | null;
  access_log: any;
  created_at: string;
  deleted_at: string | null;
}

export function useSecureAttachments(caseId?: string) {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data: attachments = [], isPending } = useQuery({
    queryKey: ['mh-secure-attachments', caseId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('mh_secure_attachments')
        .select('*')
        .eq('context', 'crisis_case')
        .eq('context_id', caseId!)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []) as unknown as SecureAttachment[];
    },
    enabled: !!caseId && !!user?.id,
  });

  const uploadAttachment = useMutation({
    mutationFn: async ({
      file, caseId: cId, tenantId, expiryDays = 30,
    }: {
      file: File;
      caseId: string;
      tenantId: string;
      expiryDays?: number;
    }) => {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('case_id', cId);
      formData.append('tenant_id', tenantId);
      formData.append('expiry_days', String(expiryDays));

      const { data, error } = await supabase.functions.invoke('secure-upload?action=upload', {
        body: formData,
      });

      if (error) throw error;
      return data.attachment as SecureAttachment;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['mh-secure-attachments', caseId] });
    },
  });

  const viewAttachment = async (attachmentId: string) => {
    const { data, error } = await supabase.functions.invoke('secure-upload?action=view', {
      body: { attachment_id: attachmentId },
    });
    if (error) throw error;
    return data as {
      url: string;
      watermark: string;
      expires_at: string;
      file_type: string;
      file_name: string;
    };
  };

  const revokeAttachment = useMutation({
    mutationFn: async (attachmentId: string) => {
      const { error } = await supabase.functions.invoke('secure-upload?action=revoke', {
        body: { attachment_id: attachmentId },
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['mh-secure-attachments', caseId] });
    },
  });

  return {
    attachments,
    isPending,
    uploadAttachment,
    viewAttachment,
    revokeAttachment,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { createCrisisNotification } from './useCrisisNotifications';

// ─── Types ───────────────────────────────────────────────────────────
export interface SupportSession {
  id: string;
  tenant_id: string;
  case_id: string | null;
  first_aider_id: string;
  requester_user_id: string;
  scheduled_start: string | null;
  scheduled_end: string | null;
  actual_start: string | null;
  actual_end: string | null;
  channel: string;
  session_notes: string | null;
  outcome: string | null;
  status: string;
  created_at: string;
  deleted_at: string | null;
}

export interface AvailabilitySlot {
  start: string; // HH:mm
  end: string;
  is_available: boolean;
  source: string;
}

export interface DailyAvailability {
  id: string;
  first_aider_id: string;
  date: string;
  time_slots: AvailabilitySlot[];
}

export interface BookableSlot {
  date: string;
  start: string;
  end: string;
}

// ─── Constants ───────────────────────────────────────────────────────
const SESSION_DURATION_MINUTES = 45;
const BUFFER_MINUTES = 15;
const DAY_KEYS = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'] as const;

// ─── Hook: Support Sessions ─────────────────────────────────────────
export function useSupportSessions(options?: { firstAiderId?: string; requesterUserId?: string }) {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data: sessions = [], isPending } = useQuery({
    queryKey: ['mh-support-sessions', options?.firstAiderId, options?.requesterUserId],
    queryFn: async () => {
      let query = supabase
        .from('mh_support_sessions')
        .select('*')
        .is('deleted_at', null)
        .order('scheduled_start', { ascending: false });

      if (options?.firstAiderId) query = query.eq('first_aider_id', options.firstAiderId);
      if (options?.requesterUserId) query = query.eq('requester_user_id', options.requesterUserId);

      const { data, error } = await query;
      if (error) throw error;
      return (data || []) as SupportSession[];
    },
    enabled: !!user?.id,
  });

  return { sessions, isPending };
}

// ─── Hook: Session Scheduling ────────────────────────────────────────
export function useSessionScheduling() {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  // Get available slots for a first aider over a date range
  const getAvailableSlots = async (
    firstAiderId: string,
    startDate: string,
    endDate: string,
    tenantId: string
  ): Promise<BookableSlot[]> => {
    // 1. Get the first aider's schedule (weekly rules)
    const { data: schedule } = await supabase
      .from('mh_first_aider_schedule')
      .select('*')
      .eq('first_aider_id', firstAiderId)
      .maybeSingle();

    if (!schedule || !schedule.is_enabled || schedule.temp_unavailable) return [];

    // 2. Get existing booked sessions in the range
    const { data: existingSessions } = await supabase
      .from('mh_support_sessions')
      .select('scheduled_start, scheduled_end')
      .eq('first_aider_id', firstAiderId)
      .is('deleted_at', null)
      .in('status', ['scheduled', 'active'])
      .gte('scheduled_start', `${startDate}T00:00:00`)
      .lte('scheduled_start', `${endDate}T23:59:59`);

    const bookedSlots = (existingSessions || []).map(s => ({
      start: new Date(s.scheduled_start!),
      end: new Date(s.scheduled_end!),
    }));

    // 3. Get any custom availability overrides
    const { data: customAvail } = await supabase
      .from('mh_first_aider_availability')
      .select('*')
      .eq('first_aider_id', firstAiderId)
      .gte('date', startDate)
      .lte('date', endDate);

    const customMap = new Map<string, AvailabilitySlot[]>();
    (customAvail || []).forEach((a: any) => {
      customMap.set(a.date, a.time_slots as AvailabilitySlot[]);
    });

    // 4. Generate bookable slots
    const slots: BookableSlot[] = [];
    const start = new Date(startDate);
    const end = new Date(endDate);
    const now = new Date();

    // Get first aider's availability config for min notice
    const { data: faData } = await supabase
      .from('mh_first_aiders')
      .select('availability_config, max_concurrent_sessions')
      .eq('id', firstAiderId)
      .single();

    const minNoticeHours = (faData?.availability_config as any)?.min_notice_hours ?? 4;
    const maxDailySessions = (faData?.availability_config as any)?.max_daily_sessions ?? 6;
    const earliestBookable = new Date(now.getTime() + minNoticeHours * 60 * 60 * 1000);

    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      const dateStr = d.toISOString().split('T')[0];
      const dayIdx = d.getDay();
      const dayKey = DAY_KEYS[dayIdx];

      // Check custom availability first, fall back to weekly rules
      let daySlots: { from: string; to: string }[];
      if (customMap.has(dateStr)) {
        daySlots = customMap.get(dateStr)!
          .filter(s => s.is_available)
          .map(s => ({ from: s.start, to: s.end }));
      } else {
        daySlots = ((schedule.weekly_rules as any)?.[dayKey] || []) as { from: string; to: string }[];
      }

      // Count existing sessions for this day
      const daySessions = bookedSlots.filter(b => b.start.toISOString().startsWith(dateStr));
      if (daySessions.length >= maxDailySessions) continue;

      // Generate time slots within available windows
      for (const window of daySlots) {
        const [startH, startM] = window.from.split(':').map(Number);
        const [endH, endM] = window.to.split(':').map(Number);

        let slotStart = new Date(d);
        slotStart.setHours(startH, startM, 0, 0);

        const windowEnd = new Date(d);
        windowEnd.setHours(endH, endM, 0, 0);

        while (slotStart.getTime() + SESSION_DURATION_MINUTES * 60000 <= windowEnd.getTime()) {
          const slotEnd = new Date(slotStart.getTime() + SESSION_DURATION_MINUTES * 60000);

          // Check minimum notice
          if (slotStart > earliestBookable) {
            // Check no conflict with existing bookings (including buffer)
            const hasConflict = bookedSlots.some(b => {
              const bufferStart = new Date(b.start.getTime() - BUFFER_MINUTES * 60000);
              const bufferEnd = new Date(b.end.getTime() + BUFFER_MINUTES * 60000);
              return slotStart < bufferEnd && slotEnd > bufferStart;
            });

            if (!hasConflict) {
              slots.push({
                date: dateStr,
                start: `${String(slotStart.getHours()).padStart(2, '0')}:${String(slotStart.getMinutes()).padStart(2, '0')}`,
                end: `${String(slotEnd.getHours()).padStart(2, '0')}:${String(slotEnd.getMinutes()).padStart(2, '0')}`,
              });
            }
          }

          // Move to next slot (session + buffer)
          slotStart = new Date(slotStart.getTime() + (SESSION_DURATION_MINUTES + BUFFER_MINUTES) * 60000);
        }
      }
    }

    return slots;
  };

  // Book a session
  const bookSession = useMutation({
    mutationFn: async (data: {
      tenant_id: string;
      first_aider_id: string;
      case_id?: string;
      date: string;
      start_time: string;
      end_time: string;
      communication_channel: string; // maps to DB column 'channel'
    }) => {
      const scheduledStart = `${data.date}T${data.start_time}:00`;
      const scheduledEnd = `${data.date}T${data.end_time}:00`;

      const { data: session, error } = await supabase
        .from('mh_support_sessions')
        .insert({
          tenant_id: data.tenant_id,
          case_id: data.case_id || null,
          first_aider_id: data.first_aider_id,
          requester_user_id: user!.id,
          scheduled_start: scheduledStart,
          scheduled_end: scheduledEnd,
          channel: data.communication_channel,
          status: 'scheduled',
        } as any)
        .select()
        .single();

      if (error) throw error;

      // If there's a linked case, update it with the session reference
      if (data.case_id) {
        await supabase
          .from('mh_crisis_cases')
          .update({ scheduled_session_id: session.id } as any)
          .eq('id', data.case_id);
      }

      // Notify the first aider
      const { data: fa } = await supabase
        .from('mh_first_aiders')
        .select('user_id')
        .eq('id', data.first_aider_id)
        .single();

      if (fa?.user_id) {
        await createCrisisNotification({
          tenant_id: data.tenant_id,
          user_id: fa.user_id,
          case_id: data.case_id || session.id,
          type: 'session_scheduled',
          title: 'New session booked',
          body: `Session scheduled for ${data.date} at ${data.start_time}`,
        });
      }

      return session as SupportSession;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['mh-support-sessions'] });
      queryClient.invalidateQueries({ queryKey: ['mh-crisis-cases'] });
    },
  });

  // Cancel a session
  const cancelSession = useMutation({
    mutationFn: async ({ sessionId, reason }: { sessionId: string; reason?: string }) => {
      const { data: session } = await supabase
        .from('mh_support_sessions')
        .select('*')
        .eq('id', sessionId)
        .single();

      if (!session) throw new Error('Session not found');

      const { error } = await supabase
        .from('mh_support_sessions')
        .update({ status: 'cancelled', session_notes: reason || null } as any)
        .eq('id', sessionId);

      if (error) throw error;

      // Notify the other party
      const isRequester = session.requester_user_id === user!.id;
      if (isRequester) {
        const { data: fa } = await supabase
          .from('mh_first_aiders')
          .select('user_id')
          .eq('id', session.first_aider_id)
          .single();
        if (fa?.user_id) {
          await createCrisisNotification({
            tenant_id: session.tenant_id,
            user_id: fa.user_id,
            case_id: session.case_id || sessionId,
            type: 'session_cancelled',
            title: 'Session cancelled',
            body: reason || 'The scheduled session has been cancelled.',
          });
        }
      } else {
        await createCrisisNotification({
          tenant_id: session.tenant_id,
          user_id: session.requester_user_id,
          case_id: session.case_id || sessionId,
          type: 'session_cancelled',
          title: 'Session cancelled',
          body: reason || 'The scheduled session has been cancelled by the first aider.',
        });
      }
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['mh-support-sessions'] }),
  });

  // Reschedule a session
  const rescheduleSession = useMutation({
    mutationFn: async (data: { sessionId: string; date: string; start_time: string; end_time: string }) => {
      const scheduledStart = `${data.date}T${data.start_time}:00`;
      const scheduledEnd = `${data.date}T${data.end_time}:00`;

      const { data: session } = await supabase
        .from('mh_support_sessions')
        .select('*')
        .eq('id', data.sessionId)
        .single();

      if (!session) throw new Error('Session not found');

      const { error } = await supabase
        .from('mh_support_sessions')
        .update({
          scheduled_start: scheduledStart,
          scheduled_end: scheduledEnd,
        } as any)
        .eq('id', data.sessionId);

      if (error) throw error;

      // Notify both parties
      const { data: fa } = await supabase
        .from('mh_first_aiders')
        .select('user_id')
        .eq('id', session.first_aider_id)
        .single();

      const notifBody = `Session rescheduled to ${data.date} at ${data.start_time}`;

      if (fa?.user_id && fa.user_id !== user!.id) {
        await createCrisisNotification({
          tenant_id: session.tenant_id,
          user_id: fa.user_id,
          case_id: session.case_id || data.sessionId,
          type: 'session_rescheduled',
          title: 'Session rescheduled',
          body: notifBody,
        });
      }
      if (session.requester_user_id !== user!.id) {
        await createCrisisNotification({
          tenant_id: session.tenant_id,
          user_id: session.requester_user_id,
          case_id: session.case_id || data.sessionId,
          type: 'session_rescheduled',
          title: 'Session rescheduled',
          body: notifBody,
        });
      }
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['mh-support-sessions'] }),
  });

  // Start a session (set actual_start)
  const startSession = useMutation({
    mutationFn: async (sessionId: string) => {
      const { error } = await supabase
        .from('mh_support_sessions')
        .update({ actual_start: new Date().toISOString(), status: 'active' } as any)
        .eq('id', sessionId);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['mh-support-sessions'] }),
  });

  // End a session
  const endSession = useMutation({
    mutationFn: async ({ sessionId, outcome, notes }: { sessionId: string; outcome: string; notes?: string }) => {
      const { error } = await supabase
        .from('mh_support_sessions')
        .update({
          actual_end: new Date().toISOString(),
          status: 'completed',
          outcome,
          session_notes: notes || null,
        } as any)
        .eq('id', sessionId);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['mh-support-sessions'] }),
  });

  return {
    getAvailableSlots,
    bookSession,
    cancelSession,
    rescheduleSession,
    startSession,
    endSession,
  };
}

// ─── Hook: Session Ratings ───────────────────────────────────────────
export function useSessionRating(sessionId?: string) {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data: rating } = useQuery({
    queryKey: ['mh-session-rating', sessionId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('mh_session_ratings')
        .select('*')
        .eq('session_id', sessionId!)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!sessionId && !!user?.id,
  });

  const submitRating = useMutation({
    mutationFn: async (data: { session_id: string; tenant_id: string; rating: number; comment?: string }) => {
      const { error } = await supabase.from('mh_session_ratings').insert({
        session_id: data.session_id,
        tenant_id: data.tenant_id,
        rater_user_id: user!.id,
        rating: data.rating,
        comment: data.comment || null,
      } as any);
      if (error) throw error;

      // Update first aider's average rating
      const { data: session } = await supabase
        .from('mh_support_sessions')
        .select('first_aider_id')
        .eq('id', data.session_id)
        .single();

      if (session?.first_aider_id) {
        const { data: allRatings } = await supabase
          .from('mh_session_ratings')
          .select('rating')
          .eq('session_id', data.session_id);

        // Get all ratings for this first aider's sessions
        const { data: faSessions } = await supabase
          .from('mh_support_sessions')
          .select('id')
          .eq('first_aider_id', session.first_aider_id);

        if (faSessions && faSessions.length > 0) {
          const sessionIds = faSessions.map(s => s.id);
          const { data: faRatings } = await supabase
            .from('mh_session_ratings')
            .select('rating')
            .in('session_id', sessionIds);

          if (faRatings && faRatings.length > 0) {
            const avg = faRatings.reduce((sum, r) => sum + (r as any).rating, 0) / faRatings.length;
            await supabase
              .from('mh_first_aiders')
              .update({ rating: Math.round(avg * 10) / 10 } as any)
              .eq('id', session.first_aider_id);
          }
        }
      }
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['mh-session-rating'] }),
  });

  return { rating, submitRating };
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';

export interface CrisisAnalytics {
  totalCases: number;
  activeCases: number;
  resolvedCases: number;
  escalatedCases: number;
  avgFirstResponseMinutes: number | null;
  avgResolutionHours: number | null;
  riskDistribution: { risk: string; count: number }[];
  intentDistribution: { intent: string; count: number }[];
  monthlyCases: { month: string; count: number }[];
  firstAiderLoad: { name: string; active: number; resolved: number }[];
}

export function useCrisisAnalytics(tenantId?: string) {
  const { user } = useAuth();

  return useQuery({
    queryKey: ['mh-crisis-analytics', tenantId],
    queryFn: async (): Promise<CrisisAnalytics> => {
      // Fetch all cases for tenant
      let query = supabase
        .from('mh_crisis_cases')
        .select('*')
        .order('created_at', { ascending: false });
      if (tenantId) query = query.eq('tenant_id', tenantId);

      const { data: cases = [], error } = await query;
      if (error) throw error;

      // Fetch first aiders for load analysis
      let faQuery = supabase
        .from('mh_first_aiders')
        .select('id, display_name')
        .is('deleted_at', null);
      if (tenantId) faQuery = faQuery.eq('tenant_id', tenantId);
      const { data: aiders = [] } = await faQuery;

      const totalCases = cases.length;
      const activeCases = cases.filter(c => ['active', 'awaiting_user', 'awaiting_first_aider', 'pending_first_aider_acceptance', 'pending_assignment'].includes(c.status)).length;
      const resolvedCases = cases.filter(c => ['resolved', 'closed'].includes(c.status)).length;
      const escalatedCases = cases.filter(c => c.status === 'escalated').length;

      // Avg first response time (cases with first_response_at and created_at)
      const responseTimes = cases
        .filter(c => c.first_response_at && c.created_at)
        .map(c => (new Date(c.first_response_at!).getTime() - new Date(c.created_at).getTime()) / 60000);
      const avgFirstResponseMinutes = responseTimes.length > 0
        ? Math.round(responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length)
        : null;

      // Avg resolution time
      const resolutionTimes = cases
        .filter(c => c.resolved_at && c.created_at)
        .map(c => (new Date(c.resolved_at!).getTime() - new Date(c.created_at).getTime()) / 3600000);
      const avgResolutionHours = resolutionTimes.length > 0
        ? Math.round(resolutionTimes.reduce((a, b) => a + b, 0) / resolutionTimes.length * 10) / 10
        : null;

      // Risk distribution
      const riskMap: Record<string, number> = {};
      cases.forEach(c => { riskMap[c.risk_level] = (riskMap[c.risk_level] || 0) + 1; });
      const riskDistribution = Object.entries(riskMap).map(([risk, count]) => ({ risk, count }));

      // Intent distribution
      const intentMap: Record<string, number> = {};
      cases.forEach(c => { intentMap[c.intent] = (intentMap[c.intent] || 0) + 1; });
      const intentDistribution = Object.entries(intentMap)
        .map(([intent, count]) => ({ intent, count }))
        .sort((a, b) => b.count - a.count);

      // Monthly cases (last 6 months)
      const monthlyCases: { month: string; count: number }[] = [];
      const now = new Date();
      for (let i = 5; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        const monthKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
        const count = cases.filter(c => {
          const cd = new Date(c.created_at);
          return cd.getFullYear() === d.getFullYear() && cd.getMonth() === d.getMonth();
        }).length;
        monthlyCases.push({ month: monthKey, count });
      }

      // First aider load
      const firstAiderLoad = (aiders || []).map((fa: any) => {
        const faCases = cases.filter(c => c.assigned_first_aider_id === fa.id);
        return {
          name: fa.display_name,
          active: faCases.filter(c => ['active', 'awaiting_user', 'awaiting_first_aider', 'pending_first_aider_acceptance'].includes(c.status)).length,
          resolved: faCases.filter(c => ['resolved', 'closed'].includes(c.status)).length,
        };
      });

      return {
        totalCases, activeCases, resolvedCases, escalatedCases,
        avgFirstResponseMinutes, avgResolutionHours,
        riskDistribution, intentDistribution, monthlyCases, firstAiderLoad,
      };
    },
    enabled: !!user?.id,
  });
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { useCrisisCases, useIsFirstAider, useFirstAiderSchedule } from '@/features/crisis/hooks/crisis/useCrisisSupport';
import { useSupportSessions } from '@/features/crisis/hooks/crisis/useSessionScheduling';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { MessageSquare, Clock, Check, X, AlertTriangle, Shield, Star, Calendar, Timer, CircleDot } from 'lucide-react';
import { format, isToday } from 'date-fns';
import { toast } from 'sonner';
import SessionWorkspace from '@/features/crisis/components/SessionWorkspace';

type AiderStatus = 'available' | 'busy' | 'offline';

export default function FirstAiderDashboard() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { isFirstAider, firstAiderId } = useIsFirstAider();
  const { cases, isPending, updateCaseStatus } = useCrisisCases({ role: 'first_aider' });
  const { schedule, upsertSchedule } = useFirstAiderSchedule(firstAiderId || undefined);
  const { sessions } = useSupportSessions(firstAiderId ? { firstAiderId } : undefined);
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('pending');
  const [aiderStatus, setAiderStatus] = useState<AiderStatus>('available');

  if (!isFirstAider) {
    return (
      <div className="space-y-6">
        <Card>
          <CardContent className="py-12 text-center">
            <AlertTriangle className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">{t('crisisSupport.firstAider.notAssigned')}</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  const myCases = cases.filter(c => c.assigned_first_aider_id === firstAiderId);
  const pendingCases = myCases.filter(c => c.status === 'pending_first_aider_acceptance');
  const activeCases = myCases.filter(c => ['active', 'awaiting_user', 'awaiting_first_aider'].includes(c.status));
  const resolvedCases = myCases.filter(c => ['resolved', 'closed'].includes(c.status));

  // Today's sessions
  const todaySessions = sessions.filter(s => {
    if (!s.scheduled_start) return false;
    return isToday(new Date(s.scheduled_start)) && s.status !== 'cancelled';
  });

  // Calculate stats
  const totalSessions = sessions.filter(s => s.status === 'completed').length;
  const avgResponseMin = myCases.length > 0
    ? Math.round(myCases.filter(c => c.first_response_at && c.created_at).reduce((sum, c) => {
        const diff = new Date(c.first_response_at!).getTime() - new Date(c.created_at).getTime();
        return sum + diff / 60000;
      }, 0) / Math.max(myCases.filter(c => c.first_response_at).length, 1))
    : 0;

  const selectedCase = myCases.find(c => c.id === selectedCaseId);

  if (selectedCase) {
    return (
      <SessionWorkspace
        caseId={selectedCase.id}
        tenantId={selectedCase.tenant_id}
        isFirstAider={true}
        onBack={() => setSelectedCaseId(null)}
      />
    );
  }

  const handleStatusChange = async (newStatus: AiderStatus) => {
    setAiderStatus(newStatus);
    if (!schedule || !firstAiderId) return;
    try {
      await upsertSchedule.mutateAsync({
        first_aider_id: firstAiderId,
        tenant_id: schedule.tenant_id,
        temp_unavailable: newStatus === 'offline',
      });
      toast.success(t('common.success'));
    } catch {
      toast.error(t('common.error'));
    }
  };

  const statusColors: Record<AiderStatus, string> = {
    available: 'bg-chart-2 text-chart-2',
    busy: 'bg-chart-3 text-chart-3',
    offline: 'bg-muted-foreground text-muted-foreground',
  };

  return (
    <div className="space-y-6">
      {/* Header with 3-state status toggle */}
      <div className="glass-card border-0 rounded-xl p-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="bg-primary/10 rounded-lg p-2"><Shield className="h-6 w-6 text-primary" /></div>
          <div>
            <h1 className="text-3xl font-bold tracking-tight">{t('crisisSupport.firstAider.title')}</h1>
            <p className="text-muted-foreground">{t('crisisSupport.firstAider.subtitle')}</p>
          </div>
        </div>
        <div className="flex items-center gap-1 bg-muted rounded-xl p-1">
          {(['available', 'busy', 'offline'] as AiderStatus[]).map(s => (
            <button
              key={s}
              onClick={() => handleStatusChange(s)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${
                aiderStatus === s ? 'bg-background shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground'
              }`}
            >
              <CircleDot className={`h-3 w-3 ${statusColors[s]}`} />
              {t(`crisisSupport.firstAider.status_${s}`)}
            </button>
          ))}
        </div>
      </div>

      {/* Professional Stats Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <Card className="glass-stat border-0 rounded-xl">
          <CardContent className="pt-6 text-center">
            <div className="mx-auto w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center mb-2">
              <MessageSquare className="h-5 w-5 text-primary" />
            </div>
            <p className="text-2xl font-bold">{activeCases.length}</p>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.firstAider.activeCases')}</p>
          </CardContent>
        </Card>
        <Card className="glass-stat border-0 rounded-xl">
          <CardContent className="pt-6 text-center">
            <div className="mx-auto w-10 h-10 rounded-xl bg-chart-2/10 flex items-center justify-center mb-2">
              <Check className="h-5 w-5 text-chart-2" />
            </div>
            <p className="text-2xl font-bold">{totalSessions}</p>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.firstAider.totalSessions')}</p>
          </CardContent>
        </Card>
        <Card className="glass-stat border-0 rounded-xl">
          <CardContent className="pt-6 text-center">
            <div className="mx-auto w-10 h-10 rounded-xl bg-chart-3/10 flex items-center justify-center mb-2">
              <Timer className="h-5 w-5 text-chart-3" />
            </div>
            <p className="text-2xl font-bold">{avgResponseMin}<span className="text-sm font-normal text-muted-foreground">m</span></p>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.firstAider.avgResponse')}</p>
          </CardContent>
        </Card>
        <Card className="glass-stat border-0 rounded-xl">
          <CardContent className="pt-6 text-center">
            <div className="mx-auto w-10 h-10 rounded-xl bg-chart-4/10 flex items-center justify-center mb-2">
              <Calendar className="h-5 w-5 text-chart-4" />
            </div>
            <p className="text-2xl font-bold">{todaySessions.length}</p>
            <p className="text-xs text-muted-foreground">{t('crisisSupport.firstAider.todaySessions')}</p>
          </CardContent>
        </Card>
      </div>

      {/* Today's Schedule */}
      {todaySessions.length > 0 && (
        <Card className="glass-card border-0 rounded-xl">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <Calendar className="h-4 w-4 text-primary" />
              {t('crisisSupport.firstAider.todaySchedule')}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-2">
            {todaySessions.map(session => (
              <div key={session.id} className="flex items-center justify-between p-3 rounded-xl border border-border bg-background">
                <div className="flex items-center gap-3">
                  <Clock className="h-4 w-4 text-muted-foreground" />
                  <div>
                    <p className="text-sm font-medium">
                      {session.scheduled_start ? format(new Date(session.scheduled_start), 'h:mm a') : '—'}
                      {session.scheduled_end ? ` – ${format(new Date(session.scheduled_end), 'h:mm a')}` : ''}
                    </p>
                    <p className="text-xs text-muted-foreground capitalize">{session.channel} · {session.status}</p>
                  </div>
                </div>
                {session.status === 'scheduled' && (
                  <Button size="sm" className="rounded-xl">{t('crisisSupport.firstAider.joinSession')}</Button>
                )}
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      {/* Case Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="glass-tabs">
          <TabsTrigger value="pending" className="rounded-xl">
            {t('crisisSupport.firstAider.pending')}
            {pendingCases.length > 0 && <Badge variant="destructive" className="ms-1.5 text-xs">{pendingCases.length}</Badge>}
          </TabsTrigger>
          <TabsTrigger value="active" className="rounded-xl">
            {t('crisisSupport.firstAider.active')}
            {activeCases.length > 0 && <Badge variant="secondary" className="ms-1.5 text-xs">{activeCases.length}</Badge>}
          </TabsTrigger>
          <TabsTrigger value="resolved" className="rounded-xl">{t('crisisSupport.firstAider.resolved')}</TabsTrigger>
        </TabsList>

        <TabsContent value="pending">
          <CaseList
            cases={pendingCases}
            isPending={isPending}
            onSelect={setSelectedCaseId}
            actions={(c) => (
              <div className="flex gap-1">
                <Button size="sm" onClick={(e) => { e.stopPropagation(); updateCaseStatus.mutateAsync({ id: c.id, status: 'active' }); }}>
                  <Check className="h-3 w-3 me-1" />{t('crisisSupport.firstAider.accept')}
                </Button>
                <Button size="sm" variant="outline" onClick={(e) => { e.stopPropagation(); updateCaseStatus.mutateAsync({ id: c.id, status: 'pending_assignment', assigned_first_aider_id: null }); }}>
                  <X className="h-3 w-3 me-1" />{t('crisisSupport.firstAider.decline')}
                </Button>
              </div>
            )}
          />
        </TabsContent>
        <TabsContent value="active">
          <CaseList cases={activeCases} isPending={isPending} onSelect={setSelectedCaseId} />
        </TabsContent>
        <TabsContent value="resolved">
          <CaseList cases={resolvedCases} isPending={isPending} onSelect={setSelectedCaseId} />
        </TabsContent>
      </Tabs>
    </div>
  );
}

// ─── Case List ─────────────────────────────────────────────────────
function CaseList({ cases, isPending, onSelect, actions }: { cases: any[]; isPending: boolean; onSelect: (id: string) => void; actions?: (c: any) => React.ReactNode }) {
  const { t } = useTranslation();

  if (isPending) return <p className="text-muted-foreground py-8 text-center">{t('common.loading')}</p>;
  if (cases.length === 0) return <p className="text-muted-foreground py-8 text-center">{t('common.noData')}</p>;

  const riskIndicator = (risk: string) => {
    if (risk === 'high') return 'border-s-4 border-s-destructive';
    if (risk === 'moderate') return 'border-s-4 border-s-chart-3';
    return 'border-s-4 border-s-chart-2';
  };

  return (
    <div className="space-y-3 mt-4">
      {cases.map(c => (
        <Card key={c.id} className={`glass-card border-0 rounded-xl cursor-pointer hover:bg-white/5 transition-colors ${riskIndicator(c.risk_level)}`} onClick={() => onSelect(c.id)}>
          <CardContent className="py-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-muted flex items-center justify-center">
                  <MessageSquare className="h-5 w-5 text-muted-foreground" />
                </div>
                <div>
                  <p className="font-medium text-sm">{t(`crisisSupport.intents.${c.intent}`)}</p>
                  <div className="flex items-center gap-2 mt-0.5">
                     <Badge variant={c.risk_level === 'high' ? 'destructive' : c.risk_level === 'moderate' ? 'secondary' : 'outline'} className="text-2xs">
                       {c.risk_level}
                     </Badge>
                     {c.urgency_level && (
                       <Badge variant="outline" className="text-2xs">U{c.urgency_level}</Badge>
                     )}
                     <span className="text-xs text-muted-foreground">{format(new Date(c.created_at), 'MMM d, h:mm a')}</span>
                     {c.anonymity_mode === 'anonymous' && <Badge variant="outline" className="text-2xs">{t('crisisSupport.request.anonymous')}</Badge>}
                  </div>
                </div>
              </div>
              {actions ? actions(c) : null}
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { useCrisisCases } from '@/features/crisis/hooks/crisis/useCrisisSupport';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { MessageSquare, Clock, ArrowLeft, X, Plus, Calendar, FileText } from 'lucide-react';
import { format } from 'date-fns';
import EnhancedChatPanel from '@/features/crisis/components/EnhancedChatPanel';

const STATUS_COLORS: Record<string, string> = {
  new: 'secondary',
  pending_assignment: 'secondary',
  pending_first_aider_acceptance: 'secondary',
  active: 'default',
  awaiting_user: 'default',
  awaiting_first_aider: 'default',
  escalated: 'destructive',
  resolved: 'outline',
  closed: 'outline',
  cancelled: 'outline',
};

function resolveIntentLabel(t: (key: string) => string, intent: string): string {
  const key = `crisisSupport.intents.${intent}`;
  const translated = String(t(key));
  return translated === key ? intent : translated;
}

export default function MySupportPage() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { cases, isPending, updateCaseStatus } = useCrisisCases({ role: 'requester' });
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('active');

  const myCases = cases.filter(c => c.requester_user_id === user?.id);
  const activeCases = myCases.filter(c => !['resolved', 'closed', 'cancelled'].includes(c.status));
  const pastCases = myCases.filter(c => ['resolved', 'closed', 'cancelled'].includes(c.status));
  const selectedCase = myCases.find(c => c.id === selectedCaseId);

  if (selectedCase) {
    return <CaseThread caseData={selectedCase} onBack={() => setSelectedCaseId(null)} />;
  }

  return (
    <div className="space-y-6">
      <div className="glass-card border-0 rounded-xl p-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-primary/10 rounded-lg p-2"><MessageSquare className="h-6 w-6 text-primary" /></div>
          <div>
            <h1 className="text-3xl font-bold tracking-tight">{t('crisisSupport.mySupport.title')}</h1>
            <p className="text-muted-foreground">{t('crisisSupport.mySupport.subtitle')}</p>
          </div>
        </div>
        <Button onClick={() => navigate('/crisis-support')} className="gap-1.5 rounded-xl">
          <Plus className="h-4 w-4" />
          {t('crisisSupport.mySupport.newRequest')}
        </Button>
      </div>

      {isPending ? (
        <p className="text-muted-foreground">{t('common.loading')}</p>
      ) : myCases.length === 0 ? (
        <Card className="glass-card border-0 rounded-xl">
          <CardContent className="py-12 text-center">
            <MessageSquare className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">{t('crisisSupport.mySupport.noCases')}</p>
            <Button onClick={() => navigate('/crisis-support')} className="mt-4">{t('crisisSupport.mySupport.newRequest')}</Button>
          </CardContent>
        </Card>
      ) : (
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="glass-tabs">
            <TabsTrigger value="active" className="rounded-xl">
              {t('crisisSupport.mySupport.activeCases')}
              {activeCases.length > 0 && <Badge variant="secondary" className="ms-1.5 text-xs">{activeCases.length}</Badge>}
            </TabsTrigger>
            <TabsTrigger value="history" className="rounded-xl">
              {t('crisisSupport.mySupport.history')}
            </TabsTrigger>
          </TabsList>

          <TabsContent value="active">
            <CaseCardList cases={activeCases} onSelect={setSelectedCaseId} />
          </TabsContent>
          <TabsContent value="history">
            <CaseCardList cases={pastCases} onSelect={setSelectedCaseId} />
          </TabsContent>
        </Tabs>
      )}
    </div>
  );
}

function CaseCardList({ cases, onSelect }: { cases: any[]; onSelect: (id: string) => void }) {
  const { t } = useTranslation();

  if (cases.length === 0) {
    return <p className="text-muted-foreground py-8 text-center">{t('common.noData')}</p>;
  }

  return (
    <div className="space-y-3 mt-4">
      {cases.map(c => (
        <Card key={c.id} className="glass-card border-0 rounded-xl cursor-pointer hover:bg-white/5 transition-colors" onClick={() => onSelect(c.id)}>
          <CardContent className="py-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-muted flex items-center justify-center">
                  <MessageSquare className="h-5 w-5 text-muted-foreground" />
                </div>
                <div>
                  <p className="font-medium text-sm">{resolveIntentLabel((key) => String(t(key)), c.intent)}</p>
                  <div className="flex items-center gap-2 mt-0.5">
                    <Clock className="h-3 w-3 text-muted-foreground" />
                    <span className="text-xs text-muted-foreground">{format(new Date(c.created_at), 'MMM d, yyyy h:mm a')}</span>
                  </div>
                </div>
              </div>
              <Badge variant={STATUS_COLORS[c.status] as any || 'secondary'} className="text-xs">
                {t(`crisisSupport.statuses.${c.status}`)}
              </Badge>
            </div>
            {/* Session notes shared by first aider (read-only) */}
            {c.status === 'resolved' && c.summary && (
              <div className="mt-3 p-3 rounded-lg bg-muted/50 border border-border">
                <div className="flex items-center gap-1.5 mb-1">
                  <FileText className="h-3 w-3 text-muted-foreground" />
                  <span className="text-2xs font-medium text-muted-foreground uppercase">{t('crisisSupport.mySupport.sharedNotes')}</span>
                </div>
                <p className="text-xs text-foreground">{c.summary}</p>
              </div>
            )}
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

// ─── Case Thread (Enhanced with EnhancedChatPanel) ───────────────────
function CaseThread({ caseData, onBack }: { caseData: any; onBack: () => void }) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { updateCaseStatus } = useCrisisCases();

  const isActive = ['active', 'awaiting_user', 'awaiting_first_aider', 'pending_first_aider_acceptance'].includes(caseData.status);

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="icon" onClick={onBack}>
          <ArrowLeft className="h-5 w-5 rtl:-scale-x-100" />
        </Button>
        <div className="flex-1">
          <h2 className="font-semibold">{resolveIntentLabel((key) => String(t(key)), caseData.intent)}</h2>
          <p className="text-xs text-muted-foreground">{format(new Date(caseData.created_at), 'MMM d, yyyy h:mm a')}</p>
        </div>
        <Badge variant={STATUS_COLORS[caseData.status] as any || 'secondary'}>
          {t(`crisisSupport.statuses.${caseData.status}`)}
        </Badge>
      </div>

      {/* Enhanced chat */}
      <Card className="glass-card border-0 rounded-xl overflow-hidden">
        <EnhancedChatPanel
          caseId={caseData.id}
          tenantId={caseData.tenant_id}
        />
      </Card>

      {/* Actions */}
      {caseData.status !== 'cancelled' && caseData.status !== 'closed' && caseData.status !== 'resolved' && (
        <Button
          variant="outline"
          onClick={() => { updateCaseStatus.mutateAsync({ id: caseData.id, status: 'cancelled' }); onBack(); }}
          className="gap-1.5"
        >
          <X className="h-4 w-4" />
          {t('crisisSupport.mySupport.cancelRequest')}
        </Button>
      )}

      {/* Follow-up from resolved */}
      {caseData.status === 'resolved' && (
        <Button
          variant="outline"
          onClick={() => { /* navigate to new request with context */ }}
          className="gap-1.5"
        >
          <Calendar className="h-4 w-4" />
          {t('crisisSupport.mySupport.scheduleFollowup')}
        </Button>
      )}
    </div>
  );
}

import React from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import type { CreateCycleInput } from '../types';

interface Props {
  form: CreateCycleInput;
  updateField: (key: keyof CreateCycleInput, value: any) => void;
  basicsValid: boolean;
  isCreating: boolean;
  onCreateCycle: () => void;
