import { TOOLKIT, TOOLKIT_CATEGORY_COLORS } from "@/config/toolkit-colors";

interface Meditation {
  id: string;
  title: string;
  duration: number; // seconds
  targetKey: string;
  emoji: string;
  description: string;
}

const MEDITATIONS: Meditation[] = [
  { id: "1", title: "Calm the Storm", duration: 300, targetKey: "anxiety", emoji: "⛈️→🌤️", description: "A gentle breathing meditation to ease anxious thoughts and return to the present moment." },
  { id: "2", title: "Sleep Wind-Down", duration: 600, targetKey: "sleep", emoji: "🌙", description: "A slow, body-relaxing sequence to prepare your mind and body for restful sleep." },
  { id: "3", title: "Focus Reset", duration: 180, targetKey: "focus", emoji: "🎯", description: "A quick 3-minute clarity reset to sharpen attention and clear mental fog." },
  { id: "4", title: "Body Scan", duration: 420, targetKey: "stress", emoji: "🧘", description: "Travel through your body releasing tension, one area at a time." },
  { id: "5", title: "Self-Compassion", duration: 300, targetKey: "mood", emoji: "💛", description: "A loving-kindness practice to cultivate gentleness and warmth toward yourself." },
  { id: "6", title: "Morning Clarity", duration: 240, targetKey: "energy", emoji: "🌅", description: "An energising morning intention-setting session to start your day with purpose." },
];

function formatTime(seconds: number) {
  const m = Math.floor(seconds / 60).toString().padStart(2, "0");
  const s = (seconds % 60).toString().padStart(2, "0");
  return `${m}:${s}`;
}

export default function MeditationLibraryTool() {
  const { t } = useTranslation();
  const [selected, setSelected] = useState<Meditation | null>(null);
  const [playing, setPlaying] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const audioRef = useRef<AudioContext | null>(null);
  const oscillatorRef = useRef<OscillatorNode | null>(null);
  const gainRef = useRef<GainNode | null>(null);

  const startAudio = () => {
    try {
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      osc.frequency.setValueAtTime(432, ctx.currentTime);
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.08, ctx.currentTime + 2);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      audioRef.current = ctx;
      oscillatorRef.current = osc;
      gainRef.current = gain;
    } catch {}
  };

  const stopAudio = () => {
    try {
      if (gainRef.current && audioRef.current) {
        gainRef.current.gain.linearRampToValueAtTime(0, audioRef.current.currentTime + 1);
        setTimeout(() => { oscillatorRef.current?.stop(); audioRef.current?.close(); }, 1100);
      }
    } catch {}
  };

  const handlePlay = () => {
    setPlaying(true);
    startAudio();
    intervalRef.current = setInterval(() => {
      setElapsed((e) => {
        if (e + 1 >= (selected?.duration ?? 0)) {
          clearInterval(intervalRef.current!);
          setPlaying(false);
          stopAudio();
          return selected?.duration ?? 0;
        }
        return e + 1;
      });
    }, 1000);
  };

  const handlePause = () => {
    setPlaying(false);
    if (intervalRef.current) clearInterval(intervalRef.current);
    stopAudio();
  };

  const handleClose = () => {
    handlePause();
    setSelected(null);
    setElapsed(0);
  };

  useEffect(() => () => { if (intervalRef.current) clearInterval(intervalRef.current); stopAudio(); }, []);

  const progress = selected ? (elapsed / selected.duration) * 100 : 0;

  return (
    <div className="rounded-lg border border-border bg-card shadow-sm overflow-hidden">
      <div className="px-5 py-4 border-b border-border bg-toolkit-sky/15">
        <div className="flex items-center gap-2">
          <span className="text-2xl">🧘</span>
          <div>
            <h2 className="font-semibold text-foreground">{t("mentalToolkit.meditation.title")}</h2>
            <p className="text-sm text-muted-foreground">{t("mentalToolkit.meditation.subtitle")}</p>
          </div>
        </div>
      </div>

      <div className="p-5">
        {/* Player */}
        {selected ? (
          <div className="space-y-5 animate-in fade-in duration-300">
            <button onClick={handleClose} className="text-sm text-muted-foreground hover:text-foreground flex items-center gap-1">
              ← Back to library
            </button>
            <div className="rounded-lg p-5 space-y-4 bg-gradient-to-br from-toolkit-lavender/15 to-toolkit-sky/15">
              <div className="text-center space-y-1">
                <div className="text-4xl">{selected.emoji}</div>
                <h3 className="font-bold text-lg text-foreground">{selected.title}</h3>
                <p className="text-sm text-muted-foreground">{selected.description}</p>
                <Badge className="text-xs rounded-full border-0 text-foreground" style={{ background: TOOLKIT_CATEGORY_COLORS[selected.targetKey] }}>
                  {t(`mentalToolkit.meditation.targets.${selected.targetKey}`)}
                </Badge>
              </div>

              {/* Timer */}
              <div className="text-center">
                <span className="text-3xl font-mono font-bold text-foreground">
                  {formatTime(selected.duration - elapsed)}
                </span>
              </div>

              {/* Progress */}
              <Progress value={progress} className="h-2 rounded-full" />

              {/* Controls */}
              <div className="flex justify-center">
                {playing ? (
                  <Button onClick={handlePause} className="rounded-full w-14 h-14 text-xl bg-toolkit-lavender text-toolkit-plum hover:opacity-90">⏸</Button>
                ) : (
                  <Button onClick={handlePlay} className="rounded-full w-14 h-14 text-xl bg-gradient-to-r from-toolkit-lavender to-toolkit-sage text-toolkit-plum hover:opacity-90">▶️</Button>
                )}
              </div>

              {elapsed >= selected.duration && (
                <p className="text-center font-semibold text-foreground">🌿 Session Complete!</p>
              )}
            </div>
          </div>
        ) : (
          /* Library Grid */
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {MEDITATIONS.map((med) => (
              <button
                key={med.id}
                onClick={() => { setSelected(med); setElapsed(0); setPlaying(false); }}
                className="rounded-lg p-4 text-start border border-border bg-background hover:bg-muted transition-all space-y-2 shadow-sm hover:shadow-md hover:-translate-y-0.5"
              >
                <div className="text-2xl">{med.emoji}</div>
                <div>
                  <p className="font-semibold text-foreground text-sm">{med.title}</p>
                  <p className="text-xs text-muted-foreground line-clamp-2 mt-0.5">{med.description}</p>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <Badge className="text-xs rounded-full border-0 text-foreground px-2" style={{ background: TOOLKIT_CATEGORY_COLORS[med.targetKey] }}>
                    {t(`mentalToolkit.meditation.targets.${med.targetKey}`)}
                  </Badge>
                  <Badge variant="outline" className="text-xs rounded-full">
                    {t("mentalToolkit.meditation.minutes", { n: Math.floor(med.duration / 60) })}
                  </Badge>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/shared/components/ui/button";
import { ArrowRight, Pause, Play, RotateCcw } from "lucide-react";
import { TOOLKIT } from "@/config/toolkit-colors";

type Technique = "box" | "sigh" | "grounding";

interface Phase {
  labelKey: string;
  duration: number;
  scale: string;
}

const BOX_PHASES: Phase[] = [
  { labelKey: "inhale", duration: 4, scale: "scale-100" },
  { labelKey: "hold", duration: 4, scale: "scale-100" },
  { labelKey: "exhale", duration: 4, scale: "scale-50" },
  { labelKey: "hold", duration: 4, scale: "scale-50" },
];

const SIGH_PHASES: Phase[] = [
  { labelKey: "inhale", duration: 2, scale: "scale-90" },
  { labelKey: "inhaleAgain", duration: 1, scale: "scale-100" },
  { labelKey: "longExhale", duration: 6, scale: "scale-50" },
];

const GROUNDING_STEPS = [
  { sense: "see", n: 5 },
  { sense: "hear", n: 4 },
  { sense: "touch", n: 3 },
  { sense: "smell", n: 2 },
  { sense: "taste", n: 1 },
];

interface Props {
  technique?: Technique;
  totalRounds?: number;
  onComplete?: (roundsCompleted: number, durationSeconds: number) => void;
  onCancel?: () => void;
}

export default function BreathingGroundingTool({ technique = "box", totalRounds = 5, onComplete, onCancel }: Props) {
  const { t } = useTranslation();
  const [running, setRunning] = useState(false);
  const [paused, setPaused] = useState(false);
  const [phaseIdx, setPhaseIdx] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [round, setRound] = useState(0);
  const [groundingStep, setGroundingStep] = useState(0);
  const [complete, setComplete] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const startTimeRef = useRef<number>(0);
  const elapsedRef = useRef<number>(0);

  const phases = technique === "box" ? BOX_PHASES : SIGH_PHASES;

  const clearTimer = useCallback(() => {
    if (timerRef.current) { clearInterval(timerRef.current); timerRef.current = null; }
  }, []);

  const reset = useCallback(() => {
    clearTimer();
    setRunning(false);
    setPaused(false);
    setPhaseIdx(0);
    setRound(0);
    setTimeLeft(0);
    setComplete(false);
    setGroundingStep(0);
    elapsedRef.current = 0;
  }, [clearTimer]);

  const start = useCallback(() => {
    setRunning(true);
    setPaused(false);
    setComplete(false);
    setPhaseIdx(0);
    setRound(1);
    setTimeLeft(phases[0].duration);
    setGroundingStep(0);
    startTimeRef.current = Date.now();
    elapsedRef.current = 0;
  }, [phases]);

  const pause = useCallback(() => {
    clearTimer();
    setPaused(true);
    elapsedRef.current += (Date.now() - startTimeRef.current) / 1000;
  }, [clearTimer]);

  const resume = useCallback(() => {
    setPaused(false);
    startTimeRef.current = Date.now();
  }, []);

  // Timer effect for box/sigh
  useEffect(() => {
    if (!running || paused || technique === "grounding") return;

    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          setPhaseIdx(pi => {
            const next = (pi + 1) % phases.length;
            if (next === 0) {
              setRound(r => {
                if (r >= totalRounds) {
                  clearTimer();
                  setRunning(false);
                  setComplete(true);
                  const dur = Math.round(elapsedRef.current + (Date.now() - startTimeRef.current) / 1000);
                  onComplete?.(r, dur);
                  return r;
                }
                return r + 1;
              });
            }
            return next;
          });
          return phases[0].duration;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearTimer();
  }, [running, paused, technique, phases, totalRounds, clearTimer, onComplete]);

  // Update timeLeft when phaseIdx changes
  useEffect(() => {
    if (running && !paused && technique !== "grounding") {
      setTimeLeft(phases[phaseIdx % phases.length].duration);
    }
  }, [phaseIdx]); // intentionally minimal deps

  const handleGroundingComplete = useCallback(() => {
    setRunning(false);
    setComplete(true);
    const dur = Math.round(elapsedRef.current + (Date.now() - startTimeRef.current) / 1000);
    onComplete?.(5, dur);
  }, [onComplete]);

  const currentPhase = phases[phaseIdx % phases.length];
  const circleScale = running && !paused ? currentPhase.scale : "scale-75";

  const phaseLabel = (key: string) => {
    const map: Record<string, string> = {
      inhale: t("mentalToolkit.breathing.inhale"),
      hold: t("mentalToolkit.breathing.hold"),
      exhale: t("mentalToolkit.breathing.exhale"),
      inhaleAgain: t("mentalToolkit.breathing.inhaleAgain"),
      longExhale: t("mentalToolkit.breathing.longExhale"),
    };
    return map[key] || key;
  };

  // Grounding technique
  if (technique === "grounding") {
    return (
      <div className="space-y-4">
        {!running && !complete && (
          <div className="text-center space-y-3">
            <p className="text-sm text-muted-foreground">{t("mentalToolkit.breathing.groundingIntro")}</p>
            <Button onClick={() => { setRunning(true); setGroundingStep(0); startTimeRef.current = Date.now(); }} className="rounded-xl px-8 bg-toolkit-sage text-toolkit-plum hover:opacity-90">
              {t("mentalToolkit.breathing.start")}
            </Button>
          </div>
        )}
        {running && (
          <div className="text-center space-y-4 animate-in fade-in duration-300">
            <div className="w-28 h-28 mx-auto rounded-full flex items-center justify-center text-4xl shadow-lg bg-gradient-to-br from-toolkit-sage/40 to-toolkit-lavender/40">
              {["👁️", "👂", "✋", "👃", "👅"][groundingStep] || "✨"}
            </div>
            <p className="text-lg font-semibold text-foreground">
              {t(`mentalToolkit.breathing.groundingPrompts.${GROUNDING_STEPS[groundingStep]?.sense}`, { n: GROUNDING_STEPS[groundingStep]?.n })}
            </p>
            <p className="text-sm text-muted-foreground">
              {t("mentalToolkit.breathing.step", { current: groundingStep + 1, total: 5 })}
            </p>
            {/* Progress dots */}
            <div className="flex gap-2 justify-center">
              {GROUNDING_STEPS.map((_, i) => (
                <div key={i} className={`w-2.5 h-2.5 rounded-full transition-all ${i <= groundingStep ? 'bg-toolkit-sage' : 'bg-muted opacity-30'}`} />
              ))}
            </div>
            <div className="flex gap-3 justify-center">
              {groundingStep < 4 ? (
                <Button onClick={() => setGroundingStep(s => s + 1)} className="rounded-xl bg-toolkit-sage text-toolkit-plum hover:opacity-90">
                  {t("mentalToolkit.breathing.next")} <ArrowRight className="h-4 w-4 ms-1 rtl:-scale-x-100" />
                </Button>
              ) : (
                <Button onClick={handleGroundingComplete} className="rounded-xl bg-toolkit-lavender text-toolkit-plum hover:opacity-90">
                  {t("mentalToolkit.breathing.finish")} 🌿
                </Button>
              )}
              <Button variant="outline" onClick={() => { reset(); onCancel?.(); }} className="rounded-xl">
                <RotateCcw className="h-4 w-4 me-1" /> {t("mentalToolkit.breathing.startOver")}
              </Button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // Box / Sigh technique
  return (
    <div className="flex flex-col items-center space-y-6">
      {/* Animated Circle */}
      <div className="relative w-44 h-44 flex items-center justify-center">
        <div
          className={`absolute inset-0 rounded-full transition-all bg-gradient-to-br from-toolkit-lavender/60 to-toolkit-sage/60 ${circleScale}`}
          style={{
            transitionDuration: running && !paused ? `${currentPhase.duration * 1000}ms` : "500ms",
            transitionTimingFunction: "ease-in-out",
          }}
        />
        <div className="relative z-10 text-center">
          {!running && !complete ? (
            <span className="text-4xl">✨</span>
          ) : running ? (
            <>
              <p className="font-bold text-lg text-toolkit-plum">
                {phaseLabel(currentPhase.labelKey)}
              </p>
              <p className="text-3xl font-bold text-toolkit-plum">{timeLeft}</p>
            </>
          ) : null}
        </div>
      </div>

      {/* Round progress dots */}
      {running && !complete && (
        <div className="flex gap-1.5 justify-center">
          {Array.from({ length: totalRounds }, (_, i) => (
            <div key={i} className={`w-2.5 h-2.5 rounded-full transition-all ${i < round ? 'bg-toolkit-lavender' : 'bg-muted opacity-30'}`} />
          ))}
        </div>
      )}

      {/* Status */}
      {running && !complete && (
        <p className="text-sm text-muted-foreground">
          {t("mentalToolkit.breathing.round", { current: round, total: totalRounds })}
          {paused && ` — ${t("mentalToolkit.breathing.pause")}`}
        </p>
      )}

      {/* Controls */}
      <div className="flex gap-3">
        {!running && !complete && (
          <Button onClick={start} className="rounded-xl px-8 bg-gradient-to-r from-toolkit-lavender to-toolkit-sage text-toolkit-plum hover:opacity-90">
            <Play className="h-4 w-4 me-1" /> {t("mentalToolkit.breathing.start")}
          </Button>
        )}
        {running && !paused && (
          <Button variant="outline" onClick={pause} className="rounded-xl px-8">
            <Pause className="h-4 w-4 me-1" /> {t("mentalToolkit.breathing.pause")}
          </Button>
        )}
        {running && paused && (
          <Button onClick={resume} className="rounded-xl px-8 bg-gradient-to-r from-toolkit-lavender to-toolkit-sage text-toolkit-plum hover:opacity-90">
            <Play className="h-4 w-4 me-1" /> {t("mentalToolkit.breathing.resume")}
          </Button>
        )}
        {running && (
          <Button variant="outline" onClick={() => { reset(); onCancel?.(); }} className="rounded-xl">
            <RotateCcw className="h-4 w-4" />
          </Button>
        )}
      </div>
    </div>
  );
}

