import React, { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/shared/components/ui/dialog';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shared/components/ui/tabs';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Slider } from '@/shared/components/ui/slider';
import { Switch } from '@/shared/components/ui/switch';
import { Alert, AlertDescription, AlertTitle } from '@/shared/components/ui/alert';
import { AlertTriangle } from 'lucide-react';
import { useAwardCycles, type AwardCycle } from '@/features/recognition/hooks/recognition/useAwardCycles';
import { ThemeBuilder } from '@/features/recognition/components/ThemeBuilder';
import { getImpactWarning } from '@/shared/utils/recognition-utils';
import type { FairnessSettings, FairnessConfig } from '@/features/cycle-builder/types';
import { buildFairnessConfig } from '@/features/cycle-builder/types';

interface CycleEditDialogProps {
  cycle: AwardCycle | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

type EditTab = 'basics' | 'themes' | 'fairness' | 'rewards';

const DEFAULT_FAIRNESS: FairnessSettings = {
  cliqueThreshold: 0.4,
  demographicParityTarget: 0.8,
  visibilityBiasCorrection: true,
  publishRawScores: true,
  allowAppeals: true,
  votingWeightAdjustmentLimit: 30,
};

function parseFairnessConfig(config: Record<string, any> | null): FairnessSettings {
  if (!config) return { ...DEFAULT_FAIRNESS };
  const fc = config as Record<string, any>;
  const bd = (fc.biasDetection ?? {}) as Record<string, any>;
  const au = (fc.auditSettings ?? {}) as Record<string, any>;
  return {
    cliqueThreshold: (bd.cliqueThreshold as number) ?? DEFAULT_FAIRNESS.cliqueThreshold,
    demographicParityTarget: (bd.demographicParityTarget as number) ?? DEFAULT_FAIRNESS.demographicParityTarget,
    visibilityBiasCorrection: (bd.visibilityBiasCorrection as boolean) ?? DEFAULT_FAIRNESS.visibilityBiasCorrection,
    publishRawScores: (au.publishRawScores as boolean) ?? DEFAULT_FAIRNESS.publishRawScores,
    allowAppeals: (au.allowAppeals as boolean) ?? DEFAULT_FAIRNESS.allowAppeals,
    votingWeightAdjustmentLimit: (fc.votingWeightAdjustmentLimit as number) ?? DEFAULT_FAIRNESS.votingWeightAdjustmentLimit,
  };
}

export const CycleEditDialog = React.memo(function CycleEditDialog({
  cycle,
  open,
  onOpenChange,
}: CycleEditDialogProps) {
  const { t } = useTranslation();
  const { updateCycle } = useAwardCycles();
  const [activeTab, setActiveTab] = useState<EditTab>('basics');

  const [form, setForm] = useState({
    name: '',
    name_ar: '',
    nomination_start: '',
    nomination_end: '',
    peer_endorsement_end: '',
    voting_start: '',
    voting_end: '',
    announcement_date: '',
    audit_review_days: 3,
    shortlist_count: 3,
    require_acknowledgment: true,
  });

  const [fairness, setFairness] = useState<FairnessSettings>({ ...DEFAULT_FAIRNESS });
  const [pointsConfig, setPointsConfig] = useState<Record<string, number>>({
    first_place: 5000, second_place: 2000, third_place: 1000, nominator_bonus: 200,
  });

  useEffect(() => {
    if (cycle) {
      setForm({
        name: cycle.name,
        name_ar: cycle.name_ar ?? '',
        nomination_start: cycle.nomination_start?.slice(0, 16) ?? '',
        nomination_end: cycle.nomination_end?.slice(0, 16) ?? '',
        peer_endorsement_end: cycle.peer_endorsement_end?.slice(0, 16) ?? '',
        voting_start: cycle.voting_start?.slice(0, 16) ?? '',
        voting_end: cycle.voting_end?.slice(0, 16) ?? '',
        announcement_date: cycle.announcement_date?.slice(0, 16) ?? '',
        audit_review_days: cycle.audit_review_days ?? 3,
        shortlist_count: cycle.shortlist_count ?? 3,
        require_acknowledgment: cycle.require_acknowledgment ?? true,
      });
      setFairness(parseFairnessConfig(cycle.fairness_config));
      const pc = (cycle.points_config || {}) as Record<string, number>;
      // Build points config supporting dynamic place_N keys
      const scCount = cycle.shortlist_count ?? 3;
      const newPc: Record<string, number> = { nominator_bonus: pc.nominator_bonus ?? 200 };
      for (let i = 1; i <= scCount; i++) {
        const key = `place_${i}`;
        // Fallback to legacy keys for 1-3
        if (pc[key] !== undefined) {
          newPc[key] = pc[key];
        } else if (i === 1) {
          newPc[key] = pc.first_place ?? 5000;
        } else if (i === 2) {
          newPc[key] = pc.second_place ?? 2000;
        } else if (i === 3) {
          newPc[key] = pc.third_place ?? 1000;
        } else {
          newPc[key] = 0;
        }
      }
      setPointsConfig(newPc);
      setActiveTab('basics');
    }
  }, [cycle]);

  const updateField = useCallback((key: string, value: string | number | boolean) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  }, []);

  const updateFairnessField = useCallback(<K extends keyof FairnessSettings>(key: K, value: FairnessSettings[K]) => {
    setFairness((prev) => ({ ...prev, [key]: value }));
  }, []);

  if (!cycle) return null;

  const isInProcess = cycle.status !== 'configuring';
  const impactWarning = getImpactWarning(cycle.status, t);

  const updatePointsField = useCallback((key: string, value: number) => {
    setPointsConfig((prev) => ({ ...prev, [key]: value }));
  }, []);

  const handleSave = () => {
    const fairnessConfig = buildFairnessConfig(fairness);
    updateCycle.mutate(
      {
        id: cycle.id,
        ...form,
        name_ar: form.name_ar || null,
        fairness_config: fairnessConfig,
        points_config: pointsConfig,
      },
      { onSuccess: () => onOpenChange(false) }
    );
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{t('recognition.cycles.editCycle')}</DialogTitle>
        </DialogHeader>

        {isInProcess && impactWarning && (
          <Alert variant="destructive" className="mb-2">
            <AlertTriangle className="h-4 w-4" />
            <AlertTitle>{t('recognition.cycles.impactAlert.title')}</AlertTitle>
            <AlertDescription>{impactWarning}</AlertDescription>
          </Alert>
        )}

        <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as EditTab)}>
          <TabsList className="grid w-full grid-cols-4 mb-4">
            <TabsTrigger value="basics">{t('recognition.cycleBuilder.basics')}</TabsTrigger>
            <TabsTrigger value="themes">{t('recognition.cycleBuilder.themes')}</TabsTrigger>
            <TabsTrigger value="fairness">{t('recognition.cycleBuilder.fairness')}</TabsTrigger>
            <TabsTrigger value="rewards">{t('recognition.cycleBuilder.rewards')}</TabsTrigger>
          </TabsList>

          {/* ── Basics Tab ── */}
          <TabsContent value="basics" className="space-y-4 mt-0">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>{t('recognition.cycles.name')}</Label>
                <Input value={form.name} onChange={(e) => updateField('name', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.cycles.nameAr')}</Label>
                <Input value={form.name_ar} onChange={(e) => updateField('name_ar', e.target.value)} dir="rtl" />
              </div>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-1">
                <Label>{t('recognition.timeline.nominationStart')}</Label>
                <Input type="datetime-local" value={form.nomination_start} onChange={(e) => updateField('nomination_start', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.timeline.nominationEnd')}</Label>
                <Input type="datetime-local" value={form.nomination_end} onChange={(e) => updateField('nomination_end', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.timeline.endorsementEnd')}</Label>
                <Input type="datetime-local" value={form.peer_endorsement_end} onChange={(e) => updateField('peer_endorsement_end', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.timeline.votingStart')}</Label>
                <Input type="datetime-local" value={form.voting_start} onChange={(e) => updateField('voting_start', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.timeline.votingEnd')}</Label>
                <Input type="datetime-local" value={form.voting_end} onChange={(e) => updateField('voting_end', e.target.value)} />
              </div>
              <div className="space-y-1">
                <Label>{t('recognition.timeline.announcement')}</Label>
                <Input type="datetime-local" value={form.announcement_date} onChange={(e) => updateField('announcement_date', e.target.value)} />
              </div>
            </div>
            <div className="space-y-1 max-w-xs">
              <Label>{t('recognition.cycles.auditDays')}</Label>
              <Input type="number" min={1} max={14} value={form.audit_review_days} onChange={(e) => updateField('audit_review_days', parseInt(e.target.value, 10) || 1)} />
            </div>
          </TabsContent>

          {/* ── Themes Tab ── */}
          <TabsContent value="themes" className="mt-0">
            <ThemeBuilder cycleId={cycle.id} />
          </TabsContent>

          {/* ── Fairness Tab ── */}
          <TabsContent value="fairness" className="space-y-4 mt-0">
            <div className="space-y-2">
              <Label>{t('recognition.fairness.cliqueThreshold')}: {(fairness.cliqueThreshold * 100).toFixed(0)}%</Label>
              <Slider value={[fairness.cliqueThreshold * 100]} onValueChange={([v]) => updateFairnessField('cliqueThreshold', v / 100)} min={10} max={90} step={5} />
            </div>
            <div className="space-y-2">
              <Label>{t('recognition.fairness.demographicParity')}: {(fairness.demographicParityTarget * 100).toFixed(0)}%</Label>
              <Slider value={[fairness.demographicParityTarget * 100]} onValueChange={([v]) => updateFairnessField('demographicParityTarget', v / 100)} min={50} max={100} step={5} />
            </div>
            <div className="flex items-center justify-between">
              <Label>{t('recognition.fairness.visibilityBias')}</Label>
              <Switch checked={fairness.visibilityBiasCorrection} onCheckedChange={(v) => updateFairnessField('visibilityBiasCorrection', v)} />
            </div>
            <div className="flex items-center justify-between">
              <Label>{t('recognition.fairness.publishRawScores')}</Label>
              <Switch checked={fairness.publishRawScores} onCheckedChange={(v) => updateFairnessField('publishRawScores', v)} />
            </div>
            <div className="flex items-center justify-between">
              <Label>{t('recognition.fairness.allowAppeals')}</Label>
              <Switch checked={fairness.allowAppeals} onCheckedChange={(v) => updateFairnessField('allowAppeals', v)} />
            </div>
            <div className="space-y-2">
              <Label>{t('recognition.fairness.votingWeightAdjustmentLimit')}: ±{fairness.votingWeightAdjustmentLimit}%</Label>
              <Slider
                value={[fairness.votingWeightAdjustmentLimit]}
                onValueChange={([v]) => updateFairnessField('votingWeightAdjustmentLimit', v)}
                min={0}
                max={50}
                step={5}
              />
              <p className="text-xs text-muted-foreground">{t('recognition.fairness.votingWeightAdjustmentLimitDesc')}</p>
            </div>
          </TabsContent>

          {/* ── Rewards Tab ── */}
          <TabsContent value="rewards" className="space-y-4 mt-0">
            <p className="text-sm text-muted-foreground">{t('recognition.rewards.description')}</p>
            
            {/* Shortlist settings */}
            <div className="space-y-2">
              <Label>{t('recognition.shortlist.shortlistCount')}: {form.shortlist_count}</Label>
              <Slider
                value={[form.shortlist_count]}
                onValueChange={([v]) => {
                  updateField('shortlist_count', v);
                  // Adjust points config to match new count
                  setPointsConfig(prev => {
                    const next = { ...prev };
                    for (let i = 1; i <= v; i++) {
                      if (next[`place_${i}`] === undefined) next[`place_${i}`] = 0;
                    }
                    // Remove keys above new count
                    for (let i = v + 1; i <= 15; i++) {
                      delete next[`place_${i}`];
                    }
                    return next;
                  });
                }}
                min={1} max={15} step={1}
              />
              <p className="text-xs text-muted-foreground">{t('recognition.shortlist.shortlistCountDesc')}</p>
            </div>

            <div className="flex items-center justify-between">
              <Label>{t('recognition.shortlist.requireAcknowledgment')}</Label>
              <Switch
                checked={form.require_acknowledgment}
                onCheckedChange={(v) => updateField('require_acknowledgment', v)}
              />
            </div>

            {/* Dynamic points per rank */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {Array.from({ length: form.shortlist_count }, (_, i) => i + 1).map(rank => (
                <div key={rank} className="space-y-1">
                  <Label>{t('recognition.shortlist.placePoints', { rank })}</Label>
                  <Input
                    type="number"
                    min={0}
                    value={pointsConfig[`place_${rank}`] ?? 0}
                    onChange={(e) => updatePointsField(`place_${rank}`, parseInt(e.target.value, 10) || 0)}
                  />
                </div>
              ))}
              <div className="space-y-1">
                <Label>{t('recognition.rewards.nominatorBonus')}</Label>
                <Input type="number" min={0} value={pointsConfig.nominator_bonus ?? 200} onChange={(e) => updatePointsField('nominator_bonus', parseInt(e.target.value, 10) || 0)} />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">{t('recognition.rewards.nominatorBonusDesc')}</p>
          </TabsContent>
        </Tabs>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            {t('common.cancel')}
          </Button>
          <Button onClick={handleSave} disabled={!form.name || updateCycle.isPending}>
            {t('common.save')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
});

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { AlertTriangle, CheckCircle, Shield, Eye, TrendingDown, TrendingUp } from 'lucide-react';
import { Progress } from '@/shared/components/ui/progress';

interface FairnessReportProps {
  report: Record<string, any>;
}

export function FairnessReport({ report }: FairnessReportProps) {
  const { t } = useTranslation();
  const cliques = report.clique_warnings || [];
  const anomalies = report.anomalies || [];
  const parity = report.demographic_parity || {};
  const visibility = report.visibility_correction || {};

  const parityStatusVariant = parity.status === 'balanced'
    ? 'secondary' as const
    : parity.status === 'imbalanced'
      ? 'destructive' as const
      : 'outline' as const;

  const parityStatusLabel = parity.status === 'balanced'
    ? t('recognition.results.parityBalanced')
    : parity.status === 'imbalanced'
      ? t('recognition.results.parityImbalanced')
      : parity.status === 'insufficient_data'
        ? t('recognition.results.insufficientData')
        : parity.status || 'N/A';

  return (
    <div className="grid gap-4 md:grid-cols-2">
      {/* Clique Detection */}
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <Shield className="h-4 w-4 text-primary" />
            {t('recognition.results.cliqueDetection')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {cliques.length === 0 ? (
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <CheckCircle className="h-4 w-4 text-chart-2" />
              {t('recognition.results.noCliques')}
            </div>
          ) : (
            <div className="space-y-2">
              {cliques.map((c: any, i: number) => (
                <div key={i} className="flex items-center gap-2 text-sm">
                  <AlertTriangle className="h-4 w-4 text-destructive" />
                  <span>{t('recognition.results.cliqueWarning', { count: c.mutual_count })}</span>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Vote Anomalies */}
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <AlertTriangle className="h-4 w-4 text-primary" />
            {t('recognition.results.voteAnomalies')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {anomalies.length === 0 ? (
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <CheckCircle className="h-4 w-4 text-chart-2" />
              {t('recognition.results.noAnomalies')}
            </div>
          ) : (
            <div className="space-y-2">
              {anomalies.map((a: any, i: number) => (
                <div key={i} className="flex items-center gap-2 text-sm">
                  <Badge variant="destructive">{a.type}</Badge>
                  <span>{t('recognition.results.anomalyCount', { count: a.count })}</span>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Demographic Parity */}
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <Shield className="h-4 w-4 text-primary" />
            {t('recognition.results.demographicParity')}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Badge variant={parityStatusVariant}>{parityStatusLabel}</Badge>

          {parity.score != null && (
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">
                {t('recognition.results.parityScore', { score: parity.score, target: parity.target })}
              </p>
              <Progress value={parity.score * 100} className="h-2" />
            </div>
          )}

          {parity.underrepresented?.length > 0 && (
            <div className="space-y-1">
              <p className="text-xs font-medium flex items-center gap-1">
                <TrendingDown className="h-3 w-3 text-destructive" />
                {t('recognition.results.underrepresented')}
              </p>
              <div className="flex flex-wrap gap-1">
                {parity.underrepresented.map((d: string) => (
                  <Badge key={d} variant="outline" className="text-2xs">{d}</Badge>
                ))}
              </div>
            </div>
          )}

          {parity.overrepresented?.length > 0 && (
            <div className="space-y-1">
              <p className="text-xs font-medium flex items-center gap-1">
                <TrendingUp className="h-3 w-3 text-chart-4" />
                {t('recognition.results.overrepresented')}
              </p>
              <div className="flex flex-wrap gap-1">
                {parity.overrepresented.map((d: string) => (
                  <Badge key={d} variant="outline" className="text-2xs">{d}</Badge>
                ))}
              </div>
            </div>
          )}

          {parity.status === 'insufficient_data' && (
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">
                {parity.department_count != null
                  ? t('recognition.results.parityDeptCount', { count: parity.department_count, required: 2 })
                  : parity.note}
              </p>
              {parity.nominee_count != null && (
                <p className="text-xs text-muted-foreground">
                  {t('recognition.results.parityNomineeCount', { count: parity.nominee_count })}
                </p>
              )}
            </div>
          )}
          {parity.note && !parity.score && parity.status !== 'insufficient_data' && (
            <p className="text-xs text-muted-foreground">{parity.note}</p>
          )}
        </CardContent>
      </Card>

      {/* Visibility Bias */}
      <Card>
        <CardHeader className="pb-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <Eye className="h-4 w-4 text-primary" />
            {t('recognition.results.visibilityBias')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {visibility.applied ? (
            <div className="flex items-center gap-2 text-sm">
              <CheckCircle className="h-4 w-4 text-chart-2" />
              <span>{t('recognition.results.correctionApplied')}</span>
            </div>
          ) : (
            <span className="text-sm text-muted-foreground">{t('recognition.results.noCorrectionNeeded')}</span>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQuery } from '@tanstack/react-query';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Label } from '@/shared/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { QuotaIndicator } from './QuotaIndicator';
import { EndorsementRequestPicker } from './EndorsementRequestPicker';
import { NominationCriteriaForm } from './NominationCriteriaForm';
import { CriteriaWeightTable } from './CriteriaWeightTable';
import { useNominations, useManagerQuota, usePeerQuota, type CreateNominationInput } from '@/features/recognition/hooks/recognition/useNominations';
import { useEmployees } from '@/hooks/org/useEmployees';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { useUserCycleNominations, useCycleConfig } from '../hooks/useRecognitionQueries';
import { User, FileText, Scale, ThumbsUp, CheckCircle, ChevronLeft, ChevronRight, Users, AlertCircle } from 'lucide-react';
import { toast } from 'sonner';
import { Alert, AlertDescription } from '@/shared/components/ui/alert';

interface NominationWizardProps {
  cycleId: string;
  themeId: string;
  preselectedNomineeId?: string;
  onBack?: () => void;
  onComplete?: () => void;
}

type Step = 'select_nominee' | 'justification' | 'criteria_evaluation' | 'review' | 'request_endorsements';
const STEPS: Step[] = ['select_nominee', 'justification', 'criteria_evaluation', 'review', 'request_endorsements'];
const VISIBLE_STEPS: Step[] = ['select_nominee', 'justification', 'criteria_evaluation', 'review'];

export function NominationWizard({ cycleId, themeId, preselectedNomineeId, onBack, onComplete }: NominationWizardProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const { createNomination } = useNominations();
  const { saveCriteriaEvaluations } = useNominationCriteria();
  const { data: managerQuota } = useManagerQuota(themeId);
  const { data: peerQuota } = usePeerQuota(themeId);
  const { employees = [] } = useEmployees();

  // Fetch existing nominations by current user in this cycle to prevent duplicates
  const { data: existingNominations } = useUserCycleNominations(cycleId, user?.id);

  const alreadyNominatedIds = new Set(existingNominations?.map(n => n.nominee_id) ?? []);

  const { data: cycleConfig } = useCycleConfig(cycleId);

  const [step, setStep] = useState<Step>('select_nominee');
  const [nomineeId, setNomineeId] = useState(preselectedNomineeId || '');
  const [nominatorRole, setNominatorRole] = useState<'manager' | 'peer' | 'self'>('peer');
  const [headline, setHeadline] = useState('');
  const [justification, setJustification] = useState('');
  const [examples, setExamples] = useState('');
  const [impact, setImpact] = useState('');
  const [criteriaEvaluations, setCriteriaEvaluations] = useState<CriterionEvaluation[]>([]);
  const [createdNominationId, setCreatedNominationId] = useState<string | null>(null);
  const [managerApprovalPending, setManagerApprovalPending] = useState(false);

  // Progress bar only shows the 4 visible steps
  const visibleStepIdx = VISIBLE_STEPS.indexOf(step as any);
  const currentStepIdx = STEPS.indexOf(step);
  const progressPercent = step === 'request_endorsements'
    ? 100
    : ((visibleStepIdx + 1) / VISIBLE_STEPS.length) * 100;
  const justificationLength = justification.trim().length;
  const isJustificationValid = justificationLength >= 200 && justificationLength <= 10000;

  const selectedEmployee = employees.find(e => e.user_id === nomineeId);

  const eligibleEmployees = (nominatorRole === 'self'
    ? employees.filter(e => e.user_id === user?.id)
    : employees.filter(e => e.user_id !== user?.id)
  ).filter(e => !e.user_id || !alreadyNominatedIds.has(e.user_id));

  const isPreselectedAlreadyNominated = !!preselectedNomineeId && alreadyNominatedIds.has(preselectedNomineeId);

  // Extract allowAppeals from cycle fairness_config
  const allowAppeals = (() => {
    const fc = cycleConfig?.fairness_config as any;
    return fc?.auditSettings?.allowAppeals === true;
  })();

  const goNext = () => {
    const idx = currentStepIdx + 1;
    if (idx < STEPS.length) setStep(STEPS[idx]);
  };

  const goPrev = () => {
    const idx = currentStepIdx - 1;
    if (idx >= 0) setStep(STEPS[idx]);
  };

  const handleCriteriaSubmit = (evals: CriterionEvaluation[]) => {
    setCriteriaEvaluations(evals);
    goNext();
  };

  const handleSubmit = async () => {
    try {
      const nominee = employees.find(e => e.user_id === nomineeId);
      const input: CreateNominationInput = {
        cycle_id: cycleId,
        theme_id: themeId,
        nominee_id: nomineeId,
        nominee_department_id: nominee?.department_id || undefined,
        nominator_role: nominatorRole,
        headline: headline.trim(),
        justification: justification.trim(),
        specific_examples: examples.trim() ? examples.split('\n').filter(Boolean) : undefined,
        impact_metrics: impact.trim() ? impact.split('\n').filter(Boolean) : undefined,
      };
      const result = await createNomination.mutateAsync({ ...input, allowAppeals });
      setCreatedNominationId(result.id);
      setManagerApprovalPending((result as any).manager_approval_status === 'pending');

      // Save criteria evaluations
      if (criteriaEvaluations.length > 0 && tenantId) {
        const rows = criteriaEvaluations.map(ce => ({
          tenant_id: tenantId,
          nomination_id: result.id,
          criterion_id: ce.criterion_id,
          weight: ce.weight,
          justification: ce.justification.trim() || null,
        }));
        await saveCriteriaEvaluations.mutateAsync(rows);
      }

      // Auto-advance to endorsement step
      setStep('request_endorsements');
    } catch {
      // error handled by mutation
    }
  };

  const isQuotaExhausted =
    (nominatorRole === 'manager' && managerQuota && managerQuota.remaining <= 0) ||
    (nominatorRole === 'peer' && peerQuota && peerQuota.remaining <= 0);

  const canProceed = () => {
    if (isQuotaExhausted && step === 'select_nominee') return false;
    switch (step) {
      case 'select_nominee':
        return !!nomineeId && !!nominatorRole;
      case 'justification':
        return !!headline.trim() && isJustificationValid;
      case 'criteria_evaluation':
        return true;
      case 'review':
        return true;
      default:
        return false;
    }
  };

  return (
    <div className="space-y-4">
      {/* Progress — only show for main 4 steps */}
      {step !== 'request_endorsements' && (
        <div className="space-y-2">
          <div className="flex justify-between text-xs text-muted-foreground">
            {VISIBLE_STEPS.map((s, i) => (
              <span key={s} className={i <= visibleStepIdx ? 'text-primary font-medium' : ''}>
                {t(`recognition.nominations.steps.${s}`)}
              </span>
            ))}
          </div>
          <Progress value={progressPercent} className="h-1.5" />
        </div>
      )}

      {/* Quota indicator for managers */}
      {nominatorRole === 'manager' && managerQuota && step === 'select_nominee' && (
        <QuotaIndicator type="manager" used={managerQuota.used} total={managerQuota.total} teamSize={managerQuota.teamSize} />
      )}

      {/* Quota indicator for peers */}
      {nominatorRole === 'peer' && peerQuota && step === 'select_nominee' && (
        <QuotaIndicator type="peer" used={peerQuota.used} total={peerQuota.total} />
      )}

      {/* Step 1: Select Nominee */}
      {step === 'select_nominee' && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <User className="h-5 w-5" />
              {t('recognition.nominations.selectNominee')}
            </CardTitle>
            <CardDescription>{t('recognition.nominations.selectNomineeDesc')}</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label>{t('recognition.nominations.yourRole')}</Label>
              <Select value={nominatorRole} onValueChange={(v) => setNominatorRole(v as typeof nominatorRole)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="peer">{t('recognition.nominations.role.peer')}</SelectItem>
                  <SelectItem value="manager">{t('recognition.nominations.role.manager')}</SelectItem>
                  <SelectItem value="self">{t('recognition.nominations.role.self')}</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {isPreselectedAlreadyNominated && (
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>
                  {t('recognition.nominations.alreadyNominatedInCycle', 'You have already nominated this person in this cycle. Please select a different colleague.')}
                </AlertDescription>
              </Alert>
            )}

            <div className="space-y-2">
              <Label>{t('recognition.nominations.nominee')}</Label>
              <Select value={nomineeId} onValueChange={setNomineeId}>
                <SelectTrigger>
                  <SelectValue placeholder={t('recognition.nominations.selectEmployee')} />
                </SelectTrigger>
                <SelectContent>
              {eligibleEmployees.filter(e => !!e.user_id).map(emp => (
                    <SelectItem key={emp.user_id!} value={emp.user_id!}>
                      {emp.full_name} {emp.department ? `(${emp.department})` : ''}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {selectedEmployee && (
                <p className="text-xs text-muted-foreground">
                  {selectedEmployee.role_title || ''} — {selectedEmployee.email}
                </p>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Step 2: Justification */}
      {step === 'justification' && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <FileText className="h-5 w-5" />
              {t('recognition.nominations.writeJustification')}
            </CardTitle>
            <CardDescription>{t('recognition.nominations.justificationDesc')}</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label>{t('recognition.nominations.headline')}</Label>
              <Input
                value={headline}
                onChange={(e) => setHeadline(e.target.value)}
                placeholder={t('recognition.nominations.headlinePlaceholder')}
                maxLength={100}
              />
              <p className="text-xs text-muted-foreground text-end">{headline.length}/100</p>
            </div>

            <div className="space-y-2">
              <Label>{t('recognition.nominations.justification')}</Label>
              <Textarea
                value={justification}
                onChange={(e) => setJustification(e.target.value)}
                placeholder={t('recognition.nominations.justificationPlaceholder')}
                rows={6}
              />
              <div className="flex justify-between text-xs">
                <span className={!isJustificationValid && justificationLength > 0 ? 'text-destructive' : 'text-muted-foreground'}>
                  {t('recognition.nominations.charRange', { min: 200, max: 10000 })}
                </span>
                <span className={isJustificationValid ? 'text-chart-2' : 'text-muted-foreground'}>
                  {justificationLength}
                </span>
              </div>
            </div>

            <div className="space-y-2">
              <Label>{t('recognition.nominations.examples')}</Label>
              <Textarea
                value={examples}
                onChange={(e) => setExamples(e.target.value)}
                placeholder={t('recognition.nominations.examplesPlaceholder')}
                rows={3}
              />
            </div>

            <div className="space-y-2">
              <Label>{t('recognition.nominations.impactMetrics')}</Label>
              <Textarea
                value={impact}
                onChange={(e) => setImpact(e.target.value)}
                placeholder={t('recognition.nominations.impactPlaceholder')}
                rows={2}
              />
            </div>
          </CardContent>
        </Card>
      )}

      {/* Step 3: Criteria Evaluation */}
      {step === 'criteria_evaluation' && (
        <NominationCriteriaForm
          themeId={themeId}
          onSubmit={handleCriteriaSubmit}
          onBack={goPrev}
        />
      )}

      {/* Step 4: Review */}
      {step === 'review' && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <CheckCircle className="h-5 w-5" />
              {t('recognition.nominations.review')}
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="rounded-lg border border-border p-3 space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">{t('recognition.nominations.nominee')}</span>
                <span className="font-medium">{selectedEmployee?.full_name}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">{t('recognition.nominations.yourRole')}</span>
                <Badge variant="outline">{t(`recognition.nominations.role.${nominatorRole}`)}</Badge>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">{t('recognition.nominations.headline')}</span>
                <span className="font-medium text-end max-w-[60%]">{headline}</span>
              </div>
              {allowAppeals && (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">{t('recognition.nominations.managerApproval')}</span>
                  {selectedEmployee?.manager_id ? (
                    <Badge variant="secondary">{t('recognition.nominations.managerApprovalStatus.pending')}</Badge>
                  ) : (
                    <Badge variant="outline">{t('recognition.nominations.managerApprovalStatus.not_required')}</Badge>
                  )}
                </div>
              )}
              {allowAppeals && !selectedEmployee?.manager_id && (
                <Alert className="mt-2">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>
                    {t('recognition.nominations.noManagerNote', 'This nominee has no manager assigned — manager approval will be skipped.')}
                  </AlertDescription>
                </Alert>
              )}
            </div>
            <p className="text-sm text-muted-foreground line-clamp-4">{justification}</p>

            {/* Criteria evaluation summary */}
            {criteriaEvaluations.length > 0 && (
              <CriteriaWeightTable
                criteria={criteriaEvaluations.map(c => ({
                  name: c.name,
                  name_ar: c.name_ar,
                  description: c.description,
                  weight: c.weight,
                }))}
                label={t('recognition.criteriaEval.title')}
              />
            )}
          </CardContent>
        </Card>
      )}

      {/* Step 5: Request Endorsements (dedicated post-submission step) */}
      {step === 'request_endorsements' && createdNominationId && (
        <div className="space-y-4">
          <div className="text-center py-4">
            <CheckCircle className="h-10 w-10 text-chart-2 mx-auto mb-2" />
            <p className="font-medium text-lg">{t('recognition.nominations.submitted')}</p>
            <p className="text-sm text-muted-foreground mt-1">
              {t('recognition.endorsements.endorsementStepDescription')}
            </p>
          </div>

          <EndorsementRequestPicker
            nominationId={createdNominationId}
            nomineeId={nomineeId}
            managerApprovalPending={managerApprovalPending}
            onComplete={onComplete}
          />

          {/* Always show a Done button at the bottom */}
          <div className="flex justify-end">
            <Button variant="outline" onClick={onComplete}>
              {t('common.done')}
            </Button>
          </div>
        </div>
      )}

      {/* Navigation — skip for criteria_evaluation (has its own nav) and request_endorsements */}
      {step !== 'criteria_evaluation' && step !== 'request_endorsements' && (
        <div className="flex items-center justify-between">
          <Button
            variant="outline"
            onClick={() => {
              if (currentStepIdx === 0 && onBack) {
                onBack();
              } else {
                goPrev();
              }
            }}
            disabled={currentStepIdx === 0 && !onBack}
          >
            <ChevronLeft className="h-4 w-4 me-1 rtl:rotate-180" />
            {t('common.back')}
          </Button>

          {step === 'review' ? (
            <Button onClick={handleSubmit} disabled={!canProceed() || createNomination.isPending}>
              {t('recognition.nominations.submitNomination')}
            </Button>
          ) : (
            <Button onClick={goNext} disabled={!canProceed()}>
              {t('common.next')}
              <ChevronRight className="h-4 w-4 ms-1 rtl:rotate-180" />
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Label } from '@/shared/components/ui/label';
import { Badge } from '@/shared/components/ui/badge';
import { Alert, AlertDescription } from '@/shared/components/ui/alert';
import { CriterionScorer } from './CriterionScorer';
import { CriteriaWeightSlider } from './CriteriaWeightSlider';
import { VotingProgress } from './VotingProgress';
import type { Ballot } from '@/features/recognition/hooks/recognition/useVoting';
import { ChevronRight, ChevronLeft, Send, CheckCircle, AlertTriangle } from 'lucide-react';

interface VotingBoothProps {
  ballots: Ballot[];
  completedCount: number;
  totalCount: number;
  votingWeightAdjustmentLimit: number; // ±percentage
  onSubmit: (data: {
    nomination_id: string;
    theme_id: string;
    cycle_id: string;
    criteria_scores: Record<string, number>;
    justifications: Record<string, string>;
    confidence_level: 'high' | 'medium' | 'low';
    adjusted_weights: Record<string, { original: number; adjusted: number }>;
  }) => void;
  isSubmitting: boolean;
}

export function VotingBooth({ ballots, completedCount, totalCount, votingWeightAdjustmentLimit, onSubmit, isSubmitting }: VotingBoothProps) {
  const { t } = useTranslation();
  const [currentIdx, setCurrentIdx] = useState(0);
  const [scores, setScores] = useState<Record<string, number>>({});
  const [justifications, setJustifications] = useState<Record<string, string>>({});
  const [adjustedWeights, setAdjustedWeights] = useState<Record<string, number>>({});
  const [confidence, setConfidence] = useState<'high' | 'medium' | 'low'>('medium');

  const ballot = ballots[currentIdx];

  // Initialize scores and weights when ballot changes
  useEffect(() => {
    if (ballot && ballot.criteria.length > 0) {
      const initialScores: Record<string, number> = {};
      const initialWeights: Record<string, number> = {};
      ballot.criteria.forEach(c => {
        initialScores[c.id] = 3;
        initialWeights[c.id] = Math.round(c.weight * 100); // convert decimal to percentage
      });
      setScores(initialScores);
      setAdjustedWeights(initialWeights);
      setJustifications({});
      setConfidence('medium');
    }
  }, [ballot?.nomination_id]);

  const totalAdjustedWeight = useMemo(
    () => Object.values(adjustedWeights).reduce((sum, w) => sum + w, 0),
    [adjustedWeights]
  );
  const isWeightValid = Math.abs(totalAdjustedWeight - 100) < 0.5;

  if (!ballot) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center justify-center py-16 space-y-3">
          <CheckCircle className="h-12 w-12 text-primary" />
          <p className="text-lg font-medium">{t('recognition.voting.allDone')}</p>
          <p className="text-sm text-muted-foreground">{t('recognition.voting.allDoneDesc')}</p>
        </CardContent>
      </Card>
    );
  }

  const handleScoreChange = (criterionId: string, score: number) => {
    setScores(prev => ({ ...prev, [criterionId]: score }));
  };

  const handleJustificationChange = (criterionId: string, text: string) => {
    setJustifications(prev => ({ ...prev, [criterionId]: text }));
  };

  const handleWeightChange = (criterionId: string, weight: number) => {
    setAdjustedWeights(prev => ({ ...prev, [criterionId]: weight }));
  };

  const canSubmit = ballot.criteria.every(c => {
    const score = scores[c.id];
    if (!score) return false;
    if ((score === 1 || score === 5) && (!justifications[c.id] || justifications[c.id].length < 50)) return false;
    return true;
  }) && isWeightValid;

  const handleSubmit = () => {
    const weightData: Record<string, { original: number; adjusted: number }> = {};
    ballot.criteria.forEach(c => {
      weightData[c.id] = {
        original: Math.round(c.weight * 100),
        adjusted: adjustedWeights[c.id] ?? Math.round(c.weight * 100),
      };
    });

    onSubmit({
      nomination_id: ballot.nomination_id,
      theme_id: ballot.theme_id,
      cycle_id: ballot.cycle_id,
      criteria_scores: scores,
      justifications,
      confidence_level: confidence,
      adjusted_weights: weightData,
    });
    // Reset and advance
    setScores({});
    setJustifications({});
    setAdjustedWeights({});
    setConfidence('medium');
    if (currentIdx < ballots.length - 1) {
      setCurrentIdx(prev => prev + 1);
    }
  };

  return (
    <div className="space-y-4">
      <VotingProgress completed={completedCount} total={totalCount} currentIndex={currentIdx} />

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="text-lg">{ballot.nominee_name}</CardTitle>
              <CardDescription>{ballot.theme_name} — {ballot.headline}</CardDescription>
            </div>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Justification excerpt */}
          <div className="rounded-md bg-muted p-3 text-sm">
            <Label className="text-xs font-medium text-muted-foreground mb-1 block">
              {t('recognition.nominations.justification')}
            </Label>
            <p className="line-clamp-4">{ballot.justification}</p>
          </div>

          {/* Weight adjustment section */}
          {votingWeightAdjustmentLimit > 0 && (
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label className="text-sm font-semibold">{t('recognition.voting.adjustWeights')}</Label>
                <Badge variant={isWeightValid ? 'default' : 'destructive'}>
                  {t('recognition.criteria.totalWeight')}: {totalAdjustedWeight}%
                </Badge>
              </div>

              {!isWeightValid && (
                <Alert variant="destructive" className="py-2">
                  <AlertTriangle className="h-4 w-4" />
                  <AlertDescription className="text-xs">
                    {t('recognition.criteriaEval.mustEqual100')}
                  </AlertDescription>
                </Alert>
              )}

              {ballot.criteria.map(criterion => (
                <CriteriaWeightSlider
                  key={`w-${criterion.id}`}
                  criterionName={criterion.name}
                  criterionDescription={criterion.description}
                  originalWeight={Math.round(criterion.weight * 100)}
                  adjustedWeight={adjustedWeights[criterion.id] ?? Math.round(criterion.weight * 100)}
                  adjustmentLimit={votingWeightAdjustmentLimit}
                  onChange={(w) => handleWeightChange(criterion.id, w)}
                />
              ))}
            </div>
          )}

          {/* Criteria scorers */}
          <div className="space-y-3">
            <Label className="text-sm font-semibold">{t('recognition.voting.rateCriteria')}</Label>
            {ballot.criteria.map(criterion => (
              <CriterionScorer
                key={criterion.id}
                criterion={criterion}
                score={scores[criterion.id] || 3}
                justification={justifications[criterion.id] || ''}
                onScoreChange={(s) => handleScoreChange(criterion.id, s)}
                onJustificationChange={(t) => handleJustificationChange(criterion.id, t)}
              />
            ))}
          </div>

          {/* Confidence level */}
          <div className="space-y-1">
            <Label className="text-sm">{t('recognition.voting.confidence')}</Label>
            <Select value={confidence} onValueChange={(v) => setConfidence(v as any)}>
              <SelectTrigger className="w-48">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="high">{t('recognition.voting.confidenceHigh')}</SelectItem>
                <SelectItem value="medium">{t('recognition.voting.confidenceMedium')}</SelectItem>
                <SelectItem value="low">{t('recognition.voting.confidenceLow')}</SelectItem>
              </SelectContent>
            </Select>
          </div>

          {/* Navigation + Submit */}
          <div className="flex items-center justify-between pt-2">
            <Button
              variant="outline"
              size="sm"
              disabled={currentIdx === 0}
              onClick={() => setCurrentIdx(prev => prev - 1)}
            >
              <ChevronLeft className="h-4 w-4 rtl:-scale-x-100" />
              {t('common.previous')}
            </Button>

            <div className="flex gap-2">
              {currentIdx < ballots.length - 1 && (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentIdx(prev => prev + 1)}
                >
                  {t('recognition.voting.skip')}
                  <ChevronRight className="h-4 w-4 rtl:-scale-x-100" />
                </Button>
              )}
              <Button
                size="sm"
                disabled={!canSubmit || isSubmitting}
                onClick={handleSubmit}
              >
                <Send className="h-4 w-4" />
                {t('recognition.voting.submitVote')}
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

