import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface Appeal {
  id: string;
  tenant_id: string;
  theme_results_id: string;
  appellant_id: string;
  grounds: string;
  description: string;
  new_evidence_attachment_ids: string[] | null;
  committee_review: Record<string, any> | null;
  submitted_at: string;
  resolved_at: string | null;
  deleted_at: string | null;
}

type AppealGrounds = 'procedural_error' | 'new_evidence' | 'bias_allegation' | 'scoring_discrepancy';

interface SubmitAppealInput {
  theme_results_id: string;
  grounds: AppealGrounds;
  description: string;
}

export function useAppeals(cycleId?: string) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: appeals = [], isPending } = useQuery({
    queryKey: ['appeals', tenantId, cycleId],
    queryFn: async () => {
      if (!cycleId) return [];
      // Get theme_results for this cycle first
      const { data: results } = await supabase
        .from('theme_results')
        .select('id')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (!results?.length) return [];
      const { data, error } = await supabase
        .from('appeals')
        .select('*')
        .in('theme_results_id', results.map(r => r.id))
        .is('deleted_at', null)
        .order('submitted_at', { ascending: false });
      if (error) throw error;
      return (data || []) as unknown as Appeal[];
    },
    enabled: !!tenantId && !!cycleId,
  });

  const submitAppeal = useMutation({
    mutationFn: async (input: SubmitAppealInput) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');
      const { data, error } = await supabase
        .from('appeals')
        .insert({
          tenant_id: tenantId,
          theme_results_id: input.theme_results_id,
          appellant_id: user.id,
          grounds: input.grounds,
          description: input.description,
        })
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['appeals'] });
      toast.success(t('recognition.appeals.submitSuccess'));
    },
    onError: () => toast.error(t('recognition.appeals.submitError')),
  });

  const resolveAppeal = useMutation({
    mutationFn: async ({ id, review }: { id: string; review: Record<string, any> }) => {
      const { error } = await supabase
        .from('appeals')
        .update({
          committee_review: review,
          resolved_at: new Date().toISOString(),
        })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['appeals'] });
      toast.success(t('recognition.appeals.resolveSuccess'));
    },
    onError: () => toast.error(t('recognition.appeals.resolveError')),
  });

  return { appeals, isPending, submitAppeal, resolveAppeal };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export type CycleStatus = 'configuring' | 'nominating' | 'voting' | 'calculating' | 'announced' | 'archived';

export interface AwardCycle {
  id: string;
  tenant_id: string;
  name: string;
  name_ar: string | null;
  created_by: string;
  status: CycleStatus;
  nomination_start: string;
  nomination_end: string;
  peer_endorsement_end: string;
  voting_start: string;
  voting_end: string;
  audit_review_days: number;
  announcement_date: string;
  fairness_config: Record<string, any>;
  points_config: Record<string, number>;
  stats: Record<string, any>;
  shortlist_count: number;
  require_acknowledgment: boolean;
  created_at: string;
  updated_at: string;
  deleted_at: string | null;
}

export interface CreateCycleInput {
  name: string;
  name_ar?: string;
  nomination_start: string;
  nomination_end: string;
  peer_endorsement_end: string;
  voting_start: string;
  voting_end: string;
  audit_review_days?: number;
  announcement_date: string;
  fairness_config?: Record<string, any>;
  shortlist_count?: number;
  require_acknowledgment?: boolean;
}

const VALID_TRANSITIONS: Record<string, string[]> = {
  configuring: ['nominating'],
  nominating: ['voting'],
  voting: ['calculating'],
  calculating: ['announced'],
  announced: ['archived'],
};

export function useAwardCycles() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: cycles = [], isPending } = useQuery({
    queryKey: ['award-cycles', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('award_cycles')
        .select('*')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as AwardCycle[];
    },
    enabled: !!tenantId,
  });

  const createCycle = useMutation({
    mutationFn: async (input: CreateCycleInput) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');
      const { data, error } = await supabase
        .from('award_cycles')
        .insert({ ...input, tenant_id: tenantId, created_by: user.id })
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['award-cycles'] });
      toast.success(t('recognition.cycles.createSuccess'));
    },
    onError: () => toast.error(t('recognition.cycles.createError')),
  });

  const updateCycle = useMutation({
    mutationFn: async ({ id, ...updates }: Partial<AwardCycle> & { id: string }) => {
      const { data, error } = await supabase
        .from('award_cycles')
        .update(updates)
        .eq('id', id)
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['award-cycles'] });
      toast.success(t('recognition.cycles.updateSuccess'));
    },
    onError: () => toast.error(t('recognition.cycles.updateError')),
  });

  const advanceStatus = useMutation({
    mutationFn: async ({ id, currentStatus, newStatus }: { id: string; currentStatus: string; newStatus: CycleStatus }) => {
      if (!VALID_TRANSITIONS[currentStatus]?.includes(newStatus)) {
        throw new Error(`Invalid transition: ${currentStatus} → ${newStatus}`);
      }
      const { data, error } = await supabase
        .from('award_cycles')
        .update({ status: newStatus })
        .eq('id', id)
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['award-cycles'] });
      toast.success(t('recognition.cycles.statusAdvanced'));
    },
    onError: (e: Error) => toast.error(e.message),
  });

  const invalidateAllRecognition = () => {
    qc.invalidateQueries({ queryKey: ['award-cycles'] });
    qc.invalidateQueries({ queryKey: ['nominations'] });
    qc.invalidateQueries({ queryKey: ['my-nominations'] });
    qc.invalidateQueries({ queryKey: ['received-nominations'] });
    qc.invalidateQueries({ queryKey: ['votes'] });
    qc.invalidateQueries({ queryKey: ['endorsements'] });
    qc.invalidateQueries({ queryKey: ['award-themes'] });
    qc.invalidateQueries({ queryKey: ['judging-criteria'] });
    qc.invalidateQueries({ queryKey: ['theme-results'] });
    qc.invalidateQueries({ queryKey: ['pending-approvals'] });
  };

  const restoreCycle = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('award_cycles')
        .update({ deleted_at: null })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      invalidateAllRecognition();
      toast.success(t('recognition.cycles.restoreSuccess'));
    },
    onError: () => toast.error(t('recognition.cycles.restoreError')),
  });

  const deleteCycle = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('award_cycles')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
      return id;
    },
    onSuccess: (_data, deletedId) => {
      invalidateAllRecognition();
      toast.success(t('recognition.cycles.deleteSuccess'), {
        action: {
          label: t('recognition.cycles.undo'),
          onClick: () => restoreCycle.mutate(deletedId),
        },
        duration: 8000,
      });
    },
    onError: () => toast.error(t('recognition.cycles.deleteError')),
  });

  return { cycles, isPending, createCycle, updateCycle, advanceStatus, deleteCycle, restoreCycle };
}

