import { useMutation } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';

interface SendEndorsementInput {
  tenantId: string;
  nominationId: string;
  requestedUserIds: string[];
  requestedBy: string;
  currentUserName: string;
  managerApprovalPending?: boolean;
}

export function useEndorsementRequests() {
  const { t } = useTranslation();

  const sendRequests = useMutation({
    mutationFn: async ({
      tenantId,
      nominationId,
      requestedUserIds,
      requestedBy,
      currentUserName,
      managerApprovalPending,
    }: SendEndorsementInput) => {
      // Insert endorsement requests
      const rows = requestedUserIds.map(uid => ({
        tenant_id: tenantId,
        nomination_id: nominationId,
        requested_user_id: uid,
        requested_by: requestedBy,
      }));
      const { error } = await supabase.from('endorsement_requests').insert(rows as any);
      if (error) throw error;

      // Send notifications unless manager approval is pending
      if (!managerApprovalPending) {
        const { data: nomData } = await supabase
          .from('nominations')
          .select('headline')
          .eq('id', nominationId)
          .single();
        const headline = nomData?.headline || '';

        const notificationRows = requestedUserIds.map(uid => ({
          tenant_id: tenantId,
          user_id: uid,
          nomination_id: nominationId,
          type: 'endorsement_requested',
          title: t('notifications.endorsementRequested', { name: currentUserName }),
          body: t('notifications.endorsementRequestedBody', { headline: headline || '—' }),
        }));
        await supabase.from('recognition_notifications').insert(notificationRows as any);
      }
    },
    onSuccess: (_, variables) => {
      toast.success(
        variables.managerApprovalPending
          ? t('recognition.endorsements.endorsementsPendingApproval')
          : t('recognition.endorsements.requestsSent')
      );
    },
    onError: () => {
      toast.error(t('recognition.endorsements.requestError'));
    },
  });

  return { sendRequests };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface PeerEndorsement {
  id: string;
  tenant_id: string;
  nomination_id: string;
  endorser_id: string;
  endorser_department_id: string | null;
  relationship: string;
  confirmation_statement: string;
  additional_context: string | null;
  is_valid: boolean | null;
  validation_reason: string | null;
  submitted_at: string;
}

export interface CreateEndorsementInput {
  nomination_id: string;
  relationship: 'direct_colleague' | 'cross_functional' | 'client' | 'reports_to';
  confirmation_statement: string;
  additional_context?: string;
}

export function useEndorsements(nominationId?: string) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: endorsements = [], isPending } = useQuery({
    queryKey: ['endorsements', nominationId],
    queryFn: async () => {
      if (!nominationId) return [];
      const { data, error } = await supabase
        .from('peer_endorsements')
        .select('*')
        .eq('nomination_id', nominationId)
        .is('deleted_at', null)
        .order('submitted_at', { ascending: false });
      if (error) throw error;
      return data as unknown as PeerEndorsement[];
    },
    enabled: !!nominationId && !!tenantId,
  });

  // Nominations that need my endorsement — only those where I was specifically requested
  const { data: myEndorsementRequests = [], isPending: requestsPending } = useQuery({
    queryKey: ['my-endorsement-requests', user?.id, tenantId],
    queryFn: async () => {
      if (!user?.id || !tenantId) return [];

      // Find endorsement requests addressed to me
      const { data: requests, error: reqErr } = await supabase
        .from('endorsement_requests')
        .select('nomination_id')
        .eq('tenant_id', tenantId)
        .eq('requested_user_id', user.id)
        .eq('status', 'pending')
        .is('deleted_at', null);
      if (reqErr) throw reqErr;
      if (!requests?.length) return [];

      const nominationIds = requests.map(r => r.nomination_id);

      // Fetch those nominations
      const { data: nominations, error: nomErr } = await supabase
        .from('nominations')
        .select('id, nominee_id, nominator_id, theme_id, headline, justification, cycle_id, manager_approval_status')
        .in('id', nominationIds)
        .in('status', ['submitted', 'endorsed'])
        .in('manager_approval_status', ['approved', 'not_required'])
        .is('deleted_at', null);
      if (nomErr) throw nomErr;
      if (!nominations?.length) return [];

      // Filter out ones I've already endorsed
      const { data: myEndorsements } = await supabase
        .from('peer_endorsements')
        .select('nomination_id')
        .eq('endorser_id', user.id)
        .is('deleted_at', null);
      const endorsedSet = new Set(myEndorsements?.map(e => e.nomination_id) || []);

      return nominations.filter(n =>
        n.nominee_id !== user.id && !endorsedSet.has(n.id)
      );
    },
    enabled: !!user?.id && !!tenantId,
  });

  const submitEndorsement = useMutation({
    mutationFn: async (input: CreateEndorsementInput) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');

      const { data, error } = await supabase
        .from('peer_endorsements')
        .insert({
          ...input,
          tenant_id: tenantId,
          endorser_id: user.id,
        })
        .select()
        .single();
      if (error) throw error;

      // Check if nomination now has sufficient endorsements
      // Count endorsements that are not explicitly invalid (null = pending review = counted)
      const { count } = await supabase
        .from('peer_endorsements')
        .select('id', { count: 'exact', head: true })
        .eq('nomination_id', input.nomination_id)
        .neq('is_valid', false)
        .is('deleted_at', null);

      if ((count ?? 0) >= 2) {
        await supabase
          .from('nominations')
          .update({ endorsement_status: 'sufficient', status: 'endorsed' })
          .eq('id', input.nomination_id);
      }

      // Mark endorsement request as completed
      await supabase
        .from('endorsement_requests')
        .update({ status: 'completed', responded_at: new Date().toISOString() } as any)
        .eq('nomination_id', input.nomination_id)
        .eq('requested_user_id', user.id);

      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['endorsements'] });
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      qc.invalidateQueries({ queryKey: ['received-nominations'] });
      toast.success(t('recognition.endorsements.submitSuccess'));
    },
    onError: () => toast.error(t('recognition.endorsements.submitError')),
  });

  return {
    endorsements,
    myEndorsementRequests,
    isPending,
    requestsPending,
    submitEndorsement,
    validCount: endorsements.filter(e => e.is_valid !== false).length,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import type { Nomination } from './useNominations';

/**
 * Hook for managers to view and act on nominations pending their approval.
 * A nomination requires manager approval when the cycle has allowAppeals enabled.
 * The manager is the nominee's direct manager (employees.manager_id).
 */
export function useNominationApprovals() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  // Fetch nominations where current user is the nominee's manager and approval is pending
  const { data: pendingApprovals = [], isPending } = useQuery({
    queryKey: ['nomination-approvals', user?.id, tenantId],
    queryFn: async () => {
      if (!user?.id) return [];

      // 1. Get current user's employee record
      const { data: currentEmployee } = await supabase
        .from('employees')
        .select('id')
        .eq('user_id', user.id)
        .is('deleted_at', null)
        .maybeSingle();

      if (!currentEmployee) return [];

      // 2. Get user_ids of direct reports (employees where manager_id = current employee)
      const { data: directReports } = await supabase
        .from('employees')
        .select('user_id')
        .eq('manager_id', currentEmployee.id)
        .is('deleted_at', null);

      if (!directReports?.length) return [];

      const reportUserIds = directReports
        .map(e => e.user_id)
        .filter((id): id is string => !!id);

      if (!reportUserIds.length) return [];

      // 3. Fetch nominations where nominee_id is one of the direct reports and approval is pending
      const { data, error } = await supabase
        .from('nominations')
        .select('*')
        .eq('tenant_id', tenantId)
        .in('nominee_id', reportUserIds)
        .eq('manager_approval_status', 'pending')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data as unknown as Nomination[];
    },
    enabled: !!user?.id && !!tenantId && !!tenantId,
  });

  const approveNomination = useMutation({
    mutationFn: async ({ id, criteriaAdjustments, additionalEndorserIds }: { id: string; criteriaAdjustments?: Record<string, { weight: number; justification: string }>; additionalEndorserIds?: string[] }) => {
      if (!user?.id) throw new Error('Not authenticated');
      const updateData: Record<string, any> = {
        manager_approval_status: 'approved',
        manager_approved_by: user.id,
        manager_approval_at: new Date().toISOString(),
        status: 'endorsed',
        endorsement_status: 'sufficient',
      };
      if (criteriaAdjustments) {
        updateData.manager_criteria_adjustments = criteriaAdjustments;
      }
      const { error } = await supabase
        .from('nominations')
        .update(updateData)
        .eq('id', id);
      if (error) throw error;

      // Get tenant_id and nomination details for notifications
      const { data: currentEmp } = await supabase
        .from('employees')
        .select('tenant_id, full_name')
        .eq('user_id', user.id)
        .is('deleted_at', null)
        .maybeSingle();

      const { data: nom } = await supabase
        .from('nominations')
        .select('headline, nominator_id, nominee_id')
        .eq('id', id)
        .single();

      let nominatorName = '';
      if (nom?.nominator_id) {
        const { data: emp } = await supabase
          .from('employees')
          .select('full_name')
          .eq('user_id', nom.nominator_id)
          .is('deleted_at', null)
          .maybeSingle();
        nominatorName = emp?.full_name || '';
      }

      // Notify the nominee that their nomination was approved
      if (nom?.nominee_id && currentEmp?.tenant_id) {
        await supabase.from('recognition_notifications').insert({
          tenant_id: currentEmp.tenant_id,
          user_id: nom.nominee_id,
          nomination_id: id,
          type: 'nomination_approved',
          title: t('recognition.nominations.notifyNomineeApproved'),
          body: t('recognition.nominations.notifyNomineeApprovedBody', { headline: nom.headline || '' }),
        } as any);
      }

      // Insert additional endorsement requests from manager
      if (additionalEndorserIds?.length && currentEmp?.tenant_id) {
        const endorserRows = additionalEndorserIds.map(uid => ({
          tenant_id: currentEmp.tenant_id,
          nomination_id: id,
          requested_user_id: uid,
          requested_by: user.id,
        }));
        await supabase.from('endorsement_requests').insert(endorserRows as any);

        // Send notifications immediately (nomination is already approved)
        const endorserNotifs = additionalEndorserIds.map(uid => ({
          tenant_id: currentEmp.tenant_id,
          user_id: uid,
          nomination_id: id,
          type: 'endorsement_requested',
          title: currentEmp.full_name ? `${currentEmp.full_name} requested your endorsement` : 'Endorsement requested',
          body: nom?.headline ? `Please review and endorse the nomination for "${nom.headline}"` : '',
        }));
        await supabase.from('recognition_notifications').insert(endorserNotifs as any);
      }

      // Send endorsement notifications for any existing pending requests
      const { data: pendingRequests } = await supabase
        .from('endorsement_requests')
        .select('requested_user_id, nomination_id')
        .eq('nomination_id', id)
        .eq('status', 'pending')
        .is('deleted_at', null);

      if (pendingRequests?.length && currentEmp?.tenant_id) {
        // Exclude the additional endorsers we just notified
        const alreadyNotified = new Set(additionalEndorserIds || []);
        const toNotify = pendingRequests.filter(r => !alreadyNotified.has(r.requested_user_id));

        if (toNotify.length) {
          const notifRows = toNotify.map(r => ({
            tenant_id: currentEmp.tenant_id,
            user_id: r.requested_user_id,
            nomination_id: id,
            type: 'endorsement_requested',
            title: nominatorName ? `${nominatorName} requested your endorsement` : 'Endorsement requested',
            body: nom?.headline ? `Please review and endorse the nomination for "${nom.headline}"` : '',
          }));
          await supabase.from('recognition_notifications').insert(notifRows as any);
        }
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['nomination-approvals'] });
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      toast.success(t('recognition.nominations.managerApproved'));
    },
    onError: () => toast.error(t('recognition.nominations.submitError')),
  });

  const rejectNomination = useMutation({
    mutationFn: async ({ id, reason }: { id: string; reason: string }) => {
      if (!user?.id) throw new Error('Not authenticated');
      const { error } = await supabase
        .from('nominations')
        .update({
          manager_approval_status: 'rejected',
          manager_approved_by: user.id,
          manager_approval_at: new Date().toISOString(),
          manager_rejection_reason: reason,
        })
        .eq('id', id);
      if (error) throw error;

      // Notify the nominee that their nomination was rejected
      const { data: nom } = await supabase
        .from('nominations')
        .select('headline, nominee_id')
        .eq('id', id)
        .single();

      const { data: currentEmp } = await supabase
        .from('employees')
        .select('tenant_id')
        .eq('user_id', user.id)
        .is('deleted_at', null)
        .maybeSingle();

      if (nom?.nominee_id && currentEmp?.tenant_id) {
        await supabase.from('recognition_notifications').insert({
          tenant_id: currentEmp.tenant_id,
          user_id: nom.nominee_id,
          nomination_id: id,
          type: 'nomination_rejected',
          title: t('recognition.nominations.notifyNomineeRejected'),
          body: t('recognition.nominations.notifyNomineeRejectedBody', { headline: nom.headline || '' }),
        } as any);
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['nomination-approvals'] });
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      toast.success(t('recognition.nominations.managerRejected'));
    },
    onError: () => toast.error(t('recognition.nominations.submitError')),
  });

  return { pendingApprovals, isPending, approveNomination, rejectNomination };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface Nomination {
  id: string;
  tenant_id: string;
  cycle_id: string;
  theme_id: string;
  nominee_id: string;
  nominee_department_id: string | null;
  nominee_tenure_months: number | null;
  nominator_id: string;
  nominator_role: string;
  nominator_department_id: string | null;
  headline: string;
  justification: string;
  specific_examples: string[] | null;
  impact_metrics: string[] | null;
  cross_department_evidence: Record<string, any> | null;
  manager_assessment: Record<string, any> | null;
  ai_analysis: Record<string, any> | null;
  endorsement_status: string;
  status: string;
  submitted_at: string | null;
  created_at: string;
  updated_at: string;
  deleted_at: string | null;
  manager_approval_status: string;
  manager_approved_by: string | null;
  manager_approval_at: string | null;
  manager_rejection_reason: string | null;
}

export interface CreateNominationInput {
  cycle_id: string;
  theme_id: string;
  nominee_id: string;
  nominee_department_id?: string;
  nominator_role: 'manager' | 'peer' | 'self';
  headline: string;
  justification: string;
  specific_examples?: string[];
  impact_metrics?: string[];
  cross_department_evidence?: Record<string, any>;
}

export function useNominations(cycleId?: string, themeId?: string) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: nominations = [], isPending } = useQuery({
    queryKey: ['nominations', tenantId, cycleId, themeId],
    queryFn: async () => {
      let query = supabase
        .from('nominations')
        .select('*')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (cycleId) query = query.eq('cycle_id', cycleId);
      if (themeId) query = query.eq('theme_id', themeId);

      const { data, error } = await query;
      if (error) throw error;
      return data as unknown as Nomination[];
    },
    enabled: !!tenantId,
  });

  // Nominations sent by current user
  const { data: myNominations = [], isPending: myPending } = useQuery({
    queryKey: ['my-nominations', user?.id, tenantId],
    queryFn: async () => {
      if (!user?.id) return [];
      const { data, error } = await supabase
        .from('nominations')
        .select('*')
        .eq('nominator_id', user.id)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as unknown as Nomination[];
    },
    enabled: !!user?.id && !!tenantId,
  });

  // Nominations where current user is nominee
  const { data: receivedNominations = [], isPending: receivedPending } = useQuery({
    queryKey: ['received-nominations', user?.id, tenantId],
    queryFn: async () => {
      if (!user?.id) return [];
      const { data, error } = await supabase
        .from('nominations')
        .select('*')
        .eq('nominee_id', user.id)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as unknown as Nomination[];
    },
    enabled: !!user?.id && !!tenantId,
  });

  const createNomination = useMutation({
    mutationFn: async (input: CreateNominationInput & { allowAppeals?: boolean }) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');
      const { allowAppeals, ...rest } = input;

      // Check if nominee has a manager assigned
      let approvalStatus: 'pending' | 'not_required' = 'not_required';
      if (allowAppeals) {
        const { data: nomineeEmp } = await supabase
          .from('employees')
          .select('manager_id')
          .eq('user_id', rest.nominee_id)
          .is('deleted_at', null)
          .maybeSingle();
        approvalStatus = nomineeEmp?.manager_id ? 'pending' : 'not_required';
      }

      // Guard: check nomination_end deadline
      const { data: cycle } = await supabase
        .from('award_cycles')
        .select('nomination_end')
        .eq('id', rest.cycle_id)
        .single();

      if (cycle && new Date(cycle.nomination_end) < new Date()) {
        throw new Error(t('recognition.nominations.periodClosed'));
      }

      const { data, error } = await supabase
        .from('nominations')
        .insert({
          ...rest,
          tenant_id: tenantId,
          nominator_id: user.id,
          nominator_department_id: null,
          status: 'submitted',
          submitted_at: new Date().toISOString(),
          manager_approval_status: approvalStatus,
        })
        .select()
        .single();
      if (error) throw error;

      // Notify the nominee that they've been nominated
      if (data && rest.nominee_id !== user.id) {
        const { data: nominatorEmp } = await supabase
          .from('employees')
          .select('full_name')
          .eq('user_id', user.id)
          .is('deleted_at', null)
          .maybeSingle();

        const nominatorName = nominatorEmp?.full_name || t('recognition.nominations.role.peer');

        await supabase.from('recognition_notifications').insert({
          tenant_id: tenantId,
          user_id: rest.nominee_id,
          nomination_id: data.id,
          type: 'nomination_received',
          title: t('recognition.nominations.notifyNomineeReceived', { nominator: nominatorName }),
          body: t('recognition.nominations.notifyNomineeReceivedBody', { headline: rest.headline }),
        } as any);
      }

      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      qc.invalidateQueries({ queryKey: ['manager-quota'] });
      qc.invalidateQueries({ queryKey: ['nomination-approvals'] });
      toast.success(t('recognition.nominations.submitSuccess'));
    },
    onError: () => toast.error(t('recognition.nominations.submitError')),
  });

  const updateNomination = useMutation({
    mutationFn: async ({ id, ...fields }: { id: string; headline?: string; justification?: string; specific_examples?: string[]; impact_metrics?: string[] }) => {
      const { data, error } = await supabase
        .from('nominations')
        .update({ ...fields, updated_at: new Date().toISOString() })
        .eq('id', id)
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      qc.invalidateQueries({ queryKey: ['received-nominations'] });
      toast.success(t('recognition.nominations.editSuccess'));
    },
    onError: () => toast.error(t('recognition.nominations.editError')),
  });

  const softDelete = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('nominations')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['nominations'] });
      qc.invalidateQueries({ queryKey: ['my-nominations'] });
      toast.success(t('recognition.nominations.deleteSuccess'));
    },
    onError: () => toast.error(t('recognition.nominations.deleteError')),
  });

  return {
    nominations,
    myNominations,
    receivedNominations,
    isPending,
    myPending,
    receivedPending,
    createNomination,
    updateNomination,
    softDelete,
  };
}

/** Manager quota hook: tracks how many nominations a manager has used for a theme */
export function useManagerQuota(themeId?: string) {
  const { user } = useAuth();
  const { tenantId } = useTenantId();

  return useQuery({
    queryKey: ['manager-quota', user?.id, themeId, tenantId],
    queryFn: async () => {
      if (!user?.id || !themeId) return { used: 0, total: Infinity, remaining: Infinity, teamSize: 0 };

      const { data: currentEmployee } = await supabase
        .from('employees')
        .select('id')
        .eq('user_id', user.id)
        .is('deleted_at', null)
        .maybeSingle();

      if (!currentEmployee) return { used: 0, total: Infinity, remaining: Infinity, teamSize: 0 };

      const { count: teamSize } = await supabase
        .from('employees')
        .select('id', { count: 'exact', head: true })
        .eq('manager_id', currentEmployee.id)
        .is('deleted_at', null);

      const size = teamSize ?? 0;
      const maxNominations = size >= 5 ? Math.floor(size * 0.3) : size;

      const { count: used } = await supabase
        .from('nominations')
        .select('id', { count: 'exact', head: true })
        .eq('nominator_id', user.id)
        .eq('theme_id', themeId)
        .eq('nominator_role', 'manager')
        .is('deleted_at', null);

      const usedCount = used ?? 0;
      return {
        used: usedCount,
        total: maxNominations,
        remaining: Math.max(0, maxNominations - usedCount),
        teamSize: size,
      };
    },
    enabled: !!user?.id && !!themeId && !!tenantId,
  });
}

const PEER_QUOTA_LIMIT = 3;

/** Peer quota hook: tracks how many nominations a peer has used for a theme */
export function usePeerQuota(themeId?: string) {
  const { user } = useAuth();
  const { tenantId } = useTenantId();

  return useQuery({
    queryKey: ['peer-quota', user?.id, themeId, tenantId],
    queryFn: async () => {
      if (!user?.id || !themeId) return { used: 0, total: PEER_QUOTA_LIMIT, remaining: PEER_QUOTA_LIMIT };

      const { count: used } = await supabase
        .from('nominations')
        .select('id', { count: 'exact', head: true })
        .eq('nominator_id', user.id)
        .eq('theme_id', themeId)
        .eq('nominator_role', 'peer')
        .is('deleted_at', null);

      const usedCount = used ?? 0;
      return {
        used: usedCount,
        total: PEER_QUOTA_LIMIT,
        remaining: Math.max(0, PEER_QUOTA_LIMIT - usedCount),
      };
    },
    enabled: !!user?.id && !!themeId && !!tenantId,
  });
}

