export function useRecognitionMonitor(cycleId: string) {
  const { tenantId } = useTenantId();

  // ── Cycle data (for allowAppeals check) ──
  const { data: cycleData } = useQuery({
    queryKey: ['recognition-monitor-cycle', cycleId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('award_cycles')
        .select('id, fairness_config')
        .eq('id', cycleId)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!cycleId,
  });

  const allowAppeals = !!(cycleData?.fairness_config as any)?.auditSettings?.allowAppeals;

  // ── Nominations data ──
  const { data: nominations = [], isPending: nomLoading } = useQuery({
    queryKey: ['recognition-monitor-nominations', cycleId, tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('nominations')
        .select('id, nominee_id, nominator_id, nominator_role, theme_id, nominee_department_id, nominator_department_id, status, submitted_at, headline, justification, specific_examples, impact_metrics, endorsement_status, manager_approval_status')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!cycleId && !!tenantId,
  });

  // ── Votes data ──
  const { data: votes = [], isPending: voteLoading } = useQuery({
    queryKey: ['recognition-monitor-votes', cycleId, tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('votes')
        .select('id, voter_id, voter_department_id, theme_id, voted_at')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!cycleId && !!tenantId,
  });

  // ── Departments (with division_id) ──
  const { data: departments = [] } = useQuery({
    queryKey: ['recognition-monitor-departments', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('departments')
        .select('id, name, name_ar, division_id')
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!tenantId,
  });

  // ── Divisions ──
  const { data: divisions = [] } = useQuery({
    queryKey: ['recognition-monitor-divisions', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('divisions')
        .select('id, name, name_ar')
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!tenantId,
  });

  // ── Sites (sections) ──
  const { data: sites = [] } = useQuery({
    queryKey: ['recognition-monitor-sites', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('sites')
        .select('id, name, name_ar')
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!tenantId,
  });

  // ── Employees per department (headcount) ──
  const { data: employees = [] } = useQuery({
    queryKey: ['recognition-monitor-employees', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('employees')
        .select('id, user_id, department_id, section_id, full_name')
        .is('deleted_at', null)
        .eq('status', 'active');
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!tenantId,
  });

  // ── Themes ──
  const { data: themes = [] } = useQuery({
    queryKey: ['recognition-monitor-themes', cycleId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('award_themes')
        .select('id, name, name_ar')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!cycleId,
  });

  // ── Lookup maps ──
  const deptMap = new Map(departments.map(d => [d.id, d]));
  const divMap = new Map(divisions.map(d => [d.id, d]));
  const siteMap = new Map(sites.map(s => [s.id, s]));
  const themeMap = new Map(themes.map(t => [t.id, t]));
  const empMap = new Map(employees.map(e => [e.user_id, e]));

  // Helper: resolve org names for an employee by user_id
  const resolveOrg = (userId: string) => {
    const emp = empMap.get(userId);
    const dept = emp?.department_id ? deptMap.get(emp.department_id) : null;
    const div = dept?.division_id ? divMap.get(dept.division_id) : null;
    const section = emp?.section_id ? siteMap.get(emp.section_id) : null;
    return {
      departmentName: dept?.name ?? '—',
      divisionName: div?.name ?? '—',
      sectionName: section?.name ?? '—',
    };
  };

  // Department nomination stats
  const deptNomMap = new Map<string, { nominations: Set<string>; nominees: Set<string> }>();
  for (const n of nominations) {
    const deptId = n.nominee_department_id ?? 'unknown';
    if (!deptNomMap.has(deptId)) deptNomMap.set(deptId, { nominations: new Set(), nominees: new Set() });
    const entry = deptNomMap.get(deptId)!;
    entry.nominations.add(n.id);
    entry.nominees.add(n.nominee_id);
  }

  const deptHeadcountMap = new Map<string, number>();
  for (const emp of employees) {
    const dId = emp.department_id ?? 'unknown';
    deptHeadcountMap.set(dId, (deptHeadcountMap.get(dId) ?? 0) + 1);
  }

  const deptNominationStats: DeptNominationStat[] = departments.map(d => ({
    departmentId: d.id,
    departmentName: d.name,
    nominationCount: deptNomMap.get(d.id)?.nominations.size ?? 0,
    uniqueNominees: deptNomMap.get(d.id)?.nominees.size ?? 0,
    headcount: deptHeadcountMap.get(d.id) ?? 0,
  }));

  // Theme distribution
  const themeDistribution: ThemeStat[] = themes.map(t => ({
    themeId: t.id,
    themeName: t.name,
    count: nominations.filter(n => n.theme_id === t.id).length,
  }));

  // Nominator role split
  const roleMap = new Map<string, number>();
  for (const n of nominations) {
    roleMap.set(n.nominator_role, (roleMap.get(n.nominator_role) ?? 0) + 1);
  }
  const roleSplit: RoleStat[] = Array.from(roleMap, ([role, count]) => ({ role, count }));

  // Parse JSON arrays safely
  const toStringArray = (val: unknown): string[] => {
    if (Array.isArray(val)) return val.map(String);
    return [];
  };

  // Recent nominations (latest 10) — enriched
  const recentNominations: RecentNomination[] = [...nominations]
    .sort((a, b) => (b.submitted_at ?? b.id).localeCompare(a.submitted_at ?? a.id))
    .slice(0, 10)
    .map(n => {
      const nomineeOrg = resolveOrg(n.nominee_id);
      const nominatorOrg = resolveOrg(n.nominator_id);
      return {
        id: n.id,
        nomineeName: empMap.get(n.nominee_id)?.full_name ?? 'Unknown',
        nominatorName: empMap.get(n.nominator_id)?.full_name ?? 'Unknown',
        nominatorRole: n.nominator_role,
        themeName: themeMap.get(n.theme_id)?.name ?? 'Unknown',
        status: n.status,
        submittedAt: n.submitted_at,
        nomineeDepartmentName: nomineeOrg.departmentName,
        nomineeDivisionName: nomineeOrg.divisionName,
        nomineeSectionName: nomineeOrg.sectionName,
        nominatorDepartmentName: nominatorOrg.departmentName,
        headline: n.headline ?? '',
        justification: n.justification ?? '',
        specificExamples: toStringArray(n.specific_examples),
        impactMetrics: toStringArray(n.impact_metrics),
        endorsementStatus: n.endorsement_status ?? 'pending',
        managerApprovalStatus: n.manager_approval_status ?? 'not_required',
      };
    });

  // Department voting stats
  const deptVoteMap = new Map<string, Set<string>>();
  for (const v of votes) {
    const deptId = v.voter_department_id ?? 'unknown';
    if (!deptVoteMap.has(deptId)) deptVoteMap.set(deptId, new Set());
    deptVoteMap.get(deptId)!.add(v.voter_id);
  }

  const deptVotingStats: DeptVotingStat[] = departments.map(d => ({
    departmentId: d.id,
    departmentName: d.name,
    eligibleVoters: deptHeadcountMap.get(d.id) ?? 0,
    votesCast: deptVoteMap.get(d.id)?.size ?? 0,
  }));

  // Theme voting progress
  const themeVotingStats = themes.map(t => ({
    themeId: t.id,
    themeName: t.name,
    totalVotes: votes.filter(v => v.theme_id === t.id).length,
  }));

  // Voting timeline
  const timelineMap = new Map<string, number>();
  for (const v of votes) {
    const date = v.voted_at?.slice(0, 10) ?? '';
    if (date) timelineMap.set(date, (timelineMap.get(date) ?? 0) + 1);
  }
  const votingTimeline: VoteTimelineDatum[] = Array.from(timelineMap, ([date, count]) => ({ date, count }))
    .sort((a, b) => a.date.localeCompare(b.date));

  // ── Approval Stats (only meaningful when allowAppeals is true) ──
  const approvalStatusMap = new Map<string, number>();
  for (const n of nominations) {
    const st = n.manager_approval_status ?? 'not_required';
    approvalStatusMap.set(st, (approvalStatusMap.get(st) ?? 0) + 1);
  }
  const approvalStats: ApprovalStat[] = Array.from(approvalStatusMap, ([status, count]) => ({ status, count }));

  const pendingApprovals = approvalStatusMap.get('pending') ?? 0;
  const approvedNominations = approvalStatusMap.get('approved') ?? 0;
  const rejectedByManager = approvalStatusMap.get('rejected') ?? 0;

  // Department approval breakdown
  const deptApprovalMap = new Map<string, { pending: number; approved: number; rejected: number; notRequired: number }>();
  for (const n of nominations) {
    const deptId = n.nominee_department_id ?? 'unknown';
    if (!deptApprovalMap.has(deptId)) deptApprovalMap.set(deptId, { pending: 0, approved: 0, rejected: 0, notRequired: 0 });
    const entry = deptApprovalMap.get(deptId)!;
    const st = n.manager_approval_status ?? 'not_required';
    if (st === 'pending') entry.pending++;
    else if (st === 'approved') entry.approved++;
    else if (st === 'rejected') entry.rejected++;
    else entry.notRequired++;
  }

  const deptApprovalStats: DeptApprovalStat[] = departments.map(d => ({
    departmentId: d.id,
    departmentName: d.name,
    ...(deptApprovalMap.get(d.id) ?? { pending: 0, approved: 0, rejected: 0, notRequired: 0 }),
  }));

  // KPIs
  const totalNominations = nominations.length;
  const uniqueNominees = new Set(nominations.map(n => n.nominee_id)).size;
  const participatingDepts = deptNominationStats.filter(d => d.nominationCount > 0).length;
  const missingDepts = deptNominationStats.filter(d => d.nominationCount === 0).length;
  const totalVotes = votes.length;
  const uniqueVoters = new Set(votes.map(v => v.voter_id)).size;
  const totalEligible = employees.length;
  const votingCompletion = totalEligible > 0 ? Math.round((uniqueVoters / totalEligible) * 100) : 0;

  return {
    isPending: nomLoading || voteLoading,
    allowAppeals,
    totalNominations,
    uniqueNominees,
    participatingDepts,
    missingDepts,
    totalVotes,
    uniqueVoters,
    votingCompletion,
    deptNominationStats,
    themeDistribution,
    roleSplit,
    recentNominations,
    deptVotingStats,
    themeVotingStats,
    votingTimeline,
    // Approval monitoring
    approvalStats,
    pendingApprovals,
    approvedNominations,
    rejectedByManager,
    deptApprovalStats,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useEffect } from 'react';

export interface RecognitionNotification {
  id: string;
  tenant_id: string;
  user_id: string;
  nomination_id: string | null;
  type: string;
  title: string;
  body: string | null;
  is_read: boolean;
  created_at: string;
  deleted_at: string | null;
}

export function useRecognitionNotifications() {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data: notifications = [], isPending } = useQuery({
    queryKey: ['recognition-notifications', user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('recognition_notifications')
        .select('*')
        .eq('user_id', user!.id)
        .is('deleted_at', null)
        .order('created_at', { ascending: false })
        .limit(50);
      if (error) throw error;
      return data as unknown as RecognitionNotification[];
    },
    enabled: !!user?.id,
  });

  const unreadCount = notifications.filter(n => !n.is_read).length;

  const markAsRead = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('recognition_notifications')
        .update({ is_read: true } as any)
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['recognition-notifications'] }),
  });

  const markAllAsRead = useMutation({
    mutationFn: async () => {
      const { error } = await supabase
        .from('recognition_notifications')
        .update({ is_read: true } as any)
        .eq('user_id', user!.id)
        .eq('is_read', false);
      if (error) throw error;
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['recognition-notifications'] }),
  });

  // Realtime subscription
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('recognition-notifications')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'recognition_notifications',
          filter: `user_id=eq.${user.id}`,
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ['recognition-notifications'] });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, queryClient]);

  return { notifications, unreadCount, isPending, markAsRead, markAllAsRead };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface RedemptionOption {
  id: string;
  tenant_id: string;
  name: string;
  name_ar: string | null;
  description: string | null;
  description_ar: string | null;
  category: string;
  points_cost: number;
  is_active: boolean | null;
  max_per_year: number | null;
  min_tenure_months: number | null;
  fulfillment_config: Record<string, any>;
  fulfillment_instructions: string | null;
  fulfillment_instructions_ar: string | null;
  created_at: string;
  deleted_at: string | null;
}

export interface RedemptionRequest {
  id: string;
  user_id: string;
  tenant_id: string;
  option_id: string;
  points_spent: number;
  status: string;
  tracking_number: string | null;
  fulfilled_at: string | null;
  hr_notes: string | null;
  rejection_reason: string | null;
  requested_at: string;
  deleted_at: string | null;
  redemption_options?: RedemptionOption;
}

export function useRedemptionCatalog() {
  const { tenantId } = useTenantId();

  const { data: options = [], isPending } = useQuery({
    queryKey: ['redemption-options', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('redemption_options')
        .select('*')
        .is('deleted_at', null)
        .eq('is_active', true)
        .order('points_cost', { ascending: true });
      if (error) throw error;
      return data as RedemptionOption[];
    },
    enabled: !!tenantId,
  });

  return { options, isPending };
}

export function useRedemptionRequests() {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: requests = [], isPending } = useQuery({
    queryKey: ['redemption-requests', tenantId, user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('redemption_requests')
        .select('*, redemption_options(*)')
        .is('deleted_at', null)
        .eq('user_id', user!.id)
        .order('requested_at', { ascending: false });
      if (error) throw error;
      return data as RedemptionRequest[];
    },
    enabled: !!tenantId && !!user?.id,
  });

  const redeem = useMutation({
    mutationFn: async ({ optionId, pointsCost, option }: { optionId: string; pointsCost: number; option?: RedemptionOption }) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');
      const { data, error } = await supabase.rpc('redeem_points', {
        p_user_id: user.id,
        p_tenant_id: tenantId,
        p_option_id: optionId,
        p_points_cost: pointsCost,
      });
      if (error) throw error;

      // Send redemption email (fire-and-forget)
      if (option) {
        const lang = i18n.language === 'ar' ? 'ar' : 'en';
        const instructions = lang === 'ar' && option.fulfillment_instructions_ar
          ? option.fulfillment_instructions_ar
          : option.fulfillment_instructions || '';
        const rewardName = lang === 'ar' && option.name_ar ? option.name_ar : option.name;

        const userEmail = user.email;
        if (userEmail) {
          supabase.functions.invoke('send-redemption-email', {
            body: {
              email: userEmail,
              rewardName,
              pointsSpent: pointsCost,
              fulfillmentInstructions: instructions,
              language: lang,
            },
          }).catch(err => console.error('Email send failed:', err));
        }
      }

      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['redemption-requests'] });
      qc.invalidateQueries({ queryKey: ['points-transactions'] });
      toast.success(t('recognition.points.redeemSuccess'));
    },
    onError: () => toast.error(t('recognition.points.redeemError')),
  });

  return { requests, isPending, redeem };
}

// Admin hooks
export function useAdminRedemptionOptions() {
  const { t } = useTranslation();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: options = [], isPending } = useQuery({
    queryKey: ['admin-redemption-options', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('redemption_options')
        .select('*')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as RedemptionOption[];
    },
    enabled: !!tenantId,
  });

  const createOption = useMutation({
    mutationFn: async (input: Omit<RedemptionOption, 'id' | 'created_at' | 'deleted_at' | 'tenant_id'>) => {
      if (!tenantId) throw new Error('Missing tenant');
      const { data, error } = await supabase
        .from('redemption_options')
        .insert({ ...input, tenant_id: tenantId })
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['admin-redemption-options'] });
      toast.success(t('recognition.points.optionCreated'));
    },
    onError: () => toast.error(t('recognition.points.optionCreateError')),
  });

  const deleteOption = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('redemption_options')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['admin-redemption-options'] });
      toast.success(t('recognition.points.optionDeleted'));
    },
    onError: () => toast.error(t('recognition.points.optionDeleteError')),
  });

  return { options, isPending, createOption, deleteOption };
}

export function useAdminRedemptionRequests() {
  const { t } = useTranslation();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: requests = [], isPending } = useQuery({
    queryKey: ['admin-redemption-requests', tenantId],
    queryFn: async () => {
      // Fetch requests
      const { data, error } = await supabase
        .from('redemption_requests')
        .select('*, redemption_options(*)')
        .is('deleted_at', null)
        .order('requested_at', { ascending: false });
      if (error) throw error;

      // Resolve user_id → employee name
      const userIds = [...new Set((data ?? []).map(r => r.user_id))];
      const { data: employees } = userIds.length > 0
        ? await supabase
            .from('employees')
            .select('user_id, full_name')
            .in('user_id', userIds)
            .is('deleted_at', null)
        : { data: [] };

      const nameMap = new Map((employees ?? []).map(e => [e.user_id, e.full_name]));

      return (data ?? []).map(r => ({
        ...r,
        employee_name: nameMap.get(r.user_id) ?? null,
      })) as (RedemptionRequest & { employee_name: string | null })[];
    },
    enabled: !!tenantId,
  });

  return { requests, isPending };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface ThemeResult {
  id: string;
  tenant_id: string;
  theme_id: string;
  cycle_id: string;
  first_place_nomination_id: string | null;
  second_place_nomination_id: string | null;
  third_place_nomination_id: string | null;
  fairness_report: Record<string, any>;
  appeal_status: string;
  published_at: string | null;
  created_at: string;
  deleted_at: string | null;
}

export interface NomineeRanking {
  id: string;
  tenant_id: string;
  theme_results_id: string;
  nomination_id: string;
  rank: number;
  raw_average_score: number | null;
  weighted_average_score: number | null;
  criterion_breakdown: Record<string, any>;
  total_votes: number | null;
  vote_distribution: Record<string, any> | null;
  confidence_interval: Record<string, any> | null;
  data_metrics_validation: Record<string, any> | null;
  created_at: string;
}

export function useResults(cycleId?: string) {
  const { t } = useTranslation();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: results = [], isPending: resultsLoading } = useQuery({
    queryKey: ['theme-results', tenantId, cycleId],
    queryFn: async () => {
      if (!cycleId) return [];
      const { data, error } = await supabase
        .from('theme_results')
        .select('*')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (error) throw error;
      return (data || []) as unknown as ThemeResult[];
    },
    enabled: !!tenantId && !!cycleId,
  });

  const resultIds = results.map(r => r.id);
  const { data: rankings = [], isPending: rankingsLoading } = useQuery({
    queryKey: ['nominee-rankings', tenantId, cycleId, resultIds],
    queryFn: async () => {
      if (!resultIds.length) return [];
      const { data, error } = await supabase
        .from('nominee_rankings')
        .select('*')
        .in('theme_results_id', resultIds)
        .is('deleted_at', null)
        .order('rank');
      if (error) throw error;
      return (data || []) as unknown as NomineeRanking[];
    },
    enabled: !!tenantId && !!cycleId && resultIds.length > 0,
  });

  const calculateResults = useMutation({
    mutationFn: async (targetCycleId: string) => {
      const { data, error } = await supabase.functions.invoke('calculate-recognition-results', {
        body: { cycle_id: targetCycleId },
      });
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['theme-results'] });
      qc.invalidateQueries({ queryKey: ['nominee-rankings'] });
      qc.invalidateQueries({ queryKey: ['award-cycles'] });
      toast.success(t('recognition.results.calculateSuccess'));
    },
    onError: () => toast.error(t('recognition.results.calculateError')),
  });

  const publishResults = useMutation({
    mutationFn: async (themeResultId: string) => {
      const { error } = await supabase
        .from('theme_results')
        .update({ published_at: new Date().toISOString() })
        .eq('id', themeResultId);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['theme-results'] });
      toast.success(t('recognition.results.publishSuccess'));
    },
    onError: () => toast.error(t('recognition.results.publishError')),
  });

  return { results, rankings, resultsLoading, rankingsLoading, calculateResults, publishResults };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { logger } from '@/shared/utils/logger';

export interface Vote {
  id: string;
  tenant_id: string;
  cycle_id: string;
  theme_id: string;
  nomination_id: string;
  voter_id: string;
  criteria_scores: Record<string, number>;
  calculated_weighted_score: number | null;
  applied_weight: number | null;
  justifications: Record<string, string> | null;
  confidence_level: string | null;
  voted_at: string;
}

export interface Ballot {
  nomination_id: string;
  theme_id: string;
  cycle_id: string;
  nominee_name: string;
  theme_name: string;
  headline: string;
  justification: string;
  criteria: {
    id: string;
    name: string;
    name_ar: string | null;
    description: string | null;
    weight: number;
    scoring_guide: Record<string, any>;
  }[];
  already_voted: boolean;
}

interface SubmitVoteInput {
  nomination_id: string;
  theme_id: string;
  cycle_id: string;
  criteria_scores: Record<string, number>;
  justifications: Record<string, string>;
  confidence_level: 'high' | 'medium' | 'low';
  adjusted_weights: Record<string, { original: number; adjusted: number }>;
}

function calculateVoterWeight(params: {
  isSameDepartment: boolean;
  isManager: boolean;
  totalPastVotes: number;
}): number {
  let weight = 1.0;
  if (params.isManager) weight += 0.3;
  if (params.isSameDepartment) weight += 0.2;
  weight += Math.min(params.totalPastVotes * 0.02, 0.2);
  return Math.round(weight * 100) / 100;
}

export function useVoting(cycleId?: string) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const qc = useQueryClient();

  const { data: ballots = [], isPending: ballotsPending } = useQuery({
    queryKey: ['voting-ballots', tenantId, cycleId],
    queryFn: async () => {
      if (!cycleId) return [];

      const { data: themes } = await supabase
        .from('award_themes')
        .select('id, name, name_ar')
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);

      if (!themes?.length) return [];
      const themeIds = themes.map(th => th.id);

      const { data: nominations } = await supabase
        .from('nominations')
        .select('id, nominee_id, theme_id, headline, justification, cycle_id')
        .in('theme_id', themeIds)
        .in('status', ['endorsed', 'shortlisted'])
        .is('deleted_at', null);

      if (!nominations?.length) return [];

      const { data: criteria } = await supabase
        .from('judging_criteria')
        .select('*')
        .in('theme_id', themeIds)
        .is('deleted_at', null)
        .order('sort_order');

      const { data: existingVotes } = await supabase
        .from('votes')
        .select('nomination_id')
        .eq('voter_id', user!.id)
        .in('nomination_id', nominations.map(n => n.id))
        .is('deleted_at', null);

      const votedSet = new Set(existingVotes?.map(v => v.nomination_id) || []);

      const nomineeIds = [...new Set(nominations.map(n => n.nominee_id))];
      const { data: employees } = await supabase
        .from('employees')
        .select('user_id, full_name')
        .in('user_id', nomineeIds);

      const nameMap = new Map(employees?.map(e => [e.user_id, e.full_name]) || []);
      const themeMap = new Map(themes.map(th => [th.id, th]));

      return nominations.map(nom => ({
        nomination_id: nom.id,
        theme_id: nom.theme_id,
        cycle_id: nom.cycle_id,
        nominee_name: nameMap.get(nom.nominee_id) || 'Unknown',
        theme_name: themeMap.get(nom.theme_id)?.name || '',
        headline: nom.headline || '',
        justification: nom.justification,
        criteria: (criteria || [])
          .filter(c => c.theme_id === nom.theme_id)
          .map(c => ({
            id: c.id,
            name: c.name,
            name_ar: c.name_ar,
            description: c.description,
            weight: c.weight,
            scoring_guide: c.scoring_guide as Record<string, any>,
          })),
        already_voted: votedSet.has(nom.id),
      })) as Ballot[];
    },
    enabled: !!tenantId && !!cycleId && !!user?.id,
  });

  const { data: myVotes = [], isPending: votesPending } = useQuery({
    queryKey: ['my-votes', tenantId, cycleId],
    queryFn: async () => {
      if (!cycleId) return [];
      const { data, error } = await supabase
        .from('votes')
        .select('*')
        .eq('voter_id', user!.id)
        .eq('cycle_id', cycleId)
        .is('deleted_at', null);
      if (error) throw error;
      return (data || []) as unknown as Vote[];
    },
    enabled: !!tenantId && !!cycleId && !!user?.id,
  });

  const submitVote = useMutation({
    mutationFn: async (input: SubmitVoteInput) => {
      if (!tenantId || !user?.id) throw new Error('Missing context');

      // Prevent duplicate vote
      const { count: existingCount } = await supabase
        .from('votes')
        .select('id', { count: 'exact', head: true })
        .eq('voter_id', user.id)
        .eq('nomination_id', input.nomination_id);
      if ((existingCount ?? 0) > 0) {
        throw new Error(t('recognition.voting.alreadyVoted', 'You have already voted for this nomination'));
      }

      // Validate extreme scores have justification
      for (const [criterionId, score] of Object.entries(input.criteria_scores)) {
        if ((score === 1 || score === 5) && (!input.justifications[criterionId] || input.justifications[criterionId].length < 50)) {
          throw new Error(t('recognition.voting.extremeScoreJustification'));
        }
      }

      // Calculate weighted total using adjusted weights
      const totalAdjustedWeight = Object.values(input.adjusted_weights).reduce((sum, w) => sum + w.adjusted, 0) || 100;
      const weightedTotal = Object.entries(input.criteria_scores).reduce((sum, [criterionId, score]) => {
        const w = input.adjusted_weights[criterionId]?.adjusted ?? 0;
        return sum + (score * w / totalAdjustedWeight);
      }, 0);

      const { count: pastVotes } = await supabase
        .from('votes')
        .select('*', { count: 'exact', head: true })
        .eq('voter_id', user.id);

      // Check if voter is in same department as nominee
      const { data: nomination } = await supabase
        .from('nominations')
        .select('nominee_id')
        .eq('id', input.nomination_id)
        .single();
      
      const voterDeptId = await supabase
        .from('employees')
        .select('department_id')
        .eq('user_id', user.id)
        .is('deleted_at', null)
        .maybeSingle();

      const nomineeDeptId = nomination?.nominee_id ? await supabase
        .from('employees')
        .select('department_id')
        .eq('user_id', nomination.nominee_id)
        .is('deleted_at', null)
        .maybeSingle() : null;

      const isSameDept = !!(voterDeptId?.data?.department_id && 
        nomineeDeptId?.data?.department_id && 
        voterDeptId.data.department_id === nomineeDeptId.data.department_id);

      // Check if voter has manager role
      const { data: managerRole } = await supabase
        .from('user_roles')
        .select('role')
        .eq('user_id', user.id)
        .eq('role', 'manager')
        .maybeSingle();

      const voterWeight = calculateVoterWeight({
        isSameDepartment: isSameDept,
        isManager: !!managerRole,
        totalPastVotes: pastVotes || 0,
      });

      const { data, error } = await supabase
        .from('votes')
        .insert({
          tenant_id: tenantId,
          cycle_id: input.cycle_id,
          theme_id: input.theme_id,
          nomination_id: input.nomination_id,
          voter_id: user.id,
          criteria_scores: input.criteria_scores,
          calculated_weighted_score: Math.round(weightedTotal * 100) / 100,
          applied_weight: voterWeight,
          justifications: input.justifications,
          confidence_level: input.confidence_level,
        })
        .select()
        .single();
      if (error) throw error;

      // Save vote criteria evaluations
      const voteEvalRows = Object.entries(input.adjusted_weights).map(([criterionId, w]) => ({
        tenant_id: tenantId,
        vote_id: data.id,
        criterion_id: criterionId,
        original_weight: w.original,
        adjusted_weight: w.adjusted,
        rating: input.criteria_scores[criterionId] ?? 3,
        justification: input.justifications[criterionId] || null,
      }));

      if (voteEvalRows.length > 0) {
        const { error: evalErr } = await supabase
          .from('vote_criteria_evaluations')
          .insert(voteEvalRows);
        if (evalErr) logger.warn('useVoting', 'Vote criteria eval insert failed:', evalErr.message);
      }

      // Award participation points for voting
      const { error: ptErr } = await supabase.from('points_transactions').insert({
        user_id: user!.id,
        tenant_id: tenantId,
        amount: 5,
        source_type: 'voter_participation',
        status: 'credited',
        description: 'Points earned for voting participation',
      });
      if (ptErr) logger.warn('useVoting', 'Voting points insert failed:', ptErr.message);

      return data;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['points-transactions'] });
      qc.invalidateQueries({ queryKey: ['voting-ballots'] });
      qc.invalidateQueries({ queryKey: ['my-votes'] });
      toast.success(t('recognition.voting.submitSuccess'));
    },
    onError: (e: Error) => toast.error(e.message || t('recognition.voting.submitError')),
  });

  const pendingBallots = ballots.filter(b => !b.already_voted);
  const completedCount = ballots.filter(b => b.already_voted).length;

  return {
    ballots,
    pendingBallots,
    completedCount,
    totalCount: ballots.length,
    myVotes,
    ballotsPending,
    votesPending,
    submitVote,
  };
}

