import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/shared/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Skeleton } from '@/shared/components/ui/skeleton';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/shared/components/ui/dropdown-menu';
import { Plus, Trophy, Calendar, MoreVertical, Pencil, Trash2, ChevronRight } from 'lucide-react';
import { useAwardCycles, type AwardCycle, type CycleStatus } from '@/features/recognition/hooks/recognition/useAwardCycles';
import { CycleStatusBadge } from '@/features/recognition/components/CycleStatusBadge';
import { CycleTimeline } from '@/features/recognition/components/CycleTimeline';
import { CycleBuilder } from '@/features/recognition/components/CycleBuilder';
import { CycleEditDialog } from '@/features/recognition/components/CycleEditDialog';
import { CycleDeleteDialog } from '@/features/recognition/components/CycleDeleteDialog';
import { ConfirmDialog } from '@/shared/dialogs/ConfirmDialog';
import { useConfirmDelete } from '@/shared/dialogs/useConfirmDelete';
import { isInProcessStatus, getImpactWarning, getNextStatus } from '@/shared/utils/recognition-utils';
import { format } from 'date-fns';

export default function RecognitionManagement() {
  const { t } = useTranslation();
  const { cycles, isPending, deleteCycle, advanceStatus } = useAwardCycles();
  const [showBuilder, setShowBuilder] = useState(false);
  const [editingCycle, setEditingCycle] = useState<AwardCycle | null>(null);

  // Impact alert state for in-process edit/delete
  const [impactAction, setImpactAction] = useState<{ type: 'edit' | 'delete'; cycle: AwardCycle } | null>(null);

  // Advance status confirmation
  const [advanceTarget, setAdvanceTarget] = useState<{ cycle: AwardCycle; nextStatus: CycleStatus } | null>(null);

  const { isOpen: isDeleteOpen, deleteId, requestDelete, setOpen: setDeleteOpen, confirm: confirmDeleteAction } = useConfirmDelete();

  const handleEditClick = (cycle: AwardCycle) => {
    if (isInProcessStatus(cycle.status)) {
      setImpactAction({ type: 'edit', cycle });
    } else {
      setEditingCycle(cycle);
    }
  };

  const handleDeleteClick = (cycle: AwardCycle) => {
    if (isInProcessStatus(cycle.status)) {
      setImpactAction({ type: 'delete', cycle });
    } else {
      requestDelete(cycle.id);
    }
  };

  const handleImpactProceed = () => {
    if (!impactAction) return;
    if (impactAction.type === 'edit') {
      setEditingCycle(impactAction.cycle);
    } else {
      requestDelete(impactAction.cycle.id);
    }
    setImpactAction(null);
  };

  const handleAdvanceClick = (cycle: AwardCycle) => {
    const nextStatus = getNextStatus(cycle.status);
    if (nextStatus) {
      setAdvanceTarget({ cycle, nextStatus });
    }
  };

  const handleAdvanceConfirm = () => {
    if (!advanceTarget) return;
    advanceStatus.mutate({
      id: advanceTarget.cycle.id,
      currentStatus: advanceTarget.cycle.status,
      newStatus: advanceTarget.nextStatus,
    });
    setAdvanceTarget(null);
  };


  if (showBuilder) {
    return (
      <div className="p-6">
        <CycleBuilder onClose={() => setShowBuilder(false)} />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Trophy className="h-6 w-6 text-primary" />
            {t('recognition.title')}
          </h1>
          <p className="text-muted-foreground">{t('recognition.subtitle')}</p>
        </div>
        <Button onClick={() => setShowBuilder(true)}>
          <Plus className="h-4 w-4 me-2" />
          {t('recognition.cycles.create')}
        </Button>
      </div>

      {isPending ? (
        <div className="grid gap-4 md:grid-cols-2">
          {[1, 2].map(i => <Skeleton key={i} className="h-48" />)}
        </div>
      ) : cycles.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-16 text-center">
            <Trophy className="h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold">{t('recognition.cycles.empty')}</h3>
            <p className="text-sm text-muted-foreground mt-1 max-w-md">{t('recognition.cycles.emptyDescription')}</p>
            <Button className="mt-4" onClick={() => setShowBuilder(true)}>
              <Plus className="h-4 w-4 me-2" />
              {t('recognition.cycles.create')}
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 md:grid-cols-2">
          {cycles.map((cycle) => {
            const nextStatus = getNextStatus(cycle.status);
            return (
              <Card key={cycle.id} className="hover:shadow-md transition-shadow">
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between">
                    <div>
                      <CardTitle className="text-lg">{cycle.name}</CardTitle>
                      <CardDescription>{t('recognition.cycles.createdAt', { date: format(new Date(cycle.created_at), 'MMM d, yyyy') })}</CardDescription>
                    </div>
                    <div className="flex items-center gap-2">
                      <CycleStatusBadge status={cycle.status as any} />
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" size="icon" className="h-8 w-8">
                            <MoreVertical className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          {nextStatus && (
                            <>
                              <DropdownMenuItem onClick={() => handleAdvanceClick(cycle)}>
                                <ChevronRight className="h-4 w-4 me-2" />
                                {t('recognition.cycles.advanceTo', { status: t(`recognition.status.${nextStatus}`) })}
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                            </>
                          )}
                          <DropdownMenuItem onClick={() => handleEditClick(cycle)}>
                            <Pencil className="h-4 w-4 me-2" />
                            {t('recognition.cycles.edit')}
                          </DropdownMenuItem>
                          <DropdownMenuItem
                            className="text-destructive focus:text-destructive"
                            onClick={() => handleDeleteClick(cycle)}
                          >
                            <Trash2 className="h-4 w-4 me-2" />
                            {t('recognition.cycles.delete')}
                          </DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </div>
                  </div>
                </CardHeader>
                <CardContent>
                  <CycleTimeline cycle={cycle} />
                  <div className="flex items-center justify-between mt-4">
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <div className="flex items-center gap-1">
                        <Calendar className="h-3.5 w-3.5" />
                        <span>{t('recognition.cycles.auditDaysLabel', { days: cycle.audit_review_days })}</span>
                      </div>
                    </div>
                    {nextStatus && (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleAdvanceClick(cycle)}
                      >
                        <ChevronRight className="h-3.5 w-3.5 me-1" />
                        {t('recognition.cycles.advanceTo', { status: t(`recognition.status.${nextStatus}`) })}
                      </Button>
                    )}
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Edit Dialog */}
      <CycleEditDialog
        cycle={editingCycle}
        open={!!editingCycle}
        onOpenChange={(open) => { if (!open) setEditingCycle(null); }}
      />

      {/* Delete Confirm with Impact Counts */}
      <CycleDeleteDialog
        cycleId={deleteId}
        cycleName={cycles.find(c => c.id === deleteId)?.name ?? ''}
        open={isDeleteOpen}
        onOpenChange={setDeleteOpen}
        onConfirm={() => confirmDeleteAction((id) => deleteCycle.mutate(id))}
        loading={deleteCycle.isPending}
      />

      {/* Impact Alert for in-process cycles */}
      <ConfirmDialog
        open={!!impactAction}
        onOpenChange={(open) => { if (!open) setImpactAction(null); }}
        title={t('recognition.cycles.impactAlert.title')}
        description={
          impactAction
            ? `${impactAction.type === 'edit'
                ? t('recognition.cycles.impactAlert.editDescription')
                : t('recognition.cycles.impactAlert.deleteDescription')
              } ${getImpactWarning(impactAction.cycle.status, t) ?? ''}`
            : ''
        }
        confirmLabel={t('recognition.cycles.impactAlert.proceed')}
        cancelLabel={t('recognition.cycles.impactAlert.cancel')}
        onConfirm={handleImpactProceed}
        destructive={impactAction?.type === 'delete'}
      />

      {/* Advance Status Confirm */}
      <ConfirmDialog
        open={!!advanceTarget}
        onOpenChange={(open) => { if (!open) setAdvanceTarget(null); }}
        title={t('recognition.cycles.confirmAdvance')}
        description={
          advanceTarget
            ? t('recognition.cycles.confirmAdvanceDescription', {
                status: t(`recognition.status.${advanceTarget.nextStatus}`),
              })
            : ''
        }
        confirmLabel={t('recognition.cycles.advanceTo', {
          status: advanceTarget ? t(`recognition.status.${advanceTarget.nextStatus}`) : '',
        })}
        onConfirm={handleAdvanceConfirm}
        loading={advanceStatus.isPending}
        destructive={false}
      />
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Label } from '@/shared/components/ui/label';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { VotingBooth } from '@/features/recognition/components/VotingBooth';
import { useVoting } from '@/features/recognition/hooks/recognition/useVoting';
import { useAwardCycles } from '@/features/recognition/hooks/recognition/useAwardCycles';
import { Vote } from 'lucide-react';

export default function VotingBoothPage() {
  const { t } = useTranslation();
  const { cycles, isPending: cyclesPending } = useAwardCycles();
  const votingCycles = cycles.filter(c => c.status === 'voting');
  const [selectedCycleId, setSelectedCycleId] = useState<string>('');

  // Auto-select if only one voting cycle
  const effectiveCycleId = selectedCycleId || (votingCycles.length === 1 ? votingCycles[0].id : '');

  const selectedCycle = cycles.find(c => c.id === effectiveCycleId);
  const fairnessConfig = selectedCycle?.fairness_config as Record<string, any> | null;
  const votingWeightAdjustmentLimit = (fairnessConfig?.votingWeightAdjustmentLimit as number) ?? 30;

  const {
    pendingBallots,
    completedCount,
    totalCount,
    ballotsPending,
    submitVote,
  } = useVoting(effectiveCycleId);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <Vote className="h-6 w-6" />
          {t('recognition.voting.title')}
        </h1>
        <p className="text-muted-foreground mt-1">{t('recognition.voting.subtitle')}</p>
      </div>

      {/* Cycle selector */}
      {cyclesPending ? (
        <Skeleton className="h-10 w-64" />
      ) : votingCycles.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center text-muted-foreground">
            {t('recognition.voting.noVotingCycles')}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {votingCycles.length > 1 && (
            <div className="space-y-1">
              <Label>{t('recognition.nominations.cycle')}</Label>
              <Select value={effectiveCycleId} onValueChange={setSelectedCycleId}>
                <SelectTrigger className="w-72">
                  <SelectValue placeholder={t('recognition.nominations.selectCycle')} />
                </SelectTrigger>
                <SelectContent>
                  {votingCycles.map(c => (
                    <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}

          {effectiveCycleId && (
            ballotsPending ? (
              <div className="space-y-3">
                <Skeleton className="h-6 w-48" />
                <Skeleton className="h-64 w-full" />
              </div>
            ) : (
              <VotingBooth
                ballots={pendingBallots}
                completedCount={completedCount}
                totalCount={totalCount}
                votingWeightAdjustmentLimit={votingWeightAdjustmentLimit}
                onSubmit={(data) => submitVote.mutate(data)}
                isSubmitting={submitVote.isPending}
              />
            )
          )}
        </div>
      )}
    </div>
  );
}

import { supabase } from '@/integrations/supabase/client';
import type { CriterionEvaluation } from '../components/CriteriaEvaluationForm';

export async function fetchEmployeeNames(userIds: string[]): Promise<Record<string, string>> {
  if (!userIds.length) return {};
  const { data, error } = await supabase
    .from('employees')
    .select('user_id, full_name')
    .in('user_id', userIds)
    .is('deleted_at', null);

  if (error) throw error;

  const map: Record<string, string> = {};
  data?.forEach(e => {
    if (e.user_id) map[e.user_id] = e.full_name;
  });
  return map;
}

export async function fetchNominationCriteriaEvaluations(nominationIds: string[]): Promise<Record<string, CriterionEvaluation[]>> {
  if (!nominationIds.length) return {};
  const { data, error } = await supabase
    .from('nomination_criteria_evaluations')
    .select('*, judging_criteria:criterion_id(name, name_ar, description)')
    .in('nomination_id', nominationIds)
    .is('deleted_at', null);

  if (error) throw error;

  const map: Record<string, CriterionEvaluation[]> = {};
  data?.forEach((row: any) => {
    if (!map[row.nomination_id]) map[row.nomination_id] = [];
    map[row.nomination_id].push({
      criterion_id: row.criterion_id,
      name: row.judging_criteria?.name || '',
      name_ar: row.judging_criteria?.name_ar || null,
      description: row.judging_criteria?.description || null,
      weight: Number(row.weight),
      justification: row.justification || '',
    });
  });
  return map;
}

export async function fetchUserCycleNominations(cycleId: string, userId: string) {
  const { data, error } = await supabase
    .from('nominations')
    .select('nominee_id')
    .eq('cycle_id', cycleId)
    .eq('nominator_id', userId)
    .is('deleted_at', null);
  if (error) throw error;
  return data || [];
}

export async function fetchCycleConfig(cycleId: string) {
  const { data, error } = await supabase
    .from('award_cycles')
    .select('fairness_config')
    .eq('id', cycleId)
    .is('deleted_at', null)
    .single();
  if (error) throw error;
  return data;
}

export async function fetchNomineeNamesForNominations(nominationIds: string[]): Promise<Record<string, string>> {
  if (!nominationIds.length) return {};
  const { data: noms, error: nomsError } = await supabase
    .from('nominations')
    .select('id, nominee_id')
    .in('id', nominationIds);
  if (nomsError) throw nomsError;
  if (!noms?.length) return {};

  const userIds = [...new Set(noms.map(n => n.nominee_id))];
  const { data: emps, error: empsError } = await supabase
    .from('employees')
    .select('user_id, full_name')
    .in('user_id', userIds);
  if (empsError) throw empsError;

  const nameMap = new Map(emps?.map(e => [e.user_id, e.full_name]) || []);
  const result: Record<string, string> = {};
  noms.forEach(n => { result[n.id] = nameMap.get(n.nominee_id) || 'Unknown'; });
  return result;
}

export async function fetchAwardThemeName(themeId: string): Promise<string | null> {
  const { data, error } = await supabase
    .from('award_themes')
    .select('name')
    .eq('id', themeId)
    .is('deleted_at', null)
    .single();
  if (error) throw error;
  return data?.name || null;
}

export async function fetchExistingEndorsers(nominationId: string): Promise<string[]> {
  const { data, error } = await supabase
    .from('endorsement_requests')
    .select('requested_user_id')
    .eq('nomination_id', nominationId)
    .is('deleted_at', null);
  if (error) throw error;
  return (data || []).map((r: any) => r.requested_user_id);
}

import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Switch } from '@/shared/components/ui/switch';
import { Label } from '@/shared/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Badge } from '@/shared/components/ui/badge';
import { Separator } from '@/shared/components/ui/separator';
import { ScrollArea } from '@/shared/components/ui/scroll-area';
