import { CALCULATION_METHODS } from '@/features/spiritual/hooks/spiritual/usePrayerTimes';
import { COUNTRIES, getCitiesForCountry } from '@/data/countryCities';

export function SpiritualPreferencesCard() {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.language === 'ar';
  const { preferences, isPending: isLoading, upsertPreferences } = useSpiritualPreferences();

  const selectedCountry = preferences?.country ?? '';
  const cities = useMemo(() => getCitiesForCountry(selectedCountry), [selectedCountry]);

  const handleToggle = (field: string, value: boolean) => {
    const updates: Record<string, any> = { [field]: value };
    // If disabling main toggle, disable all sub-toggles
    if (field === 'enabled' && !value) {
      updates.prayer_enabled = false;
      updates.quran_enabled = false;
      updates.fasting_enabled = false;
      updates.reminders_enabled = false;
    }
    upsertPreferences.mutate(updates);
  };

  const handleCountryChange = (value: string) => {
    // Clear city if switching countries
    const currentCity = preferences?.city ?? '';
    const newCities = getCitiesForCountry(value);
    const cityStillValid = newCities.some((c) => c.en === currentCity);
    const updates: Record<string, any> = { country: value };
    if (!cityStillValid) updates.city = '';
    upsertPreferences.mutate(updates);
  };

  const handleFieldChange = (field: string, value: string | number) => {
    upsertPreferences.mutate({ [field]: value } as any);
  };

  const isEnabled = preferences?.enabled ?? false;

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Moon className="h-5 w-5" />
          {t('spiritual.preferences.title')}
        </CardTitle>
        <CardDescription>{t('spiritual.preferences.description')}</CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Main toggle */}
        <div className="flex items-center justify-between">
          <div className="space-y-0.5">
            <Label className="text-base">{t('spiritual.preferences.enableToggle')}</Label>
            <p className="text-sm text-muted-foreground">{t('spiritual.preferences.enableDescription')}</p>
          </div>
          <Switch
            checked={isEnabled}
            onCheckedChange={(v) => handleToggle('enabled', v)}
            disabled={upsertPreferences.isPending}
          />
        </div>

        {isEnabled && (
          <>
            <Separator />

            {/* Sub-toggles */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <Label>{t('spiritual.preferences.prayerTracking')}</Label>
                <Switch
                  checked={preferences?.prayer_enabled ?? false}
                  onCheckedChange={(v) => handleToggle('prayer_enabled', v)}
                  disabled={upsertPreferences.isPending}
                />
              </div>

              <div className="flex items-center justify-between">
                <Label>{t('spiritual.preferences.quranEngagement')}</Label>
                <Switch
                  checked={preferences?.quran_enabled ?? false}
                  onCheckedChange={(v) => handleToggle('quran_enabled', v)}
                  disabled={upsertPreferences.isPending}
                />
              </div>

              <div className="flex items-center justify-between">
                <Label>{t('spiritual.preferences.sunnahFasting')}</Label>
                <Switch
                  checked={preferences?.fasting_enabled ?? false}
                  onCheckedChange={(v) => handleToggle('fasting_enabled', v)}
                  disabled={upsertPreferences.isPending}
                />
              </div>

              <div className="flex items-center justify-between">
                <div className="space-y-0.5">
                  <Label>{t('spiritual.preferences.spiritualReminders')}</Label>
                  <p className="text-xs text-muted-foreground">{t('spiritual.preferences.remindersDescription')}</p>
                </div>
                <Switch
                  checked={preferences?.reminders_enabled ?? false}
                  onCheckedChange={(v) => handleToggle('reminders_enabled', v)}
                  disabled={upsertPreferences.isPending}
                />
              </div>

              {preferences?.reminders_enabled && (
                <div className="space-y-2 ps-4 border-s-2 border-primary/20">
                  <Label className="text-sm">{t('spiritual.preferences.reminderIntensity')}</Label>
                  <Select
                    value={preferences?.reminder_intensity ?? 'light'}
                    onValueChange={(v) => handleFieldChange('reminder_intensity', v)}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="light">{t('spiritual.preferences.intensityLight')}</SelectItem>
                      <SelectItem value="moderate">{t('spiritual.preferences.intensityModerate')}</SelectItem>
                      <SelectItem value="high">{t('spiritual.preferences.intensityHigh')}</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              )}
            </div>

            <Separator />

            {/* Location settings */}
            <div className="space-y-4">
              <h4 className="text-sm font-medium flex items-center gap-2">
                <MapPin className="h-4 w-4" />
                {t('spiritual.preferences.locationSettings')}
              </h4>
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label>{t('spiritual.preferences.country')}</Label>
                  <Select
                    value={selectedCountry}
                    onValueChange={handleCountryChange}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue placeholder={t('spiritual.preferences.selectCountry')} />
                    </SelectTrigger>
                    <SelectContent>
                      <ScrollArea className="h-60">
                        {COUNTRIES.map((c) => (
                          <SelectItem key={c.code} value={c.code}>
                            {isRTL ? c.ar : c.en}
                          </SelectItem>
                        ))}
                      </ScrollArea>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>{t('spiritual.preferences.city')}</Label>
                  <Select
                    value={preferences?.city ?? ''}
                    onValueChange={(v) => handleFieldChange('city', v)}
                    disabled={!selectedCountry}
                  >
                    <SelectTrigger className="w-full">
                      <SelectValue placeholder={t('spiritual.preferences.selectCity')} />
