                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {CALCULATION_METHODS.map((m) => (
                      <SelectItem key={m.id} value={String(m.id)}>
                        {isRTL ? m.nameAr : m.name}
                      </SelectItem>
