                  </SelectContent>
                </Select>
              </div>
            </div>

            <Separator />

            {/* Legal disclaimer */}
            <p className="text-xs text-muted-foreground italic">
              {t('spiritual.preferences.disclaimer')}
            </p>
          </>
        )}
      </CardContent>
    </Card>
  );
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { toast } from 'sonner';

export interface FastingLog {
  id: string;
  user_id: string;
  fast_date: string;
  fast_type: string;
  completed: boolean;
  energy_rating: number | null;
  notes: string | null;
  created_at: string;
}

// Sunnah fasting types
export const FAST_TYPES = [
  { key: 'monday', labelEn: 'Monday', labelAr: 'الاثنين' },
  { key: 'thursday', labelEn: 'Thursday', labelAr: 'الخميس' },
  { key: 'white_days', labelEn: 'White Days (13-14-15)', labelAr: 'الأيام البيض (13-14-15)' },
  { key: 'shawwal', labelEn: '6 Days of Shawwal', labelAr: 'ست من شوال' },
  { key: 'arafah', labelEn: 'Day of Arafah', labelAr: 'يوم عرفة' },
  { key: 'ashura', labelEn: 'Day of Ashura', labelAr: 'يوم عاشوراء' },
  { key: 'voluntary', labelEn: 'Voluntary Fast', labelAr: 'صيام تطوعي' },
] as const;

export function useFastingLogs(dateRange?: { from: string; to: string }) {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  

  const today = new Date().toISOString().split('T')[0];
  const from = dateRange?.from ?? new Date(new Date().setDate(new Date().getDate() - 30)).toISOString().split('T')[0];
  const to = dateRange?.to ?? today;

  const { data: logs = [], isPending } = useQuery({
    queryKey: ['fasting-logs', user?.id, from, to],
    queryFn: async () => {
      if (!user?.id) return [];
      const { data, error } = await supabase
        .from('spiritual_fasting_logs')
        .select('*')
        .eq('user_id', user.id)
        .gte('fast_date', from)
        .lte('fast_date', to)
        .order('fast_date', { ascending: false });
      if (error) throw error;
      return (data ?? []) as unknown as FastingLog[];
    },
    enabled: !!user?.id,
  });

  const logFast = useMutation({
    mutationFn: async (input: {
      fast_date: string;
      fast_type: string;
      completed: boolean;
      energy_rating?: number;
      notes?: string;
    }) => {
      if (!user?.id) throw new Error('Not authenticated');
      const { data, error } = await supabase
        .from('spiritual_fasting_logs')
        .upsert(
          {
            user_id: user.id,
            fast_date: input.fast_date,
            fast_type: input.fast_type,
            completed: input.completed,
            energy_rating: input.energy_rating ?? null,
            notes: input.notes ?? null,
          },
          { onConflict: 'user_id,fast_date' }
        )
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['fasting-logs'] });
      toast.success('Fasting logged');
    },
    onError: (error: any) => {
      toast.error(error.message);
    },
  });

  const todayLog = logs.find(l => l.fast_date === today);
  const completedCount = logs.filter(l => l.completed).length;

  return { logs, isPending, logFast, todayLog, completedCount };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { toast } from 'sonner';

export interface QuranSession {
  id: string;
  user_id: string;
  duration_minutes: number;
  surah_name: string | null;
  juz_number: number | null;
  reflection_notes: string | null;
  ayahs_read: number | null;
  last_ayah_position: number | null;
  session_date: string;
  created_at: string;
}

export function useQuranSessions(dateRange?: { from: string; to: string }, surahFilter?: string) {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const today = new Date().toISOString().split('T')[0];
  const from = dateRange?.from ?? today;
  const to = dateRange?.to ?? today;

  const { data: sessions = [], isPending, isFetching } = useQuery({
    queryKey: ['quran-sessions', user?.id, from, to, surahFilter],
    queryFn: async () => {
      if (!user?.id) return [];
      let query = supabase
        .from('spiritual_quran_sessions')
        .select('*')
        .eq('user_id', user.id)
        .gte('session_date', from)
        .lte('session_date', to)
        .order('session_date', { ascending: false });
      if (surahFilter) {
        query = query.eq('surah_name', surahFilter);
      }
      const { data, error } = await query;
      if (error) throw error;
      return (data ?? []) as unknown as QuranSession[];
    },
    enabled: !!user?.id,
  });

  const logSession = useMutation({
    mutationFn: async (input: {
      duration_minutes: number;
      surah_name?: string;
      juz_number?: number;
      reflection_notes?: string;
      session_date?: string;
      ayahs_read?: number;
      last_ayah_position?: number;
    }) => {
      if (!user?.id) throw new Error('Not authenticated');
      const { data, error } = await supabase
        .from('spiritual_quran_sessions')
        .insert({
          user_id: user.id,
          duration_minutes: input.duration_minutes,
          surah_name: input.surah_name || null,
          juz_number: input.juz_number || null,
          reflection_notes: input.reflection_notes || null,
          session_date: input.session_date ?? today,
          ayahs_read: input.ayahs_read ?? 0,
          last_ayah_position: input.last_ayah_position ?? 0,
        })
        .select()
        .single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['quran-sessions'] });
      toast.success('Qur\'an session logged');
    },
    onError: (error: any) => {
      toast.error(error.message);
    },
  });

  const totalMinutes = sessions.reduce((sum, s) => sum + s.duration_minutes, 0);
  const totalSessions = sessions.length;

  return { sessions, isPending: isPending && isFetching, logSession, totalMinutes, totalSessions };
}

export function useLastQuranSession() {
  const { user } = useAuth();

  return useQuery({
    queryKey: ['quran-sessions', 'last', user?.id],
    queryFn: async () => {
      if (!user?.id) return null;
      const { data, error } = await supabase
        .from('spiritual_quran_sessions')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();
      if (error) throw error;
      return data as unknown as QuranSession | null;
    },
    enabled: !!user?.id,
  });
}

import { useQuery } from '@tanstack/react-query';

export interface QuranVerse {
  number: number;
  numberInSurah: number;
  text: string;
  translation?: string;
  juz: number;
  page: number;
}

export interface SurahMeta {
  number: number;
  name: string;
  englishName: string;
  englishNameTranslation: string;
  numberOfAyahs: number;
  revelationType: string;
}

export function useQuranSurahList() {
  return useQuery<SurahMeta[]>({
    queryKey: ['quran-surah-list'],
    queryFn: async () => {
      const res = await fetch('https://api.alquran.cloud/v1/surah');
      if (!res.ok) throw new Error('Failed to fetch surah list');
      const json = await res.json();
      return json.data;
    },
    staleTime: Infinity,
  });
}

export function useQuranSurah(surahNumber: number | null) {
  return useQuery<{ surah: SurahMeta; verses: QuranVerse[] }>({
    queryKey: ['quran-surah', surahNumber],
    queryFn: async () => {
      if (!surahNumber) throw new Error('No surah');
      // Fetch Arabic + English translation in parallel
      const [arRes, enRes] = await Promise.all([
        fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}`),
        fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}/en.sahih`),
      ]);
      if (!arRes.ok || !enRes.ok) throw new Error('Failed to fetch surah');
      const [arJson, enJson] = await Promise.all([arRes.json(), enRes.json()]);

      const arData = arJson.data;
      const enData = enJson.data;

      const verses: QuranVerse[] = arData.ayahs.map((ayah: any, i: number) => ({
        number: ayah.number,
        numberInSurah: ayah.numberInSurah,
        text: ayah.text,
        translation: enData.ayahs[i]?.text ?? '',
        juz: ayah.juz,
        page: ayah.page,
      }));

      return {
        surah: {
          number: arData.number,
          name: arData.name,
          englishName: arData.englishName,
          englishNameTranslation: arData.englishNameTranslation,
          numberOfAyahs: arData.numberOfAyahs,
          revelationType: arData.revelationType,
        },
        verses,
      };
    },
    enabled: !!surahNumber,
    staleTime: Infinity,
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { toast } from 'sonner';

export interface SpiritualPreferences {
  id: string;
  user_id: string;
  enabled: boolean;
  prayer_enabled: boolean;
  quran_enabled: boolean;
  fasting_enabled: boolean;
  reminders_enabled: boolean;
  reminder_intensity: string;
  city: string | null;
  country: string | null;
  latitude: number | null;
  longitude: number | null;
  calculation_method: number;
  created_at: string;
  updated_at: string;
}

export function useSpiritualPreferences() {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  

  const { data: preferences, isPending, isFetching } = useQuery({
    queryKey: ['spiritual-preferences', user?.id],
    queryFn: async () => {
      if (!user?.id) return null;
      const { data, error } = await supabase
        .from('spiritual_preferences')
        .select('*')
        .eq('user_id', user.id)
        .maybeSingle();
      if (error) throw error;
      return data as unknown as SpiritualPreferences | null;
    },
    enabled: !!user?.id,
  });

  const upsertPreferences = useMutation({
    mutationFn: async (updates: Partial<SpiritualPreferences>) => {
      if (!user?.id) throw new Error('Not authenticated');
      
      if (preferences?.id) {
        const { data, error } = await supabase
          .from('spiritual_preferences')
          .update(updates)
          .eq('id', preferences.id)
          .select()
          .single();
        if (error) throw error;
        return data;
      } else {
        const { data, error } = await supabase
          .from('spiritual_preferences')
          .insert({ user_id: user.id, ...updates })
          .select()
          .single();
        if (error) throw error;
        return data;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['spiritual-preferences'] });
    },
    onError: (error: any) => {
      toast.error(error.message);
    },
  });

  return {
    preferences,
    isPending: isPending && isFetching,
    upsertPreferences,
    isEnabled: preferences?.enabled ?? false,
    isPrayerEnabled: preferences?.enabled && preferences?.prayer_enabled,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export const SUNNAH_PRACTICES = [
  { key: 'fasting', emoji: '🍽️', labelEn: 'Fasting', labelAr: 'الصيام' },
  { key: 'adhkar_morning', emoji: '🌅', labelEn: 'Morning Adhkar', labelAr: 'أذكار الصباح' },
  { key: 'adhkar_evening', emoji: '🌙', labelEn: 'Evening Adhkar', labelAr: 'أذكار المساء' },
  { key: 'tahajjud', emoji: '🕌', labelEn: 'Tahajjud', labelAr: 'التهجد' },
  { key: 'duha', emoji: '☀️', labelEn: 'Duha Prayer', labelAr: 'صلاة الضحى' },
] as const;

export type PracticeKey = typeof SUNNAH_PRACTICES[number]['key'];

export interface SunnahLog {
  id: string;
  user_id: string;
  log_date: string;
  practice_type: string;
  completed: boolean;
  created_at: string;
}

export function useSunnahLogs() {
  const { user } = useAuth();
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const today = new Date().toISOString().split('T')[0];
  const thirtyDaysAgo = new Date(Date.now() - 30 * 86400000).toISOString().split('T')[0];

  const { data: logs = [], isPending } = useQuery({
    queryKey: ['sunnah-logs', user?.id, thirtyDaysAgo, today],
    queryFn: async () => {
      if (!user?.id) return [];
      const { data, error } = await supabase
        .from('spiritual_sunnah_logs')
        .select('*')
        .eq('user_id', user.id)
        .gte('log_date', thirtyDaysAgo)
        .lte('log_date', today)
        .order('log_date', { ascending: false });
      if (error) throw error;
      return (data ?? []) as unknown as SunnahLog[];
    },
    enabled: !!user?.id,
  });

  const togglePractice = useMutation({
    mutationFn: async ({ practice_type, completed }: { practice_type: string; completed: boolean }) => {
      if (!user?.id) throw new Error('Not authenticated');

      if (completed) {
        // Upsert as completed
        const { error } = await supabase
          .from('spiritual_sunnah_logs')
          .upsert(
            { user_id: user.id, log_date: today, practice_type, completed: true },
            { onConflict: 'user_id,log_date,practice_type' }
          );
        if (error) throw error;
      } else {
        // Delete the log entry to undo
        const { error } = await supabase
          .from('spiritual_sunnah_logs')
          .delete()
          .eq('user_id', user.id)
          .eq('log_date', today)
          .eq('practice_type', practice_type);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sunnah-logs'] });
    },
    onError: (error: any) => {
      toast.error(error.message);
    },
  });

  // Today's completed practices
  const todayLogs = logs.filter(l => l.log_date === today && l.completed);
  const todayCompleted = new Set(todayLogs.map(l => l.practice_type));

  // 30-day stats per practice
  const stats = SUNNAH_PRACTICES.map(p => ({
    key: p.key,
    count: logs.filter(l => l.practice_type === p.key && l.completed).length,
  }));

  const totalCompleted = logs.filter(l => l.completed).length;

  return { logs, isPending, togglePractice, todayCompleted, stats, totalCompleted };
}

