  }, [employeeId, defaultDepartmentId]);

  const handleSubmit = useCallback(async (asDraft: boolean) => {
    if (!title.trim() || !assigneeId) return;
    try {
      await createTaskAsync({
        title: title.trim(), title_ar: titleAr.trim() || null,
        description: description.trim() || null, employee_id: assigneeId,
        status: asDraft ? 'draft' : 'open', priority, visibility,
        due_date: dueDate?.toISOString() ?? null, scheduled_start: startDate?.toISOString() ?? null,
        estimated_minutes: estimatedMinutes ? parseInt(estimatedMinutes) : null,
        department_id: departmentId, initiative_id: defaultInitiativeId ?? null,
        objective_id: defaultObjectiveId ?? null, assignee_id: assigneeId,
        reviewer_id: reviewerId, approver_id: approverId,
        reminder_date: reminderDate?.toISOString() ?? null,
        tags: selectedTagIds.length > 0 ? selectedTagIds : undefined,
        created_by: employeeId,
      });
      resetForm(); onOpenChange(false);
    } catch {}
  }, [title, titleAr, description, assigneeId, priority, visibility, dueDate, startDate, estimatedMinutes, departmentId, defaultInitiativeId, defaultObjectiveId, reviewerId, approverId, reminderDate, selectedTagIds, employeeId, createTaskAsync, resetForm, onOpenChange]);

  const handleTemplateSelect = useCallback((tpl: any) => {
    setTitle(tpl.title);
    if (tpl.title_ar) setTitleAr(tpl.title_ar);
    if (tpl.description) setDescription(tpl.description);
    if (tpl.priority) setPriority(tpl.priority === 'critical' ? 0 : tpl.priority === 'high' ? 1 : tpl.priority === 'low' ? 3 : 2);
    if (tpl.visibility) setVisibility(tpl.visibility);
    if (tpl.estimated_minutes) setEstimatedMinutes(String(tpl.estimated_minutes));
    if (tpl.department_id) setDepartmentId(tpl.department_id);
    if (tpl.checklist_items?.length) {
      setChecklistItems(tpl.checklist_items.map((item: any, idx: number) => ({
        id: `tpl-${idx}`, title: typeof item === 'string' ? item : item.title || '',
        status: 'pending' as const, sort_order: idx,
      })));
    }
  }, []);

  const titleId = `${formId}-title`;
  const titleArId = `${formId}-title-ar`;
  const descId = `${formId}-desc`;
  const statusId = `${formId}-status`;
  const priorityId = `${formId}-priority`;
  const estMinId = `${formId}-est-min`;
  const visibilityId = `${formId}-visibility`;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] p-0 gap-0">
        <DialogHeader className="p-4 pb-2">
          <DialogTitle className="text-lg">{t('tasks.createTask')}</DialogTitle>
          <p className="text-xs text-muted-foreground">
            {t('tasks.createdBy')}: {employeeName || t('common.unknown')} • {lformat(new Date(), 'dd MMM yyyy • HH:mm')}
          </p>
        </DialogHeader>

        <Separator />

        <div className="flex flex-col md:flex-row flex-1 overflow-hidden">
          <ScrollArea className="flex-1 p-4 space-y-4 md:border-e">
            <TaskPrimaryForm
              titleId={titleId} titleArId={titleArId} descId={descId}
              title={title} titleAr={titleAr} description={description}
              onTitleChange={setTitle} onTitleArChange={setTitleAr} onDescriptionChange={setDescription}
              checklistItems={checklistItems} onChecklistChange={setChecklistItems}
              files={files} onFilesChange={setFiles} onTemplateSelect={handleTemplateSelect}
            />
          </ScrollArea>

          <ScrollArea className="w-full md:w-80 p-4 space-y-4">
            <TaskConfigPanel
              statusId={statusId} priorityId={priorityId} estMinId={estMinId} visibilityId={visibilityId}
              status={status} priority={priority} visibility={visibility}
              startDate={startDate} dueDate={dueDate} reminderDate={reminderDate}
              estimatedMinutes={estimatedMinutes}
              assigneeId={assigneeId} reviewerId={reviewerId} approverId={approverId}
              departmentId={departmentId} selectedTagIds={selectedTagIds} advancedOpen={advancedOpen}
              onStatusChange={setStatus} onPriorityChange={setPriority} onVisibilityChange={setVisibility}
              onStartDateChange={setStartDate} onDueDateChange={setDueDate} onReminderDateChange={setReminderDate}
              onEstimatedMinutesChange={setEstimatedMinutes}
              onAssigneeChange={setAssigneeId} onReviewerChange={setReviewerId} onApproverChange={setApproverId}
              onTagsChange={setSelectedTagIds} onAdvancedOpenChange={setAdvancedOpen}
            />
          </ScrollArea>
        </div>

        <Separator />

        <DialogFooter className="p-4 pt-3 gap-2">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isCreating}>{t('common.cancel')}</Button>
          <Button variant="secondary" onClick={() => handleSubmit(true)} disabled={isCreating || !title.trim()}>
            <Save className="h-4 w-4 me-1.5" />{t('tasks.saveDraft')}
          </Button>
          <Button onClick={() => handleSubmit(false)} disabled={isCreating || !title.trim() || !assigneeId}>
            <Send className="h-4 w-4 me-1.5" />{t('tasks.createTask')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useTaskDependencies } from '@/features/tasks/hooks/useTaskDependencies';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Link2, X, Plus, AlertTriangle, CheckCircle, ArrowRight } from 'lucide-react';
import { toast } from 'sonner';
import { useNavigate } from 'react-router-dom';

const STATUS_BADGE: Record<string, string> = {
  completed: 'bg-chart-1/10 text-chart-1',
  in_progress: 'bg-chart-2/10 text-chart-2',
  open: 'bg-chart-4/10 text-chart-4',
  blocked: 'bg-destructive/10 text-destructive',
};

export function TaskDependenciesPanel({ taskId }: { taskId: string }) {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { blockers, dependents, isPending, addDependency, removeDependency, isAdding, hasUnresolvedBlockers, useSearchTasks } = useTaskDependencies(taskId);
  const [search, setSearch] = useState('');
  const [depType, setDepType] = useState<string>('blocks');
  const [showAdd, setShowAdd] = useState(false);

  const { data: searchResults = [] } = useSearchTasks(search);

  const existingIds = new Set([...blockers.map(b => b.depends_on_task_id), ...dependents.map(d => d.task_id)]);
  const filteredResults = searchResults.filter(r => !existingIds.has(r.id));

  const handleAdd = (dependsOnId: string) => {
    addDependency(
      { dependsOnTaskId: dependsOnId, type: depType },
      {
        onSuccess: () => {
          setSearch('');
          toast.success(t('dependencies.added'));
        },
        onError: (e: any) => toast.error(e.message),
      },
    );
  };

  if (isPending) return <Skeleton className="h-32" />;

  return (
    <Card className="border-0">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="text-sm flex items-center gap-2">
            <Link2 className="h-4 w-4" />
            {t('dependencies.title')} ({blockers.length + dependents.length})
          </CardTitle>
          <Button variant="ghost" size="sm" className="h-7 text-xs" onClick={() => setShowAdd(!showAdd)}>
            <Plus className="h-3.5 w-3.5 me-1" />{t('dependencies.add')}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="space-y-3">
        {hasUnresolvedBlockers && (
          <div className="flex items-center gap-2 p-2 rounded-md bg-destructive/10 text-destructive text-xs">
            <AlertTriangle className="h-3.5 w-3.5" />
            {t('dependencies.unresolvedBlockers')}
          </div>
        )}

        {/* Add dependency */}
        {showAdd && (
          <div className="space-y-2 p-3 rounded-lg bg-muted/30">
            <div className="flex gap-2">
              <Select value={depType} onValueChange={setDepType}>
                <SelectTrigger className="w-[120px] h-8 text-xs"><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="blocks">{t('dependencies.types.blocks')}</SelectItem>
                  <SelectItem value="related">{t('dependencies.types.related')}</SelectItem>
                </SelectContent>
              </Select>
              <Input
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder={t('dependencies.searchPlaceholder')}
                className="h-8 text-xs flex-1"
              />
            </div>
            {filteredResults.length > 0 && (
              <div className="space-y-1 max-h-40 overflow-y-auto">
                {filteredResults.map(task => (
                  <button
                    key={task.id}
                    className="w-full flex items-center justify-between p-2 rounded hover:bg-muted text-start text-xs"
                    onClick={() => handleAdd(task.id)}
                    disabled={isAdding}
                  >
                    <span className="truncate">{task.title}</span>
                    <Badge className={`${STATUS_BADGE[task.status] ?? 'bg-muted text-muted-foreground'} text-2xs shrink-0`}>{task.status}</Badge>
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Blockers */}
        {blockers.length > 0 && (
          <div className="space-y-1">
            <span className="text-xs font-medium text-muted-foreground">{t('dependencies.blockedBy')}</span>
            {blockers.map(dep => {
              const task = dep.depends_on_task as any;
              const isResolved = task?.status === 'completed';
              return (
                <div key={dep.id} className="flex items-center gap-2 p-2 rounded-lg bg-muted/20 group">
                  {isResolved ? <CheckCircle className="h-3.5 w-3.5 text-chart-1 shrink-0" /> : <AlertTriangle className="h-3.5 w-3.5 text-destructive shrink-0" />}
                  <button className="text-xs text-start flex-1 truncate hover:underline" onClick={() => navigate(`/tasks/${task?.id}`)}>
                    {task?.title ?? dep.depends_on_task_id.slice(0, 8)}
                  </button>
                   <Badge variant="outline" className="text-2xs">{dep.dependency_type}</Badge>
                  <Button variant="ghost" size="icon" className="h-6 w-6 opacity-0 group-hover:opacity-100" onClick={() => removeDependency(dep.id)}>
                    <X className="h-3 w-3 text-destructive" />
                  </Button>
                </div>
              );
            })}
          </div>
        )}

        {/* Dependents */}
        {dependents.length > 0 && (
          <div className="space-y-1">
            <span className="text-xs font-medium text-muted-foreground">{t('dependencies.blocking')}</span>
            {dependents.map(dep => {
              const task = dep.dependent_task as any;
              return (
                <div key={dep.id} className="flex items-center gap-2 p-2 rounded-lg bg-muted/20 group">
                  <ArrowRight className="h-3.5 w-3.5 text-muted-foreground shrink-0 rtl:rotate-180" />
                  <button className="text-xs text-start flex-1 truncate hover:underline" onClick={() => navigate(`/tasks/${task?.id}`)}>
                    {task?.title ?? dep.task_id.slice(0, 8)}
                  </button>
                  <Badge variant="outline" className="text-2xs">{dep.dependency_type}</Badge>
                  <Button variant="ghost" size="icon" className="h-6 w-6 opacity-0 group-hover:opacity-100" onClick={() => removeDependency(dep.id)}>
                    <X className="h-3 w-3 text-destructive" />
                  </Button>
                </div>
              );
            })}
          </div>
        )}

        {blockers.length === 0 && dependents.length === 0 && !showAdd && (
          <p className="text-xs text-muted-foreground text-center py-4">{t('dependencies.empty')}</p>
        )}
      </CardContent>
    </Card>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/shared/components/ui/popover';
import { Plus, X, Tag } from 'lucide-react';
import { useTaskTags, type TaskTag } from '@/features/tasks/hooks/useTaskTags';

interface TaskTagPickerProps {
  selectedTagIds: string[];
  onChange: (tagIds: string[]) => void;
  disabled?: boolean;
}

const TAG_COLORS = ['#6366f1', '#ec4899', '#f59e0b', '#10b981', '#ef4444', '#3b82f6', '#8b5cf6', '#06b6d4'];

export function TaskTagPicker({ selectedTagIds, onChange, disabled }: TaskTagPickerProps) {
  const { t } = useTranslation();
  const { tags, createTagAsync } = useTaskTags();
  const [newTagName, setNewTagName] = useState('');
  const [selectedColor, setSelectedColor] = useState(TAG_COLORS[0]);
  const [open, setOpen] = useState(false);

  const selectedTags = tags.filter(tag => selectedTagIds.includes(tag.id));
  const availableTags = tags.filter(tag => !selectedTagIds.includes(tag.id));

  const handleCreateTag = async () => {
    if (!newTagName.trim()) return;
    try {
      const newTag = await createTagAsync({ name: newTagName.trim(), color: selectedColor });
      if (newTag) {
        onChange([...selectedTagIds, newTag.id]);
        setNewTagName('');
      }
    } catch {}
  };

  return (
    <div className="space-y-2">
      <span className="text-sm font-medium">{t('tasks.tags.title')}</span>
      <div className="flex flex-wrap gap-1">
        {selectedTags.map(tag => (
          <Badge key={tag.id} variant="secondary" className="gap-1" style={{ borderColor: tag.color }}>
            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: tag.color }} />
            {tag.name}
            {!disabled && (
              <X
                className="h-3 w-3 cursor-pointer"
                onClick={() => onChange(selectedTagIds.filter(id => id !== tag.id))}
              />
            )}
          </Badge>
        ))}
        {!disabled && (
          <Popover open={open} onOpenChange={setOpen}>
            <PopoverTrigger asChild>
              <Button variant="outline" size="sm" className="h-6 gap-1 text-xs">
                <Tag className="h-3 w-3" />
                <Plus className="h-3 w-3" />
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-64 p-3 space-y-3">
              {availableTags.length > 0 && (
                <div className="space-y-1">
                  <span className="text-xs text-muted-foreground">{t('tasks.tags.existing')}</span>
                  <div className="flex flex-wrap gap-1">
                    {availableTags.map(tag => (
                      <Badge
                        key={tag.id}
                        variant="outline"
                        className="cursor-pointer hover:bg-accent gap-1"
                        onClick={() => {
                          onChange([...selectedTagIds, tag.id]);
                          setOpen(false);
                        }}
                      >
                        <span className="w-2 h-2 rounded-full" style={{ backgroundColor: tag.color }} />
                        {tag.name}
                      </Badge>
                    ))}
                  </div>
                </div>
              )}
              <div className="space-y-2">
                <span className="text-xs text-muted-foreground">{t('tasks.tags.createNew')}</span>
                <Input
                  value={newTagName}
                  onChange={(e) => setNewTagName(e.target.value)}
                  placeholder={t('tasks.tags.namePlaceholder')}
                  className="h-7 text-xs"
                />
                <div className="flex gap-1">
                  {TAG_COLORS.map(c => (
                    <button
                      key={c}
                      className={`w-5 h-5 rounded-full border-2 ${selectedColor === c ? 'border-foreground' : 'border-transparent'}`}
                      style={{ backgroundColor: c }}
                      onClick={() => setSelectedColor(c)}
                    />
                  ))}
                </div>
                <Button size="sm" className="w-full h-7 text-xs" onClick={handleCreateTag} disabled={!newTagName.trim()}>
                  {t('tasks.tags.create')}
                </Button>
              </div>
            </PopoverContent>
          </Popover>
        )}
      </div>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { FileText } from 'lucide-react';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/shared/components/ui/select';
