import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTenantId } from '@/hooks/org/useTenantId';
import { useCurrentEmployee } from '@/features/auth/hooks/auth/useCurrentEmployee';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';

export function useRecurringTasks() {
  const { tenantId } = useTenantId();
  const { employee } = useCurrentEmployee();
  const { t } = useTranslation();
  const qc = useQueryClient();

  const { data: templates, isPending } = useQuery({
    queryKey: ['task-templates', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('task_templates')
        .select('*')
        .eq('tenant_id', tenantId!)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data ?? [];
    },
    enabled: !!tenantId,
  });

  const upsertTemplate = useMutation({
    mutationFn: async ({ editId, payload }: { editId: string | null; payload: any }) => {
      if (editId) {
        const { error } = await supabase.from('task_templates').update(payload).eq('id', editId);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('task_templates').insert(payload);
        if (error) throw error;
      }
    },
    onSuccess: (_, { editId }) => {
      qc.invalidateQueries({ queryKey: ['task-templates'] });
      toast.success(editId ? t('common.save') : t('common.create'));
    },
    onError: (e: any) => toast.error(e.message),
  });

  const toggleActive = useMutation({
    mutationFn: async ({ id, active }: { id: string; active: boolean }) => {
      const { error } = await supabase.from('task_templates').update({ is_active: active, updated_at: new Date().toISOString() }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['task-templates'] }),
  });

  const softDelete = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from('task_templates').update({ deleted_at: new Date().toISOString() }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['task-templates'] });
      toast.success(t('common.delete'));
    },
  });

  return { templates, isPending, employee, tenantId, upsertTemplate, toggleActive, softDelete };
}

import { useMutation } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface AssigneeSuggestion {
  employee_id: string;
  employee_name: string;
  confidence: number;
  reason: string;
}

export interface CompletionEstimate {
  estimated_minutes: number;
  confidence: number;
  reasoning: string;
  risk_factors: string[];
}

export interface RiskItem {
  category: string;
  description: string;
  impact: 'low' | 'medium' | 'high';
  mitigation: string;
}

export interface RiskPrediction {
  risk_level: 'low' | 'medium' | 'high' | 'critical';
  risk_score: number;
  risks: RiskItem[];
  summary: string;
}

export interface PrioritySuggestion {
  suggested_priority: 'low' | 'medium' | 'high' | 'critical';
  confidence: number;
  reasoning: string;
  factors: { factor: string; weight: 'low' | 'medium' | 'high'; detail: string }[];
}

export interface ChecklistSuggestion {
  items: { title: string; estimated_minutes: number }[];
  reasoning: string;
}

export interface DependencySuggestion {
  task_id: string;
  task_title: string;
  dependency_type: 'blocks' | 'blocked_by' | 'related';
  confidence: number;
  reason: string;
}

function useAIMutation<T>(taskId: string | undefined, action: string) {
  const { t } = useTranslation();
  return useMutation({
    mutationFn: async () => {
      const { data, error } = await supabase.functions.invoke('task-ai-engine', {
        body: { action, task_id: taskId },
      });
      if (error) throw error;
      return data?.data as T;
    },
    onError: (e: any) => {
      toast.error(e?.message || t('taskAI.error'));
    },
  });
}

export function useTaskAI(taskId: string | undefined) {
  const suggestAssignee = useAIMutation<{ suggestions: AssigneeSuggestion[] }>(taskId, 'suggest_assignee');
  const estimateCompletion = useAIMutation<CompletionEstimate>(taskId, 'estimate_completion');
  const predictRisk = useAIMutation<RiskPrediction>(taskId, 'predict_risk');
  const suggestPriority = useAIMutation<PrioritySuggestion>(taskId, 'suggest_priority');
  const suggestChecklist = useAIMutation<ChecklistSuggestion>(taskId, 'suggest_checklist');
  const suggestDependencies = useAIMutation<{ suggestions: DependencySuggestion[] }>(taskId, 'suggest_dependencies');

  return {
    suggestAssignee,
    estimateCompletion,
    predictRisk,
    suggestPriority,
    suggestChecklist,
    suggestDependencies,
    isLoading:
      suggestAssignee.isPending ||
      estimateCompletion.isPending ||
      predictRisk.isPending ||
      suggestPriority.isPending ||
      suggestChecklist.isPending ||
      suggestDependencies.isPending,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTenantId } from '@/hooks/org/useTenantId';
import { useCurrentEmployee } from '@/features/auth/hooks/auth/useCurrentEmployee';

export interface TaskDependency {
  id: string;
  task_id: string;
  depends_on_task_id: string;
  dependency_type: string;
  created_at: string;
  depends_on_task?: { id: string; title: string; status: string; priority: number };
  dependent_task?: { id: string; title: string; status: string; priority: number };
}

export function useTaskDependencies(taskId: string | undefined) {
  const { tenantId } = useTenantId();
  const { employee } = useCurrentEmployee();
  const qc = useQueryClient();

  // Dependencies this task depends ON (blockers)
  const { data: blockers = [], isPending: blockersLoading } = useQuery({
    queryKey: ['task-dependencies', 'blockers', taskId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('unified_task_dependencies')
        .select('*, depends_on_task:unified_tasks!unified_task_dependencies_depends_on_task_id_fkey(id, title, status, priority)')
        .eq('task_id', taskId!)
        .is('deleted_at', null);
      if (error) throw error;
      return (data ?? []) as unknown as TaskDependency[];
    },
    enabled: !!taskId && !!tenantId,
  });

  // Tasks that depend on THIS task (dependents)
  const { data: dependents = [], isPending: dependentsLoading } = useQuery({
    queryKey: ['task-dependencies', 'dependents', taskId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('unified_task_dependencies')
        .select('*, dependent_task:unified_tasks!unified_task_dependencies_task_id_fkey(id, title, status, priority)')
        .eq('depends_on_task_id', taskId!)
        .is('deleted_at', null);
      if (error) throw error;
      return (data ?? []) as unknown as TaskDependency[];
    },
    enabled: !!taskId && !!tenantId,
  });

  const addDependency = useMutation({
    mutationFn: async ({ dependsOnTaskId, type = 'blocks' }: { dependsOnTaskId: string; type?: string }) => {
      const { error } = await supabase
        .from('unified_task_dependencies')
        .insert({
          tenant_id: tenantId!,
          task_id: taskId!,
          depends_on_task_id: dependsOnTaskId,
          dependency_type: type,
          created_by: employee?.id,
        });
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['task-dependencies'] });
    },
  });

  const removeDependency = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('unified_task_dependencies')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['task-dependencies'] });
    },
  });

  const hasUnresolvedBlockers = blockers
    .filter(b => b.dependency_type === 'blocks')
    .some(b => {
      const task = b.depends_on_task as any;
      return task && task.status !== 'completed';
    });

  const useSearchTasks = (search: string) => {
    return useQuery({
      queryKey: ['task-dep-search', tenantId, search],
      queryFn: async () => {
        if (!search.trim() || search.length < 2) return [];
        const { data, error } = await supabase
          .from('unified_tasks')
          .select('id, title, status, priority')
          .eq('tenant_id', tenantId!)
          .is('deleted_at', null)
          .neq('id', taskId!)
          .ilike('title', `%${search}%`)
          .limit(10);
        if (error) throw error;
        return data ?? [];
      },
      enabled: !!tenantId && search.length >= 2,
    });
  };

  return {
    blockers,
    dependents,
    isPending: blockersLoading || dependentsLoading,
    addDependency: addDependency.mutate,
    removeDependency: removeDependency.mutate,
    isAdding: addDependency.isPending,
    hasUnresolvedBlockers,
    useSearchTasks,
  };
}

