const PRIORITIES = ['low', 'medium', 'high', 'critical'] as const;

interface TemplateForm {
  title: string;
  title_ar: string;
  description: string;
  priority: string;
  recurrence_pattern: string;
  recurrence_day_of_week: number | null;
