export default function RecurringTasks() {
  const { t } = useTranslation();
  const { lformat } = useLocaleFormat();
  const { templates, isPending, employee, tenantId, upsertTemplate, toggleActive, softDelete } = useRecurringTasks();
  const [open, setOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<TemplateForm>(defaultForm);

  const handleUpsert = () => {
    const now = new Date();
    const nextRun = calculateNextRun(form.recurrence_pattern, form.recurrence_day_of_week, form.recurrence_day_of_month, form.recurrence_time, now);

    const payload: any = {
      tenant_id: tenantId!,
      title: form.title,
      title_ar: form.title_ar || null,
      description: form.description || null,
      priority: form.priority,
      recurrence_pattern: form.recurrence_pattern,
      recurrence_day_of_week: ['weekly', 'biweekly'].includes(form.recurrence_pattern) ? form.recurrence_day_of_week : null,
      recurrence_day_of_month: ['monthly', 'quarterly'].includes(form.recurrence_pattern) ? form.recurrence_day_of_month : null,
      recurrence_time: form.recurrence_time,
      estimated_minutes: form.estimated_minutes,
      next_run_at: nextRun.toISOString(),
      created_by: employee?.id,
      assignee_id: employee?.id,
      updated_at: now.toISOString(),
    };

    upsertTemplate.mutate({ editId, payload }, {
      onSuccess: () => {
        setOpen(false);
        setEditId(null);
        setForm(defaultForm);
      },
    });
  };

  const openEdit = (tpl: any) => {
    setEditId(tpl.id);
    setForm({
      title: tpl.title, title_ar: tpl.title_ar || '', description: tpl.description || '',
      priority: tpl.priority, recurrence_pattern: tpl.recurrence_pattern,
      recurrence_day_of_week: tpl.recurrence_day_of_week, recurrence_day_of_month: tpl.recurrence_day_of_month,
      recurrence_time: tpl.recurrence_time || '09:00', estimated_minutes: tpl.estimated_minutes || 60,
    });
    setOpen(true);
  };

  const patternLabel = (p: string) => t(`recurringTasks.patterns.${p}`);
  const priorityColor = (p: string) => {
    const map: Record<string, string> = { critical: 'destructive', high: 'destructive', medium: 'secondary', low: 'outline' };
    return (map[p] || 'secondary') as any;
  };

  if (isPending) {
    return <div className="p-6 space-y-4"><Skeleton className="h-8 w-64" /><Skeleton className="h-40" /><Skeleton className="h-40" /></div>;
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground">{t('recurringTasks.title')}</h1>
          <p className="text-sm text-muted-foreground">{t('recurringTasks.subtitle')}</p>
        </div>
        <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setEditId(null); setForm(defaultForm); } }}>
          <DialogTrigger asChild>
            <Button><Plus className="h-4 w-4 me-2" />{t('recurringTasks.create')}</Button>
          </DialogTrigger>
          <DialogContent className="max-w-lg">
            <DialogHeader>
              <DialogTitle>{editId ? t('recurringTasks.edit') : t('recurringTasks.create')}</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div><Label>{t('recurringTasks.taskTitle')}</Label><Input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} /></div>
              <div><Label>{t('recurringTasks.taskTitleAr')}</Label><Input dir="rtl" value={form.title_ar} onChange={e => setForm(f => ({ ...f, title_ar: e.target.value }))} /></div>
              <div><Label>{t('recurringTasks.description')}</Label><Textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} /></div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>{t('recurringTasks.priority')}</Label>
                  <Select value={form.priority} onValueChange={v => setForm(f => ({ ...f, priority: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>{PRIORITIES.map(p => <SelectItem key={p} value={p}>{p}</SelectItem>)}</SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>{t('recurringTasks.pattern')}</Label>
                  <Select value={form.recurrence_pattern} onValueChange={v => setForm(f => ({ ...f, recurrence_pattern: v }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>{PATTERNS.map(p => <SelectItem key={p} value={p}>{patternLabel(p)}</SelectItem>)}</SelectContent>
                  </Select>
                </div>
              </div>
              {['weekly', 'biweekly'].includes(form.recurrence_pattern) && (
                <div>
                  <Label>{t('recurringTasks.dayOfWeek')}</Label>
                  <Select value={String(form.recurrence_day_of_week ?? 0)} onValueChange={v => setForm(f => ({ ...f, recurrence_day_of_week: Number(v) }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>{DAYS.map((d, i) => <SelectItem key={i} value={String(i)}>{d}</SelectItem>)}</SelectContent>
                  </Select>
                </div>
              )}
              {['monthly', 'quarterly'].includes(form.recurrence_pattern) && (
                <div>
                  <Label>{t('recurringTasks.dayOfMonth')}</Label>
                  <Input type="number" min={1} max={28} value={form.recurrence_day_of_month ?? 1} onChange={e => setForm(f => ({ ...f, recurrence_day_of_month: Number(e.target.value) }))} />
                </div>
              )}
              <div className="grid grid-cols-2 gap-4">
                <div><Label>{t('recurringTasks.time')}</Label><Input type="time" value={form.recurrence_time} onChange={e => setForm(f => ({ ...f, recurrence_time: e.target.value }))} /></div>
                <div><Label>{t('recurringTasks.estimatedMinutes')}</Label><Input type="number" min={5} value={form.estimated_minutes} onChange={e => setForm(f => ({ ...f, estimated_minutes: Number(e.target.value) }))} /></div>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setOpen(false)}>{t('common.cancel')}</Button>
              <Button onClick={handleUpsert} disabled={!form.title || upsertTemplate.isPending}>{editId ? t('common.save') : t('common.create')}</Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      {!templates?.length ? (
        <Card><CardContent className="py-12 text-center text-muted-foreground">{t('recurringTasks.empty')}</CardContent></Card>
      ) : (
        <div className="grid gap-4">
          {templates.map((tpl: any) => (
            <Card key={tpl.id}>
              <CardContent className="flex items-center justify-between p-5 flex-wrap gap-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <RefreshCw className="h-4 w-4 text-primary shrink-0" />
                    <span className="font-semibold text-foreground truncate">{tpl.title}</span>
                    <Badge variant={priorityColor(tpl.priority)}>{tpl.priority}</Badge>
                    <Badge variant={tpl.is_active ? 'default' : 'outline'}>{tpl.is_active ? t('recurringTasks.active') : t('recurringTasks.paused')}</Badge>
                  </div>
                  <div className="flex items-center gap-4 text-xs text-muted-foreground">
                    <span className="flex items-center gap-1"><Calendar className="h-3 w-3" />{patternLabel(tpl.recurrence_pattern)}</span>
                    <span className="flex items-center gap-1"><Clock className="h-3 w-3" />{tpl.recurrence_time?.slice(0, 5) || '09:00'}</span>
                    {tpl.next_run_at && <span>{t('recurringTasks.nextRun')}: {lformat(new Date(tpl.next_run_at), 'MMM dd, HH:mm')}</span>}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Switch checked={tpl.is_active} onCheckedChange={v => toggleActive.mutate({ id: tpl.id, active: v })} />
                  <Button size="icon" variant="ghost" onClick={() => openEdit(tpl)}><Pencil className="h-4 w-4" /></Button>
                  <Button size="icon" variant="ghost" onClick={() => softDelete.mutate(tpl.id)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

function calculateNextRun(pattern: string, dayOfWeek: number | null, dayOfMonth: number | null, timeStr: string, from: Date): Date {
  const next = new Date(from);
  const [h, m] = timeStr.split(':').map(Number);
  next.setUTCHours(h, m, 0, 0);

  switch (pattern) {
    case 'daily': next.setUTCDate(next.getUTCDate() + 1); break;
    case 'weekly': next.setUTCDate(next.getUTCDate() + 7); break;
    case 'biweekly': next.setUTCDate(next.getUTCDate() + 14); break;
    case 'monthly': next.setUTCMonth(next.getUTCMonth() + 1); if (dayOfMonth) next.setUTCDate(Math.min(dayOfMonth, 28)); break;
    case 'quarterly': next.setUTCMonth(next.getUTCMonth() + 3); if (dayOfMonth) next.setUTCDate(Math.min(dayOfMonth, 28)); break;
    default: next.setUTCDate(next.getUTCDate() + 7);
  }
  return next;
}

import { useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { Progress } from '@/shared/components/ui/progress';
import { Textarea } from '@/shared/components/ui/textarea';
import { Input } from '@/shared/components/ui/input';
import { Checkbox } from '@/shared/components/ui/checkbox';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/shared/components/ui/select';
import {
  Lock, MessageSquare, ListChecks,
  Activity, Paperclip, Clock, CalendarDays, ChevronLeft,
  Plus, Upload, FileIcon, X, Trash2,
} from 'lucide-react';
import { useTaskChecklists } from '@/features/tasks/hooks/useTaskChecklists';
import { TaskDependenciesPanel } from '@/features/tasks/components/TaskDependenciesPanel';
import { TaskTimeTrackingPanel } from '@/features/tasks/components/TaskTimeTrackingPanel';
import { TaskAIPanel } from '@/features/tasks/components/TaskAIPanel';
import { TaskCommentsPanel } from '@/features/tasks/components/TaskCommentsPanel';
import { TaskActivityTimeline } from '@/features/tasks/components/TaskActivityTimeline';
import { useTaskComments } from '@/features/tasks/hooks/useTaskComments';
import { useTaskActivity } from '@/features/tasks/hooks/useTaskActivity';
import { useTaskAttachments } from '@/features/tasks/hooks/useTaskAttachments';
import { useTaskDetail, useTaskUpdate } from '@/features/tasks/hooks/useTaskDetail';
import { useCurrentEmployee } from '@/features/auth/hooks/auth/useCurrentEmployee';
import { useLocaleFormat } from '@/shared/hooks/useLocaleFormat';
import { toast } from 'sonner';

import { getValidNextStatuses, STATUS_COLORS } from '@/features/tasks/constants/taskLifecycle';

const PRIORITY_LABELS: Record<number, { label: string; className: string }> = {
  0: { label: 'Critical', className: 'text-destructive' },
  1: { label: 'High', className: 'text-chart-5' },
  2: { label: 'Medium', className: 'text-chart-4' },
  3: { label: 'Low', className: 'text-muted-foreground' },
};

export default function TaskDetail() {
  const { id } = useParams<{ id: string }>();
  const { t } = useTranslation();
  const { lformat } = useLocaleFormat();
  const navigate = useNavigate();
  const { employee } = useCurrentEmployee();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [tab, setTab] = useState('comments');
  const [newChecklistTitle, setNewChecklistTitle] = useState('');
  const [isEditingDesc, setIsEditingDesc] = useState(false);
  const [editDesc, setEditDesc] = useState('');

  const { task, taskLoading } = useTaskDetail(id);
  const updateTask = useTaskUpdate(id);

  const { checklists, isPending: checklistLoading, updateItem, createItem, removeItem } = useTaskChecklists(id);
  const { comments, isPending: commentsLoading, addComment, removeComment, editComment } = useTaskComments(id);
  const { activities, isPending: activityLoading } = useTaskActivity(id);
  const { attachments, isPending: attachmentsLoading, uploadFile, removeFile, isUploading } = useTaskAttachments(id);

  const handleToggleChecklist = (itemId: string, currentStatus: string) => {
    updateItem({ id: itemId, status: currentStatus === 'completed' ? 'pending' : 'completed' });
  };

  const handleAddChecklistItem = () => {
    if (!newChecklistTitle.trim() || !id) return;
    createItem({ task_id: id, title: newChecklistTitle.trim(), sort_order: checklists.length });
    setNewChecklistTitle('');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !id || !employee) return;
    if (file.size > 10 * 1024 * 1024) {
      toast.error(t('tasks.attachments.maxSizeError'));
      return;
    }
    uploadFile({ task_id: id, file, uploaded_by: employee.id });
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSaveDescription = () => {
    updateTask.mutate({ description: editDesc });
    setIsEditingDesc(false);
  };

  const formatFileSize = (bytes: number | null) => {
    if (!bytes) return '';
    if (bytes < 1024) return `${bytes}B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)}KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)}MB`;
  };

  if (taskLoading) {
    return <div className="space-y-4 p-2"><Skeleton className="h-10 w-64" /><Skeleton className="h-96" /></div>;
  }

  if (!task) {
    return <div className="text-center text-muted-foreground py-20">{t('tasks.notFound')}</div>;
  }

  const priorityInfo = PRIORITY_LABELS[task.priority] ?? PRIORITY_LABELS[2];
  const statusClass = STATUS_COLORS[task.status] ?? STATUS_COLORS.draft;

  return (
    <div className="space-y-6">
      {/* Back nav */}
      <Button variant="ghost" size="sm" onClick={() => navigate(-1)} className="gap-1.5">
        <ChevronLeft className="h-4 w-4 rtl:rotate-180" />{t('common.back')}
      </Button>

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-start gap-4">
        <div className="flex-1 space-y-2">
          <div className="flex items-center gap-3 flex-wrap">
            <h1 className="text-xl font-bold">{task.title}</h1>
            {task.is_locked && <Lock className="h-4 w-4 text-chart-4" />}
          </div>
          {task.title_ar && <p className="text-sm text-muted-foreground" dir="rtl">{task.title_ar}</p>}

          {/* Inline status & priority controls */}
          <div className="flex items-center gap-2 flex-wrap">
            <Select
              value={task.status}
              onValueChange={(v) => updateTask.mutate({ status: v })}
              disabled={task.is_locked}
            >
              <SelectTrigger className="w-[170px] h-8 text-xs">
                <Badge className={`${statusClass} pointer-events-none`}>{t(`tasks.status.${task.status}`)}</Badge>
              </SelectTrigger>
              <SelectContent>
                {getValidNextStatuses(task.status, !!task.reviewer_id).map(s => (
                  <SelectItem key={s} value={s}>{t(`tasks.status.${s}`)}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={String(task.priority)}
              onValueChange={(v) => updateTask.mutate({ priority: parseInt(v) })}
              disabled={task.is_locked}
            >
              <SelectTrigger className="w-[130px] h-8 text-xs">
                <Badge variant="outline" className={priorityInfo.className}>P{task.priority} — {priorityInfo.label}</Badge>
              </SelectTrigger>
              <SelectContent>
                {[0, 1, 2, 3].map(p => (
                  <SelectItem key={p} value={String(p)}>P{p} — {PRIORITY_LABELS[p].label}</SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Badge variant="outline">{task.source_type}</Badge>
            {(task as any).employee?.full_name && (
              <Badge variant="secondary">{(task as any).employee.full_name}</Badge>
            )}
          </div>
        </div>

        <div className="flex flex-col items-end gap-2 text-sm text-muted-foreground">
          {task.due_date && (
            <span className="flex items-center gap-1.5">
              <CalendarDays className="h-4 w-4" />
              {t('tasks.fields.dueDate')}: {lformat(new Date(task.due_date), 'PPP')}
            </span>
          )}
          {task.estimated_minutes && (
            <span className="flex items-center gap-1.5">
              <Clock className="h-4 w-4" />
              {task.estimated_minutes}m {t('tasks.fields.estimated')}
            </span>
          )}
        </div>
      </div>

      {/* Progress */}
      <Card className="border-0 bg-muted/30">
        <CardContent className="p-4 space-y-2">
          <div className="flex items-center justify-between text-sm">
            <span className="font-medium">{t('tasks.fields.progress')}</span>
            <span className="font-bold">{task.progress}%</span>
          </div>
          <Progress value={task.progress} className="h-2" />
        </CardContent>
      </Card>

      {/* Description — click to edit */}
      <Card className="border-0">
        <CardHeader className="pb-2">
          <div className="flex items-center justify-between">
            <CardTitle className="text-sm">{t('tasks.fields.description')}</CardTitle>
            {!isEditingDesc && !task.is_locked && (
              <Button
                variant="ghost"
                size="sm"
                className="text-xs h-7"
                onClick={() => { setEditDesc(task.description ?? ''); setIsEditingDesc(true); }}
              >
                {t('common.edit')}
              </Button>
            )}
          </div>
        </CardHeader>
        <CardContent>
          {isEditingDesc ? (
            <div className="space-y-2">
              <Textarea
                value={editDesc}
                onChange={(e) => setEditDesc(e.target.value)}
                rows={4}
              />
              <div className="flex gap-2 justify-end">
                <Button variant="ghost" size="sm" onClick={() => setIsEditingDesc(false)}>{t('common.cancel')}</Button>
                <Button size="sm" onClick={handleSaveDescription} disabled={updateTask.isPending}>{t('common.save')}</Button>
              </div>
            </div>
          ) : (
            <p className="text-sm text-muted-foreground whitespace-pre-wrap">
              {task.description || t('tasks.noDescription')}
            </p>
          )}
        </CardContent>
      </Card>

      {/* Dependencies */}
      {id && <TaskDependenciesPanel taskId={id} />}

      {/* Time Tracking */}
      {id && <TaskTimeTrackingPanel taskId={id} />}

      {/* AI Insights */}
      {id && <TaskAIPanel taskId={id} />}

      {/* Tabs: Comments, Checklist, Attachments, Activity */}
      <Card className="border-0">
        <CardContent className="p-4">
          <Tabs value={tab} onValueChange={setTab}>
            <TabsList className="mb-4 flex-wrap">
              <TabsTrigger value="comments" className="gap-1.5 text-xs">
                <MessageSquare className="h-3.5 w-3.5" />{t('tasks.comments.title')} ({comments.length})
              </TabsTrigger>
              <TabsTrigger value="checklist" className="gap-1.5 text-xs">
                <ListChecks className="h-3.5 w-3.5" />{t('tasks.checklist.title')} ({checklists.length})
              </TabsTrigger>
              <TabsTrigger value="attachments" className="gap-1.5 text-xs">
                <Paperclip className="h-3.5 w-3.5" />{t('tasks.attachments.title')} ({attachments.length})
              </TabsTrigger>
              <TabsTrigger value="activity" className="gap-1.5 text-xs">
                <Activity className="h-3.5 w-3.5" />{t('tasks.activity.title')} ({activities.length})
              </TabsTrigger>
            </TabsList>

            {/* Comments */}
            <TabsContent value="comments">
              <TaskCommentsPanel
                comments={comments}
                isLoading={commentsLoading}
                currentEmployeeId={employee?.id}
                onAdd={addComment}
                onRemove={removeComment}
                onEdit={editComment}
                taskId={id!}
              />
            </TabsContent>

            {/* Checklist */}
            <TabsContent value="checklist" className="space-y-4">
              {checklistLoading ? <Skeleton className="h-20" /> : checklists.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">{t('tasks.checklist.empty')}</p>
              ) : (
                <div className="space-y-2">
                  {checklists.map(item => (
                    <div key={item.id} className="flex items-center gap-3 p-2 rounded-lg hover:bg-muted/30 group">
                      <Checkbox
                        checked={item.status === 'completed'}
                        onCheckedChange={() => handleToggleChecklist(item.id, item.status)}
                      />
                      <span className={`text-sm flex-1 ${item.status === 'completed' ? 'line-through text-muted-foreground' : ''}`}>
                        {item.title}
                      </span>
                      {item.due_date && (
                        <span className="text-xs text-muted-foreground">{lformat(new Date(item.due_date), 'PP')}</span>
                      )}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity"
                        onClick={() => removeItem(item.id)}
                      >
                        <X className="h-3 w-3 text-destructive" />
                      </Button>
                    </div>
                  ))}
                </div>
              )}
              {/* Add checklist item */}
              <div className="flex gap-2">
                <Input
                  value={newChecklistTitle}
                  onChange={(e) => setNewChecklistTitle(e.target.value)}
                  placeholder={t('tasks.checklist.addPlaceholder')}
                  className="flex-1 h-9"
                  onKeyDown={(e) => { if (e.key === 'Enter') handleAddChecklistItem(); }}
                />
                <Button size="sm" onClick={handleAddChecklistItem} disabled={!newChecklistTitle.trim()} className="gap-1">
                  <Plus className="h-3.5 w-3.5" />{t('common.add')}
                </Button>
              </div>
            </TabsContent>

            {/* Attachments */}
            <TabsContent value="attachments" className="space-y-4">
              {attachmentsLoading ? <Skeleton className="h-20" /> : attachments.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">{t('tasks.attachments.empty')}</p>
              ) : (
                <div className="space-y-2">
                  {attachments.map(att => (
                    <div key={att.id} className="flex items-center gap-3 p-3 rounded-lg bg-muted/30 group">
                      <FileIcon className="h-4 w-4 text-muted-foreground shrink-0" />
                      <div className="flex-1 min-w-0">
                        <a
                          href={att.file_url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-sm font-medium hover:underline truncate block"
                        >
                          {att.file_name}
                        </a>
                        <span className="text-xs text-muted-foreground">
                          {formatFileSize(att.file_size)} · {lformat(new Date(att.created_at), 'PP')}
                        </span>
                      </div>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity shrink-0"
                        onClick={() => removeFile(att.id)}
                      >
                        <Trash2 className="h-3 w-3 text-destructive" />
                      </Button>
                    </div>
                  ))}
                </div>
              )}
              <div>
                <input
                  ref={fileInputRef}
                  type="file"
                  className="hidden"
                  onChange={handleFileUpload}
                />
                <Button
                  variant="outline"
                  size="sm"
                  className="gap-1.5"
                  onClick={() => fileInputRef.current?.click()}
                  disabled={isUploading}
                >
                  <Upload className="h-3.5 w-3.5" />
                  {isUploading ? t('tasks.attachments.uploading') : t('tasks.attachments.upload')}
                </Button>
                <p className="text-xs text-muted-foreground mt-1">{t('tasks.attachments.maxSize')}</p>
              </div>
            </TabsContent>

            {/* Activity Log */}
            <TabsContent value="activity">
              <TaskActivityTimeline activities={activities} isLoading={activityLoading} />
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Skeleton } from '@/shared/components/ui/skeleton';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  PieChart, Pie, Cell, Legend, LineChart, Line, Area, AreaChart,
} from 'recharts';
import {
  CheckCircle, Clock, TrendingUp, Users, AlertTriangle, Target,
} from 'lucide-react';
import { format, subDays, startOfDay, eachDayOfInterval } from 'date-fns';
import { useMemo, useState } from 'react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { useTaskPerformanceAnalytics } from '@/features/tasks/hooks/useTaskPerformanceAnalytics';
import { CHART_AXIS_TICK, CHART_TOOLTIP_STYLE, CHART_GRID_STROKE } from '@/config/chart-styles';

type RangeKey = '7' | '14' | '30';

export default function TaskPerformanceAnalytics() {
  const { t } = useTranslation();
  const [range, setRange] = useState<RangeKey>('30');
  const { tasks, isPending, sinceDate } = useTaskPerformanceAnalytics(range);

  // ── Derived metrics ───────────────────────
  const metrics = useMemo(() => {
    if (!tasks?.length) return null;

    const total = tasks.length;
    const completedTasks = tasks.filter((t: any) => t.status === 'completed');
    const completed = completedTasks.length;
    const inProgress = tasks.filter((t: any) => t.status === 'in_progress').length;
    const overdue = tasks.filter((t: any) => t.status === 'rejected' || t.status === 'archived').length;
    const avgProgress = Math.round(tasks.reduce((sum: number, t: any) => sum + (t.progress ?? 0), 0) / total);
    const completionRate = total > 0 ? Math.round((completed / total) * 100) : 0;

    // Average completion time (created_at → updated_at for completed tasks) in hours
    const completionTimes = completedTasks
      .filter((t: any) => t.created_at && t.updated_at)
      .map((t: any) => (new Date(t.updated_at).getTime() - new Date(t.created_at).getTime()) / (1000 * 60 * 60));
    const avgCompletionHours = completionTimes.length > 0
      ? Math.round(completionTimes.reduce((a: number, b: number) => a + b, 0) / completionTimes.length * 10) / 10
      : null;

    // Status distribution
    const statusCounts: Record<string, number> = {};
    tasks.forEach((t: any) => {
      statusCounts[t.status] = (statusCounts[t.status] || 0) + 1;
    });
    const statusData = Object.entries(statusCounts).map(([name, value]) => ({ name, value }));

    // Priority distribution
    const priorityCounts: Record<string, number> = {};
    tasks.forEach((t: any) => {
      const p = t.priority || 'medium';
      priorityCounts[p] = (priorityCounts[p] || 0) + 1;
    });
    const priorityData = Object.entries(priorityCounts).map(([name, value]) => ({ name, value }));

    // Daily creation trend
    const days = eachDayOfInterval({ start: new Date(sinceDate), end: new Date() });
    const dailyMap: Record<string, { created: number; completed: number }> = {};
    days.forEach(d => {
      dailyMap[format(d, 'MM/dd')] = { created: 0, completed: 0 };
    });
    tasks.forEach((t: any) => {
      const key = format(new Date(t.created_at), 'MM/dd');
      if (dailyMap[key]) dailyMap[key].created++;
      if (t.status === 'completed') {
        const uKey = format(new Date(t.updated_at), 'MM/dd');
        if (dailyMap[uKey]) dailyMap[uKey].completed++;
      }
    });
    const trendData = Object.entries(dailyMap).map(([date, v]) => ({ date, ...v }));

    // Top performers (by completed tasks count)
    const employeeMap: Record<string, { name: string; completed: number; total: number }> = {};
    tasks.forEach((t: any) => {
      const eid = t.employee_id;
      if (!eid) return;
      if (!employeeMap[eid]) {
        const empName = (t.employees as any)?.full_name ?? 'Unknown';
        employeeMap[eid] = { name: empName, completed: 0, total: 0 };
      }
      employeeMap[eid].total++;
      if (t.status === 'completed') employeeMap[eid].completed++;
    });
    const topPerformers = Object.values(employeeMap)
      .sort((a, b) => b.completed - a.completed)
      .slice(0, 10);

    // Format avg completion time for display
    const avgCompletionDisplay = avgCompletionHours !== null
      ? avgCompletionHours >= 24
        ? `${Math.round(avgCompletionHours / 24 * 10) / 10}d`
        : `${Math.round(avgCompletionHours)}h`
      : '—';

    return { total, completed, inProgress, overdue, avgProgress, completionRate, avgCompletionDisplay, statusData, priorityData, trendData, topPerformers };
  }, [tasks, sinceDate]);

  const STATUS_COLORS = ['hsl(var(--primary))', 'hsl(var(--chart-2))', 'hsl(var(--chart-3))', 'hsl(var(--chart-4))', 'hsl(var(--chart-5))', 'hsl(var(--muted-foreground))'];
  const PRIORITY_COLORS: Record<string, string> = {
    critical: 'hsl(var(--destructive))',
    high: 'hsl(var(--chart-5))',
    medium: 'hsl(var(--chart-4))',
    low: 'hsl(var(--chart-2))',
  };

  if (isPending) {
    return (
      <div className="p-6 space-y-6">
        <Skeleton className="h-8 w-64" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          {[...Array(5)].map((_, i) => <Skeleton key={i} className="h-28" />)}
        </div>
        <Skeleton className="h-80" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground">{t('taskAnalytics.title')}</h1>
          <p className="text-sm text-muted-foreground">{t('taskAnalytics.subtitle')}</p>
        </div>
        <Select value={range} onValueChange={(v) => setRange(v as RangeKey)}>
          <SelectTrigger className="w-[140px]">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="7">{t('taskAnalytics.last7')}</SelectItem>
            <SelectItem value="14">{t('taskAnalytics.last14')}</SelectItem>
            <SelectItem value="30">{t('taskAnalytics.last30')}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {!metrics ? (
        <Card><CardContent className="py-12 text-center text-muted-foreground">{t('common.noData')}</CardContent></Card>
      ) : (
        <>
          {/* KPI Cards */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
            <KPICard icon={Target} label={t('taskAnalytics.totalTasks')} value={metrics.total} />
            <KPICard icon={CheckCircle} label={t('taskAnalytics.completionRate')} value={`${metrics.completionRate}%`} />
            <KPICard icon={TrendingUp} label={t('taskAnalytics.avgProgress')} value={`${metrics.avgProgress}%`} />
            <KPICard icon={Clock} label={t('taskAnalytics.avgCompletionTime')} value={metrics.avgCompletionDisplay} />
            <KPICard icon={AlertTriangle} label={t('taskAnalytics.inProgress')} value={metrics.inProgress} />
          </div>

          {/* Charts Row 1 */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Trend */}
            <Card>
              <CardHeader><CardTitle className="text-base">{t('taskAnalytics.dailyTrend')}</CardTitle></CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={280}>
                  <AreaChart data={metrics.trendData}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_GRID_STROKE} />
                    <XAxis dataKey="date" tick={CHART_AXIS_TICK} />
                    <YAxis tick={CHART_AXIS_TICK} />
                    <Tooltip contentStyle={CHART_TOOLTIP_STYLE} />
                    <Area type="monotone" dataKey="created" stackId="1" fill="hsl(var(--primary))" stroke="hsl(var(--primary))" fillOpacity={0.3} name={t('taskAnalytics.created')} />
                    <Area type="monotone" dataKey="completed" stackId="2" fill="hsl(var(--chart-2))" stroke="hsl(var(--chart-2))" fillOpacity={0.3} name={t('taskAnalytics.completed')} />
                    <Legend />
                  </AreaChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            {/* Status Distribution */}
            <Card>
              <CardHeader><CardTitle className="text-base">{t('taskAnalytics.statusDistribution')}</CardTitle></CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={280}>
                  <PieChart>
                    <Pie data={metrics.statusData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={100} label>
                      {metrics.statusData.map((_: any, i: number) => (
                        <Cell key={i} fill={STATUS_COLORS[i % STATUS_COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip />
                    <Legend />
                  </PieChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          </div>

          {/* Charts Row 2 */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Priority */}
            <Card>
              <CardHeader><CardTitle className="text-base">{t('taskAnalytics.priorityBreakdown')}</CardTitle></CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={metrics.priorityData}>
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_GRID_STROKE} />
                    <XAxis dataKey="name" tick={CHART_AXIS_TICK} />
                    <YAxis tick={CHART_AXIS_TICK} />
                    <Tooltip contentStyle={CHART_TOOLTIP_STYLE} />
                    <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                      {metrics.priorityData.map((entry: any, i: number) => (
                        <Cell key={i} fill={PRIORITY_COLORS[entry.name] || 'hsl(var(--muted-foreground))'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            {/* Top Performers */}
            <Card>
              <CardHeader><CardTitle className="text-base">{t('taskAnalytics.topPerformers')}</CardTitle></CardHeader>
              <CardContent>
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={metrics.topPerformers} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" stroke={CHART_GRID_STROKE} />
                    <XAxis type="number" tick={CHART_AXIS_TICK} />
                    <YAxis type="category" dataKey="name" width={120} tick={{ ...CHART_AXIS_TICK, fontSize: 12 }} />
                    <Tooltip contentStyle={CHART_TOOLTIP_STYLE} />
                    <Bar dataKey="completed" fill="hsl(var(--chart-2))" radius={[0, 4, 4, 0]} name={t('taskAnalytics.completed')} />
                    <Bar dataKey="total" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} name={t('taskAnalytics.totalTasks')} opacity={0.4} />
                    <Legend />
                  </BarChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>
          </div>
        </>
      )}
    </div>
  );
}

function KPICard({ icon: Icon, label, value }: { icon: any; label: string; value: string | number }) {
  return (
    <Card>
      <CardContent className="flex items-center gap-4 p-5">
        <div className="p-2.5 rounded-lg bg-primary/10">
          <Icon className="h-5 w-5 text-primary" />
        </div>
        <div>
          <p className="text-sm text-muted-foreground">{label}</p>
          <p className="text-2xl font-bold text-foreground">{value}</p>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Textarea } from '@/shared/components/ui/textarea';
import { Switch } from '@/shared/components/ui/switch';
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from '@/shared/components/ui/dialog';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/shared/components/ui/select';
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from '@/shared/components/ui/alert-dialog';
import { Plus, Pencil, Trash2, FileText, Search, CheckSquare } from 'lucide-react';
import { useTaskTemplates, type CreateTemplateInput } from '@/features/tasks/hooks/useTaskTemplates';

const PRIORITIES = [
  { value: 'low', label: 'tasks.priority.low' },
  { value: 'medium', label: 'tasks.priority.medium' },
  { value: 'high', label: 'tasks.priority.high' },
  { value: 'critical', label: 'tasks.priority.critical' },
];

const VISIBILITIES = [
  { value: 'private', label: 'tasks.visibility.private' },
  { value: 'department', label: 'tasks.visibility.department' },
  { value: 'cross_department', label: 'tasks.visibility.cross_department' },
  { value: 'organization', label: 'tasks.visibility.organization' },
];

const defaultForm: CreateTemplateInput & { checklist_text: string } = {
  name: '',
  name_ar: '',
  title: '',
  title_ar: '',
  description: '',
  description_ar: '',
  priority: 'medium',
  visibility: 'department',
  estimated_minutes: null,
  checklist_items: [],
  checklist_text: '',
};

export default function TaskTemplates() {
  const { t } = useTranslation();
  const { templates, isPending, createTemplate, updateTemplate, deleteTemplate, toggleActive } = useTaskTemplates();

  const [search, setSearch] = useState('');
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [form, setForm] = useState(defaultForm);

  const filtered = templates.filter(t =>
    !search || t.name?.toLowerCase().includes(search.toLowerCase()) || t.title?.toLowerCase().includes(search.toLowerCase())
  );

  const openCreate = () => {
    setEditId(null);
    setForm(defaultForm);
    setDialogOpen(true);
  };

  const openEdit = (tpl: any) => {
    setEditId(tpl.id);
    const items = Array.isArray(tpl.checklist_items) ? tpl.checklist_items : [];
    setForm({
      name: tpl.name || '',
      name_ar: tpl.name_ar || '',
      title: tpl.title || '',
      title_ar: tpl.title_ar || '',
      description: tpl.description || '',
      description_ar: tpl.description_ar || '',
      priority: tpl.priority || 'medium',
      visibility: tpl.visibility || 'department',
      estimated_minutes: tpl.estimated_minutes,
      checklist_items: items,
      checklist_text: items.map((i: any) => i.title || i).join('\n'),
    });
    setDialogOpen(true);
  };

  const handleSubmit = async () => {
    const checklistItems = form.checklist_text
      .split('\n')
      .map(l => l.trim())
      .filter(Boolean)
      .map(title => ({ title, status: 'pending' }));

    const payload: CreateTemplateInput = {
      name: form.name,
      name_ar: form.name_ar,
      title: form.title,
      title_ar: form.title_ar,
      description: form.description,
      description_ar: form.description_ar,
      priority: form.priority,
      visibility: form.visibility,
      estimated_minutes: form.estimated_minutes,
      checklist_items: checklistItems,
    };

    if (editId) {
      await updateTemplate.mutateAsync({ id: editId, ...payload });
    } else {
      await createTemplate.mutateAsync(payload);
    }
    setDialogOpen(false);
  };

  const priorityColor = (p: string) => {
    switch (p) {
      case 'critical': return 'destructive';
      case 'high': return 'default';
      case 'medium': return 'secondary';
      default: return 'outline';
    }
  };

  return (
    <div className="container mx-auto p-4 md:p-6 space-y-6">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">{t('taskTemplates.title')}</h1>
          <p className="text-sm text-muted-foreground">{t('taskTemplates.subtitle')}</p>
        </div>
        <Button onClick={openCreate} className="gap-2">
          <Plus className="h-4 w-4" />
          {t('taskTemplates.create')}
        </Button>
      </div>

      <div className="relative max-w-sm">
        <Search className="absolute start-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
        <Input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder={t('common.search')}
          className="ps-9"
        />
      </div>

      {isPending ? (
        <div className="text-center py-12 text-muted-foreground">{t('common.loading')}</div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <FileText className="h-12 w-12 mx-auto text-muted-foreground/50 mb-3" />
            <p className="text-muted-foreground">{t('taskTemplates.empty')}</p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map(tpl => (
            <Card key={tpl.id} className={!tpl.is_active ? 'opacity-60' : ''}>
              <CardHeader className="pb-2">
                <div className="flex items-start justify-between gap-2">
                  <div className="min-w-0 flex-1">
                    <CardTitle className="text-base truncate">{tpl.name || tpl.title}</CardTitle>
                    {tpl.name && tpl.title && (
                      <p className="text-xs text-muted-foreground truncate mt-0.5">{tpl.title}</p>
                    )}
                  </div>
                  <Switch
                    checked={tpl.is_active}
                    onCheckedChange={active => toggleActive.mutate({ id: tpl.id, active })}
                  />
                </div>
              </CardHeader>
              <CardContent className="space-y-3">
                {tpl.description && (
                  <p className="text-sm text-muted-foreground line-clamp-2">{tpl.description}</p>
                )}
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant={priorityColor(tpl.priority)}>{t(`tasks.priority.${tpl.priority}`)}</Badge>
                  <Badge variant="outline">{t(`tasks.visibility.${tpl.visibility}`)}</Badge>
                  {tpl.estimated_minutes && (
                    <Badge variant="outline">{tpl.estimated_minutes}m</Badge>
                  )}
                  {Array.isArray(tpl.checklist_items) && tpl.checklist_items.length > 0 && (
                    <Badge variant="outline" className="gap-1">
                      <CheckSquare className="h-3 w-3" />
                      {tpl.checklist_items.length}
                    </Badge>
                  )}
                </div>
                <div className="flex items-center gap-2 pt-1">
                  <Button size="sm" variant="outline" onClick={() => openEdit(tpl)}>
                    <Pencil className="h-3.5 w-3.5 me-1" />{t('common.edit')}
                  </Button>
                  <Button size="sm" variant="outline" className="text-destructive" onClick={() => setDeleteId(tpl.id)}>
                    <Trash2 className="h-3.5 w-3.5 me-1" />{t('common.delete')}
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Create / Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={v => { setDialogOpen(v); if (!v) setEditId(null); }}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editId ? t('taskTemplates.edit') : t('taskTemplates.create')}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div><Label>{t('taskTemplates.templateName')} *</Label>
              <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} /></div>
            <div><Label>{t('taskTemplates.templateNameAr')}</Label>
              <Input dir="rtl" value={form.name_ar} onChange={e => setForm(f => ({ ...f, name_ar: e.target.value }))} /></div>
            <div><Label>{t('tasks.fields.title')} *</Label>
              <Input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} /></div>
            <div><Label>{t('tasks.fields.titleAr')}</Label>
              <Input dir="rtl" value={form.title_ar} onChange={e => setForm(f => ({ ...f, title_ar: e.target.value }))} /></div>
            <div><Label>{t('tasks.fields.description')}</Label>
              <Textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} rows={3} /></div>
            <div className="grid grid-cols-2 gap-4">
              <div><Label>{t('tasks.fields.priority')}</Label>
                <Select value={form.priority} onValueChange={v => setForm(f => ({ ...f, priority: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {PRIORITIES.map(p => <SelectItem key={p.value} value={p.value}>{t(p.label)}</SelectItem>)}
                  </SelectContent>
                </Select></div>
              <div><Label>{t('tasks.fields.visibility')}</Label>
                <Select value={form.visibility} onValueChange={v => setForm(f => ({ ...f, visibility: v }))}>
                  <SelectTrigger><SelectValue /></SelectTrigger>
                  <SelectContent>
                    {VISIBILITIES.map(v => <SelectItem key={v.value} value={v.value}>{t(v.label)}</SelectItem>)}
                  </SelectContent>
                </Select></div>
            </div>
            <div><Label>{t('tasks.fields.estimatedMinutes')}</Label>
              <Input type="number" value={form.estimated_minutes ?? ''} onChange={e => setForm(f => ({ ...f, estimated_minutes: e.target.value ? Number(e.target.value) : null }))} placeholder="60" /></div>
            <div><Label>{t('taskTemplates.checklistHint')}</Label>
              <Textarea value={form.checklist_text} onChange={e => setForm(f => ({ ...f, checklist_text: e.target.value }))} rows={4} placeholder={t('taskTemplates.checklistPlaceholder')} /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>{t('common.cancel')}</Button>
            <Button onClick={handleSubmit} disabled={!form.name.trim() || !form.title.trim() || createTemplate.isPending || updateTemplate.isPending}>
              {editId ? t('common.save') : t('common.create')}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t('taskTemplates.deleteConfirm')}</AlertDialogTitle>
            <AlertDialogDescription>{t('taskTemplates.deleteDescription')}</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={() => { if (deleteId) deleteTemplate.mutate(deleteId); setDeleteId(null); }}>
              {t('common.delete')}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Textarea } from '@/shared/components/ui/textarea';
import { Button } from '@/shared/components/ui/button';
import { RadioGroup, RadioGroupItem } from '@/shared/components/ui/radio-group';
import { Label } from '@/shared/components/ui/label';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Slider } from '@/shared/components/ui/slider';
import { Brain, CheckCircle2, ChevronDown } from 'lucide-react';
import { useMoodPathwayQuestions } from '@/hooks/wellness/useMoodPathwayQuestions';
import { useMoodQuestionConfig } from '@/hooks/wellness/useMoodQuestionConfig';
import { Question } from '@/hooks/questions/useQuestions';

export interface PathwayAnswer {
  questionId: string;
  questionTextEn: string;
  selectedOption: string;
  freeText?: string;
  theme: string;
}

interface MoodPathwayQuestionsProps {
  moodLevel: string;
  moodScore: number;
  tenantId: string;
  language: string;
  onAnswersChange: (answers: PathwayAnswer[]) => void;
}

// Likert-5 labels
const LIKERT_LABELS_EN = ['Strongly Disagree', 'Disagree', 'Neutral', 'Agree', 'Strongly Agree'];
const LIKERT_LABELS_AR = ['أرفض بشدة', 'أرفض', 'محايد', 'أوافق', 'أوافق بشدة'];

/** Resolve bilingual option to display string */
function resolveOption(opt: string | { text: string; text_ar?: string }, isRTL: boolean): string {
  if (typeof opt === 'string') return opt;
  return isRTL && opt.text_ar ? opt.text_ar : opt.text;
}

export function MoodPathwayQuestions({
  moodLevel,
  tenantId,
  language,
  onAnswersChange,
}: MoodPathwayQuestionsProps) {
  const { t } = useTranslation();
  const isRTL = language === 'ar';

  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [freeTexts, setFreeTexts] = useState<Record<string, string>>({});
  const [isSkipped, setIsSkipped] = useState(false);

  const { configs, isPending: configsLoading } = useMoodQuestionConfig(tenantId);
  const config = configs?.find((c: any) => c.mood_level === moodLevel);
  const maxQuestions = configsLoading ? 0 : (config?.max_questions ?? 2);
  const { data, isLoading } = useMoodPathwayQuestions(moodLevel, tenantId, maxQuestions);
  const questions = data || [];

  const isEnabled = !config || config.is_enabled;
  const enableFreeText = config?.enable_free_text ?? false;
  const isExtremeMood = moodLevel === 'great' || moodLevel === 'need_help';

  // Emit answers upward whenever they change
  useEffect(() => {
    if (isSkipped || questions.length === 0) {
      onAnswersChange([]);
      return;
    }

    // Use a stringified version of questions to avoid reference inequality loops
    const payload: PathwayAnswer[] = questions
      .map((q: Question) => ({
        questionId: q.id,
        questionTextEn: q.text,
        selectedOption: answers[q.id] || '',
        freeText: freeTexts[q.id] || undefined,
        theme: q.category?.name || 'general',
      }))
      .filter(a => a.selectedOption !== '');

    onAnswersChange(payload);
  }, [answers, freeTexts, questions.length, isSkipped]);

  const handleOptionSelect = (questionId: string, value: string) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const selectAndAdvance = (questionId: string, value: string) => {
    handleOptionSelect(questionId, value);
  };

  const handleFreeText = (questionId: string, value: string) => {
    setFreeTexts(prev => ({ ...prev, [questionId]: value }));
  };

  // Render the correct input based on question type
  const renderPathwayInput = (q: Question) => {
    const currentAnswer = answers[q.id] || '';
    const rawOptions = (q.options || []) as Array<string | { text: string; text_ar?: string }>;
    const resolvedOptions = rawOptions.map(opt => resolveOption(opt, isRTL));

    switch (q.type) {
      case 'numeric_scale':
        return (
          <div className="space-y-3 px-2">
            <Slider
              min={1}
              max={10}
              step={1}
              value={[Number(currentAnswer) || 5]}
              onValueChange={v => handleOptionSelect(q.id, String(v[0]))}
              onValueCommit={v => selectAndAdvance(q.id, String(v[0]))}
            />
            <div className="flex justify-between text-xs text-muted-foreground">
              <span>1</span>
              <span className="text-lg font-bold text-primary transition-all duration-200">
                {currentAnswer || '5'}
              </span>
              <span>10</span>
            </div>
          </div>
        );

      case 'yes_no': {
        const yesLabel = resolvedOptions[0] || (isRTL ? 'نعم' : 'Yes');
        const noLabel = resolvedOptions[1] || (isRTL ? 'لا' : 'No');
        return (
          <div className="flex gap-3">
            {[yesLabel, noLabel].map((label, i) => {
              const isSelected = currentAnswer === label;
              return (
                <Button
                  key={i}
                  type="button"
                  variant={isSelected ? 'default' : 'outline'}
                  className="flex-1 gap-1.5"
                  onClick={() => selectAndAdvance(q.id, label)}
                >
                  {label}
                  {isSelected && <CheckCircle2 className="h-3.5 w-3.5" />}
                </Button>
              );
            })}
          </div>
        );
      }

      case 'likert_5': {
        const labels = isRTL ? LIKERT_LABELS_AR : LIKERT_LABELS_EN;
        return (
          <RadioGroup
            value={currentAnswer}
            onValueChange={v => selectAndAdvance(q.id, v)}
            className="space-y-1.5"
          >
            {labels.map((label, i) => {
              const val = String(i + 1);
              const isSelected = currentAnswer === val;
              return (
                <div
                  key={i}
                  className={`flex items-center gap-2.5 p-2.5 rounded-lg border transition-all duration-200 text-sm cursor-pointer ${
                    isSelected ? 'border-primary bg-primary/5' : 'hover:bg-muted/50'
                  }`}
                  onClick={() => selectAndAdvance(q.id, val)}
                >
                  <RadioGroupItem value={val} id={`pathway-likert-${q.id}-${i}`} />
                  <Label
                    htmlFor={`pathway-likert-${q.id}-${i}`}
                    className="cursor-pointer flex-1 text-sm leading-snug"
                    dir="auto"
                  >
                    {label}
                  </Label>
                  {isSelected && <CheckCircle2 className="h-3.5 w-3.5 text-primary shrink-0" />}
                </div>
              );
            })}
          </RadioGroup>
        );
      }

      case 'multiple_choice': {
        if (resolvedOptions.length === 0) {
          // Fallback to textarea if no options defined
          return (
            <Textarea
              value={currentAnswer}
              onChange={e => handleOptionSelect(q.id, e.target.value)}
              placeholder={t('moodPathway.freeTextPlaceholder')}
              rows={2}
              className="resize-none text-sm rounded-xl"
              dir="auto"
            />
          );
        }
        return (
          <RadioGroup
            value={currentAnswer}
            onValueChange={v => selectAndAdvance(q.id, v)}
            className="space-y-1.5"
          >
            {resolvedOptions.map((opt, i) => {
              const isSelected = currentAnswer === opt;
              return (
                <div
                  key={i}
                  className={`flex items-center gap-2.5 p-2.5 rounded-lg border transition-all duration-200 text-sm cursor-pointer ${
                    isSelected ? 'border-primary bg-primary/5' : 'hover:bg-muted/50'
                  }`}
                  onClick={() => selectAndAdvance(q.id, opt)}
                >
                  <RadioGroupItem value={opt} id={`pathway-${q.id}-${i}`} />
                  <Label
                    htmlFor={`pathway-${q.id}-${i}`}
                    className="cursor-pointer flex-1 text-sm leading-snug"
                    dir="auto"
                  >
                    {opt}
                  </Label>
                  {isSelected && <CheckCircle2 className="h-3.5 w-3.5 text-primary shrink-0" />}
                </div>
              );
            })}
          </RadioGroup>
        );
      }

      // open_ended or any other type
      default:
        return (
          <Textarea
            value={currentAnswer}
            onChange={e => handleOptionSelect(q.id, e.target.value)}
            placeholder={t('moodPathway.freeTextPlaceholder')}
            rows={2}
            className="resize-none text-sm rounded-xl"
            dir="auto"
          />
        );
    }
  };

  if (!isEnabled || isSkipped) return null;

  if (isLoading) {
    return (
      <div className="space-y-3 animate-in fade-in duration-300">
        <div className="flex items-center gap-2">
          <div className="flex h-7 w-7 items-center justify-center rounded-full bg-primary/10">
            <Brain className="h-3.5 w-3.5 text-primary animate-pulse" />
          </div>
          <p className="text-sm font-semibold">{t('moodPathway.loadingQuestions')}</p>
        </div>
        <Skeleton className="h-24 w-full rounded-xl" />
      </div>
    );
  }

  if (questions.length === 0) return null;

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="flex h-7 w-7 items-center justify-center rounded-full bg-primary/10">
            <Brain className="h-3.5 w-3.5 text-primary" />
          </div>
          <h4 className="text-sm font-semibold">{t('moodPathway.title')}</h4>
        </div>
        <Button
          variant="ghost"
          size="sm"
          className="text-xs text-muted-foreground h-7 px-2 gap-1"
          onClick={() => {
            setIsSkipped(true);
            onAnswersChange([]);
          }}
        >
          <ChevronDown className="h-3 w-3" />
          {t('moodPathway.skipQuestions')}
        </Button>
      </div>

      {/* Questions */}
      {questions.map((q: Question) => {
        const questionText = isRTL && q.text_ar ? q.text_ar : q.text;
        const isAnswered = !!answers[q.id];
        const categoryName = q.category
          ? (isRTL && q.category.name_ar ? q.category.name_ar : q.category.name)
          : null;

        return (
          <div key={q.id} className="rounded-xl border bg-card p-3 sm:p-4 space-y-3">
            <p className="font-medium text-sm text-center" dir="auto">
              {questionText}
            </p>

            {/* Type-aware input */}
            {renderPathwayInput(q)}

            {/* Free-text for extreme moods when enabled */}
            {enableFreeText && isExtremeMood && isAnswered && q.type !== 'open_ended' && (
              <div className="pt-1 space-y-1.5 animate-in fade-in duration-200">
                <p className="text-xs text-muted-foreground text-center">
                  {t('moodPathway.shareMore')}
                </p>
                <Textarea
                  value={freeTexts[q.id] || ''}
                  onChange={e => handleFreeText(q.id, e.target.value)}
                  placeholder={t('moodPathway.freeTextPlaceholder')}
                  rows={2}
                  className="resize-none text-sm rounded-xl"
                  dir="auto"
                />
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/shared/components/ui/dialog';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Checkbox } from '@/shared/components/ui/checkbox';
import { Badge } from '@/shared/components/ui/badge';
import { ScrollArea } from '@/shared/components/ui/scroll-area';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Search, Tag } from 'lucide-react';
import { useQuestions, Question } from '@/hooks/questions/useQuestions';
import { useQuestionCategories } from '@/hooks/questions/useQuestionCategories';

const MOOD_META: Record<string, { emoji: string; label: string; label_ar: string }> = {
  great: { emoji: '😄', label: 'Great', label_ar: 'ممتاز' },
  good: { emoji: '🙂', label: 'Good', label_ar: 'جيد' },
  okay: { emoji: '😐', label: 'Okay', label_ar: 'عادي' },
  struggling: { emoji: '😟', label: 'Struggling', label_ar: 'أعاني' },
  need_help: { emoji: '😢', label: 'Need Help', label_ar: 'بحاجة للمساعدة' },
};

interface MoodQuestionPickerDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  moodLevel: string;
  onSave: (questionIds: string[], moodLevel: string) => Promise<void>;
  isSaving?: boolean;
}

export function MoodQuestionPickerDialog({
  open,
  onOpenChange,
  moodLevel,
  onSave,
  isSaving,
}: MoodQuestionPickerDialogProps) {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.dir() === 'rtl';

  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('all');

  const { questions, isPending } = useQuestions();
  const { categories } = useQuestionCategories();

  const moodMeta = MOOD_META[moodLevel];

  // Questions currently tagged for this mood
  const taggedIds = useMemo(() => {
    return questions
      .filter(q => {
        const levels = (q as any).mood_levels;
        return Array.isArray(levels) && levels.includes(moodLevel);
      })
      .map(q => q.id);
  }, [questions, moodLevel]);

  const [localSelected, setLocalSelected] = useState<Set<string>>(() => new Set(taggedIds));

  // Sync when dialog opens or taggedIds change
  useMemo(() => {
    if (open) setLocalSelected(new Set(taggedIds));
  }, [open, taggedIds.join(',')]);

  const filtered = useMemo(() => {
    return questions.filter(q => {
      if (categoryFilter !== 'all' && q.category_id !== categoryFilter) return false;
      const text = isRTL && q.text_ar ? q.text_ar : q.text;
      if (search && !text.toLowerCase().includes(search.toLowerCase())) return false;
      return true;
    });
  }, [questions, categoryFilter, search, isRTL]);

  const toggle = (id: string) => {
    setLocalSelected(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleSave = async () => {
    await onSave(Array.from(localSelected), moodLevel);
    onOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] flex flex-col gap-0 p-0">
        <DialogHeader className="p-6 pb-4 border-b">
          <div className="flex items-center gap-2">
            <Tag className="h-4 w-4 text-primary" />
            <DialogTitle>
              {t('moodPathway.browseQuestions')}
              {moodMeta && <span className="ms-1">{moodMeta.emoji}</span>}
            </DialogTitle>
            <span className="text-xs border rounded-full px-2 py-0.5 text-muted-foreground">
              {moodMeta && (isRTL ? moodMeta.label_ar : moodMeta.label)}
            </span>
          </div>
          <DialogDescription>
            {t('moodPathway.browseQuestionsDesc')}
          </DialogDescription>
        </DialogHeader>

        {/* Filters */}
        <div className="p-4 border-b flex gap-3">
          <div className="relative flex-1">
            <Search className="absolute start-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder={t('common.search')}
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="ps-8"
            />
          </div>
          <Select value={categoryFilter} onValueChange={setCategoryFilter}>
            <SelectTrigger className="w-48">
              <SelectValue placeholder={t('questions.category')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t('common.all')}</SelectItem>
              {categories.map(cat => (
                <SelectItem key={cat.id} value={cat.id}>
                  <div className="flex items-center gap-2">
                    <span className="h-2 w-2 rounded-full" style={{ backgroundColor: cat.color || '#3B82F6' }} />
                    {isRTL && cat.name_ar ? cat.name_ar : cat.name}
                  </div>
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Question list */}
        <ScrollArea className="flex-1 p-4 min-h-[300px] max-h-[420px]">
          {isPending ? (
            <div className="space-y-3">
              {[1, 2, 3, 4].map(i => <Skeleton key={i} className="h-14 w-full rounded-lg" />)}
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-10 text-muted-foreground text-sm">
              {t('common.noData')}
            </div>
          ) : (
            <div className="space-y-2">
              {filtered.map((q: Question) => {
                const isChecked = localSelected.has(q.id);
                const text = isRTL && q.text_ar ? q.text_ar : q.text;
                return (
                  <label
                    key={q.id}
                    className={`flex items-start gap-3 p-3 rounded-lg border cursor-pointer transition-colors ${
                      isChecked ? 'border-primary bg-primary/5' : 'hover:bg-muted/50'
                    }`}
                  >
                    <Checkbox
                      checked={isChecked}
                      onCheckedChange={() => toggle(q.id)}
                      className="mt-0.5"
                    />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm leading-snug line-clamp-2" dir="auto">{text}</p>
                      <div className="flex items-center gap-2 mt-1">
                        {q.category && (
                           <Badge variant="outline" className="text-2xs px-1.5 py-0">
                             {isRTL && q.category.name_ar ? q.category.name_ar : q.category.name}
                           </Badge>
                         )}
                         <Badge variant="outline" className="text-2xs px-1.5 py-0">
                           {t(`questions.types.${q.type}`)}
                        </Badge>
                      </div>
                    </div>
                  </label>
                );
              })}
            </div>
          )}
        </ScrollArea>

        <DialogFooter className="p-4 border-t">
          <span className="text-sm text-muted-foreground me-auto">
            {localSelected.size} {t('common.selected')}
          </span>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            {t('common.cancel')}
          </Button>
          <Button onClick={handleSave} disabled={isSaving}>
            {t('common.save')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export interface CheckinScheduledQuestion {
  id: string;
  schedule_id: string;
  question_id: string;
  question_source: string;
  scheduled_delivery: string;
  status: string;
  question: {
    id: string;
    text: string;
    text_ar: string | null;
    type: string;
    options: unknown[] | null;
    category: {
      id: string;
      name: string;
      name_ar: string | null;
      color: string;
    } | null;
  } | null;
}

export function useCheckinScheduledQuestions(employeeId?: string, excludeQuestionId?: string) {
  const today = new Date().toISOString().split('T')[0];

  const { data: questions = [], isPending, error, refetch } = useQuery({
    queryKey: ['checkin-scheduled-questions', employeeId, today, excludeQuestionId],
    queryFn: async () => {
      if (!employeeId) return [];

      const todayEnd = `${today}T23:59:59.999Z`;

      // Fetch only daily-checkin scheduled questions (exclude survey schedules)
      // First get active daily_checkin schedule IDs
      const { data: checkinSchedules } = await supabase
        .from('question_schedules')
        .select('id')
        .eq('schedule_type', 'daily_checkin')
        .is('deleted_at', null);

      const checkinScheduleIds = (checkinSchedules || []).map(s => s.id);
      if (!checkinScheduleIds.length) return [];

      const todayStart = `${today}T00:00:00.000Z`;

      const { data: scheduledRows, error: sqError } = await supabase
        .from('scheduled_questions')
        .select('id, schedule_id, question_id, question_source, scheduled_delivery, status')
        .eq('employee_id', employeeId)
        .in('status', ['pending', 'delivered'])
        .in('schedule_id', checkinScheduleIds)
        .gte('scheduled_delivery', todayStart)
        .lte('scheduled_delivery', todayEnd)
        .order('scheduled_delivery', { ascending: true });

      if (sqError) throw sqError;
      if (!scheduledRows?.length) return [];

      // Group question IDs by source
      const questionsBySource: Record<string, string[]> = {};
      for (const row of scheduledRows) {
        const source = row.question_source || 'questions';
        if (!questionsBySource[source]) questionsBySource[source] = [];
        questionsBySource[source].push(row.question_id);
      }

      // Fetch question details from each source table
      const questionMap = new Map<string, CheckinScheduledQuestion['question']>();

      // From 'questions' table
      if (questionsBySource['questions']?.length) {
        const { data } = await supabase
          .from('questions')
          .select('id, text, text_ar, type, options, category:question_categories(id, name, name_ar, color)')
          .in('id', questionsBySource['questions']);
        (data || []).forEach((q: any) => {
          questionMap.set(q.id, {
            id: q.id,
            text: q.text,
            text_ar: q.text_ar,
            type: q.type,
            options: q.options,
            category: Array.isArray(q.category) ? q.category[0] || null : q.category,
          });
        });
      }

      // From 'wellness_questions' table
      if (questionsBySource['wellness_questions']?.length) {
        const { data } = await supabase
          .from('wellness_questions')
          .select('id, question_text_en, question_text_ar, question_type, options')
          .in('id', questionsBySource['wellness_questions']);
        (data || []).forEach((q: any) => {
          questionMap.set(q.id, {
            id: q.id,
            text: q.question_text_en,
            text_ar: q.question_text_ar,
            type: q.question_type,
            options: q.options,
            category: null,
          });
        });
      }

      // From 'generated_questions' table
      if (questionsBySource['generated_questions']?.length) {
        const { data } = await supabase
          .from('generated_questions')
          .select('id, question_text, question_text_ar, type, options')
          .in('id', questionsBySource['generated_questions']);
        (data || []).forEach((q: any) => {
          questionMap.set(q.id, {
            id: q.id,
            text: q.question_text,
            text_ar: q.question_text_ar,
            type: q.type,
            options: q.options,
            category: null,
          });
        });
      }

      // Merge and deduplicate (exclude the daily wellness question if provided)
      return scheduledRows
        .filter(row => !excludeQuestionId || row.question_id !== excludeQuestionId)
        .map(row => ({
          ...row,
          question_source: row.question_source || 'questions',
          question: questionMap.get(row.question_id) || null,
        }))
        .filter(row => row.question !== null) as CheckinScheduledQuestion[];
    },
    enabled: !!employeeId,
  });

  return { questions, isPending, error, refetch };
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Brain, Info } from 'lucide-react';
import { useMoodQuestionConfig, type MoodQuestionConfig } from '@/hooks/wellness/useMoodQuestionConfig';
import { useMoodDefinitions, type MoodDefinition } from '@/hooks/wellness/useMoodDefinitions';
import { useQuestions } from '@/hooks/questions/useQuestions';
import { useMoodTagging } from '@/features/admin/hooks/admin/useMoodTagging';
import { useTenantId } from '@/hooks/org/useTenantId';
import { MoodQuestionPickerDialog } from '@/features/wellness/components/MoodQuestionPickerDialog';
import { MoodDefinitionDialog } from '@/components/mood/MoodDefinitionDialog';
import { MoodDefinitionManager } from '@/components/mood/settings/MoodDefinitionManager';
import { MoodConfigCard } from '@/components/mood/settings/MoodConfigCard';
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from '@/shared/components/ui/alert-dialog';

export default function MoodPathwaySettings() {
  const { t, i18n } = useTranslation();
  const isRTL = i18n.language === 'ar';

  const { tenantId } = useTenantId();

  const [localConfigs, setLocalConfigs] = useState<Record<string, MoodQuestionConfig>>({});
  const [savingMood, setSavingMood] = useState<string | null>(null);
  const [pickerOpen, setPickerOpen] = useState<string | null>(null);
  const [moodDialogOpen, setMoodDialogOpen] = useState(false);
  const [editingMood, setEditingMood] = useState<MoodDefinition | null>(null);
  const [deletingMood, setDeletingMood] = useState<MoodDefinition | null>(null);

  const { configs, isPending: configsLoading, upsertConfig } = useMoodQuestionConfig(tenantId);
  const { moods, isPending: moodsLoading, upsertMood, deleteMood, toggleMood, reorderMoods } = useMoodDefinitions(tenantId);
  const { questions } = useQuestions();
  const { getTaggedQuestions, saveTags, unlinkQuestion, isSaving: savingTags } = useMoodTagging(questions);
  const isLoading = configsLoading || moodsLoading;

  useEffect(() => {
    if (!configs.length) return;
    const map: Record<string, MoodQuestionConfig> = {};
    configs.forEach(c => { map[c.mood_level] = { ...c }; });
    setLocalConfigs(map);
  }, [configs]);

  const updateLocal = (moodLevel: string, field: keyof MoodQuestionConfig, value: any) => {
    setLocalConfigs(prev => ({
      ...prev,
      [moodLevel]: { ...prev[moodLevel], tenant_id: tenantId!, mood_level: moodLevel, [field]: value },
    }));
  };

  const handleSave = async (moodLevel: string) => {
    const config = localConfigs[moodLevel];
    if (!config || !tenantId) return;
    setSavingMood(moodLevel);
    try { await upsertConfig.mutateAsync({ ...config, tenant_id: tenantId }); }
    finally { setSavingMood(null); }
  };

  const handleMoodDialogSave = (data: Partial<MoodDefinition>) => {
    if (!tenantId) return;
    const nextOrder = editingMood ? editingMood.sort_order : moods.length;
    upsertMood.mutate({
      ...data, tenant_id: tenantId, key: data.key!,
      sort_order: data.sort_order ?? nextOrder,
      is_active: data.is_active ?? true, is_default: data.is_default ?? false,
    } as any, {
      onSuccess: () => { setMoodDialogOpen(false); setEditingMood(null); },
    });
  };

  const handleMoveUp = (index: number) => {
    if (index === 0) return;
    const ordered = [...moods];
    [ordered[index - 1], ordered[index]] = [ordered[index], ordered[index - 1]];
    reorderMoods.mutate(ordered.map(m => m.id));
  };

  const handleMoveDown = (index: number) => {
    if (index >= moods.length - 1) return;
    const ordered = [...moods];
    [ordered[index], ordered[index + 1]] = [ordered[index + 1], ordered[index]];
    reorderMoods.mutate(ordered.map(m => m.id));
  };

  const handleDeleteMood = () => {
    if (!deletingMood) return;
    deleteMood.mutate(deletingMood.id, { onSettled: () => setDeletingMood(null) });
  };

  return (
    <div className="space-y-6 p-6">
      {/* Page header */}
      <div className="flex items-start gap-4">
        <div className="flex h-12 w-12 items-center justify-center rounded-lg bg-primary/10 shrink-0">
          <Brain className="h-6 w-6 text-primary" />
        </div>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">{t('moodPathway.settingsTitle')}</h1>
          <p className="text-muted-foreground text-sm mt-1">{t('moodPathway.settingsDesc')}</p>
        </div>
      </div>

      {/* Info banner */}
      <div className="glass-card border-0 rounded-xl p-4 flex items-start gap-3">
        <Info className="h-4 w-4 text-primary mt-0.5 shrink-0" />
        <p className="text-sm text-muted-foreground">{t('moodPathway.settingsInfo')}</p>
      </div>

      {/* Mood Definitions Management */}
      <MoodDefinitionManager
        moods={moods}
        isLoading={moodsLoading}
        isRTL={isRTL}
        canDelete={moods.length > 2}
        onAdd={() => { setEditingMood(null); setMoodDialogOpen(true); }}
        onEdit={(mood) => { setEditingMood(mood); setMoodDialogOpen(true); }}
        onDelete={setDeletingMood}
        onToggle={(id, v) => toggleMood.mutate({ id, is_active: v })}
        onMoveUp={handleMoveUp}
        onMoveDown={handleMoveDown}
      />

      {/* Per-Mood Pathway Cards */}
      {isLoading ? (
        <div className="space-y-4">
          {[1, 2, 3].map(i => <Skeleton key={i} className="h-48 w-full rounded-lg" />)}
        </div>
      ) : (
        <div className="space-y-4">
          {moods.filter(m => m.is_active).map(moodDef => (
            <MoodConfigCard
              key={moodDef.id}
              moodDef={moodDef}
              config={localConfigs[moodDef.key]}
              taggedQuestions={getTaggedQuestions(moodDef.key)}
              isRTL={isRTL}
              isSaving={savingMood === moodDef.key}
              onUpdateField={updateLocal}
              onSave={handleSave}
              onOpenPicker={setPickerOpen}
              onUnlinkQuestion={unlinkQuestion}
            />
          ))}
        </div>
      )}

      {/* Question picker dialog */}
      {pickerOpen && (
        <MoodQuestionPickerDialog
          open={!!pickerOpen}
          onOpenChange={open => { if (!open) setPickerOpen(null); }}
          moodLevel={pickerOpen}
          onSave={saveTags}
          isSaving={savingTags}
        />
      )}

      {/* Mood definition dialog */}
      <MoodDefinitionDialog
        open={moodDialogOpen}
        onOpenChange={open => { if (!open) { setMoodDialogOpen(false); setEditingMood(null); } else setMoodDialogOpen(true); }}
        mood={editingMood}
        onSave={handleMoodDialogSave}
        isSaving={upsertMood.isPending}
        existingKeys={moods.map(m => m.key)}
        existingMoods={moods}
      />

      {/* Delete confirmation dialog */}
      <AlertDialog open={!!deletingMood} onOpenChange={open => { if (!open) setDeletingMood(null); }}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t('common.confirm')}</AlertDialogTitle>
            <AlertDialogDescription>
              {t('moodPathway.deleteMoodConfirm')}
              {deletingMood?.is_default && (
                <span className="block mt-2 font-medium text-destructive">{t('moodPathway.deletingDefaultWarning')}</span>
              )}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteMood} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              {t('common.delete')}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

/**
 * Check-in Service — handles mood entry submission and related operations.
 * No React imports — pure async functions.
 */

import { supabase } from '@/integrations/supabase/client';
import { calculatePoints } from '@/features/recognition/services/gamificationService';
import { logger } from '@/shared/utils/logger';
import { DuplicateCheckinError, ServiceUnavailableError } from '@/shared/utils/errors';

export interface CheckinParams {
  tenantId: string;
  employeeId: string;
  userId: string;
  moodLevel: string;
  moodScore: number;
  comment?: string | null;
  supportActions?: string[];
  answerValue?: Record<string, unknown> | null;
  currentStreak: number;
  entryDate: string;
  language?: string;
  pathwayAnswers?: { theme: string; selectedOption?: string; answer?: string; freeText?: string }[];
}

export interface CheckinResult {
  tip: string;
  pointsEarned: number;
  newStreak: number;
}

/**
 * Fetch today's existing mood entry for an employee.
 */
export async function fetchTodayEntry(employeeId: string, date: string) {
  const { data, error } = await supabase
    .from('mood_entries')
    .select('*')
    .eq('employee_id', employeeId)
    .eq('entry_date', date)
    .maybeSingle();

  if (error) throw error;
  return data;
}

/**
 * Generate an AI wellness tip (optional — failure is non-fatal).
 */
export async function generateDailyTip(
  moodLevel: string,
  pathwayAnswers: CheckinParams['pathwayAnswers'],
  language: string
): Promise<string> {
  try {
    const { data } = await supabase.functions.invoke('generate-daily-tip', {
      body: { moodLevel, pathwayAnswers: pathwayAnswers || [], language },
    });
    return data?.tip || '';
  } catch {
    return '';
  }
}

/**
 * Submit a mood entry + points transaction.
 * Returns { alreadySubmitted: true } if unique constraint is violated.
 */
export async function submitMoodEntry(params: CheckinParams): Promise<CheckinResult> {
  const {
    tenantId, employeeId, userId, moodLevel, moodScore,
    comment, supportActions, answerValue, currentStreak, entryDate,
    language, pathwayAnswers,
  } = params;

  // 1. Generate AI tip (optional)
  const tip = await generateDailyTip(moodLevel, pathwayAnswers, language || 'en');

  // 2. Calculate points based on streak BEFORE today
  const points = calculatePoints(currentStreak);
  const newStreak = currentStreak + 1;

  // 3. Insert mood entry
  const { error: moodError } = await supabase
    .from('mood_entries' as any)
    .insert({
      tenant_id: tenantId,
      employee_id: employeeId,
      mood_level: moodLevel,
      mood_score: moodScore,
      answer_value: answerValue ?? null,
      answer_text: comment || null,
      ai_tip: tip || null,
      support_actions: supportActions || [],
      points_earned: points,
      streak_count: newStreak,
      entry_date: entryDate,
    });

  if (moodError) {
    if (moodError.code === '23505') {
      throw new DuplicateCheckinError();
    }
    throw new ServiceUnavailableError(moodError.message || 'Failed to save mood entry');
  }

  // 4. Insert into points ledger
  const { error: ptError } = await supabase
    .from('points_transactions')
    .insert({
      user_id: userId,
      tenant_id: tenantId,
      amount: points,
      source_type: 'daily_checkin',
      status: 'credited',
      description: 'Daily check-in streak reward',
    });

  if (ptError) {
    // Log but don't throw — mood entry already succeeded
    logger.warn('checkinService', 'Points ledger insert failed:', ptError.message);
  }

  return { tip, pointsEarned: points, newStreak };
}

import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
