              <FormField control={form.control} name="status" render={({ field }) => (
                <FormItem><FormLabel>{t('common.status')}</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                    <SelectContent>
                      <SelectItem value="planned">{t('workload.status.planned')}</SelectItem>
                      <SelectItem value="in_progress">{t('workload.status.inProgress')}</SelectItem>
                      <SelectItem value="completed">{t('workload.status.completed')}</SelectItem>
                      <SelectItem value="on_hold">{t('workload.status.onHold')}</SelectItem>
                    </SelectContent>
                  </Select>
                <FormMessage /></FormItem>
              )} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <FormField control={form.control} name="start_date" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.initiatives.startDate')}</FormLabel><FormControl><Input type="date" {...field} /></FormControl><FormMessage /></FormItem>
              )} />
              <FormField control={form.control} name="end_date" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.initiatives.endDate')}</FormLabel><FormControl><Input type="date" {...field} /></FormControl><FormMessage /></FormItem>
              )} />
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>{t('common.cancel')}</Button>
              <Button type="submit" disabled={isSubmitting}>{isSubmitting ? t('common.loading') : t('common.save')}</Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useEffect } from 'react';
import {
  Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle,
} from '@/shared/components/ui/dialog';
import {
  Form, FormControl, FormField, FormItem, FormLabel, FormMessage,
} from '@/shared/components/ui/form';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Button } from '@/shared/components/ui/button';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/shared/components/ui/select';
import { EmployeePicker } from '@/features/workload/components/EmployeePicker';
import type { Objective } from '@/features/workload/hooks/useObjectives';

const schema = z.object({
  title: z.string().min(1).max(200),
  title_ar: z.string().max(200).optional().or(z.literal('')),
  description: z.string().max(1000).optional().or(z.literal('')),
  description_ar: z.string().max(1000).optional().or(z.literal('')),
  year: z.coerce.number().int().min(2020).max(2050),
  quarter: z.enum(['Q1', 'Q2', 'Q3', 'Q4']),
  status: z.enum(['on_track', 'at_risk', 'delayed', 'completed']),
  start_date: z.string().min(1),
  end_date: z.string().optional().or(z.literal('')),
  owner_user_id: z.string().nullable().optional(),
  accountable_user_id: z.string().nullable().optional(),
});

type FormValues = z.infer<typeof schema>;

interface Props {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  objective?: Objective | null;
  onSubmit: (data: any) => void;
  isSubmitting: boolean;
}

export function ObjectiveDialog({ open, onOpenChange, objective, onSubmit, isSubmitting }: Props) {
  const { t } = useTranslation();
  const isEditing = !!objective;

  const form = useForm<FormValues>({
    resolver: zodResolver(schema),
    defaultValues: {
      title: '', title_ar: '', description: '', description_ar: '',
      year: new Date().getFullYear(), quarter: 'Q1', status: 'on_track',
      start_date: new Date().toISOString().split('T')[0], end_date: '',
      owner_user_id: null, accountable_user_id: null,
    },
  });

  useEffect(() => {
    if (objective) {
      form.reset({
        title: objective.title, title_ar: objective.title_ar || '',
        description: objective.description || '', description_ar: objective.description_ar || '',
        year: objective.year, quarter: objective.quarter as any,
        status: objective.status as any,
        start_date: objective.start_date, end_date: objective.end_date || '',
        owner_user_id: objective.owner_user_id || null,
        accountable_user_id: (objective as any).accountable_user_id || null,
      });
    } else {
      form.reset({
        title: '', title_ar: '', description: '', description_ar: '',
        year: new Date().getFullYear(), quarter: 'Q1', status: 'on_track',
        start_date: new Date().toISOString().split('T')[0], end_date: '',
        owner_user_id: null, accountable_user_id: null,
      });
    }
  }, [objective, form]);

  const handleSubmit = (data: FormValues) => {
    onSubmit({
      ...data,
      title_ar: data.title_ar || null,
      description: data.description || null,
      description_ar: data.description_ar || null,
      end_date: data.end_date || null,
      owner_user_id: data.owner_user_id || null,
      accountable_user_id: data.accountable_user_id || null,
    });
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[550px]">
        <DialogHeader>
          <DialogTitle>{isEditing ? t('workload.objectives.edit') : t('workload.objectives.add')}</DialogTitle>
          <DialogDescription>{isEditing ? t('workload.objectives.editDesc') : t('workload.objectives.addDesc')}</DialogDescription>
        </DialogHeader>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-4">
            <FormField control={form.control} name="title" render={({ field }) => (
              <FormItem><FormLabel>{t('workload.objectives.title')}</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>
            )} />
            <FormField control={form.control} name="title_ar" render={({ field }) => (
              <FormItem><FormLabel>{t('workload.objectives.titleAr')}</FormLabel><FormControl><Input {...field} dir="rtl" /></FormControl><FormMessage /></FormItem>
            )} />
            <FormField control={form.control} name="description" render={({ field }) => (
              <FormItem><FormLabel>{t('workload.objectives.description')}</FormLabel><FormControl><Textarea {...field} rows={2} /></FormControl><FormMessage /></FormItem>
            )} />
            <div className="grid grid-cols-2 gap-4">
              <FormField control={form.control} name="owner_user_id" render={({ field }) => (
                <FormItem>
                  <FormLabel>{t('workload.assignment.owner')}</FormLabel>
                  <FormControl><EmployeePicker value={field.value} onChange={field.onChange} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
              <FormField control={form.control} name="accountable_user_id" render={({ field }) => (
                <FormItem>
                  <FormLabel>{t('workload.assignment.accountable')}</FormLabel>
                  <FormControl><EmployeePicker value={field.value} onChange={field.onChange} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
            </div>
            <div className="grid grid-cols-3 gap-4">
              <FormField control={form.control} name="year" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.objectives.year')}</FormLabel><FormControl><Input type="number" {...field} /></FormControl><FormMessage /></FormItem>
              )} />
              <FormField control={form.control} name="quarter" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.objectives.quarter')}</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                    <SelectContent>
                      <SelectItem value="Q1">Q1</SelectItem>
                      <SelectItem value="Q2">Q2</SelectItem>
                      <SelectItem value="Q3">Q3</SelectItem>
                      <SelectItem value="Q4">Q4</SelectItem>
                    </SelectContent>
                  </Select>
                <FormMessage /></FormItem>
              )} />
              <FormField control={form.control} name="status" render={({ field }) => (
                <FormItem><FormLabel>{t('common.status')}</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                    <SelectContent>
                      <SelectItem value="on_track">{t('workload.status.onTrack')}</SelectItem>
                      <SelectItem value="at_risk">{t('workload.status.atRisk')}</SelectItem>
                      <SelectItem value="delayed">{t('workload.status.delayed')}</SelectItem>
                      <SelectItem value="completed">{t('workload.status.completed')}</SelectItem>
                    </SelectContent>
                  </Select>
                <FormMessage /></FormItem>
              )} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <FormField control={form.control} name="start_date" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.objectives.startDate')}</FormLabel><FormControl><Input type="date" {...field} /></FormControl><FormMessage /></FormItem>
              )} />
              <FormField control={form.control} name="end_date" render={({ field }) => (
                <FormItem><FormLabel>{t('workload.objectives.endDate')}</FormLabel><FormControl><Input type="date" {...field} /></FormControl><FormMessage /></FormItem>
              )} />
            </div>
            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>{t('common.cancel')}</Button>
              <Button type="submit" disabled={isSubmitting}>{isSubmitting ? t('common.loading') : t('common.save')}</Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { CheckCircle2, XCircle, Eye, CalendarDays } from 'lucide-react';
import { useLocaleFormat } from '@/shared/hooks/useLocaleFormat';
import { EmptyState } from '@/shared/empty/EmptyState';
import { useApprovalQueue } from '@/features/tasks/hooks/useApprovalQueue';

export function WorkloadApprovalsView() {
  const { t } = useTranslation();
  const { lformat } = useLocaleFormat();
  const navigate = useNavigate();
  const { pendingTasks, tasksLoading, updateStatus } = useApprovalQueue();

  const handleApprove = (id: string) => updateStatus.mutate({ id, status: 'completed' });
  const handleReject = (id: string) => updateStatus.mutate({ id, status: 'rejected' });

  if (tasksLoading) return <Skeleton className="h-64" />;

  if (pendingTasks.length === 0) {
    return <EmptyState title={t('tasks.approvalEmpty')} description={t('tasks.approvalEmptyDesc')} />;
  }

  return (
    <div className="space-y-3">
      {pendingTasks.map(task => (
        <Card key={task.id} className="border-0 bg-muted/20 hover:bg-muted/40 transition-colors">
          <CardContent className="p-4">
            <div className="flex flex-col sm:flex-row sm:items-center gap-3">
              <div className="flex-1 min-w-0 space-y-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-medium text-sm">{task.title}</span>
                  <Badge variant="outline" className={task.status === 'pending_approval' ? 'bg-chart-5/10 text-chart-5' : 'bg-chart-4/10 text-chart-4'}>
                    {t(`tasks.status.${task.status}`)}
                  </Badge>
                  <Badge variant="outline">P{task.priority}</Badge>
                </div>
                {(task as any).employee?.full_name && (
                  <p className="text-xs text-muted-foreground">{t('tasks.fields.assignee')}: {(task as any).employee.full_name}</p>
                )}
                {task.description && <p className="text-xs text-muted-foreground line-clamp-2">{task.description}</p>}
                <div className="flex items-center gap-3 text-xs text-muted-foreground">
                  {task.due_date && (
                    <span className="flex items-center gap-1"><CalendarDays className="h-3 w-3" />{lformat(new Date(task.due_date), 'PP')}</span>
                  )}
                  <span>{t('tasks.fields.progress')}: {task.progress}%</span>
                </div>
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <Button size="sm" variant="ghost" onClick={() => navigate(`/tasks/${task.id}`)} className="gap-1">
                  <Eye className="h-3.5 w-3.5" />{t('common.view')}
                </Button>
                <Button size="sm" variant="default" onClick={() => handleApprove(task.id)} className="gap-1" disabled={updateStatus.isPending}>
                  <CheckCircle2 className="h-3.5 w-3.5" />{t('tasks.approve')}
                </Button>
                <Button size="sm" variant="destructive" onClick={() => handleReject(task.id)} className="gap-1" disabled={updateStatus.isPending}>
                  <XCircle className="h-3.5 w-3.5" />{t('tasks.reject')}
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocaleFormat } from '@/shared/hooks/useLocaleFormat';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from '@/shared/components/ui/select';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import {
  format, startOfMonth, endOfMonth, startOfWeek, endOfWeek,
  addMonths, subMonths, addWeeks, subWeeks,
  eachDayOfInterval, isSameMonth, isToday,
} from 'date-fns';
import type { UnifiedTask } from '@/features/workload/hooks/useUnifiedTasks';

const STATUS_COLORS: Record<string, string> = {
  draft: 'bg-muted text-muted-foreground',
  open: 'bg-chart-2/15 text-chart-2',
  in_progress: 'bg-chart-2/15 text-chart-2',
  under_review: 'bg-chart-4/15 text-chart-4',
  pending_approval: 'bg-chart-5/15 text-chart-5',
  completed: 'bg-chart-1/15 text-chart-1',
  rejected: 'bg-destructive/15 text-destructive',
  archived: 'bg-muted text-muted-foreground',
};

const PRIORITY_DOTS: Record<number, string> = {
  0: 'bg-destructive',
  1: 'bg-chart-5',
  2: 'bg-chart-4',
  3: 'bg-muted-foreground',
};

interface WorkloadCalendarViewProps {
  tasks: UnifiedTask[];
  isPending: boolean;
}

export function WorkloadCalendarView({ tasks, isPending }: WorkloadCalendarViewProps) {
  const { t } = useTranslation();
  const { lformat } = useLocaleFormat();
  const navigate = useNavigate();

  const [currentDate, setCurrentDate] = useState(new Date());
  const [view, setView] = useState<'month' | 'week'>('month');

  const days = useMemo(() => {
    if (view === 'month') {
      const monthStart = startOfMonth(currentDate);
      const monthEnd = endOfMonth(currentDate);
      const calStart = startOfWeek(monthStart, { weekStartsOn: 0 });
      const calEnd = endOfWeek(monthEnd, { weekStartsOn: 0 });
      return eachDayOfInterval({ start: calStart, end: calEnd });
    } else {
      const weekStart = startOfWeek(currentDate, { weekStartsOn: 0 });
      const weekEnd = endOfWeek(currentDate, { weekStartsOn: 0 });
      return eachDayOfInterval({ start: weekStart, end: weekEnd });
    }
  }, [currentDate, view]);

  const tasksByDate = useMemo(() => {
    const map = new Map<string, UnifiedTask[]>();
    tasks.forEach(task => {
      if (!task.due_date) return;
      const key = task.due_date.split('T')[0];
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(task);
    });
    return map;
  }, [tasks]);

  const handlePrev = () => setCurrentDate(prev => view === 'month' ? subMonths(prev, 1) : subWeeks(prev, 1));
  const handleNext = () => setCurrentDate(prev => view === 'month' ? addMonths(prev, 1) : addWeeks(prev, 1));
  const handleToday = () => setCurrentDate(new Date());

  const weekDayHeaders = useMemo(() => {
    const start = startOfWeek(new Date(), { weekStartsOn: 0 });
    return eachDayOfInterval({ start, end: endOfWeek(start, { weekStartsOn: 0 }) })
      .map(d => lformat(d, 'EEE'));
  }, []);

  const unscheduledCount = useMemo(() => tasks.filter(t => !t.due_date).length, [tasks]);

  return (
    <div className="space-y-4">
      {/* Controls */}
      <Card className="border-0 bg-muted/30">
        <CardContent className="p-3 flex flex-wrap items-center justify-between gap-3">
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={handlePrev}>
              <ChevronLeft className="h-4 w-4 rtl:rotate-180" />
            </Button>
            <h2 className="text-sm font-semibold min-w-[160px] text-center">
              {view === 'month'
                ? lformat(currentDate, 'MMMM yyyy')
                : `${lformat(startOfWeek(currentDate, { weekStartsOn: 0 }), 'MMM d')} — ${lformat(endOfWeek(currentDate, { weekStartsOn: 0 }), 'MMM d, yyyy')}`
              }
            </h2>
            <Button variant="ghost" size="icon" className="h-8 w-8" onClick={handleNext}>
              <ChevronRight className="h-4 w-4 rtl:rotate-180" />
            </Button>
            <Button variant="outline" size="sm" className="h-8 text-xs" onClick={handleToday}>
              {t('tasks.calendar.today')}
            </Button>
          </div>
          <div className="flex items-center gap-2">
            {unscheduledCount > 0 && (
              <Badge variant="secondary" className="text-xs">
                {unscheduledCount} {t('tasks.calendar.unscheduled')}
              </Badge>
            )}
            <Select value={view} onValueChange={(v) => setView(v as 'month' | 'week')}>
              <SelectTrigger className="w-[100px] h-8 text-xs"><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="month">{t('tasks.calendar.month')}</SelectItem>
                <SelectItem value="week">{t('tasks.calendar.week')}</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      {/* Grid */}
      {isPending ? (
        <Skeleton className="h-[500px]" />
      ) : (
        <Card className="border-0 overflow-hidden">
          <CardContent className="p-0">
            <div className="grid grid-cols-7 border-b">
              {weekDayHeaders.map(day => (
                <div key={day} className="py-2 px-1 text-center text-xs font-medium text-muted-foreground">
                  {day}
                </div>
              ))}
            </div>
            <div className={`grid grid-cols-7 ${view === 'week' ? 'min-h-[300px]' : ''}`}>
              {days.map(day => {
                const dateKey = format(day, 'yyyy-MM-dd');
                const dayTasks = tasksByDate.get(dateKey) ?? [];
                const inMonth = view === 'month' ? isSameMonth(day, currentDate) : true;
                const today = isToday(day);
                const maxVisible = view === 'week' ? 8 : 3;
                const overflow = dayTasks.length - maxVisible;

                return (
                  <div
                    key={dateKey}
                    className={`border-b border-e min-h-[80px] p-1 transition-colors ${
                      !inMonth ? 'bg-muted/20' : 'hover:bg-muted/10'
                    } ${view === 'week' ? 'min-h-[200px]' : ''}`}
                  >
                    <div className={`text-xs font-medium mb-1 flex items-center justify-center w-6 h-6 rounded-full mx-auto ${
                      today ? 'bg-primary text-primary-foreground' : inMonth ? '' : 'text-muted-foreground/50'
                    }`}>
                      {lformat(day, 'd')}
                    </div>
                    <div className="space-y-0.5">
                      {dayTasks.slice(0, maxVisible).map(task => (
                        <button
                          key={task.id}
                          onClick={() => navigate(`/tasks/${task.id}`)}
                          className={`w-full text-start rounded px-1.5 py-0.5 text-2xs leading-tight truncate flex items-center gap-1 transition-colors hover:ring-1 hover:ring-ring ${
                            STATUS_COLORS[task.status] ?? STATUS_COLORS.draft
                          }`}
                        >
                          <span className={`h-1.5 w-1.5 rounded-full shrink-0 ${PRIORITY_DOTS[task.priority] ?? PRIORITY_DOTS[2]}`} />
                          <span className="truncate">{task.title}</span>
                        </button>
                      ))}
                      {overflow > 0 && (
                        <p className="text-2xs text-muted-foreground text-center">
                          +{overflow} {t('tasks.calendar.more')}
                        </p>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/shared/components/ui/dialog';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Lock, ShieldCheck } from 'lucide-react';
import type { UnifiedTask, UnifiedTaskInsert, UnifiedTaskUpdate, TaskComment } from '@/features/workload/hooks/useUnifiedTasks';
import { useTaskEvidenceUpload } from '@/features/workload';
import { toast } from 'sonner';
import { TaskDialogForm } from './task-dialog/TaskDialogForm';
import { TaskCommentSection } from './task-dialog/TaskCommentSection';
import { TaskEvidenceSection } from './task-dialog/TaskEvidenceSection';

interface TaskDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  task?: UnifiedTask | null;
  employeeId: string;
  tenantId: string;
  onCreate: (data: UnifiedTaskInsert) => void;
  onUpdate: (data: UnifiedTaskUpdate) => void;
  isSubmitting: boolean;
  onAddComment?: (data: { id: string; comment: TaskComment }) => void;
  currentEmployeeName?: string;
}

export function TaskDialog({ open, onOpenChange, task, employeeId, tenantId, onCreate, onUpdate, isSubmitting, onAddComment, currentEmployeeName }: TaskDialogProps) {
  const { t } = useTranslation();
  const isEdit = !!task;
  const isLocked = task?.is_locked ?? false;
  const [closureComment, setClosureComment] = useState('');
  const [progress, setProgress] = useState(task?.progress ?? 0);
  const [closureError, setClosureError] = useState(false);
  const { evidence, uploading, loadEvidence, uploadEvidence } = useTaskEvidenceUpload(tenantId);

  useEffect(() => {
    setProgress(task?.progress ?? 0);
    setClosureComment('');
    setClosureError(false);
    if (task?.id) loadEvidence(task.id);
  }, [task?.id, open]);

  const { register, handleSubmit, setValue, watch, reset } = useForm({
    defaultValues: {
      title: task?.title ?? '', description: task?.description ?? '',
      priority: task?.priority ?? 3, status: task?.status ?? 'draft',
      estimated_minutes: task?.estimated_minutes ?? null,
      due_date: task?.due_date ? task.due_date.split('T')[0] : '',
      scheduled_start: task?.scheduled_start ? task.scheduled_start.split('T')[0] : '',
    },
  });

  const computeStatus = (prog: number, currentStatus: string) => {
    if (prog >= 100) return 'completed';
    if (prog > 0 && ['draft', 'open'].includes(currentStatus)) return 'in_progress';
    if (currentStatus === 'todo' || currentStatus === 'blocked') return 'open';
    return currentStatus || 'open';
  };

  const onSubmit = (data: any) => {
    const derivedStatus = computeStatus(progress, data.status);
    if (derivedStatus === 'completed' && progress >= 100 && !closureComment.trim() && isEdit) {
      setClosureError(true);
      return;
    }
    if (isEdit && task) {
      if (derivedStatus === 'completed' && closureComment.trim() && onAddComment) {
        onAddComment({
          id: task.id,
          comment: {
            id: crypto.randomUUID(), employee_id: employeeId,
            employee_name: currentEmployeeName || 'User',
            text: `📋 ${t('workload.tasks.closureComment')}: ${closureComment.trim()}`,
            created_at: new Date().toISOString(),
          },
        });
      }
      onUpdate({
        id: task.id, title: data.title, description: data.description || null,
        priority: Number(data.priority), status: derivedStatus, progress,
        estimated_minutes: data.estimated_minutes ? Number(data.estimated_minutes) : null,
        due_date: data.due_date || null, scheduled_start: data.scheduled_start || null,
      });
    } else {
      onCreate({
        tenant_id: tenantId, employee_id: employeeId, title: data.title,
        description: data.description || null, priority: Number(data.priority),
        status: 'draft', estimated_minutes: data.estimated_minutes ? Number(data.estimated_minutes) : null,
        due_date: data.due_date || null, source_type: 'manual',
      });
    }
    onOpenChange(false);
    reset();
  };

  const handleEvidenceUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files?.length || !task) return;
    const success = await uploadEvidence(task.id, employeeId, e.target.files[0]);
    if (success) toast.success(t('workload.tasks.evidenceUploaded'));
    else toast.error(t('workload.tasks.evidenceUploadError'));
    e.target.value = '';
  };

  const handleMarkVerified = () => {
    if (!task) return;
    onUpdate({ id: task.id, metadata: { ...(task.metadata as Record<string, unknown> ?? {}), verified: true } } as UnifiedTaskUpdate);
    toast.success(t('workload.tasks.verified'));
    onOpenChange(false);
  };

  const isCompleted = task?.status === 'completed';
  const isVerified = !!(task?.metadata as Record<string, unknown>)?.verified;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            {isEdit ? t('commandCenter.editTask') : t('commandCenter.addTask')}
            {isLocked && <Lock className="h-4 w-4 text-chart-4" />}
            {isVerified && <ShieldCheck className="h-4 w-4 text-primary" />}
          </DialogTitle>
          <DialogDescription>{isEdit ? t('commandCenter.editTaskDesc') : t('commandCenter.addTaskDesc')}</DialogDescription>
        </DialogHeader>

        {isEdit && task && (
          <div className="flex flex-wrap gap-2 text-xs text-muted-foreground">
            <Badge variant="outline" className="text-2xs">{t('workload.tasks.source')}: {task.source_type}</Badge>
            {task.created_by && <Badge variant="outline" className="text-2xs">{t('workload.tasks.createdBy')}: {task.created_by}</Badge>}
            <Badge variant="outline" className="text-2xs">{new Date(task.created_at).toLocaleDateString()}</Badge>
          </div>
        )}

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <TaskDialogForm
            isEdit={isEdit} isLocked={isLocked} isVerified={isVerified} task={task}
            register={register} watch={watch} setValue={setValue}
            progress={progress} onProgressChange={setProgress} computeStatus={computeStatus}
            closureComment={closureComment} onClosureCommentChange={setClosureComment}
            closureError={closureError} onClosureErrorClear={() => setClosureError(false)}
            onUpdate={onUpdate}
          />

          {isEdit && task && (isCompleted || isVerified) && (
            <TaskEvidenceSection
              evidence={evidence} isVerified={isVerified} isCompleted={isCompleted}
              uploading={uploading} onUpload={handleEvidenceUpload} onMarkVerified={handleMarkVerified}
            />
          )}

          {isEdit && (
            <TaskCommentSection
              comments={task?.comments ?? []} employeeId={employeeId}
              currentEmployeeName={currentEmployeeName} onAddComment={onAddComment}
              taskId={task?.id ?? ''}
            />
          )}

          <div className="flex justify-end gap-2 pt-2">
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>{t('common.cancel')}</Button>
            {!isVerified && (
              <Button type="submit" disabled={isSubmitting}>{isEdit ? t('common.save') : t('common.create')}</Button>
            )}
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { UseFormRegister, UseFormWatch, UseFormSetValue } from 'react-hook-form';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { Label } from '@/shared/components/ui/label';
import { Progress } from '@/shared/components/ui/progress';
import { Slider } from '@/shared/components/ui/slider';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { AlertCircle } from 'lucide-react';
import type { UnifiedTask, UnifiedTaskUpdate } from '@/features/workload/hooks/useUnifiedTasks';

interface TaskDialogFormProps {
  isEdit: boolean;
  isLocked: boolean;
  isVerified: boolean;
  task?: UnifiedTask | null;
  register: UseFormRegister<any>;
  watch: UseFormWatch<any>;
  setValue: UseFormSetValue<any>;
  progress: number;
  onProgressChange: (value: number) => void;
  computeStatus: (prog: number, currentStatus: string) => string;
  closureComment: string;
  onClosureCommentChange: (value: string) => void;
  closureError: boolean;
  onClosureErrorClear: () => void;
  onUpdate: (data: UnifiedTaskUpdate) => void;
}

const priorityOptions = [1, 2, 3, 4, 5];

const STATUS_MAP: Record<string, string> = {
  draft: 'planned', open: 'planned', in_progress: 'inProgress',
  under_review: 'underReview', pending_approval: 'pendingApproval',
  completed: 'completed', rejected: 'rejected', archived: 'archived',
};

export function TaskDialogForm({
  isEdit, isLocked, isVerified, task,
  register, watch, setValue,
  progress, onProgressChange, computeStatus,
  closureComment, onClosureCommentChange, closureError, onClosureErrorClear,
  onUpdate,
}: TaskDialogFormProps) {
  const { t } = useTranslation();
  const watchedStatus = watch('status');

  return (
    <>
      <div className="space-y-2">
        <Label>{t('commandCenter.taskTitle')}</Label>
        <Input {...register('title', { required: true })} placeholder={t('commandCenter.taskTitlePlaceholder')} disabled={isLocked} />
      </div>
      <div className="space-y-2">
        <Label>{t('commandCenter.taskDescription')}</Label>
        <Textarea {...register('description')} rows={2} disabled={isLocked} />
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-2">
          <Label>{t('commandCenter.priority')}</Label>
          <Select value={String(watch('priority'))} onValueChange={(v) => setValue('priority', Number(v))} disabled={isLocked}>
            <SelectTrigger><SelectValue /></SelectTrigger>
            <SelectContent>
              {priorityOptions.map(p => (
                <SelectItem key={p} value={String(p)}>P{p}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="space-y-2">
          <Label>{t('common.status')}</Label>
          <div className="flex items-center gap-2 h-10 px-3 rounded-md border bg-muted/30 text-sm">
            {t(`workload.status.${STATUS_MAP[computeStatus(progress, watchedStatus)] ?? 'planned'}`)}
          </div>
        </div>
      </div>

      {/* Progress Slider */}
      {isEdit && (
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <Label>{t('workload.tasks.progress')}</Label>
            <span className="text-sm font-bold text-primary">{progress}%</span>
          </div>
          <Slider
            value={[progress]}
            onValueChange={([v]) => { onProgressChange(v); onClosureErrorClear(); }}
            max={100} step={5} disabled={isVerified}
          />
          <Progress value={progress} className="h-2" />
        </div>
      )}

      {/* Blocked indicator */}
      {isEdit && (
        <div className="flex items-center gap-2">
          <input
            type="checkbox" id="blocked-toggle"
            checked={!!(task?.metadata as Record<string, unknown>)?.is_blocked}
            onChange={(e) => {
              if (task) {
                onUpdate({ id: task.id, metadata: { ...(task.metadata as Record<string, unknown> ?? {}), is_blocked: e.target.checked } } as UnifiedTaskUpdate);
              }
            }}
            className="rounded" disabled={isVerified}
          />
          <Label htmlFor="blocked-toggle" className="text-sm text-destructive">{t('workload.status.blocked')}</Label>
        </div>
      )}

      <div className="grid grid-cols-3 gap-3">
        <div className="space-y-2">
          <Label>{t('commandCenter.estMinutes')}</Label>
          <Input type="number" {...register('estimated_minutes')} min={0} disabled={isLocked} />
        </div>
        <div className="space-y-2">
          <Label>{t('workload.tasks.startDate')}</Label>
          <Input type="date" {...register('scheduled_start')} disabled={isLocked} />
        </div>
        <div className="space-y-2">
          <Label>{t('commandCenter.dueDate')}</Label>
          <Input type="date" {...register('due_date')} disabled={isLocked} />
        </div>
      </div>

      {/* Closure Comment */}
      {isEdit && progress >= 100 && !isVerified && (
        <div className="space-y-2 border-t pt-3">
          <Label className="flex items-center gap-1.5">
            {t('workload.tasks.closureComment')} <span className="text-destructive">*</span>
          </Label>
          <Textarea
            value={closureComment}
            onChange={(e) => { onClosureCommentChange(e.target.value); onClosureErrorClear(); }}
            placeholder={t('workload.tasks.closureCommentPlaceholder')}
            rows={2}
          />
          {closureError && (
            <p className="text-xs text-destructive flex items-center gap-1">
              <AlertCircle className="h-3 w-3" /> {t('workload.tasks.closureCommentRequired')}
            </p>
          )}
        </div>
      )}
    </>
  );
}

import { Badge } from '@/shared/components/ui/badge';
import { useTranslation } from 'react-i18next';
import { differenceInDays } from 'date-fns';

export type SlaStatus = 'within_sla' | 'approaching' | 'breached';

export function getSlaStatus(dueDate: string | null, completedAt?: string | null): SlaStatus {
  if (!dueDate) return 'within_sla';
  if (completedAt) return 'within_sla';
  const daysLeft = differenceInDays(new Date(dueDate), new Date());
  if (daysLeft < 0) return 'breached';
  if (daysLeft <= 2) return 'approaching';
  return 'within_sla';
}

const variantMap: Record<SlaStatus, 'default' | 'secondary' | 'destructive'> = {
  within_sla: 'default',
  approaching: 'secondary',
  breached: 'destructive',
};

interface Props {
  dueDate: string | null;
  completedAt?: string | null;
  className?: string;
}

export function SlaBadge({ dueDate, completedAt, className }: Props) {
  const { t } = useTranslation();
  const status = getSlaStatus(dueDate, completedAt);

  return (
    <Badge variant={variantMap[status]} className={className}>
      {t(`governance.sla.${status}`)}
    </Badge>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
