                                                  </>
                                                )}
                                              </div>
                                            </TableCell>
                                          </TableRow>
                                        ))}
                                      </TableBody>
                                    </Table>
                                  )}
                                </CardContent>
                              )}
                            </Card>
                          );
                        })}
                      </div>
                    )}
                  </CardContent>
                )}
              </Card>
            );
          })}
        </div>
      )}

      {/* Dialogs */}
      <ObjectiveDialog open={objDialogOpen} onOpenChange={setObjDialogOpen} objective={selectedObj} onSubmit={handleObjSubmit} isSubmitting={objCreating || objUpdating} />
      {expandedObjId && <InitiativeDialog open={initDialogOpen} onOpenChange={setInitDialogOpen} initiative={selectedInit} objectiveId={expandedObjId} onSubmit={handleInitSubmit} isSubmitting={initCreating || initUpdating} />}
      <ActionDialog open={actionDialogOpen} onOpenChange={setActionDialogOpen} action={selectedAction} initiativeId={actionInitId} onSubmit={handleActionSubmit} isSubmitting={actCreating || actUpdating} />

      <AlertDialog open={deleteObjDialog} onOpenChange={setDeleteObjDialog}>
        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>{t('workload.objectives.deleteTitle')}</AlertDialogTitle><AlertDialogDescription>{t('workload.objectives.deleteDesc')}</AlertDialogDescription></AlertDialogHeader>
        <AlertDialogFooter><AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel><AlertDialogAction onClick={confirmDeleteObj} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={objDeleting}>{t('common.delete')}</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
      </AlertDialog>
      <AlertDialog open={deleteInitDialog} onOpenChange={setDeleteInitDialog}>
        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>{t('workload.initiatives.deleteTitle')}</AlertDialogTitle><AlertDialogDescription>{t('workload.initiatives.deleteDesc')}</AlertDialogDescription></AlertDialogHeader>
        <AlertDialogFooter><AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel><AlertDialogAction onClick={confirmDeleteInit} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={initDeleting}>{t('common.delete')}</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
      </AlertDialog>
      <AlertDialog open={deleteActionDialog} onOpenChange={setDeleteActionDialog}>
        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>{t('workload.actions.deleteTitle')}</AlertDialogTitle><AlertDialogDescription>{t('workload.actions.deleteDesc')}</AlertDialogDescription></AlertDialogHeader>
        <AlertDialogFooter><AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel><AlertDialogAction onClick={confirmDeleteAction} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={actDeleting}>{t('common.delete')}</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Progress } from '@/shared/components/ui/progress';
import { Plus, Users, CheckCircle2, Clock, AlertTriangle, Download, Upload } from 'lucide-react';
import { DistributeTaskDialog } from '@/features/workload/components/representative/DistributeTaskDialog';
import { BatchDetailDialog } from '@/features/workload/components/representative/BatchDetailDialog';
import { BulkImportDialog } from '@/features/workload/components/representative/BulkImportDialog';
import { downloadTemplate } from '@/features/workload/components/representative/csvTemplate';
import { useState } from 'react';

interface TaskDistributionTabProps {
  tasks: any[];
  assignments: any[];
  distributeTask: any;
  isDistributing: boolean;
  bulkDistribute: any;
  isBulkDistributing: boolean;
}

export function TaskDistributionTab({ tasks, assignments, distributeTask, isDistributing, bulkDistribute, isBulkDistributing }: TaskDistributionTabProps) {
  const { t } = useTranslation();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [importOpen, setImportOpen] = useState(false);
  const [selectedBatch, setSelectedBatch] = useState<{ id: string; title: string } | null>(null);

  const batches = useMemo(() => {
    const map = new Map<string, typeof tasks>();
    for (const task of tasks) {
      const batchId = task.source_id ?? 'unknown';
      if (!map.has(batchId)) map.set(batchId, []);
      map.get(batchId)!.push(task);
    }
    return Array.from(map.entries()).map(([batchId, batchTasks]) => ({
      batchId,
      title: batchTasks[0]?.title ?? '',
      due_date: batchTasks[0]?.due_date,
      total: batchTasks.length,
      done: batchTasks.filter((t: any) => t.status === 'completed').length,
      inProgress: batchTasks.filter((t: any) => t.status === 'in_progress').length,
      blocked: batchTasks.filter((t: any) => t.status === 'blocked').length,
    }));
  }, [tasks]);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-end gap-2">
        <Button variant="outline" size="sm" onClick={downloadTemplate}><Download className="h-4 w-4 me-2" />{t('representative.downloadTemplate')}</Button>
        <Button variant="outline" size="sm" onClick={() => setImportOpen(true)}><Upload className="h-4 w-4 me-2" />{t('representative.bulkImport')}</Button>
        <Button onClick={() => setDialogOpen(true)}><Plus className="h-4 w-4 me-2" />{t('representative.assignTask')}</Button>
      </div>

      {batches.length === 0 ? (
        <Card><CardContent className="flex flex-col items-center justify-center py-12 text-muted-foreground"><p>{t('representative.noBatches')}</p></CardContent></Card>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {batches.map(batch => {
            const completion = batch.total > 0 ? Math.round((batch.done / batch.total) * 100) : 0;
            return (
              <Card key={batch.batchId} className="cursor-pointer hover:border-primary/50 transition-colors" onClick={() => setSelectedBatch({ id: batch.batchId, title: batch.title })}>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm">{batch.title}</CardTitle>
                  {batch.due_date && <CardDescription className="text-xs">{t('representative.dueDate')}: {new Date(batch.due_date).toLocaleDateString()}</CardDescription>}
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="flex items-center gap-4 text-xs">
                    <span className="flex items-center gap-1 text-muted-foreground"><Users className="h-3 w-3" /> {batch.total}</span>
                    <span className="flex items-center gap-1 text-chart-1"><CheckCircle2 className="h-3 w-3" /> {batch.done}</span>
                    <span className="flex items-center gap-1 text-chart-4"><Clock className="h-3 w-3" /> {batch.inProgress}</span>
                    {batch.blocked > 0 && <span className="flex items-center gap-1 text-destructive"><AlertTriangle className="h-3 w-3" /> {batch.blocked}</span>}
                  </div>
                  <div className="w-full bg-muted rounded-full h-2"><div className="bg-primary rounded-full h-2 transition-all" style={{ width: `${completion}%` }} /></div>
                  <p className="text-xs text-end text-muted-foreground">{completion}%</p>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      <DistributeTaskDialog open={dialogOpen} onOpenChange={setDialogOpen} assignments={assignments} onSubmit={distributeTask} isSubmitting={isDistributing} />
      <BulkImportDialog open={importOpen} onOpenChange={setImportOpen} onSubmit={bulkDistribute} isSubmitting={isBulkDistributing} />
      <BatchDetailDialog open={!!selectedBatch} onOpenChange={(open) => { if (!open) setSelectedBatch(null); }} batchId={selectedBatch?.id ?? null} batchTitle={selectedBatch?.title ?? ''} />
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/shared/components/ui/accordion';
import { DataTable } from '@/shared/data-table/DataTable';
import { Flame, AlertTriangle } from 'lucide-react';

interface MemberSummary {
  id: string;
  name: string;
  role: string | null;
  department: string | null;
  active: number;
  completed: number;
  overdue: number;
  highPriority: number;
  avgProgress: number;
  total: number;
}

interface TeamMemberAccordionProps {
  members: MemberSummary[];
  tasksByEmployee: Map<string, any[]>;
  taskColumns: any[];
  isLoading: boolean;
}

export function TeamMemberAccordion({ members, tasksByEmployee, taskColumns, isLoading }: TeamMemberAccordionProps) {
  const { t } = useTranslation();

  if (isLoading) {
    return <div className="h-64 animate-pulse bg-muted/30 rounded-lg" />;
  }

  if (members.length === 0) {
    return <div className="text-center py-8 text-sm text-muted-foreground">{t('teamWorkload.noTasksFound')}</div>;
  }

  return (
    <Accordion type="multiple" className="space-y-2">
      {members.map(member => {
        const memberTasks = tasksByEmployee.get(member.id) ?? [];
        const overdueRatio = member.active > 0 ? member.overdue / member.active : 0;
        const riskLevel = overdueRatio > 0.5 ? 'high' : overdueRatio > 0.25 ? 'medium' : 'low';

        return (
          <AccordionItem key={member.id} value={member.id} className="border rounded-lg bg-muted/10 px-1">
            <AccordionTrigger className="py-3 px-3 hover:no-underline">
              <div className="flex flex-1 items-center justify-between me-3">
                <div className="flex items-center gap-3 min-w-0">
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-medium text-sm truncate">{member.name}</span>
                      {riskLevel === 'high' && (
                        <Badge variant="destructive" className="gap-1 text-2xs py-0 px-1.5">
                          <Flame className="h-2.5 w-2.5" />{t('tasks.managerOverview.atRisk')}
                        </Badge>
                      )}
                      {riskLevel === 'medium' && (
                        <Badge className="bg-chart-5/10 text-chart-5 gap-1 text-2xs py-0 px-1.5">
                          <AlertTriangle className="h-2.5 w-2.5" />{t('tasks.managerOverview.warning')}
                        </Badge>
                      )}
                    </div>
                    <div className="flex items-center gap-2 text-xs text-muted-foreground">
                      {member.role && <span>{member.role}</span>}
                      {member.role && member.department && <span>·</span>}
                      {member.department && <span>{member.department}</span>}
                    </div>
                  </div>
                </div>

                {/* Desktop stats */}
                <div className="hidden sm:flex items-center gap-4">
                  <div className="text-center">
                    <div className="text-xs font-bold">{member.active}</div>
                    <p className="text-2xs text-muted-foreground">{t('tasks.stats.active')}</p>
                  </div>
                  <div className="text-center">
                    <div className="text-xs font-bold text-chart-1">{member.completed}</div>
                    <p className="text-2xs text-muted-foreground">{t('tasks.stats.completed')}</p>
                  </div>
                  <div className="text-center">
                    <div className={`text-xs font-bold ${member.overdue > 0 ? 'text-destructive' : ''}`}>{member.overdue}</div>
                    <p className="text-2xs text-muted-foreground">{t('tasks.stats.overdue')}</p>
                  </div>
                  <div className="text-center">
                    <div className="text-xs font-bold text-chart-5">{member.highPriority}</div>
                    <p className="text-2xs text-muted-foreground">P1</p>
                  </div>
                  <div className="w-20">
                    <div className="flex items-center justify-between text-2xs mb-0.5">
                      <span className="text-muted-foreground">{t('tasks.managerOverview.avgProgress')}</span>
                      <span className="font-medium">{member.avgProgress}%</span>
                    </div>
                    <Progress value={member.avgProgress} className="h-1" />
                  </div>
                </div>
              </div>
            </AccordionTrigger>
            <AccordionContent className="px-2 pb-3">
              {/* Mobile stats */}
              <div className="sm:hidden grid grid-cols-4 gap-2 text-center mb-3 py-2 px-2 rounded-lg bg-muted/20">
                <div>
                  <div className="text-sm font-bold">{member.active}</div>
                  <p className="text-2xs text-muted-foreground">{t('tasks.stats.active')}</p>
                </div>
                <div>
                  <div className="text-sm font-bold text-chart-1">{member.completed}</div>
                  <p className="text-2xs text-muted-foreground">{t('tasks.stats.completed')}</p>
                </div>
                <div>
                  <div className={`text-sm font-bold ${member.overdue > 0 ? 'text-destructive' : ''}`}>{member.overdue}</div>
                  <p className="text-2xs text-muted-foreground">{t('tasks.stats.overdue')}</p>
                </div>
                <div>
                  <div className="text-sm font-bold text-chart-5">{member.highPriority}</div>
                  <p className="text-2xs text-muted-foreground">P1</p>
                </div>
              </div>

              {memberTasks.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">{t('teamWorkload.noTasksFound')}</p>
              ) : (
                <DataTable
                  columns={taskColumns}
                  data={memberTasks}
                  rowKey={row => row.id}
                  isLoading={false}
                  emptyMessage={t('teamWorkload.noTasksFound')}
                  bordered={false}
                />
              )}
            </AccordionContent>
          </AccordionItem>
        );
      })}
    </Accordion>
  );
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTenantId } from '@/hooks/org/useTenantId';

export interface BurnoutPrediction {
  id: string;
  employee_id: string;
  burnout_probability_score: number;
  confidence_score: number;
  ai_reasoning: string | null;
  indicators: Record<string, number>;
  predicted_at: string;
}

export function useBurnoutPredictions() {
  const { tenantId } = useTenantId();

  const query = useQuery({
    queryKey: ['burnout-predictions', tenantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('burnout_predictions')
        .select('*')
        .eq('tenant_id', tenantId!)
        .is('deleted_at', null)
        .order('predicted_at', { ascending: false })
        .limit(200);

      if (error) throw error;

      // Deduplicate: keep latest per employee
      const latest: Record<string, any> = {};
      (data ?? []).forEach(row => {
        if (!latest[row.employee_id]) latest[row.employee_id] = row;
      });

      return Object.values(latest) as BurnoutPrediction[];
    },
    enabled: !!tenantId,
    staleTime: 5 * 60_000,
  });

  const highRisk = (query.data ?? []).filter(p => p.burnout_probability_score > 60);

  return {
    predictions: query.data ?? [],
    highRisk,
    isPending: query.isPending,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { useTenantId } from '@/hooks/org/useTenantId';

export interface TaskComment {
  id: string;
  employee_id: string;
  employee_name: string;
  text: string;
  created_at: string;
}

export interface UnifiedTask {
  id: string;
  tenant_id: string;
  employee_id: string;
  source_type: string;
  source_id: string | null;
  connector_id: string | null;
  title: string;
  title_ar: string | null;
  description: string | null;
  estimated_minutes: number | null;
  actual_minutes: number | null;
  scheduled_start: string | null;
  scheduled_end: string | null;
  due_date: string | null;
  is_work_hours: boolean;
  priority: number;
  status: string;
  progress: number;
  external_url: string | null;
  tags: string[];
  metadata: Record<string, unknown>;
  is_locked: boolean;
  locked_by: string | null;
  locked_at: string | null;
  comments: TaskComment[];
  created_by: string | null;
  created_at: string;
  updated_at: string;
  deleted_at: string | null;
}

export interface UnifiedTaskInsert {
  tenant_id: string;
  employee_id: string;
  title: string;
  title_ar?: string | null;
  description?: string | null;
  source_type?: string;
  estimated_minutes?: number | null;
  due_date?: string | null;
  priority?: number;
  status?: string;
  tags?: string[];
  created_by?: string | null;
}

export interface UnifiedTaskUpdate extends Partial<UnifiedTaskInsert> {
  id: string;
  actual_minutes?: number | null;
  scheduled_start?: string | null;
  scheduled_end?: string | null;
  progress?: number;
}

export function useUnifiedTasks(employeeId?: string) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const { tenantId } = useTenantId();

  const tasksQuery = useQuery({
    queryKey: ['unified-tasks', tenantId, employeeId],
    queryFn: async () => {
      let query = supabase
        .from('unified_tasks')
        .select('*')
        .is('deleted_at', null)
        .order('priority', { ascending: true })
        .order('due_date', { ascending: true, nullsFirst: false });
      if (employeeId) query = query.eq('employee_id', employeeId);
      const { data, error } = await query;
      if (error) throw error;
      return (data ?? []).map((d: Record<string, unknown>) => ({ ...d, comments: (d.comments as TaskComment[]) ?? [] })) as UnifiedTask[];
    },
    enabled: !!tenantId,
  });

  const createMutation = useMutation({
    mutationFn: async (item: UnifiedTaskInsert) => {
      const { data, error } = await supabase.from('unified_tasks').insert(item).select().single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.tasks.createSuccess'));
    },
    onError: () => toast.error(t('workload.tasks.createError')),
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, ...updates }: UnifiedTaskUpdate) => {
      const { data, error } = await supabase.from('unified_tasks').update(updates).eq('id', id).select().single();
      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.tasks.updateSuccess'));
    },
    onError: () => toast.error(t('workload.tasks.updateError')),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error, count } = await supabase
        .from('unified_tasks')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.tasks.deleteSuccess'));
    },
    onError: (err: any) => {
      console.error('Delete task failed:', err?.message, err?.code, err);
      toast.error(t('workload.tasks.deleteError'));
    },
  });

  const lockMutation = useMutation({
    mutationFn: async ({ id, locked_by }: { id: string; locked_by: string }) => {
      const { error } = await supabase.from('unified_tasks').update({
        is_locked: true, locked_by, locked_at: new Date().toISOString(),
      }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.lock.lockSuccess'));
    },
    onError: () => toast.error(t('workload.lock.lockError')),
  });

  const unlockMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from('unified_tasks').update({
        is_locked: false, locked_by: null, locked_at: null,
      }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.lock.unlockSuccess'));
    },
    onError: () => toast.error(t('workload.lock.unlockError')),
  });

  const addCommentMutation = useMutation({
    mutationFn: async ({ id, comment }: { id: string; comment: TaskComment }) => {
      // Fetch current comments, append new one
      const { data: current, error: fetchErr } = await supabase
        .from('unified_tasks').select('comments').eq('id', id).single();
      if (fetchErr) throw fetchErr;
      const existing = (current?.comments as unknown as TaskComment[]) ?? [];
      const comments = [...existing, comment] as unknown as Record<string, unknown>[];
      const { error } = await supabase.from('unified_tasks').update({ comments: comments as any }).eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['unified-tasks'] });
      toast.success(t('workload.comments.addSuccess'));
    },
    onError: () => toast.error(t('workload.comments.addError')),
  });

  return {
    tasks: tasksQuery.data ?? [],
    isPending: tasksQuery.isPending,
    createTask: createMutation.mutate,
    updateTask: updateMutation.mutate,
    deleteTask: deleteMutation.mutate,
    lockTask: lockMutation.mutate,
    unlockTask: unlockMutation.mutate,
    addComment: addCommentMutation.mutate,
    isCreating: createMutation.isPending,
    isUpdating: updateMutation.isPending,
    isDeleting: deleteMutation.isPending,
  };
}

