import type { Objective } from '@/features/workload/hooks/useObjectives';
import type { Initiative } from '@/features/workload/hooks/useInitiatives';
import type { ObjAction } from '@/features/workload/hooks/useActions';
import { InitiativeDialog } from '@/features/workload/components/InitiativeDialog';
import { ActionDialog } from '@/features/workload/components/ActionDialog';
import { useTenantId } from '@/hooks/org/useTenantId';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useAuditLog } from '@/hooks/audit/useAuditLog';
import { useUserPermissions, useHasRole } from '@/features/auth/hooks/auth/useUserPermissions';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/shared/components/ui/tooltip';
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from '@/shared/components/ui/table';

const statusColors: Record<string, string> = {
  planned: 'bg-muted text-muted-foreground',
  in_progress: 'bg-chart-1/15 text-chart-1',
  completed: 'bg-chart-2/15 text-chart-2',
  on_hold: 'bg-chart-4/15 text-chart-4',
  on_track: 'bg-chart-2/15 text-chart-2',
  at_risk: 'bg-chart-4/15 text-chart-4',
  delayed: 'bg-destructive/15 text-destructive',
  scheduled: 'bg-primary/15 text-primary',
  blocked: 'bg-destructive/15 text-destructive',
};

export default function ObjectiveDetail() {
  const { t } = useTranslation();
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { tenantId } = useTenantId();
  const { user } = useAuth();
  const { logEvent } = useAuditLog();
  const { isSuperAdmin } = useUserPermissions();
  const { hasRole: isTenantAdmin } = useHasRole('tenant_admin');
  const { hasRole: isManager } = useHasRole('manager');
  const { isRepresentative } = useIsRepresentative();
  const canManage = isSuperAdmin || isTenantAdmin || isManager || isRepresentative;
  const canUnlock = canManage; // only managers/admins can unlock
  const { objectives, isPending: objLoading, lockObjective, unlockObjective } = useObjectives();
  const {
    initiatives, isPending: initLoading, createInitiative, updateInitiative, deleteInitiative,
    lockInitiative, unlockInitiative,
    isCreating: initCreating, isUpdating: initUpdating, isDeleting: initDeleting,
  } = useInitiatives(id);

  const objective = objectives.find(o => o.id === id);

  const [initDialogOpen, setInitDialogOpen] = useState(false);
  const [selectedInit, setSelectedInit] = useState<Initiative | null>(null);
  const [deleteInitDialog, setDeleteInitDialog] = useState(false);
  const [initToDelete, setInitToDelete] = useState<string | null>(null);

  const [expandedInitiative, setExpandedInitiative] = useState<string | null>(null);
  const [actionDialogOpen, setActionDialogOpen] = useState(false);
  const [selectedAction, setSelectedAction] = useState<ObjAction | null>(null);
  const [actionInitId, setActionInitId] = useState<string>('');
  const [deleteActionDialog, setDeleteActionDialog] = useState(false);
  const [actionToDelete, setActionToDelete] = useState<string | null>(null);
  const [justifyDeleteOpen, setJustifyDeleteOpen] = useState(false);
  const [justifyDeleteTarget, setJustifyDeleteTarget] = useState<{ type: 'initiative' | 'action'; id: string } | null>(null);
  const [escalationTaskId, setEscalationTaskId] = useState<string | null>(null);

  const {
    actions, createAction, updateAction, deleteAction,
    lockAction, unlockAction,
    isCreating: actCreating, isUpdating: actUpdating, isDeleting: actDeleting,
  } = useActions(expandedInitiative || undefined);

  if (objLoading) return <div className="space-y-4">{[1,2,3].map(i => <Skeleton key={i} className="h-24" />)}</div>;
  if (!objective) return <div className="text-center py-12 text-muted-foreground">{t('common.noData')}</div>;

  const handleInitSubmit = (data: Record<string, unknown>) => {
    if (selectedInit) updateInitiative({ id: selectedInit.id, ...data } as any);
    else createInitiative({ ...data, tenant_id: tenantId } as any);
    setInitDialogOpen(false);
  };

  const handleActionSubmit = (data: Record<string, unknown>) => {
    if (selectedAction) updateAction({ id: selectedAction.id, ...data } as any);
    else createAction({ ...data, tenant_id: tenantId } as any);
    setActionDialogOpen(false);
  };

  const userId = user?.id ?? '';

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="glass-card border-0 rounded-xl p-6">
        <Button variant="ghost" size="sm" className="mb-3 -ms-2" onClick={() => navigate('/admin/workload/objectives')}>
          <ChevronLeft className="h-4 w-4 me-1 rtl:-scale-x-100" />{t('common.back')}
        </Button>
        <div className="flex items-start justify-between">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <Badge variant="outline">{objective.year} {objective.quarter}</Badge>
              <Badge variant="outline" className={statusColors[objective.status] || ''}>{t(`workload.status.${objective.status}`)}</Badge>
              {objective.is_locked && (
                <Badge variant="outline" className="bg-chart-4/15 text-chart-4 gap-1">
                  <Lock className="h-3 w-3" />{t('workload.lock.locked')}
                </Badge>
              )}
            </div>
            <h1 className="text-2xl font-bold">{objective.title}</h1>
            {objective.description && <p className="text-muted-foreground mt-1">{objective.description}</p>}
          </div>
          <div className="flex items-center gap-2">
            {/* Lock: representatives + managers; Unlock: only managers/admins */}
            {(!objective.is_locked || canUnlock) && (
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button variant="outline" size="icon" className="h-8 w-8"
                    onClick={() => objective.is_locked ? unlockObjective(objective.id) : lockObjective({ id: objective.id, locked_by: userId })}>
                    {objective.is_locked ? <Unlock className="h-4 w-4" /> : <Lock className="h-4 w-4" />}
                  </Button>
                </TooltipTrigger>
                <TooltipContent>{objective.is_locked ? t('workload.lock.unlock') : t('workload.lock.lock')}</TooltipContent>
              </Tooltip>
            )}
            <div className="text-end">
              <span className="text-3xl font-bold">{Number(objective.progress).toFixed(0)}%</span>
              <Progress value={Number(objective.progress)} className="w-32 h-2 mt-1" />
              <p className="text-2xs text-muted-foreground mt-0.5">{t('workload.lock.autoCalculated')}</p>
            </div>
          </div>
        </div>
      </div>

      {/* Initiatives Section */}
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-semibold flex items-center gap-2"><Rocket className="h-5 w-5 text-primary" />{t('workload.initiatives.sectionTitle')}</h2>
        {!objective.is_locked && canManage && (
          <Button onClick={() => { setSelectedInit(null); setInitDialogOpen(true); }}><Plus className="me-2 h-4 w-4" />{t('workload.initiatives.add')}</Button>
        )}
      </div>

      {initLoading ? (
        <div className="space-y-3">{[1,2].map(i => <Skeleton key={i} className="h-20" />)}</div>
      ) : initiatives.length === 0 ? (
        <Card className="glass-card border-0 rounded-xl">
          <CardContent className="flex flex-col items-center justify-center py-8 text-center">
            <FolderOpen className="h-10 w-10 text-muted-foreground/40 mb-3" />
            <p className="text-muted-foreground">{t('workload.initiatives.empty')}</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {initiatives.map(init => {
            const isExpanded = expandedInitiative === init.id;
            return (
              <Card key={init.id} className="glass-card border-0 rounded-xl">
                <CardHeader className="pb-2 cursor-pointer" onClick={() => setExpandedInitiative(isExpanded ? null : init.id)}>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <ArrowRight className={`h-4 w-4 transition-transform rtl:-scale-x-100 ${isExpanded ? 'rotate-90' : ''}`} />
                      <div>
                        <div className="flex items-center gap-1.5">
                          <CardTitle className="text-base">{init.title}</CardTitle>
                          {init.is_locked && <Lock className="h-3.5 w-3.5 text-chart-4" />}
                        </div>
                        {init.description && <p className="text-xs text-muted-foreground mt-0.5">{init.description}</p>}
                      </div>
                    </div>
                    <div className="flex items-center gap-2" onClick={e => e.stopPropagation()}>
                      <Badge variant="outline" className={statusColors[init.status] || ''}>{t(`workload.status.${init.status}`)}</Badge>
                      <Progress value={Number(init.progress)} className="w-20 h-2" />
                      <span className="text-xs text-muted-foreground w-8">{Number(init.progress).toFixed(0)}%</span>
                      {(!init.is_locked || canUnlock) && (
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <Button variant="ghost" size="icon" className="h-7 w-7"
                              onClick={() => init.is_locked ? unlockInitiative(init.id) : lockInitiative({ id: init.id, locked_by: userId })}>
                              {init.is_locked ? <Unlock className="h-3.5 w-3.5" /> : <Lock className="h-3.5 w-3.5" />}
                            </Button>
                          </TooltipTrigger>
                          <TooltipContent>{init.is_locked ? t('workload.lock.unlock') : t('workload.lock.lock')}</TooltipContent>
                        </Tooltip>
                      )}
                      {!init.is_locked && canManage && (
                        <>
                          <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => { setSelectedInit(init); setInitDialogOpen(true); }}><Pencil className="h-3.5 w-3.5" /></Button>
                          <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive" onClick={() => { setJustifyDeleteTarget({ type: 'initiative', id: init.id }); setJustifyDeleteOpen(true); }}><Trash2 className="h-3.5 w-3.5" /></Button>
                        </>
                      )}
                    </div>
                  </div>
                </CardHeader>
                {isExpanded && (
                  <CardContent className="pt-0">
                    <div className="flex items-center justify-between mb-3 mt-2">
                      <h3 className="text-sm font-medium text-muted-foreground">{t('workload.actions.sectionTitle')}</h3>
                      {!init.is_locked && canManage && (
                        <Button variant="outline" size="sm" onClick={() => { setSelectedAction(null); setActionInitId(init.id); setActionDialogOpen(true); }}>
                          <Plus className="me-1 h-3.5 w-3.5" />{t('workload.actions.add')}
                        </Button>
                      )}
                    </div>
                    {actions.length === 0 ? (
                      <p className="text-sm text-muted-foreground text-center py-4">{t('workload.actions.empty')}</p>
                    ) : (
                      <Table>
                        <TableHeader>
                          <TableRow>
                            <TableHead>{t('workload.actions.title')}</TableHead>
                            <TableHead className="w-16">{t('workload.actions.priority')}</TableHead>
                            <TableHead className="w-20">{t('workload.actions.estimatedHours')}</TableHead>
                            <TableHead className="w-20">SLA</TableHead>
                            <TableHead className="w-24">{t('common.status')}</TableHead>
                            <TableHead className="w-24">{t('common.actions')}</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {actions.map(act => (
                            <TableRow key={act.id}>
                              <TableCell className="font-medium">
                                <div className="flex items-center gap-1.5">
                                  {act.title}
                                  {act.is_locked && <Lock className="h-3 w-3 text-chart-4" />}
                                </div>
                              </TableCell>
                              <TableCell><Badge variant="outline">P{act.priority}</Badge></TableCell>
                              <TableCell>{Number(act.estimated_hours)}h</TableCell>
                              <TableCell><SlaBadge dueDate={act.planned_end} completedAt={act.status === 'completed' ? act.updated_at : null} className="text-xs" /></TableCell>
                              <TableCell><Badge variant="outline" className={statusColors[act.status] || ''}>{t(`workload.status.${act.status}`)}</Badge></TableCell>
                              <TableCell>
                                <div className="flex gap-1">
                                  {(!act.is_locked || canUnlock) && (
                                    <Tooltip>
                                      <TooltipTrigger asChild>
                                        <Button variant="ghost" size="icon" className="h-7 w-7"
                                          onClick={() => act.is_locked ? unlockAction(act.id) : lockAction({ id: act.id, locked_by: userId })}>
                                          {act.is_locked ? <Unlock className="h-3.5 w-3.5" /> : <Lock className="h-3.5 w-3.5" />}
                                        </Button>
                                      </TooltipTrigger>
                                      <TooltipContent>{act.is_locked ? t('workload.lock.unlock') : t('workload.lock.lock')}</TooltipContent>
                                    </Tooltip>
                                  )}
                                  {!act.is_locked && canManage && (
                                    <>
                                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => { setSelectedAction(act); setActionInitId(init.id); setActionDialogOpen(true); }}><Pencil className="h-3.5 w-3.5" /></Button>
                                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive" onClick={() => { setJustifyDeleteTarget({ type: 'action', id: act.id }); setJustifyDeleteOpen(true); }}><Trash2 className="h-3.5 w-3.5" /></Button>
                                      <Tooltip>
                                        <TooltipTrigger asChild>
                                          <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => setEscalationTaskId(escalationTaskId === act.id ? null : act.id)}>
                                            <AlertTriangle className="h-3.5 w-3.5" />
                                          </Button>
                                        </TooltipTrigger>
                                        <TooltipContent>{t('governance.escalation.title')}</TooltipContent>
                                      </Tooltip>
                                    </>
                                  )}
                                </div>
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    )}
                  </CardContent>
                )}
              </Card>
            );
          })}
        </div>
      )}

      {/* Dialogs */}
      <InitiativeDialog open={initDialogOpen} onOpenChange={setInitDialogOpen} initiative={selectedInit} objectiveId={id!} onSubmit={handleInitSubmit} isSubmitting={initCreating || initUpdating} />
      <ActionDialog open={actionDialogOpen} onOpenChange={setActionDialogOpen} action={selectedAction} initiativeId={actionInitId} onSubmit={handleActionSubmit} isSubmitting={actCreating || actUpdating} />

      {/* Escalation Panel for selected task */}
      {escalationTaskId && (() => {
        const act = actions.find(a => a.id === escalationTaskId);
        return act ? (
          <EscalationPanel taskId={act.id} taskTitle={act.title} dueDate={act.planned_end} completedAt={act.status === 'completed' ? act.updated_at : null} />
        ) : null;
      })()}

      {/* Justification Delete Dialog */}
      <JustificationDialog
        open={justifyDeleteOpen}
        onOpenChange={setJustifyDeleteOpen}
        actionLabel={t('common.delete')}
        description={t('governance.justification.deleteDesc')}
        isPending={initDeleting || actDeleting}
        onConfirm={(justification) => {
          if (justifyDeleteTarget?.type === 'initiative') {
            deleteInitiative(justifyDeleteTarget.id);
            logEvent({
              tenant_id: tenantId,
              entity_type: 'initiative',
              entity_id: justifyDeleteTarget.id,
              action: 'delete',
              changes: { justification },
            });
          } else if (justifyDeleteTarget?.type === 'action') {
            deleteAction(justifyDeleteTarget.id);
            logEvent({
              tenant_id: tenantId,
              entity_type: 'objective_action',
              entity_id: justifyDeleteTarget.id,
              action: 'delete',
              changes: { justification },
            });
          }
          setJustifyDeleteOpen(false);
          setJustifyDeleteTarget(null);
        }}
      />

      <AlertDialog open={deleteInitDialog} onOpenChange={setDeleteInitDialog}>
        <AlertDialogContent>
          <AlertDialogHeader><AlertDialogTitle>{t('workload.initiatives.deleteTitle')}</AlertDialogTitle><AlertDialogDescription>{t('workload.initiatives.deleteDesc')}</AlertDialogDescription></AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={() => { if (initToDelete) { deleteInitiative(initToDelete); setDeleteInitDialog(false); } }} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={initDeleting}>{t('common.delete')}</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <AlertDialog open={deleteActionDialog} onOpenChange={setDeleteActionDialog}>
        <AlertDialogContent>
          <AlertDialogHeader><AlertDialogTitle>{t('workload.actions.deleteTitle')}</AlertDialogTitle><AlertDialogDescription>{t('workload.actions.deleteDesc')}</AlertDialogDescription></AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={() => { if (actionToDelete) { deleteAction(actionToDelete); setDeleteActionDialog(false); } }} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={actDeleting}>{t('common.delete')}</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { Progress } from '@/shared/components/ui/progress';
import { Plus, Target, ChevronRight, Pencil, Trash2, Crosshair } from 'lucide-react';
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from '@/shared/components/ui/alert-dialog';
import { useObjectives, useIsRepresentative } from '@/features/workload';
import type { Objective } from '@/features/workload/hooks/useObjectives';
import { ObjectiveDialog } from '@/features/workload/components/ObjectiveDialog';
import { useTenantId } from '@/hooks/org/useTenantId';
import { useNavigate } from 'react-router-dom';
import { useUserPermissions, useHasRole } from '@/features/auth/hooks/auth/useUserPermissions';

const statusColors: Record<string, string> = {
  on_track: 'bg-chart-2/15 text-chart-2 border-chart-2/30',
  at_risk: 'bg-chart-4/15 text-chart-4 border-chart-4/30',
  delayed: 'bg-destructive/15 text-destructive border-destructive/30',
  completed: 'bg-primary/15 text-primary border-primary/30',
};

export default function ObjectivesManagement() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { tenantId } = useTenantId();
  const { isSuperAdmin } = useUserPermissions();
  const { hasRole: isTenantAdmin } = useHasRole('tenant_admin');
  const { hasRole: isManager } = useHasRole('manager');
  const { isRepresentative } = useIsRepresentative();
  const canManage = isSuperAdmin || isTenantAdmin || isManager || isRepresentative;
  const {
    objectives, isPending, createObjective, updateObjective, deleteObjective,
    isCreating, isUpdating, isDeleting,
  } = useObjectives();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selected, setSelected] = useState<Objective | null>(null);
  const [toDelete, setToDelete] = useState<string | null>(null);

  const handleCreate = () => { setSelected(null); setDialogOpen(true); };
  const handleEdit = (obj: Objective) => { setSelected(obj); setDialogOpen(true); };
  const handleDelete = (id: string) => { setToDelete(id); setDeleteDialogOpen(true); };
  const confirmDelete = () => { if (toDelete) { deleteObjective(toDelete); setDeleteDialogOpen(false); setToDelete(null); } };

  const handleSubmit = (data: any) => {
    if (selected) {
      updateObjective({ id: selected.id, ...data });
    } else {
      createObjective({ ...data, tenant_id: tenantId });
    }
    setDialogOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="glass-card border-0 rounded-xl p-6 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-primary/10 rounded-lg p-2"><Target className="h-6 w-6 text-primary" /></div>
          <div>
            <h1 className="text-3xl font-bold tracking-tight">{t('workload.objectives.pageTitle')}</h1>
            <p className="text-muted-foreground text-sm">{t('workload.objectives.pageDesc')}</p>
          </div>
        </div>
        {canManage && <Button onClick={handleCreate}><Plus className="me-2 h-4 w-4" />{t('workload.objectives.add')}</Button>}
      </div>

      {isPending ? (
        <div className="grid gap-4 md:grid-cols-2">{[1,2,3,4].map(i => <Card key={i} className="glass-card border-0 animate-pulse h-40" />)}</div>
      ) : objectives.length === 0 ? (
        <Card className="glass-card border-0 rounded-xl">
          <CardContent className="flex flex-col items-center justify-center py-12 text-center">
            <Crosshair className="h-12 w-12 text-muted-foreground/40 mb-4" />
            <p className="text-muted-foreground">{t('workload.objectives.empty')}</p>
            <Button variant="outline" className="mt-4" onClick={handleCreate}><Plus className="me-2 h-4 w-4" />{t('workload.objectives.add')}</Button>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 md:grid-cols-2">
          {objectives.map(obj => (
            <Card key={obj.id} className="glass-card border-0 rounded-xl hover:shadow-md transition-shadow cursor-pointer group"
              onClick={() => navigate(`/admin/workload/objectives/${obj.id}`)}>
              <CardHeader className="pb-2">
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <Badge variant="outline" className="text-xs">{obj.year} {obj.quarter}</Badge>
                      <Badge variant="outline" className={statusColors[obj.status] || ''}>{t(`workload.status.${obj.status}`)}</Badge>
                    </div>
                    <CardTitle className="text-lg leading-snug">{obj.title}</CardTitle>
                  </div>
                   <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>
                    {canManage && <>
                      <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleEdit(obj)}><Pencil className="h-4 w-4" /></Button>
                      <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => handleDelete(obj.id)}><Trash2 className="h-4 w-4" /></Button>
                    </>}
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                {obj.description && <p className="text-sm text-muted-foreground mb-3 line-clamp-2">{obj.description}</p>}
                <div className="flex items-center gap-3">
                  <Progress value={Number(obj.progress)} className="flex-1 h-2" />
                  <span className="text-sm font-medium text-muted-foreground">{Number(obj.progress).toFixed(0)}%</span>
                  <ChevronRight className="h-4 w-4 text-muted-foreground rtl:-scale-x-100" />
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      <ObjectiveDialog open={dialogOpen} onOpenChange={setDialogOpen} objective={selected} onSubmit={handleSubmit} isSubmitting={isCreating || isUpdating} />

      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t('workload.objectives.deleteTitle')}</AlertDialogTitle>
            <AlertDialogDescription>{t('workload.objectives.deleteDesc')}</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete} className="bg-destructive text-destructive-foreground hover:bg-destructive/90" disabled={isDeleting}>{t('common.delete')}</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { CreateTaskModal } from '@/features/tasks/components/CreateTaskModal';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { StatusBadge, GENERIC_TASK_STATUS_CONFIG } from '@/shared/status-badge';
import { Skeleton } from '@/shared/components/ui/skeleton';
import { Progress } from '@/shared/components/ui/progress';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { useWorkloadAnalytics, useObjectives, useInitiatives, useDepartmentTasks } from '@/features/workload';
import { useAuth } from '@/features/auth/hooks/auth/useAuth';
import { useTenantId } from '@/hooks/org/useTenantId';
import { TeamTaskFilters, type TaskFilters } from '@/features/workload/components/team/TeamTaskFilters';
import { AddTeamTaskDialog } from '@/features/workload/components/team/AddTeamTaskDialog';
import { TeamStatCards } from '@/features/workload/components/team/TeamStatCards';
import { WorkloadDistributionChart } from '@/features/workload/components/team/WorkloadDistributionChart';
import { ExecutionMetricsCard } from '@/features/workload/components/team/ExecutionMetricsCard';
import { RiskAlertsCard } from '@/features/workload/components/team/RiskAlertsCard';
import { TeamMemberAccordion } from '@/features/workload/components/team/TeamMemberAccordion';
import {
  Users, AlertTriangle, TrendingUp, CheckCircle2, Plus,
  Lock, Unlock, Trash2, Search,
} from 'lucide-react';
import { useLocaleFormat } from '@/shared/hooks/useLocaleFormat';

const priorityLabels: Record<number, string> = { 1: 'P1', 2: 'P2', 3: 'P3', 4: 'P4', 5: 'P5' };

interface MemberSummary {
  id: string; name: string; role: string | null; department: string | null;
  active: number; completed: number; overdue: number; highPriority: number; avgProgress: number; total: number;
}

export default function TeamWorkload() {
  const { t } = useTranslation();
  const { lformat } = useLocaleFormat();
  const { user } = useAuth();
  const { tenantId } = useTenantId();
  const { teamLoad, isPending: analyticsLoading } = useWorkloadAnalytics();
  const { objectives } = useObjectives();
  const { initiatives } = useInitiatives();
  const {
    employees, tasks, isPending: tasksLoading,
    createTask, deleteTask, lockTask, unlockTask, isCreating,
  } = useDepartmentTasks();

  const [addOpen, setAddOpen] = useState(false);
  const [enterpriseModalOpen, setEnterpriseModalOpen] = useState(false);
  const [filters, setFilters] = useState<TaskFilters>({ status: 'all', priority: 'all', employeeId: 'all', sourceType: 'all', search: '' });
  const [memberSearch, setMemberSearch] = useState('');
  const [sortBy, setSortBy] = useState<'name' | 'overdue' | 'active' | 'progress'>('overdue');

  const now = new Date();

  const filteredTasks = useMemo(() => {
    return tasks.filter(task => {
      if (filters.status !== 'all' && task.status !== filters.status) return false;
      if (filters.priority !== 'all' && task.priority !== parseInt(filters.priority)) return false;
      if (filters.employeeId !== 'all' && task.employee_id !== filters.employeeId) return false;
      if (filters.sourceType !== 'all' && task.source_type !== filters.sourceType) return false;
      if (filters.search) {
        const s = filters.search.toLowerCase();
        if (!task.title.toLowerCase().includes(s) && !(task.title_ar ?? '').toLowerCase().includes(s)) return false;
      }
      return true;
    });
  }, [tasks, filters]);

  const tasksByEmployee = useMemo(() => {
    const map = new Map<string, typeof filteredTasks>();
    filteredTasks.forEach(task => {
      const list = map.get(task.employee_id) ?? [];
      list.push(task);
      map.set(task.employee_id, list);
    });
    return map;
  }, [filteredTasks]);

  const memberSummaries = useMemo<MemberSummary[]>(() => {
    const summaries = employees.map(emp => {
      const empTasks = tasksByEmployee.get(emp.id) ?? [];
      const active = empTasks.filter(t => !['completed', 'archived', 'rejected'].includes(t.status));
      const completed = empTasks.filter(t => t.status === 'completed');
      const overdue = active.filter(t => t.due_date && new Date(t.due_date) < now);
      const highPriority = active.filter(t => t.priority <= 1);
      const avgProgress = active.length > 0 ? Math.round(active.reduce((sum, t) => sum + (t.progress ?? 0), 0) / active.length) : 0;
      return { id: emp.id, name: emp.full_name, role: emp.role_title ?? null, department: null, active: active.length, completed: completed.length, overdue: overdue.length, highPriority: highPriority.length, avgProgress, total: empTasks.length };
    });

    let result = memberSearch.trim() ? summaries.filter(s => s.name.toLowerCase().includes(memberSearch.toLowerCase())) : summaries;
    return [...result].sort((a, b) => {
      switch (sortBy) {
        case 'overdue': return b.overdue - a.overdue;
        case 'active': return b.active - a.active;
        case 'progress': return a.avgProgress - b.avgProgress;
        default: return a.name.localeCompare(b.name);
      }
    });
  }, [employees, tasksByEmployee, memberSearch, sortBy, now]);

  const riskMembers = useMemo(
    () => teamLoad.filter(m => m.estimatedMinutes > 480 || m.overdueTasks > 2 || m.offHoursMinutes > 120),
    [teamLoad]
  );

  const totalTasks = teamLoad.reduce((s, m) => s + m.totalTasks, 0);
  const totalDone = teamLoad.reduce((s, m) => s + m.doneTasks, 0);
  const totalOverdue = teamLoad.reduce((s, m) => s + m.overdueTasks, 0);
  const completionRate = totalTasks > 0 ? Math.round((totalDone / totalTasks) * 100) : 0;
  const overdueRate = totalTasks > 0 ? Math.round((totalOverdue / totalTasks) * 100) : 0;
  const velocity = totalTasks > 0 ? Math.round((totalDone / 30) * 100) / 100 : 0;

  const workloadDistribution = useMemo(() => {
    const classify = (minutes: number) => {
      const pct = (minutes / 480) * 100;
      if (pct < 60) return 'underutilized';
      if (pct <= 90) return 'healthy';
      if (pct <= 110) return 'high_load';
      return 'burnout_risk';
    };
    const counts = { underutilized: 0, healthy: 0, high_load: 0, burnout_risk: 0 };
    teamLoad.forEach(m => { counts[classify(m.estimatedMinutes) as keyof typeof counts]++; });
    return [
      { name: t('executive.underutilized'), value: counts.underutilized, fill: 'hsl(var(--chart-1))' },
      { name: t('executive.healthy'), value: counts.healthy, fill: 'hsl(var(--chart-2))' },
      { name: t('executive.highLoad'), value: counts.high_load, fill: 'hsl(var(--chart-4))' },
      { name: t('executive.burnoutRiskLabel'), value: counts.burnout_risk, fill: 'hsl(var(--destructive))' },
    ];
  }, [teamLoad, t]);

  const statCards = [
    { title: t('teamWorkload.teamSize'), value: teamLoad.length, icon: Users },
    { title: t('teamWorkload.atRiskMembers'), value: riskMembers.length, icon: AlertTriangle },
    { title: t('teamWorkload.objContributing'), value: objectives.length, icon: TrendingUp },
    { title: t('teamWorkload.initActive'), value: initiatives.filter(i => i.status !== 'completed').length, icon: CheckCircle2 },
  ];

  const memberTaskColumns = [
    {
      id: 'title', header: t('workload.tasks.title'),
      cell: (row: typeof filteredTasks[number]) => (
        <div>
          <p className="text-sm font-medium">{row.title}</p>
          {row.title_ar && <p className="text-xs text-muted-foreground" dir="rtl">{row.title_ar}</p>}
        </div>
      ),
    },
    {
      id: 'status', header: t('common.status'), className: 'w-28',
      cell: (row: typeof filteredTasks[number]) => <StatusBadge status={row.status} config={GENERIC_TASK_STATUS_CONFIG} translationPrefix="teamWorkload" />,
    },
    {
      id: 'priority', header: t('workload.tasks.priority'), className: 'w-20',
      cell: (row: typeof filteredTasks[number]) => <Badge variant={row.priority <= 2 ? 'destructive' : 'secondary'} className="text-xs">{priorityLabels[row.priority] ?? `P${row.priority}`}</Badge>,
    },
    {
      id: 'dueDate', header: t('workload.tasks.dueDate'), className: 'w-28',
      cell: (row: typeof filteredTasks[number]) => <span className="text-sm text-muted-foreground">{row.due_date ? lformat(new Date(row.due_date), 'MMM dd') : '—'}</span>,
    },
    {
      id: 'estimated', header: t('workload.tasks.estimatedMinutes'), className: 'w-20',
      cell: (row: typeof filteredTasks[number]) => <span className="text-sm text-muted-foreground">{row.estimated_minutes ? `${row.estimated_minutes}m` : '—'}</span>,
    },
    {
      id: 'source', header: t('teamWorkload.source'), className: 'w-28',
      cell: (row: typeof filteredTasks[number]) => <span className="text-xs text-muted-foreground capitalize">{row.source_type.replace('_', ' ')}</span>,
    },
    {
      id: 'actions', header: '', headerHidden: true, className: 'w-20',
      cell: (row: typeof filteredTasks[number]) => (
        <div className="flex items-center gap-1">
          {row.is_locked ? (
            <Button size="icon" variant="ghost" className="h-7 w-7" onClick={() => unlockTask(row.id)}><Unlock className="h-3.5 w-3.5" /></Button>
          ) : (
            <Button size="icon" variant="ghost" className="h-7 w-7" onClick={() => lockTask({ id: row.id, locked_by: user?.id ?? '' })}><Lock className="h-3.5 w-3.5" /></Button>
          )}
          <Button size="icon" variant="ghost" className="h-7 w-7 text-destructive" onClick={() => deleteTask(row.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">{t('teamWorkload.pageTitle')}</h1>
          <p className="text-muted-foreground text-sm">{t('teamWorkload.pageDesc')}</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={() => setAddOpen(true)} className="gap-2"><Plus className="h-4 w-4" />{t('teamWorkload.quickAssign')}</Button>
          <Button onClick={() => setEnterpriseModalOpen(true)} className="gap-2"><Plus className="h-4 w-4" />{t('tasks.createTask')}</Button>
        </div>
      </div>

      <TeamStatCards cards={statCards} isLoading={analyticsLoading} />

      <div className="grid gap-4 md:grid-cols-2">
        <WorkloadDistributionChart data={workloadDistribution} isLoading={analyticsLoading} />
        <ExecutionMetricsCard velocity={velocity} completionRate={completionRate} overdueRate={overdueRate} />
      </div>

      <RiskAlertsCard members={riskMembers} />

      {/* Team Members */}
      <Card className="glass-card border-0">
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <CardTitle className="text-base">{t('teamWorkload.departmentTasks')}</CardTitle>
            <Badge variant="secondary" className="text-xs">{filteredTasks.length} {t('teamWorkload.allTasks')}</Badge>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          <TeamTaskFilters filters={filters} onChange={setFilters} employees={employees} />
          <div className="flex flex-wrap items-center gap-3">
            <div className="relative flex-1 min-w-[200px] max-w-sm">
              <Search className="absolute start-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input value={memberSearch} onChange={(e) => setMemberSearch(e.target.value)} placeholder={t('tasks.managerOverview.searchMembers')} className="ps-9 h-9" />
            </div>
            <Select value={sortBy} onValueChange={(v) => setSortBy(v as typeof sortBy)}>
              <SelectTrigger className="w-[160px] h-9"><SelectValue /></SelectTrigger>
              <SelectContent>
                <SelectItem value="overdue">{t('tasks.managerOverview.sortOverdue')}</SelectItem>
                <SelectItem value="active">{t('tasks.managerOverview.sortActive')}</SelectItem>
                <SelectItem value="progress">{t('tasks.managerOverview.sortProgress')}</SelectItem>
                <SelectItem value="name">{t('tasks.managerOverview.sortName')}</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <TeamMemberAccordion members={memberSummaries} tasksByEmployee={tasksByEmployee} taskColumns={memberTaskColumns} isLoading={tasksLoading} />
        </CardContent>
      </Card>

      {/* Objective Alignment */}
      <Card className="glass-card border-0">
        <CardHeader className="pb-2">
          <CardTitle className="text-base">{t('teamWorkload.objectiveAlignment')}</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {analyticsLoading ? <Skeleton className="h-20" /> : objectives.length > 0 ? objectives.slice(0, 5).map(obj => (
            <div key={obj.id} className="space-y-1.5">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium truncate">{obj.title}</span>
                <span className="text-xs text-muted-foreground">{obj.progress}%</span>
              </div>
              <Progress value={obj.progress} className="h-1.5" />
            </div>
          )) : (
            <p className="text-sm text-muted-foreground py-4 text-center">{t('workload.objectives.empty')}</p>
          )}
        </CardContent>
      </Card>

      {tenantId && user?.id && (
        <AddTeamTaskDialog open={addOpen} onOpenChange={setAddOpen} employees={employees} tenantId={tenantId} createdBy={user.id} onSubmit={createTask} isCreating={isCreating} />
      )}
      {user?.id && (
        <CreateTaskModal open={enterpriseModalOpen} onOpenChange={setEnterpriseModalOpen} employeeId={user.id} />
      )}
    </div>
  );
}

import { useQuery } from '@tanstack/react-query';
import { logger } from '@/shared/utils/logger';
import { supabase } from '@/integrations/supabase/client';
import { useCurrentEmployee } from '@/features/auth/hooks/auth/useCurrentEmployee';
import { useMoodDefinitions } from '@/hooks/wellness/useMoodDefinitions';
import { useGamification } from '@/hooks/wellness/useGamification';
import { format, subDays, getDay, startOfMonth } from 'date-fns';

export interface PersonalMoodEntry {
  date: string;
  score: number;
  level: string;
}

export interface MoodDistributionItem {
  level: string;
  count: number;
}

export interface DayActivity {
  day: number; // 0=Sun .. 6=Sat
  count: number;
}

export interface SurveyStats {
  totalAnswered: number;
  avgScore: number;
  completionRate: number;
}

export function usePersonalMoodDashboard() {
  const { employee, isPending: empLoading } = useCurrentEmployee();
  const employeeId = employee?.id ?? null;
  const tenantId = employee?.tenant_id ?? null;

  const { moods: moodDefs, isPending: defsLoading } = useMoodDefinitions(tenantId);
  const { streak, isPending: streakLoading } = useGamification(employeeId);

  // ── Extended mood history (90 days) ──
  const { data: moodHistory = [], isPending: histLoading } = useQuery({
    queryKey: ['personal-mood-history-90', employeeId],
    queryFn: async () => {
      if (!employeeId) return [];
      const since = format(subDays(new Date(), 90), 'yyyy-MM-dd');
      const { data, error } = await supabase
        .from('mood_entries')
        .select('entry_date, mood_score, mood_level')
        .eq('employee_id', employeeId)
        .gte('entry_date', since)
        .order('entry_date', { ascending: true })
        .limit(10000);
      if (error) throw error;
      return (data || []).map((e: any) => ({
        date: e.entry_date,
        score: e.mood_score,
        level: e.mood_level,
      })) as PersonalMoodEntry[];
    },
    enabled: !!employeeId,
  });

  // ── Org average (only for admins/managers – RLS restricts employees) ──
  const { data: orgAvgMap = {}, isPending: orgPending } = useQuery({
    queryKey: ['org-mood-avg-14', tenantId],
    queryFn: async () => {
      if (!tenantId) return {};
      const since = format(subDays(new Date(), 14), 'yyyy-MM-dd');
      // This will only return data if user has tenant-level access (admin/manager)
      const { data, error } = await supabase
        .from('mood_entries')
        .select('entry_date, mood_score')
        .eq('tenant_id', tenantId)
        .gte('entry_date', since)
        .limit(10000);
      if (error) {
        // RLS will block non-admins – return empty gracefully
        logger.warn('usePersonalMoodDashboard', 'Org average unavailable (RLS):', error.message);
        return {};
      }
      if (!data || data.length === 0) return {};
      // Group by date and average
      const grouped: Record<string, { sum: number; count: number }> = {};
      for (const e of data as any[]) {
        const d = e.entry_date;
        if (!grouped[d]) grouped[d] = { sum: 0, count: 0 };
        grouped[d].sum += e.mood_score;
        grouped[d].count++;
      }
      const result: Record<string, number> = {};
      for (const [d, v] of Object.entries(grouped)) {
        result[d] = Math.round((v.sum / v.count) * 10) / 10;
      }
      return result;
    },
    enabled: !!tenantId,
  });

  // ── Survey stats ──
  const { data: surveyStats, isPending: surveyPending } = useQuery({
    queryKey: ['personal-survey-stats', employeeId],
    queryFn: async (): Promise<SurveyStats> => {
      if (!employeeId) return { totalAnswered: 0, avgScore: 0, completionRate: 0 };

      // BUG-16 fix: Scope to survey-type schedules and exclude soft-deleted rows
      const { data: surveySchedules } = await supabase
        .from('question_schedules')
        .select('id')
        .eq('schedule_type', 'survey')
        .is('deleted_at', null);

      const surveyScheduleIds = (surveySchedules ?? []).map(s => s.id);
      if (!surveyScheduleIds.length) return { totalAnswered: 0, avgScore: 0, completionRate: 0 };

      // Get scheduled_question IDs for this employee's survey schedules
      const { data: sqData } = await supabase
        .from('scheduled_questions')
        .select('id')
        .in('schedule_id', surveyScheduleIds)
        .eq('employee_id', employeeId);

      const sqIds = (sqData ?? []).map(sq => sq.id);
      if (!sqIds.length) return { totalAnswered: 0, avgScore: 0, completionRate: 0 };

      // Total answered (non-draft, non-deleted, scoped to survey)
      const { count: answeredCount, error: aErr } = await supabase
        .from('employee_responses')
        .select('id', { count: 'exact', head: true })
        .in('scheduled_question_id', sqIds)
        .eq('employee_id', employeeId)
        .eq('is_draft', false)
        .is('deleted_at', null);
      if (aErr) throw aErr;

      // Total delivered
      const { count: deliveredCount, error: dErr } = await supabase
        .from('scheduled_questions')
        .select('id', { count: 'exact', head: true })
        .in('schedule_id', surveyScheduleIds)
        .eq('employee_id', employeeId)
        .in('status', ['delivered', 'answered']);
      if (dErr) throw dErr;

      // Avg score from survey responses only
      const { data: responses, error: rErr } = await supabase
        .from('employee_responses')
        .select('answer_value')
        .in('scheduled_question_id', sqIds)
        .eq('employee_id', employeeId)
        .eq('is_draft', false)
        .is('deleted_at', null)
        .limit(5000);
      if (rErr) throw rErr;

      let scoreSum = 0;
      let scoreCount = 0;
      for (const r of (responses || []) as any[]) {
        const val = r.answer_value;
        let num: number | null = null;
        if (typeof val === 'number') num = val;
        else if (typeof val === 'string') num = parseFloat(val);
        else if (typeof val === 'object' && val !== null) {
          num = val.value ?? val.score ?? null;
        }
        if (num !== null && !isNaN(num)) {
          scoreSum += num;
          scoreCount++;
        }
      }

      const total = answeredCount ?? 0;
      const delivered = deliveredCount ?? 0;
      return {
        totalAnswered: total,
        avgScore: scoreCount > 0 ? Math.round((scoreSum / scoreCount) * 10) / 10 : 0,
        completionRate: delivered > 0 ? Math.round((total / delivered) * 100) : 0,
      };
    },
    enabled: !!employeeId,
  });

  // ── Reframe stats ──
  const { data: reframeStats, isPending: reframePending } = useQuery({
    queryKey: ['reframe-stats', employeeId],
    queryFn: async () => {
      if (!employeeId) return { total: 0, thisMonth: 0, streak: 0 };
      const { data, error } = await supabase
        .from('thought_reframes')
        .select('created_at')
        .eq('employee_id', employeeId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false })
        .limit(500);
      if (error) return { total: 0, thisMonth: 0, streak: 0 };
      const entries = (data || []) as unknown as { created_at: string }[];
      const monthStart = format(startOfMonth(new Date()), 'yyyy-MM-dd');
      const thisMonth = entries.filter(r => r.created_at.slice(0, 10) >= monthStart).length;
      const uniqueDays = [...new Set(entries.map(r => r.created_at.slice(0, 10)))].sort().reverse();
      let streak = 0;
      const today = format(new Date(), 'yyyy-MM-dd');
      const yesterday = format(subDays(new Date(), 1), 'yyyy-MM-dd');
      if (uniqueDays[0] === today || uniqueDays[0] === yesterday) {
        let expected = uniqueDays[0];
        for (const day of uniqueDays) {
          if (day === expected) { streak++; expected = format(subDays(new Date(day), 1), 'yyyy-MM-dd'); }
          else break;
        }
      }
      return { total: entries.length, thisMonth, streak };
    },
    enabled: !!employeeId,
  });

  // ── Breathing stats ──
  const { data: breathingStats, isPending: breathingPending } = useQuery({
    queryKey: ['breathing-stats', employeeId],
    queryFn: async () => {
      if (!employeeId) return { totalSessions: 0, totalMinutes: 0, currentStreak: 0, avgMoodImprovement: 0, thisMonth: 0, favoriteExercise: null as string | null };
      const { data, error } = await supabase
        .from('breathing_sessions')
        .select('created_at, duration_seconds, technique, mood_before, mood_after, completed')
        .eq('employee_id', employeeId)
        .is('deleted_at', null)
        .eq('completed', true)
        .order('created_at', { ascending: false })
        .limit(500);
      if (error) return { totalSessions: 0, totalMinutes: 0, currentStreak: 0, avgMoodImprovement: 0, thisMonth: 0, favoriteExercise: null as string | null };
      const entries = (data || []) as unknown as { created_at: string; duration_seconds: number; technique: string; mood_before: number | null; mood_after: number | null; completed: boolean }[];
      const totalSessions = entries.length;
      const totalMinutes = Math.round(entries.reduce((s, r) => s + r.duration_seconds, 0) / 60);
      const monthStart = format(startOfMonth(new Date()), 'yyyy-MM-dd');
      const thisMonth = entries.filter(r => r.created_at.slice(0, 10) >= monthStart).length;
      // Streak
      const uniqueDays = [...new Set(entries.map(r => r.created_at.slice(0, 10)))].sort().reverse();
      let currentStreak = 0;
      const today = format(new Date(), 'yyyy-MM-dd');
      const yesterday = format(subDays(new Date(), 1), 'yyyy-MM-dd');
      if (uniqueDays.length > 0 && (uniqueDays[0] === today || uniqueDays[0] === yesterday)) {
        let expected = uniqueDays[0];
        for (const day of uniqueDays) {
          if (day === expected) { currentStreak++; expected = format(subDays(new Date(day), 1), 'yyyy-MM-dd'); }
          else break;
        }
      }
      // Avg mood improvement
      const withBoth = entries.filter(r => r.mood_before != null && r.mood_after != null);
      const avgMoodImprovement = withBoth.length > 0
        ? Math.round((withBoth.reduce((s, r) => s + (r.mood_after! - r.mood_before!), 0) / withBoth.length) * 10) / 10
        : 0;
      // Favorite exercise
      const techCounts: Record<string, number> = {};
      for (const s of entries) techCounts[s.technique] = (techCounts[s.technique] || 0) + 1;
      const favoriteExercise = Object.entries(techCounts).sort((a, b) => b[1] - a[1])[0]?.[0] ?? null;
      return { totalSessions, totalMinutes, currentStreak, avgMoodImprovement, thisMonth, favoriteExercise };
    },
    enabled: !!employeeId,
  });

  // ── Derived data ──
  const today = format(new Date(), 'yyyy-MM-dd');
  const todayEntry = moodHistory.find((e) => e.date === today);

  // 7-day average
  const recentEntries = moodHistory.filter(
    (e) => e.date >= format(subDays(new Date(), 7), 'yyyy-MM-dd')
  );
  const avgMood7d =
    recentEntries.length > 0
      ? Math.round(
          (recentEntries.reduce((s, e) => s + e.score, 0) / recentEntries.length) * 10
        ) / 10
      : 0;

  const burnoutZone: 'thriving' | 'watch' | 'atRisk' =
    avgMood7d >= 3.5 ? 'thriving' : avgMood7d >= 2.5 ? 'watch' : 'atRisk';

  // Monthly check-ins
  const firstOfMonth = format(
    new Date(new Date().getFullYear(), new Date().getMonth(), 1),
    'yyyy-MM-dd'
  );
  const monthlyCheckins = moodHistory.filter((e) => e.date >= firstOfMonth).length;
  const daysInMonth = new Date(
    new Date().getFullYear(),
    new Date().getMonth() + 1,
    0
  ).getDate();

  // Mood distribution
  const distribution: Record<string, number> = {};
  for (const e of moodHistory) {
    distribution[e.level] = (distribution[e.level] || 0) + 1;
  }

  // Day-of-week activity
  const dayActivity: number[] = [0, 0, 0, 0, 0, 0, 0];
  for (const e of moodHistory) {
    const dayOfWeek = getDay(new Date(e.date));
    dayActivity[dayOfWeek]++;
  }

  // 14-day trend data for chart
  const last14 = moodHistory.filter(
    (e) => e.date >= format(subDays(new Date(), 14), 'yyyy-MM-dd')
  );

  const hasOrgData = Object.keys(orgAvgMap).length > 0;

  const isPending = empLoading || defsLoading || streakLoading || histLoading || orgPending || surveyPending || reframePending || breathingPending;

  return {
    employee,
    isPending,
    moodDefs,
    streak,
    moodHistory,
    last14,
    orgAvgMap,
    hasOrgData,
    todayEntry,
    avgMood7d,
    burnoutZone,
    monthlyCheckins,
    daysInMonth,
    distribution,
    dayActivity,
    surveyStats: surveyStats ?? { totalAnswered: 0, avgScore: 0, completionRate: 0 },
    reframeStats: reframeStats ?? { total: 0, thisMonth: 0, streak: 0 },
    breathingStats: breathingStats ?? { totalSessions: 0, totalMinutes: 0, currentStreak: 0, avgMoodImprovement: 0, thisMonth: 0, favoriteExercise: null },
  };
}

import { useQuery } from '@tanstack/react-query';
