import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import type { Tables, TablesInsert } from '@/integrations/supabase/types';
import { logger } from '@/shared/utils/logger';

export type AuditLog = Tables<'audit_logs'>;
export type AuditLogInsert = TablesInsert<'audit_logs'>;

export type AuditAction = 'create' | 'update' | 'delete' | 'module_toggle' | 'status_change' | 'permission_change';
export type EntityType = 'tenant' | 'subscription' | 'user' | 'plan' | 'role' | 'permission' | 'user_role' | 'strategic_objective' | 'initiative' | 'objective_action';

interface LogEventParams {
  tenant_id?: string | null;
  entity_type: EntityType;
  entity_id: string;
  action: AuditAction;
  changes?: Record<string, any>;
  metadata?: Record<string, any>;
}

export function useAuditLog(options?: { tenantId?: string; limit?: number }) {
  const queryClient = useQueryClient();

  const logsQuery = useQuery({
    queryKey: ['audit-logs', options?.tenantId, options?.limit],
    queryFn: async () => {
      let query = supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false });

      if (options?.tenantId) {
        query = query.eq('tenant_id', options.tenantId);
      }

      if (options?.limit) {
        query = query.limit(options.limit);
      } else {
        query = query.limit(100);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as AuditLog[];
    },
  });

  const logEventMutation = useMutation({
    mutationFn: async (params: LogEventParams) => {
      // Get current user
      const { data: { user } } = await supabase.auth.getUser();
      
      const logEntry: AuditLogInsert = {
        tenant_id: params.tenant_id,
        user_id: user?.id || null,
        entity_type: params.entity_type,
        entity_id: params.entity_id,
        action: params.action,
        changes: params.changes || {},
        metadata: params.metadata || {},
      };

      const { data, error } = await supabase
        .from('audit_logs')
        .insert(logEntry)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['audit-logs'] });
    },
  });

  const logEvent = async (params: LogEventParams) => {
    try {
      await logEventMutation.mutateAsync(params);
    } catch (error) {
      logger.error('useAuditLog', 'Failed to log audit event', error);
    }
  };

  return {
    logs: logsQuery.data ?? [],
    isPending: logsQuery.isPending,
    error: logsQuery.error,
    logEvent,
    isLogging: logEventMutation.isPending,
  };
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { logger } from '@/shared/utils/logger';
import type { HSLColor } from '@/shared/types/common.types/branding';

export type AssetType = 'logo' | 'logo_light' | 'logo_dark' | 'favicon' | 'icon_light' | 'icon_dark' | 'pwa_icon' | 'pwa_icon_light' | 'pwa_icon_dark';

export interface BrandingConfig {
  colors: {
    primary: HSLColor;
    secondary: HSLColor;
    accent: HSLColor;
  };
  logo_url: string | null;
  logo_light_url: string | null;
  logo_dark_url: string | null;
  favicon_url: string | null;
  icon_light_url: string | null;
  icon_dark_url: string | null;
  pwa_icon_url: string | null;
  // New strict keys
  pwa_icon_light_url?: string | null;
  pwa_icon_dark_url?: string | null;
}

const DEFAULT_BRANDING: BrandingConfig = {
  colors: {
    primary: { h: 221, s: 83, l: 53 },
    secondary: { h: 210, s: 40, l: 96 },
    accent: { h: 142, s: 76, l: 36 }
  },
  logo_url: null,
  logo_light_url: null,
  logo_dark_url: null,
  favicon_url: null,
  icon_light_url: null,
  icon_dark_url: null,
  pwa_icon_url: null,
  pwa_icon_light_url: null,
  pwa_icon_dark_url: null
};

export function useBranding(tenantId?: string) {
  const { t } = useTranslation();
  
  const [branding, setBranding] = useState<BrandingConfig>(DEFAULT_BRANDING);
  const [isPending, setIsPending] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  // Fetch branding config
  const fetchBranding = useCallback(async () => {
    if (!tenantId) {
      setIsPending(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('tenants')
        .select('branding_config')
        .eq('id', tenantId)
        .single();

      if (error) throw error;

      let newConfig = { ...DEFAULT_BRANDING };

      if (data?.branding_config) {
        const config = data.branding_config as unknown as BrandingConfig;
        newConfig = {
          ...newConfig,
          ...config,
          colors: {
            ...newConfig.colors,
            ...(config.colors || {})
          }
        };
      }

      setBranding(newConfig);

    } catch (error) {
      logger.error('useBranding', 'Error fetching branding', error);
    } finally {
      setIsPending(false);
    }
  }, [tenantId]);

  useEffect(() => {
    fetchBranding();
  }, [fetchBranding]);

  // Upload file to storage
  const uploadFile = async (file: File, type: AssetType): Promise<string | null> => {
    if (!tenantId) return null;

    const fileExt = file.name.split('.').pop();
    const fileName = `${type}.${fileExt}`;
    const filePath = `${tenantId}/${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from('brand-assets')
      .upload(filePath, file, { upsert: true });

    if (uploadError) {
      console.error('Upload error:', uploadError);
      throw uploadError;
    }

    const { data: { publicUrl } } = supabase.storage
      .from('brand-assets')
      .getPublicUrl(filePath);

    return publicUrl;
  };

  // Save branding config
  const saveBranding = async (
    config: BrandingConfig,
    files?: Partial<Record<AssetType, File | null>>
  ) => {
    if (!tenantId) {
      toast.error('No tenant ID provided');
      return false;
    }

    setIsSaving(true);

    try {
      let updatedConfig = { ...config };

      // Upload each file type if provided — all through brand-assets bucket
      if (files) {
        const fileTypes: AssetType[] = [
          'logo', 'logo_light', 'logo_dark',
          'favicon', 'icon_light', 'icon_dark',
          'pwa_icon', 'pwa_icon_light', 'pwa_icon_dark'
        ];

        for (const type of fileTypes) {
          const file = files[type];
          if (file) {
            const url = await uploadFile(file, type);
            if (url) {
              const urlKey = `${type}_url` as keyof BrandingConfig;
              (updatedConfig as any)[urlKey] = url;
            }
          }
        }
      }

      // Update tenant branding config (Legacy JSON column still updated for backward compat or non-strict fields)
      const { error } = await supabase
        .from('tenants')
        .update({ branding_config: JSON.parse(JSON.stringify(updatedConfig)) })
        .eq('id', tenantId);

      if (error) throw error;

      setBranding(updatedConfig);

      toast.success(t('branding.savedSuccess'));

      return true;
    } catch (error) {
      console.error('Error saving branding:', error);
      toast.error(t('branding.savedError'));
      return false;
    } finally {
      setIsSaving(false);
    }
  };

  // Reset to defaults
  const resetBranding = () => {
    setBranding(DEFAULT_BRANDING);
  };

  return {
    branding,
    setBranding,
    isPending,
    isSaving,
    saveBranding,
    resetBranding,
    defaultBranding: DEFAULT_BRANDING
  };
}

import { useEffect } from 'react';
import type { BrandingConfig } from './useBranding';

/**
 * Dynamically updates PWA manifest link if tenant has custom PWA icon.
 * Also updates the web app manifest icon references in the document head.
 */
export function useDynamicPWA(branding: BrandingConfig | null) {
  useEffect(() => {
    if (!branding) return;

    // Helper to Create Manifest Blob
    const createManifestBlob = () => {
      // Default to what we have
      const existingIcons = [];

      // We prioritize the strictly isolated assets
      const iconLight = branding.pwa_icon_light_url || branding.pwa_icon_url || '/pwa-192x192.png';
      const iconDark = branding.pwa_icon_dark_url || branding.pwa_icon_url || '/pwa-192x192.png';

      const manifestContent = {
        name: "Tammal",
        short_name: "Tammal",
        description: "Multi-tenant SaaS Application",
        theme_color: "#ffffff",
        background_color: "#ffffff",
        display: "standalone",
        start_url: "/",
        icons: [
          {
            src: iconLight,
            sizes: "192x192",
            type: "image/png",
            purpose: "any maskable"
          },
          {
            src: iconLight,
            sizes: "512x512",
            type: "image/png",
            purpose: "any maskable"
          },
          // We can add "dark" specific icons if browsers support 'media' in manifest icons in the future of this project,
          // but currently switching manifests or standard icons is the way. 
          // For now, we will use the 'light' icon as the default standard one for the manifest, 
          // as dynamic OS theme switching for manifest icons is tricky without a separate dark manifest.
        ]
      };

      const stringManifest = JSON.stringify(manifestContent);
      const blob = new Blob([stringManifest], { type: 'application/json' });
      return URL.createObjectURL(blob);
    };

    // Update Manifest Link
    const updateManifest = () => {
      const manifestUrl = createManifestBlob();
      let link = document.querySelector('link[rel="manifest"]') as HTMLLinkElement;

      if (link) {
        URL.revokeObjectURL(link.href); // Clean up old
        link.href = manifestUrl;
      } else {
        link = document.createElement('link');
        link.rel = 'manifest';
        link.href = manifestUrl;
        document.head.appendChild(link);
      }
    };

    updateManifest();

    // Update Apple Touch Icon & Favicon (Dynamic based on system preference is valid via matchMedia)
    const updateFavicons = () => {
      const isDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      const activeIcon = isDark
        ? (branding.pwa_icon_dark_url || branding.pwa_icon_url)
        : (branding.pwa_icon_light_url || branding.pwa_icon_url);

      if (activeIcon) {
        let appleLink = document.querySelector('link[rel="apple-touch-icon"]') as HTMLLinkElement;
        if (appleLink) appleLink.href = activeIcon;

        let favLink = document.querySelector('link[rel="icon"][sizes="any"]') as HTMLLinkElement;
        if (!favLink) favLink = document.querySelector('link[rel="icon"]') as HTMLLinkElement;
        if (favLink) favLink.href = activeIcon;
      }
    };

    // Initial call
    updateFavicons();

    // Listen for theme changes to update favicon dynamically
    const matcher = window.matchMedia('(prefers-color-scheme: dark)');
    const changeHandler = () => updateFavicons();
    matcher.addEventListener('change', changeHandler);

    return () => {
      matcher.removeEventListener('change', changeHandler);
    };

  }, [branding?.pwa_icon_url, branding?.pwa_icon_light_url, branding?.pwa_icon_dark_url]);
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { Json } from '@/integrations/supabase/types';

export type EmployeeStatus = 'active' | 'resigned' | 'terminated';

export interface Employee {
  id: string;
  tenant_id: string;
  user_id: string | null;
  employee_number: string | null;
  full_name: string;
  email: string;
  department: string | null;
  department_id: string | null;
  branch_id: string | null;
  section_id: string | null;
  role_title: string | null;
  manager_id: string | null;
  hire_date: string | null;
  status: EmployeeStatus;
  metadata: Json;
  created_at: string;
  updated_at: string;
  deleted_at: string | null;
  manager?: {
    id: string;
    full_name: string;
  } | null;
}

export interface CreateEmployeeInput {
  tenant_id: string;
  full_name: string;
  email: string;
  employee_number?: string;
  department?: string;
  department_id?: string | null;
  branch_id?: string | null;
  section_id?: string | null;
  role_title?: string;
  manager_id?: string;
  hire_date?: string;
  status?: EmployeeStatus;
  metadata?: Json;
}

export interface EmployeeFilters {
  department?: string;
  status?: EmployeeStatus;
  search?: string;
}

export function useEmployees(filters?: EmployeeFilters) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const { data: employees = [], isPending, error } = useQuery({
    queryKey: ['employees', filters],
    queryFn: async () => {
      let query = supabase
        .from('employees')
        .select('*')
        .is('deleted_at', null)
        .order('full_name', { ascending: true });

      if (filters?.department) {
        query = query.eq('department', filters.department);
      }
      if (filters?.status) {
        query = query.eq('status', filters.status);
      }
      if (filters?.search) {
        query = query.or(`full_name.ilike.%${filters.search}%,email.ilike.%${filters.search}%`);
      }

      const { data, error } = await query;

      if (error) throw error;
      
      const employeesData = (data || []) as Employee[];
      const managerIds = [...new Set(employeesData.filter(e => e.manager_id).map(e => e.manager_id as string))];
      
      let managersMap = new Map<string, { id: string; full_name: string }>();
      if (managerIds.length > 0) {
        const { data: managers } = await supabase
          .from('employees')
          .select('id, full_name')
          .in('id', managerIds);
        if (managers) {
          managers.forEach(m => managersMap.set(m.id, m));
        }
      }

      return employeesData.map(emp => ({
        ...emp,
        manager: emp.manager_id ? managersMap.get(emp.manager_id) || null : null,
      }));
    },
  });

  const { data: departments = [] } = useQuery({
    queryKey: ['employee-departments'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('employees')
        .select('department')
        .is('deleted_at', null)
        .not('department', 'is', null);

      if (error) throw error;
      const uniqueDepts = [...new Set(data.map(d => d.department).filter(Boolean))] as string[];
      return uniqueDepts.sort();
    },
  });

  const createEmployee = useMutation({
    mutationFn: async (input: CreateEmployeeInput) => {
      const { data, error } = await supabase
        .from('employees')
        .insert({
          tenant_id: input.tenant_id,
          full_name: input.full_name,
          email: input.email,
          employee_number: input.employee_number,
          department: input.department,
          department_id: input.department_id || null,
          branch_id: input.branch_id || null,
          section_id: input.section_id || null,
          role_title: input.role_title,
          manager_id: input.manager_id,
          hire_date: input.hire_date,
          status: input.status || 'active',
          metadata: input.metadata || {},
        })
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employees'] });
      queryClient.invalidateQueries({ queryKey: ['employee-departments'] });
      toast.success(t('employees.createSuccess'));
    },
    onError: (error: Error) => {
      if (error.message.includes('duplicate')) {
        toast.error(t('employees.duplicateEmail'));
      } else {
        toast.error(t('employees.createError'));
      }
    },
  });

  const updateEmployee = useMutation({
    mutationFn: async ({ id, manager, ...updates }: Partial<Employee> & { id: string }) => {
      const { data, error } = await supabase
        .from('employees')
        .update(updates)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employees'] });
      queryClient.invalidateQueries({ queryKey: ['employee-departments'] });
      toast.success(t('employees.updateSuccess'));
    },
    onError: () => {
      toast.error(t('employees.updateError'));
    },
  });

  const deleteEmployee = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('employees')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['employees'] });
      toast.success(t('employees.deleteSuccess'));
    },
    onError: () => {
      toast.error(t('employees.deleteError'));
    },
  });

  const bulkImport = useMutation({
    mutationFn: async (employees: CreateEmployeeInput[]) => {
      const insertData = employees.map(emp => ({
        tenant_id: emp.tenant_id,
        full_name: emp.full_name,
        email: emp.email,
        employee_number: emp.employee_number,
        department: emp.department,
        department_id: emp.department_id || null,
        branch_id: emp.branch_id || null,
        section_id: emp.section_id || null,
        role_title: emp.role_title,
        manager_id: emp.manager_id,
        hire_date: emp.hire_date,
        status: emp.status || 'active',
        metadata: emp.metadata || {},
      }));
      
      const { data, error } = await supabase
        .from('employees')
        .insert(insertData)
        .select();

      if (error) throw error;
      return data;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['employees'] });
      queryClient.invalidateQueries({ queryKey: ['employee-departments'] });
      toast.success(t('employees.importSuccess', { count: data.length }));
    },
    onError: () => {
      toast.error(t('employees.importError'));
    },
  });

  return {
    employees,
    departments,
    isPending,
    error,
    createEmployee,
    updateEmployee,
    deleteEmployee,
    bulkImport,
  };
}

/**
 * useOrgTree — single read-only hook that fetches the full org structure
 * (branches, divisions, departments, sites) in parallel, caches them via
 * React Query, and exposes derived selectors that reuse the cache.
 *
 * Consumers that only need read access to org data should prefer this hook
 * over individual useBranches/useDivisions/useDepartments/useSites hooks.
 * The individual CRUD hooks remain the canonical way to mutate org entities.
 */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import type { Branch } from './useBranches';
import type { Division } from './useDivisions';
import type { Department } from './useDepartments';
import type { Site } from './useSites';

export interface OrgTree {
  branches: Branch[];
  divisions: Division[];
  departments: Department[];
  sites: Site[];
  isPending: boolean;

  // Derived selectors — memoised on the arrays
  getBranch: (id: string) => Branch | undefined;
  getDivision: (id: string) => Division | undefined;
  getDepartment: (id: string) => Department | undefined;
  getSite: (id: string) => Site | undefined;
  getDepartmentsByDivision: (divisionId: string) => Department[];
  getDepartmentsByBranch: (branchId: string) => Department[];
  getSitesByBranch: (branchId: string) => Site[];
  getSitesByDepartment: (departmentId: string) => Site[];
}

export function useOrgTree(): OrgTree {
  const branchesQuery = useQuery({
    queryKey: ['branches'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('branches')
        .select('*')
        .is('deleted_at', null)
        .order('name', { ascending: true });
      if (error) throw error;
      return data as Branch[];
    },
    staleTime: 1000 * 60 * 5, // 5 min — org structure changes rarely
  });

  const divisionsQuery = useQuery({
    queryKey: ['divisions'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('divisions')
        .select('*')
        .is('deleted_at', null)
        .order('name', { ascending: true });
      if (error) throw error;
      return data as Division[];
    },
    staleTime: 1000 * 60 * 5,
  });

  const departmentsQuery = useQuery({
    queryKey: ['departments'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('departments')
        .select('*')
        .is('deleted_at', null)
        .order('sort_order', { ascending: true });
      if (error) throw error;
      return data as Department[];
    },
    staleTime: 1000 * 60 * 5,
  });

  const sitesQuery = useQuery({
    queryKey: ['sites'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('sites')
        .select('*')
        .is('deleted_at', null)
        .order('name', { ascending: true });
      if (error) throw error;
      return data as Site[];
    },
    staleTime: 1000 * 60 * 5,
  });

  const branches = branchesQuery.data ?? [];
  const divisions = divisionsQuery.data ?? [];
  const departments = departmentsQuery.data ?? [];
  const sites = sitesQuery.data ?? [];

  // Build lookup maps — only recompute when data reference changes
  const branchMap = useMemo(
    () => new Map(branches.map(b => [b.id, b])),
    [branches],
  );
  const divisionMap = useMemo(
    () => new Map(divisions.map(d => [d.id, d])),
    [divisions],
  );
  const departmentMap = useMemo(
    () => new Map(departments.map(d => [d.id, d])),
    [departments],
  );
  const siteMap = useMemo(
    () => new Map(sites.map(s => [s.id, s])),
    [sites],
  );

  // Derived selectors
  const getBranch = useMemo(() => (id: string) => branchMap.get(id), [branchMap]);
  const getDivision = useMemo(() => (id: string) => divisionMap.get(id), [divisionMap]);
  const getDepartment = useMemo(() => (id: string) => departmentMap.get(id), [departmentMap]);
  const getSite = useMemo(() => (id: string) => siteMap.get(id), [siteMap]);

  const getDepartmentsByDivision = useMemo(
    () => (divisionId: string) => departments.filter(d => d.division_id === divisionId),
    [departments],
  );
  const getDepartmentsByBranch = useMemo(
    () => (branchId: string) => departments.filter(d => d.branch_id === branchId),
    [departments],
  );
  const getSitesByBranch = useMemo(
    () => (branchId: string) => sites.filter(s => s.branch_id === branchId),
    [sites],
  );
  const getSitesByDepartment = useMemo(
    () => (departmentId: string) => sites.filter(s => s.department_id === departmentId),
    [sites],
  );

  return {
    branches,
    divisions,
    departments,
    sites,
    isPending:
      branchesQuery.isPending ||
      divisionsQuery.isPending ||
      departmentsQuery.isPending ||
      sitesQuery.isPending,
    getBranch,
    getDivision,
    getDepartment,
    getSite,
    getDepartmentsByDivision,
    getDepartmentsByBranch,
    getSitesByBranch,
    getSitesByDepartment,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { useAuditLog } from '@/hooks/audit/useAuditLog';
import { logger } from '@/shared/utils/logger';

export interface Invitation {
  id: string;
  code: string;
  email: string;
  full_name: string | null;
  phone_number: string | null;
  tenant_id: string;
  branch_id: string | null;
  employee_id: string | null;
  expires_at: string;
  used: boolean;
  used_at: string | null;
  used_by: string | null;
  deleted_at: string | null;
  delivery_status: string;
  delivery_channel: string;
  email_sent_at: string | null;
  whatsapp_sent_at: string | null;
  last_send_error: string | null;
  metadata: Record<string, any>;
  created_at: string;
  created_by: string | null;
}

export interface CreateInvitationInput {
  email: string;
  full_name?: string;
  phone_number?: string;
  tenant_id: string;
  branch_id?: string;
  employee_id?: string;
  expiry_days?: number;
  delivery_channel?: 'email' | 'whatsapp';
  tenant_name?: string;
}

// Generate 8-character alphanumeric code (excludes ambiguous chars: O, 0, I, 1, L)
function generateInvitationCode(): string {
  const chars = 'ABCDEFGHJKMNPQRSTUVWXYZ23456789';
  let code = '';
  for (let i = 0; i < 8; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return code;
}

export function useTenantInvitations(tenantId?: string) {
  const { t, i18n } = useTranslation();
  const queryClient = useQueryClient();
  const { logEvent } = useAuditLog();

  const invitationsQuery = useQuery({
    queryKey: ['invitations', tenantId],
    queryFn: async () => {
      if (!tenantId) return [];

      const { data, error } = await supabase
        .from('invitations')
        .select('*')
        .eq('tenant_id', tenantId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (error) throw error;
      return data as Invitation[];
    },
    enabled: !!tenantId,
  });

  const createMutation = useMutation({
    mutationFn: async (input: CreateInvitationInput) => {
      const code = generateInvitationCode();
      const expiryDays = input.expiry_days || 7;
      const expiresAt = new Date();
      expiresAt.setDate(expiresAt.getDate() + expiryDays);

      const { data: user } = await supabase.auth.getUser();

      const { data, error } = await supabase
        .from('invitations')
        .insert({
          code,
          email: input.email,
          full_name: input.full_name || null,
          phone_number: input.phone_number || null,
          tenant_id: input.tenant_id,
          branch_id: input.branch_id || null,
          employee_id: input.employee_id || null,
          expires_at: expiresAt.toISOString(),
          delivery_channel: input.delivery_channel || 'email',
          created_by: user.user?.id || null,
        })
        .select()
        .single();

      if (error) throw error;
      if (error) throw error;

      // Trigger email sending
      try {
        await supabase.functions.invoke('send-invitation-email', {
          body: {
            email: input.email,
            code,
            tenantName: input.tenant_name ?? 'Organization',
            fullName: input.full_name,
            expiresAt: expiresAt.toISOString(),
            inviteUrl: `${window.location.origin}/auth/accept-invite?code=${code}`,
            language: i18n.language === 'ar' ? 'ar' : 'en',
            tenant_id: input.tenant_id
          },
        });
      } catch (emailError) {
        logger.error('useTenantInvitations', 'Failed to send invitation email', emailError);
        // We don't throw here to avoid rolling back the invitation creation
        toast.error(t('invitations.emailSendError'));
      }

      return data as Invitation;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['invitations', tenantId] });
      toast.success(t('invitations.createSuccess'));

      logEvent({
        tenant_id: data.tenant_id,
        entity_type: 'tenant',
        entity_id: data.id,
        action: 'create',
        changes: { after: data },
        metadata: { type: 'invitation' },
      });
    },
    onError: (error) => {
      toast.error(t('invitations.createError'));
      logger.error('useTenantInvitations', 'Create failed', error);
    },
  });

  const resendMutation = useMutation({
    mutationFn: async (invitationId: string) => {
      const { data, error } = await supabase
        .from('invitations')
        .update({
          delivery_status: 'pending',
          last_send_error: null,
        })
        .eq('id', invitationId)
        .select()
        .single();

      if (error) throw error;

      if (error) throw error;

      // Fetch tenant details for the email
      const { data: tenant } = await supabase
        .from('tenants')
        .select('name')
        .eq('id', data.tenant_id)
        .single();

      // Trigger edge function to send email
      try {
        await supabase.functions.invoke('send-invitation-email', {
          body: {
            email: data.email,
            code: data.code,
            tenantName: tenant?.name || 'Tammal',
            fullName: data.full_name,
            expiresAt: data.expires_at,
            inviteUrl: `${window.location.origin}/auth/accept-invite?code=${data.code}`,
            language: (data.metadata as Record<string, unknown>)?.language || 'en'
          },
        });
      } catch (emailError) {
        logger.error('useTenantInvitations', 'Failed to resend invitation email', emailError);
        throw emailError;
      }

      return data as Invitation;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['invitations', tenantId] });
      toast.success(t('invitations.resendSuccess'));
    },
    onError: (error) => {
      toast.error(t('invitations.resendError'));
      logger.error('useTenantInvitations', 'Resend failed', error);
    },
  });

  const revokeMutation = useMutation({
    mutationFn: async (invitationId: string) => {
      const { data: before } = await supabase
        .from('invitations')
        .select('*')
        .eq('id', invitationId)
        .single();

      const { error } = await supabase
        .from('invitations')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', invitationId);

      if (error) throw error;
      return { id: invitationId, before };
    },
    onSuccess: ({ id, before }) => {
      queryClient.invalidateQueries({ queryKey: ['invitations', tenantId] });
      toast.success(t('invitations.revokeSuccess'));

      logEvent({
        tenant_id: tenantId,
        entity_type: 'tenant',
        entity_id: id,
        action: 'delete',
        changes: { before },
        metadata: { type: 'invitation_revoke' },
      });
    },
    onError: (error) => {
      toast.error(t('invitations.revokeError'));
      logger.error('useTenantInvitations', 'Revoke failed', error);
    },
  });

  // Get invitation status
  const getStatus = (invitation: Invitation): 'pending' | 'used' | 'expired' | 'revoked' => {
    if (invitation.deleted_at) return 'revoked';
    if (invitation.used) return 'used';
    if (new Date(invitation.expires_at) < new Date()) return 'expired';
    return 'pending';
  };

  // Calculate days remaining
  const getDaysRemaining = (invitation: Invitation): number => {
    const now = new Date();
    const expires = new Date(invitation.expires_at);
    const diffTime = expires.getTime() - now.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  return {
    invitations: invitationsQuery.data ?? [],
    isPending: invitationsQuery.isPending && invitationsQuery.isFetching,
    error: invitationsQuery.error,
    createInvitation: createMutation.mutate,
    resendInvitation: resendMutation.mutate,
    revokeInvitation: revokeMutation.mutate,
    isCreating: createMutation.isPending,
    isResending: resendMutation.isPending,
    isRevoking: revokeMutation.isPending,
    getStatus,
    getDaysRemaining,
  };
}

// Hook to verify invitation code (for signup flow)
export function useVerifyInvitation(code?: string) {
  return useQuery({
    queryKey: ['invitation-verify', code],
    queryFn: async () => {
      if (!code) return null;

      const { data, error } = await supabase
        .from('invitations')
        .select('*, tenants(name)')
        .eq('code', code)
        .is('deleted_at', null)
        .is('used', false)
        .gt('expires_at', new Date().toISOString())
        .single();

      if (error) throw error;
      return data;
    },
    enabled: !!code && code.length === 8,
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import type { Tables, TablesInsert, TablesUpdate } from '@/integrations/supabase/types';
import type { Plan } from './usePlans';
import { useAuditLog } from '@/hooks/audit/useAuditLog';
import { logger } from '@/shared/utils/logger';
import { addDays } from 'date-fns';
import type { SecuritySettings } from '@/shared/types/common.types/tenant';

export type Tenant = Tables<'tenants'> & {
  plan?: Plan | null;
};
export type TenantInsert = TablesInsert<'tenants'>;
export type TenantUpdate = TablesUpdate<'tenants'>;

export function useTenants() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const { logEvent } = useAuditLog();

  const tenantsQuery = useQuery({
    queryKey: ['tenants-full'],
    queryFn: async () => {
      // Fetch tenants with their associated plans
      const { data: tenants, error: tenantsError } = await supabase
        .from('tenants')
        .select('*')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (tenantsError) throw tenantsError;

      // Fetch all plans to map them
      const { data: plans, error: plansError } = await supabase
        .from('plans')
        .select('*')
        .is('deleted_at', null);

      if (plansError) throw plansError;

      // Map plans to tenants
      const plansMap = new Map(plans?.map(p => [p.id, p]) || []);
      
      return (tenants || []).map(tenant => ({
        ...tenant,
        plan: tenant.plan_id ? plansMap.get(tenant.plan_id) || null : null,
      }));
    },
  });

  const createMutation = useMutation({
    mutationFn: async (tenant: TenantInsert) => {
      const { data, error } = await supabase
        .from('tenants')
        .insert(tenant as any)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      queryClient.invalidateQueries({ queryKey: ['tenants'] });
      toast.success(t('tenants.createSuccess'));
      
      // Log audit event
      logEvent({
        tenant_id: data.id,
        entity_type: 'tenant',
        entity_id: data.id,
        action: 'create',
        changes: { after: data },
      });
    },
    onError: (error) => {
      toast.error(t('tenants.createError'));
      logger.error('useTenants', 'Create failed', error);
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, ...updates }: TenantUpdate & { id: string }) => {
      // Fetch current state for audit logging
      const { data: before } = await supabase
        .from('tenants')
        .select('*')
        .eq('id', id)
        .single();

      const { data, error } = await supabase
        .from('tenants')
        .update(updates as any)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return { data, before };
    },
    onSuccess: ({ data, before }) => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      queryClient.invalidateQueries({ queryKey: ['tenants'] });
      toast.success(t('tenants.updateSuccess'));
      
      // Determine action type
      const beforeSettings = before?.settings as any;
      const afterSettings = data.settings as any;
      const isModuleToggle = beforeSettings?.modules && afterSettings?.modules &&
        JSON.stringify(beforeSettings.modules) !== JSON.stringify(afterSettings.modules);
      const isStatusChange = before?.status !== data.status;
      
      logEvent({
        tenant_id: data.id,
        entity_type: 'tenant',
        entity_id: data.id,
        action: isModuleToggle ? 'module_toggle' : isStatusChange ? 'status_change' : 'update',
        changes: { before, after: data },
      });
    },
    onError: (error) => {
      toast.error(t('tenants.updateError'));
      logger.error('useTenants', 'Update failed', error);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      // Fetch current state for audit logging
      const { data: before } = await supabase
        .from('tenants')
        .select('*')
        .eq('id', id)
        .single();

      // Soft delete
      const { error } = await supabase
        .from('tenants')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);

      if (error) throw error;
      return { id, before };
    },
    onSuccess: ({ id, before }) => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      queryClient.invalidateQueries({ queryKey: ['tenants'] });
      toast.success(t('tenants.deleteSuccess'));
      
      logEvent({
        tenant_id: id,
        entity_type: 'tenant',
        entity_id: id,
        action: 'delete',
        changes: { before },
      });
    },
    onError: (error) => {
      toast.error(t('tenants.deleteError'));
      logger.error('useTenants', 'Delete failed', error);
    },
  });

  // Trial Management
  const startTrialMutation = useMutation({
    mutationFn: async ({ tenantId, days }: { tenantId: string; days: number }) => {
      const now = new Date();
      const endDate = addDays(now, days);

      const { data, error } = await supabase
        .from('tenants')
        .update({
          subscription_status: 'trialing',
          trial_start_date: now.toISOString(),
          trial_end_date: endDate.toISOString(),
        } as any)
        .eq('id', tenantId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      toast.success(t('tenants.trialStarted'));
    },
    onError: (error) => {
      toast.error(t('tenants.updateError'));
      logger.error('useTenants', 'Start trial failed', error);
    },
  });

  const extendTrialMutation = useMutation({
    mutationFn: async ({ tenantId, days, endDate }: { tenantId: string; days?: number; endDate?: string }) => {
      // Get current trial end date
      const { data: tenant } = await supabase
        .from('tenants')
        .select('trial_end_date')
        .eq('id', tenantId)
        .single();

      let newEndDate: Date;
      if (endDate) {
        newEndDate = new Date(endDate);
      } else if (days && tenant?.trial_end_date) {
        newEndDate = addDays(new Date(tenant.trial_end_date), days);
      } else {
        throw new Error('Either days or endDate must be provided');
      }

      const { data, error } = await supabase
        .from('tenants')
        .update({
          trial_end_date: newEndDate.toISOString(),
        } as any)
        .eq('id', tenantId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      toast.success(t('tenants.trialExtended'));
    },
    onError: (error) => {
      toast.error(t('tenants.updateError'));
      logger.error('useTenants', 'Extend trial failed', error);
    },
  });

  const endTrialMutation = useMutation({
    mutationFn: async (tenantId: string) => {
      const { data, error } = await supabase
        .from('tenants')
        .update({
          subscription_status: 'inactive',
        } as any)
        .eq('id', tenantId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      toast.success(t('tenants.trialEnded'));
    },
    onError: (error) => {
      toast.error(t('tenants.updateError'));
      logger.error('useTenants', 'End trial failed', error);
    },
  });

  // Security Settings
  const updateSecurityMutation = useMutation({
    mutationFn: async ({ tenantId, settings }: { tenantId: string; settings: SecuritySettings }) => {
      const { data, error } = await supabase
        .from('tenants')
        .update(settings as any)
        .eq('id', tenantId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tenants-full'] });
      toast.success(t('tenants.updateSuccess'));
    },
    onError: (error) => {
      toast.error(t('tenants.updateError'));
      logger.error('useTenants', 'Update security failed', error);
    },
  });

  return {
    tenants: tenantsQuery.data ?? [],
    isPending: tenantsQuery.isPending,
    error: tenantsQuery.error,
    createTenant: createMutation.mutate,
    updateTenant: updateMutation.mutate,
    deleteTenant: deleteMutation.mutate,
    isCreating: createMutation.isPending,
    isUpdating: updateMutation.isPending,
    isDeleting: deleteMutation.isPending,
    // Trial management
    startTrial: startTrialMutation.mutate,
    extendTrial: extendTrialMutation.mutate,
    endTrial: endTrialMutation.mutate,
    isTrialUpdating: startTrialMutation.isPending || extendTrialMutation.isPending || endTrialMutation.isPending,
    // Security settings
    updateSecuritySettings: updateSecurityMutation.mutate,
    isSecurityUpdating: updateSecurityMutation.isPending,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import type { Tables } from '@/integrations/supabase/types';
import { logger } from '@/shared/utils/logger';

export type Profile = Tables<'profiles'>;
export type UserRole = Tables<'user_roles'>;

export interface UserWithRoles extends Omit<Profile, 'status'> {
  user_roles: (UserRole & { 
    roles?: {
      id: string;
      name: string;
      name_ar: string | null;
      color: string;
    } | null;
  })[];
  email?: string;
  status: string;
}

export interface UserFilters {
  tenantId?: string;
  role?: string;
  search?: string;
  status?: string;
}

export function useUsers(filters?: UserFilters) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const usersQuery = useQuery({
    queryKey: ['users', filters],
    queryFn: async () => {
      // If no tenantId provided, return empty array
      if (!filters?.tenantId) {
        return [] as UserWithRoles[];
      }

      // Query from the profiles_with_email view to get emails
      let query = supabase
        .from('profiles_with_email')
        .select('*')
        .eq('tenant_id', filters.tenantId)
        .order('created_at', { ascending: false });

      if (filters?.search) {
        query = query.or(`full_name.ilike.%${filters.search}%,email.ilike.%${filters.search}%`);
      }

      if (filters?.status) {
        query = query.eq('status', filters.status);
      }

      const { data: profiles, error } = await query;
      if (error) throw error;

      if (!profiles || profiles.length === 0) {
        return [] as UserWithRoles[];
      }

      // Fetch user roles WITH custom role details
      const userIds = profiles.map((p: any) => p.user_id);
      const { data: userRolesData, error: rolesError } = await supabase
        .from('user_roles')
        .select(`
          id,
          user_id,
          role,
          custom_role_id,
          created_at,
          roles:custom_role_id(id, name, name_ar, color)
        `)
        .in('user_id', userIds);

      if (rolesError) {
        logger.error('useUsers', 'Error fetching user roles', rolesError);
      }

      // Map roles to users
      return profiles.map((profile: any) => ({
        ...profile,
        user_roles: (userRolesData || [])
          .filter(ur => ur.user_id === profile.user_id)
          .map(ur => ({
            ...ur,
            roles: ur.roles as { id: string; name: string; name_ar: string | null; color: string } | null
          }))
      })) as UserWithRoles[];
    },
    enabled: !!filters?.tenantId,
  });

  // Mutation to update profile (name, status, job_title, department, phone, location, avatar_url)
  const updateProfile = useMutation({
    mutationFn: async ({ 
      id, 
      full_name, 
      status, 
      job_title, 
      department, 
      phone, 
      location,
      avatar_url 
    }: { 
      id: string; 
      full_name?: string; 
      status?: string;
      job_title?: string;
      department?: string;
      phone?: string;
      location?: string;
      avatar_url?: string | null;
    }) => {
      const updates: Record<string, any> = {};
      if (full_name !== undefined) updates.full_name = full_name;
      if (status !== undefined) updates.status = status;
      if (job_title !== undefined) updates.job_title = job_title;
      if (department !== undefined) updates.department = department;
      if (phone !== undefined) updates.phone = phone;
      if (location !== undefined) updates.location = location;
      if (avatar_url !== undefined) updates.avatar_url = avatar_url;

      const { data, error } = await supabase
        .from('profiles')
        .update(updates)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['users'] });
      toast.success(t('users.updateSuccess'));
    },
    onError: (error) => {
      toast.error(t('users.updateError'));
      logger.error('useUsers', 'Update profile failed', error);
    },
  });

  // Mutation to send password reset email
  const sendPasswordReset = useMutation({
    mutationFn: async ({ userId, email }: { userId: string; email: string }) => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error('Not authenticated');

      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/admin-reset-password`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({ user_id: userId, email }),
        }
      );

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'Failed to send password reset');
      }

      return response.json();
    },
    onSuccess: () => {
      toast.success(t('users.passwordResetSent'));
    },
    onError: (error) => {
      toast.error(t('users.passwordResetError'));
      logger.error('useUsers', 'Password reset failed', error);
    },
  });

  // Mutation to change user status
  const changeUserStatus = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: 'active' | 'inactive' | 'suspended' }) => {
      const { data, error } = await supabase
        .from('profiles')
        .update({ status })
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['users'] });
      const statusMessage = variables.status === 'active' 
        ? t('users.reactivateSuccess')
        : variables.status === 'suspended'
          ? t('users.suspendSuccess')
          : t('users.deactivateSuccess');
      toast.success(statusMessage);
    },
    onError: (error) => {
      toast.error(t('users.statusChangeError'));
      logger.error('useUsers', 'Status change failed', error);
    },
  });

  return {
    users: usersQuery.data ?? [],
    isPending: usersQuery.isPending && usersQuery.isFetching,
    error: usersQuery.error,
    refetch: usersQuery.refetch,
    updateProfile,
    changeUserStatus,
    sendPasswordReset,
  };
}

export function useUserRoles(userId?: string) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const userRolesQuery = useQuery({
    queryKey: ['user-roles', userId],
    queryFn: async () => {
      if (!userId) return [];
      
      const { data, error } = await supabase
        .from('user_roles')
        .select(`
          *,
          roles:custom_role_id(id, name, name_ar, color, description)
        `)
        .eq('user_id', userId);

      if (error) throw error;
      return data;
    },
    enabled: !!userId,
  });

  const assignRole = useMutation({
    mutationFn: async ({ 
      userId, 
      customRoleId, 
      role = 'user' 
    }: { 
      userId: string; 
      customRoleId?: string; 
      role?: 'super_admin' | 'tenant_admin' | 'manager' | 'user';
    }) => {
      const { data, error } = await supabase
        .from('user_roles')
        .insert({ 
          user_id: userId, 
          role,
          custom_role_id: customRoleId || null,
        })
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['user-roles'] });
      queryClient.invalidateQueries({ queryKey: ['users'] });
      toast.success(t('users.roleAssignSuccess'));
    },
    onError: (error) => {
      toast.error(t('users.roleAssignError'));
      logger.error('useUsers', 'Assign role failed', error);
    },
  });

  const removeRole = useMutation({
    mutationFn: async (userRoleId: string) => {
      const { error } = await supabase
        .from('user_roles')
        .delete()
        .eq('id', userRoleId);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['user-roles'] });
      queryClient.invalidateQueries({ queryKey: ['users'] });
      toast.success(t('users.roleRemoveSuccess'));
    },
    onError: (error) => {
      toast.error(t('users.roleRemoveError'));
      logger.error('useUsers', 'Remove role failed', error);
    },
  });

  const updateUserRole = useMutation({
    mutationFn: async ({ 
      userRoleId, 
      customRoleId 
    }: { 
      userRoleId: string; 
      customRoleId: string | null;
    }) => {
      const { data, error } = await supabase
        .from('user_roles')
        .update({ custom_role_id: customRoleId })
        .eq('id', userRoleId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['user-roles'] });
      queryClient.invalidateQueries({ queryKey: ['users'] });
      toast.success(t('users.roleUpdateSuccess'));
    },
    onError: (error) => {
      toast.error(t('users.roleUpdateError'));
      logger.error('useUsers', 'Update user role failed', error);
    },
  });

  return {
    userRoles: userRolesQuery.data ?? [],
    isPending: userRolesQuery.isPending && userRolesQuery.isFetching,
    error: userRolesQuery.error,
    assignRole,
    removeRole,
    updateUserRole,
  };
}

import { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface EnhancedGeneratedQuestion {
  question_text: string;
  question_text_ar: string;
  type: string;
  complexity: string;
  tone: string;
  explanation: string;
  confidence_score: number;
  bias_flag: boolean;
  ambiguity_flag: boolean;
  validation_status: 'pending' | 'passed' | 'warning' | 'failed';
  validation_details: Record<string, any>;
  options?: { text: string; text_ar: string }[];
  framework_reference?: string | null;
  psychological_construct?: string | null;
  scoring_mechanism?: string | null;
  category_name?: string | null;
  subcategory_name?: string | null;
  mood_levels: string[];
  // Analytical fields
  category_id?: string | null;
  subcategory_id?: string | null;
  mood_score?: number;
  affective_state?: string;
  generation_period_id?: string | null;
  question_hash?: string;
}

export interface ValidationReport {
  overall_result: 'passed' | 'warning' | 'failed';
  validation_results: Record<string, { result: string; details: any }>;
  per_question: { validation_status: string; validation_details: Record<string, any> }[];
  avg_confidence: number;
  critic_result?: any;
}

export interface AdvancedSettings {
  requireExplanation: boolean;
  enableBiasDetection: boolean;
  enableAmbiguityDetection: boolean;
  enableDuplicateDetection: boolean;
  enableCriticPass: boolean;
  minWordLength: number;
}

export interface GenerateInput {
  questionCount: number;
  complexity: string;
  tone: string;
  questionType: string;
  model: string;
  accuracyMode: string;
  advancedSettings: AdvancedSettings;
  language?: string;
  useExpertKnowledge?: boolean;
  knowledgeDocumentIds?: string[];
  customPrompt?: string;
  selectedFrameworks?: string[];
  categoryIds?: string[];
  subcategoryIds?: string[];
  moodLevels?: string[];
  periodId?: string;
}



import { VALID_QUESTION_TYPES } from '@/config/constants';
const VALID_TYPES = VALID_QUESTION_TYPES as readonly string[];

function normalizeQuestionType(t: string): string {
  if (VALID_TYPES.includes(t)) return t;
  const lower = (t || '').toLowerCase().replace(/[\s-]+/g, '_');
  if (lower.includes('open') || lower.includes('free_text') || lower.includes('qualitative')) return 'open_ended';
  if (lower.includes('scenario') || lower.includes('situational')) return 'multiple_choice';
  if (lower.includes('likert') || lower.includes('agreement')) return 'likert_5';
  if (lower.includes('numeric') || lower.includes('scale') || lower.includes('rating')) return 'numeric_scale';
  if (lower.includes('yes') || lower.includes('binary')) return 'yes_no';
  if (lower.includes('multiple') || lower.includes('mcq') || lower.includes('choice')) return 'multiple_choice';
  return 'likert_5';
}

export function useEnhancedAIGeneration() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const [questions, setQuestions] = useState<EnhancedGeneratedQuestion[]>([]);
  const [validationReport, setValidationReport] = useState<ValidationReport | null>(null);
  const [generationMeta, setGenerationMeta] = useState<{ model: string; duration_ms: number } | null>(null);
  const [regeneratingIndex, setRegeneratingIndex] = useState<number | null>(null);

  const lastMoodLevelsRef = { current: [] as string[] };
  const replaceAtIndexRef = { current: null as number | null };

  const generateMutation = useMutation({
    mutationFn: async (input: GenerateInput & { _replaceAtIndex?: number }) => {
      lastMoodLevelsRef.current = input.moodLevels || [];
      replaceAtIndexRef.current = input._replaceAtIndex ?? null;
      const { _replaceAtIndex, ...body } = input;
      const { data, error } = await supabase.functions.invoke('generate-questions', {
        body,
      });
      if (error) throw error;
      if (data?.error) throw new Error(data.error);
      return data;
    },
    onSuccess: (data) => {
      const defaultMoods = lastMoodLevelsRef.current;
      const normalized = (data.questions || []).map((q: any) => ({
        ...q,
        type: normalizeQuestionType(q.type),
        mood_levels: (Array.isArray(q.mood_levels) && q.mood_levels.length > 0) ? q.mood_levels : defaultMoods,
      }));

      const idx = replaceAtIndexRef.current;
      if (idx !== null && normalized.length > 0) {
        // Single regeneration: replace only the question at the given index
        setQuestions(prev => prev.map((q, i) => i === idx ? normalized[0] : q));
      } else {
        setQuestions(normalized);
      }
      replaceAtIndexRef.current = null;
      setRegeneratingIndex(null);

      setGenerationMeta({ model: data.model, duration_ms: data.duration_ms });
      setValidationReport(null);
      toast.success(t('aiGenerator.generateSuccess', { count: data.questions.length }));
    },
    onError: (error: Error) => {
      replaceAtIndexRef.current = null;
      setRegeneratingIndex(null);
      if (error.message.includes('Rate limit')) {
        toast.error(t('aiGenerator.rateLimitError'));
      } else if (error.message.includes('credits')) {
        toast.error(t('aiGenerator.creditsError'));
      } else {
        toast.error(error.message || t('aiGenerator.generateError'));
      }
    },
  });

  const validateMutation = useMutation({
    mutationFn: async (params: { questions: EnhancedGeneratedQuestion[]; accuracyMode: string; model?: string; enableCriticPass: boolean; minWordLength: number; selectedFrameworkIds?: string[]; knowledgeDocumentIds?: string[]; hasDocuments?: boolean; periodId?: string }) => {
      const { data, error } = await supabase.functions.invoke('validate-questions', {
        body: params,
      });
      if (error) throw error;
      if (data?.error) throw new Error(data.error);
      return data as ValidationReport;
    },
    onSuccess: (report) => {
      setValidationReport(report);
      setQuestions(prev =>
        prev.map((q, i) => ({
          ...q,
          validation_status: (report.per_question[i]?.validation_status || 'pending') as any,
          validation_details: report.per_question[i]?.validation_details || {},
        }))
      );
      const msg = report.overall_result === 'passed'
        ? t('aiGenerator.validationPassed')
        : report.overall_result === 'warning'
          ? t('aiGenerator.validationWarnings')
          : t('aiGenerator.validationFailed');
      toast[report.overall_result === 'failed' ? 'error' : report.overall_result === 'warning' ? 'warning' : 'success'](msg);
    },
    onError: (error: Error) => {
      toast.error(error.message || t('aiGenerator.validationError'));
    },
  });

  const saveWellnessMutation = useMutation({
    mutationFn: async (params: { questions: EnhancedGeneratedQuestion[]; targetBatchId?: string }) => {
      const { data, error } = await supabase.functions.invoke('save-question-batch', {
        body: {
          purpose: 'wellness',
          questions: params.questions,
          targetBatchId: params.targetBatchId,
        },
      });
      if (error) throw error;
      if (data?.error) throw new Error(data.error);
      return data.savedCount as number;
    },
    onSuccess: (count) => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      queryClient.invalidateQueries({ queryKey: ['wellness-batches'] });
      queryClient.invalidateQueries({ queryKey: ['wellness-questions'] });
      toast.success(t('aiGenerator.wellnessSaveSuccess', { count }));
    },
    onError: (error: Error) => {
      toast.error(error.message || t('aiGenerator.wellnessSaveError'));
    },
  });

  const saveSetMutation = useMutation({
    mutationFn: async (params: {
      questions: EnhancedGeneratedQuestion[];
      model: string;
      accuracyMode: string;
      settings: any;
      validationReport: ValidationReport | null;
      targetBatchId?: string;
    }) => {
      const { data, error } = await supabase.functions.invoke('save-question-batch', {
        body: {
          purpose: 'survey',
          questions: params.questions,
          targetBatchId: params.targetBatchId,
          model: params.model,
          accuracyMode: params.accuracyMode,
          settings: params.settings,
          validationReport: params.validationReport ? {
            overall_result: params.validationReport.overall_result,
            validation_results: params.validationReport.validation_results,
            critic_result: params.validationReport.critic_result,
          } : null,
        },
      });
      if (error) throw error;
      if (data?.error) throw new Error(data.error);
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      toast.success(t('batches.saveSuccess'));
    },
    onError: (error: Error) => {
      toast.error(error.message || t('aiGenerator.saveError'));
    },
  });

  const removeQuestion = (index: number) => {
    setQuestions(prev => prev.filter((_, i) => i !== index));
    if (validationReport) {
      setValidationReport(prev => prev ? {
        ...prev,
        per_question: prev.per_question.filter((_, i) => i !== index),
      } : null);
    }
  };

  const updateQuestion = (index: number, updates: Partial<EnhancedGeneratedQuestion>) => {
    setQuestions(prev => prev.map((q, i) => i === index ? { ...q, ...updates } : q));
  };

  const clearAll = () => {
    setQuestions([]);
    setValidationReport(null);
    setGenerationMeta(null);
  };

  return {
    questions,
    validationReport,
    generationMeta,
    generate: (input: GenerateInput & { _replaceAtIndex?: number }) => {
      setRegeneratingIndex(input._replaceAtIndex ?? null);
      generateMutation.mutate(input);
    },
    validate: validateMutation.mutate,
    saveSet: saveSetMutation.mutate,
    saveWellness: saveWellnessMutation.mutate,
    removeQuestion,
    updateQuestion,
    clearAll,
    isGenerating: generateMutation.isPending,
    regeneratingIndex,
    isValidating: validateMutation.isPending,
    isSaving: saveSetMutation.isPending,
    isSavingWellness: saveWellnessMutation.isPending,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { useState } from 'react';

export interface QuestionBatch {
  id: string;
  name: string | null;
  tenant_id: string | null;
  user_id: string | null;
  model_used: string;
  accuracy_mode: string;
  status: string;
  question_count: number;
  created_at: string | null;
  deleted_at: string | null;
  creator_name?: string | null;
  purpose: 'survey' | 'wellness';
  generation_period_id?: string | null;
}

export interface BatchQuestion {
  id: string;
  question_text: string;
  question_text_ar: string | null;
  type: string;
  complexity: string | null;
  tone: string | null;
  confidence_score: number | null;
  validation_status: string | null;
  bias_flag: boolean | null;
  ambiguity_flag: boolean | null;
  explanation: string | null;
  options: any;
  created_at: string | null;
}

import { MAX_BATCH_SIZE } from '@/config/constants';

export function useQuestionBatches(tenantId: string | null) {
  const queryClient = useQueryClient();
  const { t } = useTranslation();
  const [expandedBatchQuestions, setExpandedBatchQuestions] = useState<Record<string, BatchQuestion[]>>({});

  const batchesQuery = useQuery({
    queryKey: ['question-batches', tenantId],
    queryFn: async () => {
      if (!tenantId) return [];

      // Fetch survey batches from question_sets
      const { data: surveyData, error: surveyError } = await supabase
        .from('question_sets')
        .select('*')
        .eq('tenant_id', tenantId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (surveyError) throw surveyError;

      // Fetch wellness batches from question_generation_batches
      const { data: wellnessData, error: wellnessError } = await supabase
        .from('question_generation_batches')
        .select('*')
        .eq('tenant_id', tenantId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });
      if (wellnessError) throw wellnessError;

      // Collect all user IDs for profile lookup
      const surveyUserIds = (surveyData || []).map(b => b.user_id).filter(Boolean) as string[];
      const wellnessUserIds = (wellnessData || []).map(b => b.created_by).filter(Boolean) as string[];
      const allUserIds = [...new Set([...surveyUserIds, ...wellnessUserIds])];

      let profileMap: Record<string, string> = {};
      if (allUserIds.length > 0) {
        const { data: profiles } = await supabase
          .from('profiles')
          .select('user_id, full_name')
          .in('user_id', allUserIds);
        if (profiles) {
          profileMap = Object.fromEntries(profiles.map(p => [p.user_id, p.full_name || '']));
        }
      }

      const surveyBatches: QuestionBatch[] = (surveyData || []).map(b => ({
        id: b.id,
        name: b.name,
        tenant_id: b.tenant_id,
        user_id: b.user_id,
        model_used: b.model_used,
        accuracy_mode: b.accuracy_mode,
        status: b.status,
        question_count: b.question_count,
        created_at: b.created_at,
        deleted_at: b.deleted_at,
        creator_name: b.user_id ? profileMap[b.user_id] || null : null,
        purpose: 'survey' as const,
        generation_period_id: (b as any).generation_period_id || null,
      }));

      const wellnessBatches: QuestionBatch[] = (wellnessData || []).map(b => ({
        id: b.id,
        name: (b as any).name || null,
        tenant_id: b.tenant_id,
        user_id: b.created_by,
        model_used: '',
        accuracy_mode: '',
        status: b.status,
        question_count: b.question_count,
        created_at: b.created_at,
        deleted_at: b.deleted_at,
        creator_name: b.created_by ? profileMap[b.created_by] || null : null,
        purpose: 'wellness' as const,
        generation_period_id: (b as any).generation_period_id || null,
      }));

      // Merge and sort by created_at descending
      const all = [...surveyBatches, ...wellnessBatches].sort((a, b) => {
        const da = a.created_at ? new Date(a.created_at).getTime() : 0;
        const db = b.created_at ? new Date(b.created_at).getTime() : 0;
        return db - da;
      });

      return all;
    },
    enabled: !!tenantId,
  });

  const fetchBatchQuestions = async (batchId: string) => {
    // Find batch to determine purpose
    const batch = (batchesQuery.data || []).find(b => b.id === batchId);

    if (batch?.purpose === 'wellness') {
      // Fetch from wellness_questions
      const { data, error } = await supabase
        .from('wellness_questions')
        .select('*')
        .eq('batch_id', batchId)
        .is('deleted_at', null)
        .order('created_at', { ascending: true });
      if (error) throw error;
      const questions: BatchQuestion[] = (data || []).map(q => ({
        id: q.id,
        question_text: q.question_text_en,
        question_text_ar: q.question_text_ar,
        type: q.question_type,
        complexity: null,
        tone: null,
        confidence_score: null,
        validation_status: q.status,
        bias_flag: null,
        ambiguity_flag: null,
        explanation: null,
        options: q.options,
        created_at: q.created_at,
      }));
      setExpandedBatchQuestions(prev => ({ ...prev, [batchId]: questions }));
      return questions;
    } else {
      // Fetch from generated_questions (survey)
      const { data, error } = await supabase
        .from('generated_questions')
        .select('*')
        .eq('question_set_id', batchId)
        .order('created_at', { ascending: true });
      if (error) throw error;
      const questions = (data || []) as BatchQuestion[];
      setExpandedBatchQuestions(prev => ({ ...prev, [batchId]: questions }));
      return questions;
    }
  };

  const publishBatch = useMutation({
    mutationFn: async (batchId: string) => {
      const batch = (batchesQuery.data || []).find(b => b.id === batchId);
      if (batch?.purpose === 'wellness') {
        // Publish all wellness questions in the batch
        await supabase
          .from('wellness_questions')
          .update({ status: 'published' })
          .eq('batch_id', batchId)
          .is('deleted_at', null);
        const { error } = await supabase
          .from('question_generation_batches')
          .update({ status: 'published', published_at: new Date().toISOString() })
          .eq('id', batchId);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('question_sets')
          .update({ status: 'published' })
          .eq('id', batchId);
        if (error) throw error;
      }
    },
    onSuccess: (_data, batchId) => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      // Refresh expanded questions to show updated status
      setExpandedBatchQuestions(prev => {
        const updated = { ...prev };
        if (updated[batchId]) {
          updated[batchId] = updated[batchId].map(q => ({
            ...q,
            validation_status: 'published',
          }));
        }
        return updated;
      });
      toast.success(t('batches.publishSuccess', 'Batch published successfully'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const deactivateBatch = useMutation({
    mutationFn: async (batchId: string) => {
      const batch = (batchesQuery.data || []).find(b => b.id === batchId);
      if (batch?.purpose === 'wellness') {
        await supabase
          .from('wellness_questions')
          .update({ status: 'inactive' } as any)
          .eq('batch_id', batchId)
          .is('deleted_at', null);
        const { error } = await supabase
          .from('question_generation_batches')
          .update({ status: 'inactive' } as any)
          .eq('id', batchId);
        if (error) throw error;
      } else {
        await supabase
          .from('generated_questions')
          .update({ validation_status: 'inactive' })
          .eq('question_set_id', batchId);
        const { error } = await supabase
          .from('question_sets')
          .update({ status: 'inactive' })
          .eq('id', batchId);
        if (error) throw error;
      }
    },
    onSuccess: (_data, batchId) => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      setExpandedBatchQuestions(prev => {
        const updated = { ...prev };
        if (updated[batchId]) {
          updated[batchId] = updated[batchId].map(q => ({
            ...q,
            validation_status: 'inactive',
          }));
        }
        return updated;
      });
      toast.success(t('batches.deactivateSuccess', 'Batch deactivated successfully'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const deactivateQuestions = useMutation({
    mutationFn: async ({ batchId, questionIds, purpose }: { batchId: string; questionIds: string[]; purpose: 'survey' | 'wellness' }) => {
      if (purpose === 'wellness') {
        const { error } = await supabase
          .from('wellness_questions')
          .update({ status: 'inactive' } as any)
          .in('id', questionIds);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('generated_questions')
          .update({ validation_status: 'inactive' })
          .in('id', questionIds);
        if (error) throw error;
      }
    },
    onSuccess: (_data, { batchId, questionIds }) => {
      setExpandedBatchQuestions(prev => {
        const updated = { ...prev };
        if (updated[batchId]) {
          updated[batchId] = updated[batchId].map(q =>
            questionIds.includes(q.id) ? { ...q, validation_status: 'inactive' } : q
          );
        }
        return updated;
      });
      toast.success(t('batches.questionsDeactivated', 'Selected questions deactivated'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const activateBatch = useMutation({
    mutationFn: async (batchId: string) => {
      const batch = (batchesQuery.data || []).find(b => b.id === batchId);
      if (batch?.purpose === 'wellness') {
        await supabase
          .from('wellness_questions')
          .update({ status: 'published' } as any)
          .eq('batch_id', batchId)
          .is('deleted_at', null);
        const { error } = await supabase
          .from('question_generation_batches')
          .update({ status: 'published' } as any)
          .eq('id', batchId);
        if (error) throw error;
      } else {
        await supabase
          .from('generated_questions')
          .update({ validation_status: 'published' })
          .eq('question_set_id', batchId);
        const { error } = await supabase
          .from('question_sets')
          .update({ status: 'published' })
          .eq('id', batchId);
        if (error) throw error;
      }
    },
    onSuccess: (_data, batchId) => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      setExpandedBatchQuestions(prev => {
        const updated = { ...prev };
        if (updated[batchId]) {
          updated[batchId] = updated[batchId].map(q => ({
            ...q,
            validation_status: 'published',
          }));
        }
        return updated;
      });
      toast.success(t('batches.activateSuccess'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const activateQuestions = useMutation({
    mutationFn: async ({ batchId, questionIds, purpose }: { batchId: string; questionIds: string[]; purpose: 'survey' | 'wellness' }) => {
      if (purpose === 'wellness') {
        const { error } = await supabase
          .from('wellness_questions')
          .update({ status: 'published' } as any)
          .in('id', questionIds);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('generated_questions')
          .update({ validation_status: 'published' })
          .in('id', questionIds);
        if (error) throw error;
      }
    },
    onSuccess: (_data, { batchId, questionIds }) => {
      setExpandedBatchQuestions(prev => {
        const updated = { ...prev };
        if (updated[batchId]) {
          updated[batchId] = updated[batchId].map(q =>
            questionIds.includes(q.id) ? { ...q, validation_status: 'published' } : q
          );
        }
        return updated;
      });
      toast.success(t('batches.questionsActivated'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const deleteBatch = useMutation({
    mutationFn: async (batchId: string) => {
      const batch = (batchesQuery.data || []).find(b => b.id === batchId);
      if (batch?.purpose === 'wellness') {
        await supabase
          .from('wellness_questions')
          .update({ deleted_at: new Date().toISOString() })
          .eq('batch_id', batchId);
        const { error } = await supabase
          .from('question_generation_batches')
          .update({ deleted_at: new Date().toISOString() })
          .eq('id', batchId);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('question_sets')
          .update({ deleted_at: new Date().toISOString() })
          .eq('id', batchId);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      toast.success(t('batches.deleteSuccess'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const renameBatch = useMutation({
    mutationFn: async ({ batchId, newName }: { batchId: string; newName: string }) => {
      const batch = (batchesQuery.data || []).find(b => b.id === batchId);
      if (batch?.purpose === 'wellness') {
        const { error } = await supabase
          .from('question_generation_batches')
          .update({ name: newName } as any)
          .eq('id', batchId);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('question_sets')
          .update({ name: newName })
          .eq('id', batchId);
        if (error) throw error;
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-batches'] });
      toast.success(t('batches.renameSuccess', 'Batch renamed successfully'));
    },
    onError: (err: Error) => {
      toast.error(err.message);
    },
  });

  const availableBatches = (batchesQuery.data || []).filter(
    b => b.purpose === 'survey' && b.question_count < MAX_BATCH_SIZE
  );

  const availableWellnessBatches = (batchesQuery.data || []).filter(
    b => b.purpose === 'wellness' && b.question_count < MAX_BATCH_SIZE && b.status === 'draft'
  );

  return {
    batches: batchesQuery.data || [],
    isPending: batchesQuery.isPending,
    availableBatches,
    availableWellnessBatches,
    fetchBatchQuestions,
    expandedBatchQuestions,
    publishBatch,
    deactivateBatch,
    deactivateQuestions,
    activateBatch,
    activateQuestions,
    deleteBatch,
    renameBatch,
    MAX_BATCH_SIZE,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface QuestionSchedule {
  id: string;
  tenant_id: string;
  name: string;
  description: string | null;
  frequency: '1_per_day' | '2_per_day' | '3_days_per_week' | 'weekly' | 'custom';
  custom_schedule: Record<string, unknown> | null;
  target_audience: { all?: boolean; departments?: string[]; specific_employees?: string[] };
  active_categories: string[];
  timezone: string;
  preferred_time: string;
  avoid_weekends: boolean;
  avoid_holidays: boolean;
  questions_per_delivery: number;
  enable_ai_generation: boolean;
  enable_validation: boolean;
  status: 'active' | 'paused' | 'draft';
  created_by: string | null;
  created_at: string;
  updated_at: string;
  deleted_at: string | null;
  batch_ids: string[];
  weekend_days: number[];
  schedule_type: 'daily_checkin' | 'survey';
  start_date: string | null;
  end_date: string | null;
  generation_period_id: string | null;
}

export interface CreateScheduleInput {
  tenant_id: string;
  name: string;
  description?: string;
  frequency?: QuestionSchedule['frequency'];
  custom_schedule?: Record<string, unknown>;
  target_audience?: QuestionSchedule['target_audience'];
  active_categories?: string[];
  timezone?: string;
  preferred_time?: string;
  avoid_weekends?: boolean;
  avoid_holidays?: boolean;
  questions_per_delivery?: number;
  enable_ai_generation?: boolean;
  enable_validation?: boolean;
  status?: QuestionSchedule['status'];
  batch_ids?: string[];
  weekend_days?: number[];
  schedule_type?: 'daily_checkin' | 'survey';
  start_date?: string | null;
  end_date?: string | null;
  generation_period_id?: string | null;
}

export function useQuestionSchedules(tenantId?: string) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const { data: schedules = [], isPending, error } = useQuery({
    queryKey: ['question-schedules', tenantId],
    queryFn: async () => {
      let query = supabase
        .from('question_schedules')
        .select('*')
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (tenantId) {
        query = query.eq('tenant_id', tenantId);
      }

      const { data, error } = await query;
      if (error) throw error;
      
      return data.map(schedule => ({
        ...schedule,
        target_audience: (schedule.target_audience || { all: true }) as QuestionSchedule['target_audience'],
        active_categories: (schedule.active_categories || []) as string[],
        batch_ids: (schedule.batch_ids || []) as string[],
        weekend_days: (schedule.weekend_days || [5, 6]) as number[],
        schedule_type: (schedule.schedule_type || 'daily_checkin') as QuestionSchedule['schedule_type'],
        start_date: schedule.start_date || null,
        end_date: schedule.end_date || null,
        generation_period_id: (schedule as any).generation_period_id || null,
      })) as QuestionSchedule[];
    },
  });

  const createSchedule = useMutation({
    mutationFn: async (input: CreateScheduleInput) => {
      const insertData = {
        tenant_id: input.tenant_id,
        name: input.name,
        description: input.description,
        frequency: input.frequency,
        custom_schedule: input.custom_schedule as unknown as null,
        target_audience: (input.target_audience || { all: true }) as unknown as null,
        active_categories: (input.active_categories || []) as unknown as null,
        timezone: input.timezone,
        preferred_time: input.preferred_time,
        avoid_weekends: input.avoid_weekends,
        avoid_holidays: input.avoid_holidays,
        questions_per_delivery: input.questions_per_delivery,
        enable_ai_generation: input.enable_ai_generation,
        enable_validation: input.enable_validation,
        status: input.status,
        batch_ids: (input.batch_ids || []) as unknown as null,
        weekend_days: (input.weekend_days || [5, 6]) as unknown as null,
        schedule_type: input.schedule_type || 'daily_checkin',
        start_date: input.start_date || null,
        end_date: input.end_date || null,
        generation_period_id: input.generation_period_id || null,
      };

      const { data, error } = await supabase
        .from('question_schedules')
        .insert(insertData)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-schedules'] });
      toast.success(t('schedules.createSuccess'));
    },
    onError: () => {
      toast.error(t('schedules.createError'));
    },
  });

  const updateSchedule = useMutation({
    mutationFn: async ({ id, ...updates }: Partial<QuestionSchedule> & { id: string }) => {
      const updateData: Record<string, unknown> = {};
      if (updates.name !== undefined) updateData.name = updates.name;
      if (updates.description !== undefined) updateData.description = updates.description;
      if (updates.frequency !== undefined) updateData.frequency = updates.frequency;
      if (updates.custom_schedule !== undefined) updateData.custom_schedule = updates.custom_schedule;
      if (updates.target_audience !== undefined) updateData.target_audience = updates.target_audience;
      if (updates.active_categories !== undefined) updateData.active_categories = updates.active_categories;
      if (updates.timezone !== undefined) updateData.timezone = updates.timezone;
      if (updates.preferred_time !== undefined) updateData.preferred_time = updates.preferred_time;
      if (updates.avoid_weekends !== undefined) updateData.avoid_weekends = updates.avoid_weekends;
      if (updates.avoid_holidays !== undefined) updateData.avoid_holidays = updates.avoid_holidays;
      if (updates.questions_per_delivery !== undefined) updateData.questions_per_delivery = updates.questions_per_delivery;
      if (updates.enable_ai_generation !== undefined) updateData.enable_ai_generation = updates.enable_ai_generation;
      if (updates.enable_validation !== undefined) updateData.enable_validation = updates.enable_validation;
      if (updates.status !== undefined) updateData.status = updates.status;
      if (updates.batch_ids !== undefined) updateData.batch_ids = updates.batch_ids;
      if (updates.weekend_days !== undefined) updateData.weekend_days = updates.weekend_days;
      if (updates.schedule_type !== undefined) updateData.schedule_type = updates.schedule_type;
      if (updates.start_date !== undefined) updateData.start_date = updates.start_date;
      if (updates.end_date !== undefined) updateData.end_date = updates.end_date;
      if (updates.generation_period_id !== undefined) updateData.generation_period_id = updates.generation_period_id;
      
      const { data, error } = await supabase
        .from('question_schedules')
        .update(updateData)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-schedules'] });
      toast.success(t('schedules.updateSuccess'));
    },
    onError: () => {
      toast.error(t('schedules.updateError'));
    },
  });

  const deleteSchedule = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('question_schedules')
        .update({ deleted_at: new Date().toISOString() })
        .eq('id', id);

      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-schedules'] });
      toast.success(t('schedules.deleteSuccess'));
    },
    onError: () => {
      toast.error(t('schedules.deleteError'));
    },
  });

  const toggleStatus = useMutation({
    mutationFn: async ({ id, status }: { id: string; status: 'active' | 'paused' }) => {
      const { data, error } = await supabase
        .from('question_schedules')
        .update({ status })
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['question-schedules'] });
      toast.success(t('schedules.updateSuccess'));
    },
    onError: () => {
      toast.error(t('schedules.updateError'));
    },
  });

  return {
    schedules,
    isPending,
    error,
    createSchedule,
    updateSchedule,
    deleteSchedule,
    toggleStatus,
  };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

export interface ScheduledQuestion {
  id: string;
  schedule_id: string;
  employee_id: string;
  question_id: string;
  tenant_id: string;
  scheduled_delivery: string;
  actual_delivery: string | null;
  status: 'pending' | 'delivered' | 'answered' | 'skipped' | 'expired' | 'failed';
  delivery_channel: 'email' | 'app' | 'sms';
  question_source: string;
  reminder_count: number;
  created_at: string;
  question?: {
    id: string;
    text: string;
    text_ar: string | null;
    type: string;
    options: unknown[] | null;
    validation_status?: string | null;
    category?: {
      id: string;
      name: string;
      name_ar: string | null;
      color: string;
    };
  };
}

export interface SurveyScheduleMeta {
  schedule_id: string;
  schedule_name: string;
  start_date: string | null;
  end_date: string | null;
}

export function useScheduledQuestions(employeeId?: string, status?: string) {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const { data: scheduledQuestions = [], isPending, error, refetch } = useQuery({
    queryKey: ['scheduled-questions', employeeId, status],
    queryFn: async () => {
      // 1. Get only survey-type schedule IDs to keep this hook scoped to the survey page
      const { data: surveySchedules } = await supabase
        .from('question_schedules')
        .select('id')
        .eq('schedule_type', 'survey')
        .is('deleted_at', null);

      const surveyScheduleIds = (surveySchedules || []).map(s => s.id);
      if (!surveyScheduleIds.length) return [];

      let query = supabase
        .from('scheduled_questions')
        .select('*')
        .in('schedule_id', surveyScheduleIds)
        .order('scheduled_delivery', { ascending: true })
        .order('question_id', { ascending: true });

      if (employeeId) {
        query = query.eq('employee_id', employeeId);
      }

      if (status) {
        query = query.eq('status', status);
      } else {
        // Default: fetch pending, delivered (not yet answered)
        query = query.in('status', ['pending', 'delivered']);
      }

      const { data, error } = await query;
      if (error) throw error;

      const rows = data || [];

      // Fetch question details based on question_source
      const questionsIds = rows.filter(r => r.question_source === 'questions').map(r => r.question_id);
      const wellnessIds = rows.filter(r => r.question_source === 'wellness_questions').map(r => r.question_id);
      const generatedIds = rows.filter(r => r.question_source === 'generated_questions').map(r => r.question_id);

      let questionsMap: Record<string, any> = {};

      if (questionsIds.length > 0) {
        const { data: qData } = await supabase
          .from('questions')
          .select('id, text, text_ar, type, options, category:question_categories(id, name, name_ar, color)')
          .in('id', questionsIds);
        (qData || []).forEach((q: any) => {
          questionsMap[q.id] = {
            id: q.id,
            text: q.text,
            text_ar: q.text_ar,
            type: q.type,
            options: q.options,
            category: Array.isArray(q.category) ? q.category[0] : q.category,
          };
        });
      }

      if (wellnessIds.length > 0) {
        const { data: wData } = await supabase
          .from('wellness_questions')
          .select('id, question_text_en, question_text_ar, question_type, options')
          .in('id', wellnessIds);
        (wData || []).forEach((q: any) => {
          questionsMap[q.id] = {
            id: q.id,
            text: q.question_text_en,
            text_ar: q.question_text_ar,
            type: q.question_type,
            options: q.options,
            category: null,
          };
        });
      }

      if (generatedIds.length > 0) {
        const { data: gData } = await supabase
          .from('generated_questions')
          .select('id, question_text, question_text_ar, type, options, validation_status')
          .in('id', generatedIds);
        (gData || []).forEach((q: any) => {
          questionsMap[q.id] = {
            id: q.id,
            text: q.question_text,
            text_ar: q.question_text_ar,
            type: q.type,
            options: q.options,
            category: null,
            validation_status: q.validation_status,
          };
        });
      }

      return rows.map((row: any) => ({
        ...row,
        question: questionsMap[row.question_id] || null,
      })) as ScheduledQuestion[];
    },
    enabled: !!employeeId,
  });

  // BUG-13 fix: Fetch ALL survey schedule metadata, not just the first one.
  // Returns the schedule whose time window is currently active (or the earliest upcoming one).
  const { data: surveyMeta } = useQuery({
    queryKey: ['survey-schedule-meta', employeeId],
    queryFn: async () => {
      if (!employeeId) return null;

      const { data: sqData } = await supabase
        .from('scheduled_questions')
        .select('schedule_id')
        .eq('employee_id', employeeId)
        .in('status', ['pending', 'delivered']);

      if (!sqData?.length) return null;

      const scheduleIds = [...new Set(sqData.map(s => s.schedule_id))];

      const { data: schedules } = await supabase
        .from('question_schedules')
        .select('id, name, start_date, end_date, schedule_type')
        .in('id', scheduleIds)
        .eq('schedule_type', 'survey')
        .is('deleted_at', null);

      if (!schedules?.length) return null;

      // Pick the most relevant schedule: prefer currently-open, then earliest upcoming
      const now = new Date();
      const mapped = schedules.map(s => ({
        schedule_id: s.id,
        schedule_name: s.name,
        start_date: s.start_date,
        end_date: s.end_date,
      } as SurveyScheduleMeta));

      // Currently open window
      const active = mapped.find(m => {
        const started = !m.start_date || new Date(m.start_date) <= now;
        const notEnded = !m.end_date || new Date(m.end_date) >= now;
        return started && notEnded;
      });
      if (active) return active;

      // Earliest upcoming
      const upcoming = mapped
        .filter(m => m.start_date && new Date(m.start_date) > now)
        .sort((a, b) => new Date(a.start_date!).getTime() - new Date(b.start_date!).getTime());
      if (upcoming.length) return upcoming[0];

      // Fallback: most recently ended
      return mapped.sort((a, b) => {
        const aEnd = a.end_date ? new Date(a.end_date).getTime() : 0;
        const bEnd = b.end_date ? new Date(b.end_date).getTime() : 0;
        return bEnd - aEnd;
      })[0];
    },
    enabled: !!employeeId,
  });

  const pendingQuestions = scheduledQuestions.filter(
    sq => sq.status === 'delivered' || sq.status === 'pending'
  );

  const skipQuestion = useMutation({
    mutationFn: async (id: string) => {
      const { data, error } = await supabase
        .from('scheduled_questions')
        .update({ status: 'skipped' })
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['scheduled-questions'] });
      toast.success(t('survey.questionSkipped'));
    },
    onError: () => {
      toast.error(t('survey.skipError'));
    },
  });

  return {
    scheduledQuestions,
    pendingQuestions,
    surveyMeta,
    isPending,
    error,
    refetch,
    skipQuestion,
  };
}

export function useAnsweredSurveyCheck(employeeId?: string) {
  const { data: hasAnswered = false, isPending } = useQuery({
    queryKey: ['answered-survey-check', employeeId],
    queryFn: async () => {
      if (!employeeId) return false;

      // BUG-14 fix: Scope to survey-type schedules and exclude soft-deleted rows
      const { data: surveySchedules } = await supabase
        .from('question_schedules')
        .select('id')
        .eq('schedule_type', 'survey')
        .is('deleted_at', null);

      const surveyScheduleIds = (surveySchedules ?? []).map(s => s.id);
      if (!surveyScheduleIds.length) return false;

      // Get scheduled_question IDs for this employee's survey schedules
      const { data: sqData } = await supabase
        .from('scheduled_questions')
        .select('id')
        .in('schedule_id', surveyScheduleIds)
        .eq('employee_id', employeeId);

      const sqIds = (sqData ?? []).map(sq => sq.id);
      if (!sqIds.length) return false;

      const { count } = await supabase
        .from('employee_responses')
        .select('id', { count: 'exact', head: true })
        .in('scheduled_question_id', sqIds)
        .eq('employee_id', employeeId)
        .eq('is_draft', false)
        .is('deleted_at', null);

      return (count ?? 0) > 0;
    },
    enabled: !!employeeId,
  });

  return { hasAnswered, isPending };
}

import { useState, useEffect, useCallback } from 'react';
import { logger } from '@/shared/utils/logger';

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed'; platform: string }>;
}

export function usePWAInstall() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [isIOS, setIsIOS] = useState(false);
  const [isAndroid, setIsAndroid] = useState(false);

  useEffect(() => {
    // Check if already installed (standalone mode)
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches
      || (window.navigator as any).standalone === true;
    setIsInstalled(isStandalone);

    // Detect platform
    const userAgent = window.navigator.userAgent.toLowerCase();
    setIsIOS(/iphone|ipad|ipod/.test(userAgent));
    setIsAndroid(/android/.test(userAgent));

    // Listen for the install prompt
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
    };

    // Listen for successful installation
    const handleAppInstalled = () => {
      setIsInstalled(true);
      setDeferredPrompt(null);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    window.addEventListener('appinstalled', handleAppInstalled);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
      window.removeEventListener('appinstalled', handleAppInstalled);
    };
  }, []);

  const installApp = useCallback(async () => {
    if (!deferredPrompt) return false;

    try {
      await deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      
      if (outcome === 'accepted') {
        setDeferredPrompt(null);
        return true;
      }
      return false;
    } catch (error) {
      logger.error('usePWAInstall', 'Install failed', error);
      return false;
    }
  }, [deferredPrompt]);

  return {
    canInstall: !!deferredPrompt,
    isInstalled,
    isIOS,
    isAndroid,
    installApp,
  };
}

import { useState, useCallback, useRef, useEffect } from 'react';

interface SpeechRecognitionEvent {
  results: SpeechRecognitionResultList;
  resultIndex: number;
}

interface UseSpeechToTextOptions {
  lang?: string;
  onResult?: (transcript: string) => void;
}

export function useSpeechToText({ lang = 'en-US', onResult }: UseSpeechToTextOptions = {}) {
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);
  const onResultRef = useRef(onResult);

  useEffect(() => {
    onResultRef.current = onResult;
  }, [onResult]);

  const isSupported =
    typeof window !== 'undefined' &&
    ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window);

  const startListening = useCallback(() => {
    if (!isSupported) return;

    const SpeechRecognition =
      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    const recognition = new SpeechRecognition();
    recognition.lang = lang;
    recognition.interimResults = false;
    recognition.continuous = false;
    recognition.maxAlternatives = 1;

    recognition.onresult = (event: SpeechRecognitionEvent) => {
      const transcript = event.results[event.results.length - 1]?.[0]?.transcript || '';
      if (transcript && onResultRef.current) {
        onResultRef.current(transcript);
      }
    };

    recognition.onerror = () => {
      setIsListening(false);
      recognitionRef.current = null;
    };

    recognition.onend = () => {
      setIsListening(false);
      recognitionRef.current = null;
    };

    recognitionRef.current = recognition;
    recognition.start();
    setIsListening(true);
  }, [isSupported, lang]);

  const stopListening = useCallback(() => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
    setIsListening(false);
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  return { isListening, startListening, stopListening, isSupported };
}

import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Progress } from '@/shared/components/ui/progress';
import { Skeleton } from '@/shared/components/ui/skeleton';
