      .select("id")
      .eq("schedule_type", "survey")
      .eq("status", "active")
      .is("deleted_at", null);

    if (schedError) {
      console.error("Error fetching survey schedules:", schedError);
      throw schedError;
    }

    const surveyScheduleIds = (surveySchedules ?? []).map(s => s.id);

    if (!surveyScheduleIds.length) {
