import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version",
};

// ─── Theme pools per mood level ───────────────────────────────────────────────
const THEME_POOLS: Record<string, string[]> = {
  great: [
    "positive_drivers",
    "recognition",
    "team_connection",
    "energy_source",
    "purpose_alignment",
    "momentum_building",
  ],
  good: [
    "engagement",
    "collaboration",
    "satisfaction",
    "progress",
    "growth",
    "energy_level",
  ],
  okay: [
    "minor_friction",
    "workload_balance",
    "focus_clarity",
    "emotional_energy",
    "support_access",
  ],
  struggling: [
    "stressors",
    "burnout_signals",
    "work_life_spillover",
    "communication_gaps",
    "support_needs",
    "work_pressure",
  ],
  need_help: [
    "immediate_stress_source",
    "support_preference",
    "human_connection",
    "safety_support",
  ],
};

// ─── SHA-256 hash utility ─────────────────────────────────────────────────────
async function sha256(text: string): Promise<string> {
  const msgBuffer = new TextEncoder().encode(text);
  const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map((b) => b.toString(16).padStart(2, "0")).join("");
}

// ─── Safety check for need_help ───────────────────────────────────────────────
function ensureSafetyOptions(questions: any[], moodLevel: string): any[] {
  if (moodLevel !== "need_help") return questions;

  return questions.map((q, idx) => {
    if (idx !== 0) return q; // only enforce on first question

    const safetyOptionEn = "I'd like to talk to HR or my manager";
    const safetyOptionAr = "أود التحدث مع الموارد البشرية أو مديري";
    const professionalOptionEn = "I'd prefer professional support";
    const professionalOptionAr = "أفضل الحصول على دعم متخصص";

    const hasHR = q.options_en?.some((o: string) =>
      o.toLowerCase().includes("hr") ||
      o.toLowerCase().includes("manager")
    );
    const hasProfessional = q.options_en?.some((o: string) =>
      o.toLowerCase().includes("professional")
    );

    let options_en = [...(q.options_en || [])];
    let options_ar = [...(q.options_ar || [])];

    if (!hasHR) {
      options_en = [safetyOptionEn, ...options_en.slice(0, 2)];
      options_ar = [safetyOptionAr, ...options_ar.slice(0, 2)];
    }
    if (!hasProfessional) {
      if (!options_en.includes(professionalOptionEn)) {
        options_en = [...options_en.slice(0, 3), professionalOptionEn];
        options_ar = [...options_ar.slice(0, 3), professionalOptionAr];
      }
    }

    return { ...q, options_en, options_ar };
  });
}

// ─── AI generation ────────────────────────────────────────────────────────────
async function generateQuestionsFromAI(
  moodLevel: string,
  moodScore: number,
  language: string,
  selectedTheme: string,
  usedThemes: string[],
  customContext: string,
  randomSeed: string,
  LOVABLE_API_KEY: string
): Promise<any[]> {
  const lang = language === "ar" ? "Arabic" : "English";
  const themesContext =
    usedThemes.length > 0
      ? `Previously used themes to AVOID semantic similarity: ${usedThemes.join(", ")}.`
      : "No previously used themes.";

  const systemPrompt = `You are a licensed workplace clinical psychologist specializing in organizational wellbeing and employee mental health.
Your role is to generate empathetic, non-intrusive follow-up questions for an employee check-in system.

STRICT CLINICAL RULES:
- NO diagnostic labels (never use: depressed, anxious, clinical, disorder)
- ALL options must be normalizing — low-mood options must feel non-stigmatizing
- Questions must be answerable within 30 seconds
- NO assumptions about gender, family structure, religious beliefs
- Use warm, supportive language
- Keep options concise (max 8 words each)
- Randomization seed: ${randomSeed} — use this to vary phrasing from previous generations

RESPONSE FORMAT (return valid JSON array ONLY, no markdown, no explanation):
[
  {
    "question_text_en": "...",
    "question_text_ar": "...",
    "options_en": ["option1", "option2", "option3"],
    "options_ar": ["خيار1", "خيار2", "خيار3"],
    "question_type": "multiple_choice",
    "theme": "${selectedTheme}"
  }
]`;

  const userPrompt = `Employee mood level: ${moodLevel} (score: ${moodScore}/5)
Focus theme: ${selectedTheme}
${themesContext}
${customContext ? `Custom organizational context: ${customContext}` : ""}

Generate exactly 1 follow-up question (2 if the mood is extreme like "great" or "need_help").
The question must explore the "${selectedTheme}" theme in the context of the "${moodLevel}" mood.

${
  moodLevel === "need_help"
    ? `SAFETY REQUIREMENT: Include these options:
- "I'd like to talk to HR or my manager" / "أود التحدث مع الموارد البشرية أو مديري"
- "I'd prefer professional support" / "أفضل الحصول على دعم متخصص"
Only rotate the theme for the SECOND question if generating 2. Never omit safety options.`
    : ""
}

Return ONLY the JSON array, no markdown code blocks.`;

  const response = await fetch(
    "https://ai.gateway.lovable.dev/v1/chat/completions",
    {
      method: "POST",
      headers: {
        Authorization: `Bearer ${LOVABLE_API_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: "google/gemini-3-flash-preview",
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt },
        ],
        temperature: 0.85,
      }),
    }
  );

  if (!response.ok) {
    const status = response.status;
    if (status === 429) throw new Error("RATE_LIMIT");
    if (status === 402) throw new Error("CREDITS_EXHAUSTED");
    throw new Error(`AI_ERROR:${status}`);
  }

  const data = await response.json();
  const content = data.choices?.[0]?.message?.content || "[]";

  // Parse JSON — strip markdown if present
  const cleaned = content
    .replace(/```json\n?/g, "")
    .replace(/```\n?/g, "")
    .trim();

  const parsed = JSON.parse(cleaned);
  return Array.isArray(parsed) ? parsed : [parsed];
}

// ─── Main handler ─────────────────────────────────────────────────────────────
serve(async (req) => {
  if (req.method === "OPTIONS")
    return new Response(null, { headers: corsHeaders });

  try {
    const LOVABLE_API_KEY = Deno.env.get("LOVABLE_API_KEY");
    if (!LOVABLE_API_KEY)
      throw new Error("LOVABLE_API_KEY is not configured");

    const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

    const serviceClient = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

    const { moodLevel, moodScore, language, tenantId, userId } =
      await req.json();

    if (!moodLevel || !tenantId || !userId) {
      return new Response(
        JSON.stringify({ error: "Missing required fields: moodLevel, tenantId, userId" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // ── Step 1: Fetch 14-day question history for this user + mood ────────────
    const { data: historyRows } = await serviceClient
      .from("mood_question_history")
      .select("question_hash, theme, created_at")
      .eq("user_id", userId)
      .eq("mood_level", moodLevel)
      .gte(
        "created_at",
        new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString()
      )
      .order("created_at", { ascending: false });

    const usedHashes = new Set<string>(
      (historyRows || []).map((r: any) => r.question_hash)
    );
    const usedThemes = new Set<string>(
      (historyRows || []).map((r: any) => r.theme)
    );

    // ── Step 2: Select unused theme ───────────────────────────────────────────
    const themePool = THEME_POOLS[moodLevel] || THEME_POOLS["okay"];
    let selectedTheme =
      themePool.find((t) => !usedThemes.has(t)) || themePool[0];

    // For need_help: safety_support is always the first theme
    if (moodLevel === "need_help" && !usedThemes.has("safety_support")) {
      selectedTheme = "safety_support";
    }

    // ── Step 3: Fetch tenant config ───────────────────────────────────────────
    const { data: configRow } = await serviceClient
      .from("mood_question_configs")
      .select("*")
      .eq("tenant_id", tenantId)
      .eq("mood_level", moodLevel)
      .maybeSingle();

    const config = configRow || {
      is_enabled: true,
      enable_free_text: moodLevel === "need_help" || moodLevel === "great",
      custom_prompt_context: "",
    };

    if (!config.is_enabled) {
      return new Response(
        JSON.stringify({ questions: [], disabled: true }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // ── Steps 4-5: Generate with retry + duplicate check ─────────────────────
    let finalQuestions: any[] = [];
    let attempts = 0;
    const maxAttempts = 3;

    while (attempts < maxAttempts) {
      attempts++;
      const randomSeed = crypto.randomUUID();

      try {
        let generated = await generateQuestionsFromAI(
          moodLevel,
          moodScore,
          language,
          selectedTheme,
          Array.from(usedThemes),
          config.custom_prompt_context || "",
          randomSeed,
          LOVABLE_API_KEY
        );

        // Hash check
        const hashes: string[] = [];
        let hasDuplicate = false;

        for (const q of generated) {
          const hash = await sha256(q.question_text_en || "");
          if (usedHashes.has(hash)) {
            hasDuplicate = true;
            break;
          }
          hashes.push(hash);
        }

        if (hasDuplicate && attempts < maxAttempts) {
          // Try next unused theme on second retry
          if (attempts === 2) {
            const nextTheme = themePool.find(
              (t) => t !== selectedTheme && !usedThemes.has(t)
            );
            if (nextTheme) selectedTheme = nextTheme;
          }
          continue;
        }

        // ── Step 6: Safety override for need_help ─────────────────────────
        generated = ensureSafetyOptions(generated, moodLevel);

        // Attach hashes and free_text flag
        finalQuestions = generated.map((q, i) => ({
          ...q,
          _hash: hashes[i] || "",
          enable_free_text:
            config.enable_free_text &&
            (moodLevel === "need_help" || moodLevel === "great"),
        }));

        break;
      } catch (err: any) {
        if (attempts >= maxAttempts) throw err;
      }
    }

    // ── Step 7: Store question history ────────────────────────────────────────
    if (finalQuestions.length > 0) {
      const historyInserts = finalQuestions.map((q) => ({
        tenant_id: tenantId,
        user_id: userId,
        mood_level: moodLevel,
        question_hash: q._hash,
        theme: q.theme || selectedTheme,
      }));

      await serviceClient.from("mood_question_history").insert(historyInserts);
    }

    // ── Step 8: Return clean response ─────────────────────────────────────────
    const questions = finalQuestions.map(({ _hash, ...q }) => q);

    return new Response(JSON.stringify({ questions }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (e: any) {
    console.error("generate-mood-questions error:", e);

    if (e.message === "RATE_LIMIT") {
      return new Response(
        JSON.stringify({ error: "Rate limit exceeded, please try again later." }),
        { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }
    if (e.message === "CREDITS_EXHAUSTED") {
      return new Response(
        JSON.stringify({ error: "AI credits exhausted." }),
        { status: 402, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(
      JSON.stringify({
        error: e instanceof Error ? e.message : "Unknown error",
      }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

/**
 * Cost-Aware Provider Router — PR-AI-INT-02
 *
 * Multi-objective scoring: Quality, Latency, Stability, Cost, Confidence.
 * Supports routing modes (performance/balanced/cost_saver), budget enforcement,
 * SLA penalties, confidence decay, and diversity guard.
 *
 * Backward-compatible: falls back to hybridRouter on any failure.
 * No PII or prompt content is logged.
 */

import {
  clamp01,
  computeAlphaBeta,
  computeEpsilon,
  computeEwmaUpdate,
  seededRandom,
  EWMA_LAMBDA,
  type HybridProvider,
  type ProviderCandidate,
  type MetricsRow,
} from "./hybridRouter.ts";

// ── Types ───────────────────────────────────────────────────────

export type RoutingMode = 'performance' | 'balanced' | 'cost_saver';
export type BudgetState = 'under_limit' | 'soft_limit' | 'hard_limit' | 'no_config';

export interface CostAwareWeights {
  w_quality: number;
  w_latency: number;
  w_stability: number;
  w_cost: number;
  w_confidence: number;
}

export interface BudgetConfig {
  monthly_budget: number;
  soft_limit_percentage: number;
  routing_mode: RoutingMode;
  current_month_usage: number;
}

export interface PenaltyRow {
  provider: string;
  feature: string;
  penalty_multiplier: number;
  penalty_expires_at: string;
}

export interface UsageRow {
  provider: string;
  usage_percentage: number;
}

export interface ExtendedMetricsRow extends MetricsRow {
  cost_ewma: number;
  last_call_at: string | null;
}

export interface CostAwareScoreBreakdown {
  provider: string;
  model: string;
  finalScore: number;
  qualityScore: number;
  latencyScore: number;
  stabilityScore: number;
  costScore: number;
  confidenceScore: number;
  penaltyMultiplier: number;
  decayFactor: number;
}

export interface CostAwareRoutingResult {
  ranked: ProviderCandidate[];
  selected: ProviderCandidate;
  mode: 'explore' | 'exploit';
  routingMode: RoutingMode;
  budgetState: BudgetState;
  epsilon: number;
  alpha: number;
  beta: number;
  tenantFpSamples: number;
  costWeight: number;
  penaltyApplied: boolean;
  decayApplied: boolean;
  diversityTriggered: boolean;
  scoreBreakdown: CostAwareScoreBreakdown[];
}

export interface CostAwareRankParams {
  tenantId: string | null;
  feature: string;
  purpose: string;
  candidates: ProviderCandidate[];
  /** Override for testing */
  _randomFn?: () => number;
  /** Override for testing - current time */
  _nowMs?: number;
}

// ── Constants ───────────────────────────────────────────────────

const MODE_WEIGHTS: Record<RoutingMode, CostAwareWeights> = {
  performance: { w_quality: 0.45, w_latency: 0.20, w_stability: 0.20, w_cost: 0.05, w_confidence: 0.10 },
  balanced:    { w_quality: 0.20, w_latency: 0.20, w_stability: 0.20, w_cost: 0.20, w_confidence: 0.20 },
  cost_saver:  { w_quality: 0.25, w_latency: 0.15, w_stability: 0.10, w_cost: 0.40, w_confidence: 0.10 },
};

const SOFT_LIMIT_COST_BOOST = 1.5;
const DIVERSITY_USAGE_THRESHOLD = 95;
const DIVERSITY_MIN_EPSILON = 0.15;
const DEFAULT_DECAY_FACTOR = 0.5;
const CONFIDENCE_SAMPLE_CAP = 100;
const DECAY_HALF_LIFE_DAYS = 30;
const DEFAULT_PENALTY_MULTIPLIER = 0.7;
const DEFAULT_PENALTY_TTL_MINUTES = 10;

// ── Weight Helpers ──────────────────────────────────────────────

export function getWeightsForMode(mode: RoutingMode): CostAwareWeights {
  return { ...(MODE_WEIGHTS[mode] || MODE_WEIGHTS.balanced) };
}

export function applyBudgetAdjustment(
  weights: CostAwareWeights,
  budgetConfig: BudgetConfig | null,
): { weights: CostAwareWeights; budgetState: BudgetState; effectiveMode: RoutingMode } {
  if (!budgetConfig) {
    return { weights, budgetState: 'no_config', effectiveMode: 'balanced' };
  }

  const usageRatio = budgetConfig.monthly_budget > 0
    ? budgetConfig.current_month_usage / budgetConfig.monthly_budget
    : 0;

  // Hard limit: force cost_saver
  if (budgetConfig.current_month_usage >= budgetConfig.monthly_budget && budgetConfig.monthly_budget > 0) {
    const costSaverWeights = getWeightsForMode('cost_saver');
    return { weights: costSaverWeights, budgetState: 'hard_limit', effectiveMode: 'cost_saver' };
  }

  // Soft limit: boost cost weight by 1.5x and renormalize
  if (usageRatio > budgetConfig.soft_limit_percentage) {
    const boosted = { ...weights };
    boosted.w_cost *= SOFT_LIMIT_COST_BOOST;
    const sum = boosted.w_quality + boosted.w_latency + boosted.w_stability + boosted.w_cost + boosted.w_confidence;
    if (sum > 0) {
      boosted.w_quality /= sum;
      boosted.w_latency /= sum;
      boosted.w_stability /= sum;
      boosted.w_cost /= sum;
      boosted.w_confidence /= sum;
    }
    return { weights: boosted, budgetState: 'soft_limit', effectiveMode: budgetConfig.routing_mode };
  }

  return { weights, budgetState: 'under_limit', effectiveMode: budgetConfig.routing_mode };
}

export function normalizeWeights(w: CostAwareWeights): CostAwareWeights {
  const sum = w.w_quality + w.w_latency + w.w_stability + w.w_cost + w.w_confidence;
  if (sum <= 0) return { ...MODE_WEIGHTS.balanced };
  return {
    w_quality: w.w_quality / sum,
    w_latency: w.w_latency / sum,
    w_stability: w.w_stability / sum,
    w_cost: w.w_cost / sum,
    w_confidence: w.w_confidence / sum,
  };
}

// ── Score Computations ──────────────────────────────────────────

export function computeConfidenceScore(
  sampleCount: number,
  lastCallAt: string | null,
  nowMs: number,
): number {
  const sampleFactor = Math.min(sampleCount / CONFIDENCE_SAMPLE_CAP, 1);
  if (!lastCallAt) return sampleFactor * DEFAULT_DECAY_FACTOR;

  const lastCallMs = new Date(lastCallAt).getTime();
  const daysSince = (nowMs - lastCallMs) / (1000 * 60 * 60 * 24);
  const recencyFactor = Math.exp(-daysSince / DECAY_HALF_LIFE_DAYS);
  return sampleFactor * recencyFactor;
}

export function computeDecayFactor(lastCallAt: string | null, nowMs: number): number {
  if (!lastCallAt) return DEFAULT_DECAY_FACTOR;
  const lastCallMs = new Date(lastCallAt).getTime();
  const daysSince = (nowMs - lastCallMs) / (1000 * 60 * 60 * 24);
  return Math.exp(-daysSince / DECAY_HALF_LIFE_DAYS);
}

export function computeRelativeScores(
  candidates: { latency: number; cost: number }[],
): { latencyScores: number[]; costScores: number[] } {
  if (candidates.length === 0) return { latencyScores: [], costScores: [] };

  const maxLatency = Math.max(...candidates.map(c => c.latency), 1);
  const maxCost = Math.max(...candidates.map(c => c.cost), 0.0001);

  const latencyScores = candidates.map(c => clamp01(1 - c.latency / maxLatency));
  const costScores = candidates.map(c => clamp01(1 - c.cost / maxCost));

  return { latencyScores, costScores };
}

export function computeMultiObjectiveScore(
  weights: CostAwareWeights,
  qualityScore: number,
  latencyScore: number,
  stabilityScore: number,
  costScore: number,
  confidenceScore: number,
): number {
  return (
    weights.w_quality * qualityScore +
    weights.w_latency * latencyScore +
    weights.w_stability * stabilityScore +
    weights.w_cost * costScore +
    weights.w_confidence * confidenceScore
  );
}

// ── Main Ranking Function ───────────────────────────────────────

export async function rankProvidersCostAware(
  supabase: any,
  params: CostAwareRankParams,
): Promise<CostAwareRoutingResult> {
  const { tenantId, feature, purpose, candidates, _randomFn, _nowMs } = params;
  const nowMs = _nowMs ?? Date.now();

  // ── Fetch all data in parallel ──
  const globalQuery = supabase
    .from('ai_provider_metrics_agg')
    .select('scope, provider, model, ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count, cost_ewma, last_call_at')
    .eq('scope', 'global')
    .eq('feature', feature)
    .eq('purpose', purpose);

  const tenantQuery = tenantId
    ? supabase
        .from('ai_provider_metrics_agg')
        .select('scope, provider, model, ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count, cost_ewma, last_call_at')
        .eq('scope', 'tenant')
        .eq('tenant_id', tenantId)
        .eq('feature', feature)
        .eq('purpose', purpose)
    : Promise.resolve({ data: [] });

  const budgetQuery = tenantId
    ? supabase
        .from('tenant_ai_budget_config')
        .select('monthly_budget, soft_limit_percentage, routing_mode, current_month_usage')
        .eq('tenant_id', tenantId)
        .maybeSingle()
    : Promise.resolve({ data: null });

  const penaltyQuery = supabase
    .from('ai_provider_penalties')
    .select('provider, feature, penalty_multiplier, penalty_expires_at')
    .eq('feature', feature)
    .gt('penalty_expires_at', new Date(nowMs).toISOString());

  const usageQuery = supabase
    .from('ai_provider_usage_24h')
    .select('provider, usage_percentage');

  const [globalRes, tenantRes, budgetRes, penaltyRes, usageRes] = await Promise.all([
    globalQuery, tenantQuery, budgetQuery, penaltyQuery, usageQuery,
  ]);

  const globalRows: ExtendedMetricsRow[] = globalRes.data || [];
  const tenantRows: ExtendedMetricsRow[] = tenantRes.data || [];
  const budgetConfig: BudgetConfig | null = budgetRes.data || null;
  const penalties: PenaltyRow[] = penaltyRes.data || [];
  const usageRows: UsageRow[] = usageRes.data || [];

  // Build lookup maps
  const globalMap = new Map<string, ExtendedMetricsRow>();
  for (const r of globalRows) globalMap.set(`${r.provider}::${r.model}`, r);

  const tenantMap = new Map<string, ExtendedMetricsRow>();
  for (const r of tenantRows) tenantMap.set(`${r.provider}::${r.model}`, r);

  const penaltyMap = new Map<string, number>();
  for (const p of penalties) penaltyMap.set(p.provider, p.penalty_multiplier);

  // Compute tenant sample count for alpha/beta
  const tenantFpSamples = tenantRows.reduce((sum, r) => sum + r.sample_count, 0);
  const { alpha, beta } = computeAlphaBeta(tenantFpSamples);
  let epsilon = computeEpsilon(tenantFpSamples);

  // Determine routing mode and budget state
  const effectiveRoutingMode: RoutingMode = (budgetConfig?.routing_mode as RoutingMode) || 'balanced';
  let baseWeights = getWeightsForMode(effectiveRoutingMode);
  const { weights: adjustedWeights, budgetState, effectiveMode } = applyBudgetAdjustment(baseWeights, budgetConfig);

  // Diversity guard
  let diversityTriggered = false;
  for (const u of usageRows) {
    if (u.usage_percentage > DIVERSITY_USAGE_THRESHOLD) {
      epsilon = Math.max(epsilon, DIVERSITY_MIN_EPSILON);
      diversityTriggered = true;
      break;
    }
  }

  // ── Score each candidate ──
  // First pass: collect raw latency/cost for relative normalization
  const rawMetrics = candidates.map(c => {
    const key = `${c.provider}::${c.model}`;
    const gm = globalMap.get(key);
    const tm = tenantMap.get(key);
    const blendedLatency = gm
      ? (tm ? alpha * gm.ewma_latency_ms + beta * tm.ewma_latency_ms : gm.ewma_latency_ms)
      : (tm ? tm.ewma_latency_ms : 500);
    const blendedCost = gm
      ? (tm ? alpha * (gm.cost_ewma || gm.ewma_cost_per_1k) + beta * (tm.cost_ewma || tm.ewma_cost_per_1k) : (gm.cost_ewma || gm.ewma_cost_per_1k))
      : (tm ? (tm.cost_ewma || tm.ewma_cost_per_1k) : 0.005);
    return { latency: blendedLatency, cost: blendedCost };
  });

  const { latencyScores, costScores } = computeRelativeScores(rawMetrics);

  let penaltyApplied = false;
  let decayApplied = false;

  const scored: CostAwareScoreBreakdown[] = candidates.map((c, i) => {
    const key = `${c.provider}::${c.model}`;
    const gm = globalMap.get(key);
    const tm = tenantMap.get(key);

    // Quality: blended EWMA
    const gQuality = gm ? clamp01(gm.ewma_quality / 100) : 0.5;
    const tQuality = tm ? clamp01(tm.ewma_quality / 100) : 0.5;
    const qualityScore = alpha * gQuality + beta * tQuality;

    // Stability: blended success rate
    const gStability = gm ? clamp01(gm.ewma_success_rate) : 0.5;
    const tStability = tm ? clamp01(tm.ewma_success_rate) : 0.5;
    const stabilityScore = alpha * gStability + beta * tStability;

    // Confidence: based on combined sample count + recency
    const totalSamples = (gm?.sample_count || 0) + (tm?.sample_count || 0);
    const lastCall = tm?.last_call_at || gm?.last_call_at || null;
    const confidenceScore = computeConfidenceScore(totalSamples, lastCall, nowMs);

    // Multi-objective score
    const rawScore = computeMultiObjectiveScore(
      adjustedWeights,
      qualityScore,
      latencyScores[i],
      stabilityScore,
      costScores[i],
      confidenceScore,
    );

    // Apply SLA penalty
    const penalty = penaltyMap.get(c.provider) ?? 1.0;
    if (penalty < 1.0) penaltyApplied = true;

    // Apply confidence decay
    const decayFactor = computeDecayFactor(lastCall, nowMs);
    if (decayFactor < 0.99) decayApplied = true;

    const finalScore = rawScore * penalty * decayFactor;

    return {
      provider: c.provider,
      model: c.model,
      finalScore,
      qualityScore,
      latencyScore: latencyScores[i],
      stabilityScore,
      costScore: costScores[i],
      confidenceScore,
      penaltyMultiplier: penalty,
      decayFactor,
    };
  });

  // Sort best-first
  scored.sort((a, b) => b.finalScore - a.finalScore);

  // Exploit vs explore
  const rng = _randomFn ?? Math.random;
  const isExplore = rng() < epsilon;
  let selected: ProviderCandidate;

  if (isExplore && scored.length > 1) {
    const top3 = scored.slice(0, Math.min(3, scored.length));
    const idx = Math.floor(rng() * top3.length);
    selected = { provider: top3[idx].provider as HybridProvider, model: top3[idx].model };
  } else {
    selected = { provider: scored[0].provider as HybridProvider, model: scored[0].model };
  }

  const ranked = scored.map(s => ({ provider: s.provider as HybridProvider, model: s.model }));

  return {
    ranked,
    selected,
    mode: isExplore ? 'explore' : 'exploit',
    routingMode: effectiveMode,
    budgetState,
    epsilon,
    alpha,
    beta,
    tenantFpSamples,
    costWeight: adjustedWeights.w_cost,
    penaltyApplied,
    decayApplied,
    diversityTriggered,
    scoreBreakdown: scored.slice(0, 3),
  };
}

// ── Post-Call Updates ────────────────────────────────────────────

export interface UpdateParamsV2 {
  scope: 'global' | 'tenant';
  tenantId: string | null;
  feature: string;
  purpose: string;
  provider: string;
  model: string;
  latencyMs: number;
  costPer1k: number;
  qualityAvg: number;
  success: boolean;
}

export async function updateProviderMetricsV2(
  supabase: any,
  params: UpdateParamsV2,
): Promise<void> {
  try {
    const { scope, tenantId, feature, purpose, provider, model, latencyMs, costPer1k, qualityAvg, success } = params;

    let query = supabase
      .from('ai_provider_metrics_agg')
      .select('ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count, cost_ewma')
      .eq('scope', scope)
      .eq('feature', feature)
      .eq('purpose', purpose)
      .eq('provider', provider)
      .eq('model', model);

    if (scope === 'tenant' && tenantId) {
      query = query.eq('tenant_id', tenantId);
    } else {
      query = query.is('tenant_id', null);
    }

    const { data: existing } = await query.maybeSingle();

    const updated = computeEwmaUpdate(existing, { latencyMs, costPer1k, qualityAvg, success });

    // Cost EWMA update
    const lambda = EWMA_LAMBDA;
    const newCostEwma = existing?.cost_ewma != null
      ? lambda * costPer1k + (1 - lambda) * existing.cost_ewma
      : costPer1k;

    const nowIso = new Date().toISOString();

    if (existing) {
      let updateQuery = supabase
        .from('ai_provider_metrics_agg')
        .update({
          ...updated,
          cost_ewma: newCostEwma,
          last_call_at: nowIso,
          last_updated: nowIso,
        })
        .eq('scope', scope)
        .eq('feature', feature)
        .eq('purpose', purpose)
        .eq('provider', provider)
        .eq('model', model);

      if (scope === 'tenant' && tenantId) {
        updateQuery = updateQuery.eq('tenant_id', tenantId);
      } else {
        updateQuery = updateQuery.is('tenant_id', null);
      }

      await updateQuery;
    } else {
      await supabase
        .from('ai_provider_metrics_agg')
        .insert({
          scope,
          tenant_id: scope === 'tenant' ? tenantId : null,
          feature,
          purpose,
          provider,
          model,
          ...updated,
          cost_ewma: newCostEwma,
          last_call_at: nowIso,
          last_updated: nowIso,
        });
    }

    // Fire-and-forget: raw event
    supabase
      .from('ai_provider_events')
      .insert({
        tenant_id: tenantId,
        feature,
        purpose,
        provider,
        model,
        latency_ms: latencyMs,
        estimated_cost: costPer1k,
        quality_avg: qualityAvg,
        success,
      })
      .then(() => {})
      .catch(() => {});
  } catch (err) {
    console.warn('updateProviderMetricsV2 failed (fail-open):', err instanceof Error ? err.message : 'unknown');
  }
}

// ── SLA Penalty ─────────────────────────────────────────────────

export async function applySlaPenalty(
  supabase: any,
  provider: string,
  feature: string,
  multiplier: number = DEFAULT_PENALTY_MULTIPLIER,
  ttlMinutes: number = DEFAULT_PENALTY_TTL_MINUTES,
): Promise<void> {
  try {
    const expiresAt = new Date(Date.now() + ttlMinutes * 60 * 1000).toISOString();
    await supabase
      .from('ai_provider_penalties')
      .upsert(
        { provider, feature, penalty_multiplier: multiplier, penalty_expires_at: expiresAt },
        { onConflict: 'provider,feature' },
      );
  } catch (err) {
    console.warn('applySlaPenalty failed (fail-open):', err instanceof Error ? err.message : 'unknown');
  }
}

// ── Usage Update ────────────────────────────────────────────────

export async function updateUsage24h(
  supabase: any,
  provider: string,
  allProviders: string[] = ['openai', 'gemini', 'anthropic'],
): Promise<void> {
  try {
    // Atomic increment via database function (M1 fix - no race condition)
    await supabase.rpc('increment_usage_24h', { p_provider: provider });

    // Recalculate usage percentages
    const { data: allUsage } = await supabase
      .from('ai_provider_usage_24h')
      .select('provider, calls_last_24h');

    if (allUsage && allUsage.length > 0) {
      const totalCalls = allUsage.reduce((s: number, r: any) => s + (r.calls_last_24h || 0), 0);
      if (totalCalls > 0) {
        for (const row of allUsage) {
          const pct = ((row.calls_last_24h || 0) / totalCalls) * 100;
          supabase
            .from('ai_provider_usage_24h')
            .update({ usage_percentage: pct, last_updated: new Date().toISOString() })
            .eq('provider', row.provider)
            .then(() => {})
            .catch(() => {});
        }
      }
    }
  } catch (err) {
    console.warn('updateUsage24h failed (fail-open):', err instanceof Error ? err.message : 'unknown');
  }
}

/**
 * CostGuard v3.0 — Plan-Based + Override Limit Resolution
 *
 * Uses limitResolver to determine tenant limits from:
 *   1. Override (ai_tenant_limits)
 *   2. Plan (ai_plan_limits via ai_tenant_plan)
 *   3. None → unlimited
 *
 * Behavior unchanged:
 * - Hard block at 100% (throws CostLimitExceededError).
 * - Soft warning at configurable threshold (default 80%).
 * - Creates at most one alert per tenant + month + feature + limit_type.
 * - Never blocks below 100%. Never throws on warning/alert path.
 */

import { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";
import { resolveTenantAiLimits, type LimitsSource } from "./limitResolver.ts";

// ── Types ──────────────────────────────────────────────────────────
export interface CostGuardContext {
  tenantId: string;
  feature: string;
  supabase: SupabaseClient;
}

export interface CostCheckResult {
  allowed: boolean;
  tokenPercent: number;
  costPercent: number;
  warningTriggered: boolean;
  warningLimitType: string | null;
  blocked: boolean;
  blockedLimitType: string | null;
  /** The tenant's configured warning threshold (for telemetry) */
  threshold: number;
  /** Where limits were resolved from */
  limits_source: LimitsSource;
  /** The plan key if limits came from a plan */
  plan_key: string | null;
}

// ── Error ──────────────────────────────────────────────────────────
export class CostLimitExceededError extends Error {
  constructor(limitType: string, percent: number) {
    super(`AI cost limit exceeded (${limitType}: ${percent.toFixed(1)}%)`);
    this.name = "CostLimitExceededError";
  }
}

// ── Main check ─────────────────────────────────────────────────────
export async function checkBeforeExecution(ctx: CostGuardContext): Promise<CostCheckResult> {
  const { tenantId, feature, supabase } = ctx;

  const result: CostCheckResult = {
    allowed: true,
    tokenPercent: 0,
    costPercent: 0,
    warningTriggered: false,
    warningLimitType: null,
    blocked: false,
    blockedLimitType: null,
    threshold: 80,
    limits_source: "none",
    plan_key: null,
  };

  // 1. Resolve tenant limits (override → plan → none)
  const resolved = await resolveTenantAiLimits(supabase, tenantId);
  result.limits_source = resolved.source;
  result.plan_key = resolved.plan_key;
  result.threshold = resolved.warning_threshold_percent;

  // No limits configured → allow freely
  if (resolved.source === "none") return result;

  const tokenLimit = resolved.monthly_token_limit;
  const costLimit = resolved.monthly_cost_limit;
  const warningThreshold = resolved.warning_threshold_percent;

  // If both limits are null (unlimited), allow freely
  if (tokenLimit === null && costLimit === null) return result;

  // 2. Calculate current month usage from ai_generation_logs
  const now = new Date();
  const monthStart = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, "0")}-01T00:00:00Z`;
  const monthKey = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, "0")}`;

  const { data: usageRows } = await supabase
    .from("ai_generation_logs")
    .select("tokens_used, duration_ms")
    .eq("tenant_id", tenantId)
    .gte("created_at", monthStart)
    .eq("success", true);

  const totalTokens = (usageRows || []).reduce((sum: number, r: any) => sum + (r.tokens_used || 0), 0);
  const estimatedCost = totalTokens / 1000 * 0.001;

  result.tokenPercent = tokenLimit !== null && tokenLimit > 0 ? (totalTokens / tokenLimit) * 100 : 0;
  result.costPercent = costLimit !== null && costLimit > 0 ? (estimatedCost / costLimit) * 100 : 0;

  // 3. Check hard block (100%)
  if (result.tokenPercent >= 100) {
    result.allowed = false;
    result.blocked = true;
    result.blockedLimitType = "token";
    throw new CostLimitExceededError("token", result.tokenPercent);
  }
  if (result.costPercent >= 100) {
    result.allowed = false;
    result.blocked = true;
    result.blockedLimitType = "cost";
    throw new CostLimitExceededError("cost", result.costPercent);
  }

  // 4. Soft warning at configurable threshold
  if (result.tokenPercent >= warningThreshold) {
    result.warningTriggered = true;
    result.warningLimitType = "token";
    await createUsageAlertOnce(supabase, tenantId, feature, "token", monthKey, warningThreshold, result.tokenPercent);
  }
  if (result.costPercent >= warningThreshold) {
    result.warningTriggered = true;
    result.warningLimitType = result.warningLimitType ? "both" : "cost";
    await createUsageAlertOnce(supabase, tenantId, feature, "cost", monthKey, warningThreshold, result.costPercent);
  }

  return result;
}

// ── Alert creation with 23505 dedup ────────────────────────────────
async function createUsageAlertOnce(
  supabase: SupabaseClient,
  tenantId: string,
  feature: string,
  limitType: string,
  monthKey: string,
  thresholdPercent: number,
  currentPercent: number,
): Promise<void> {
  try {
    const { error } = await supabase.from("ai_usage_alerts").insert({
      tenant_id: tenantId,
      feature,
      limit_type: limitType,
      month_key: monthKey,
      threshold_percent: thresholdPercent,
      current_percent: currentPercent,
    });

    if (error) {
      if (error.code === "23505") return;
      console.warn(`CostGuard: alert insert failed code=${error.code} msg=${error.message}`);
    } else {
      console.log(
        `CostGuard: usage alert created tenant=${tenantId.substring(0, 8)}… type=${limitType} pct=${currentPercent.toFixed(1)} threshold=${thresholdPercent}`,
      );
    }
  } catch (err) {
    console.warn("CostGuard: alert creation threw", err instanceof Error ? err.message : "unknown");
  }
}

/**
 * Predictive Cost & Performance Engine — PR-AI-INT-04
 *
 * Provides:
 * - Rolling 7-day burn rate & monthly cost projection
 * - Exponential smoothing for cost forecasting
 * - SLA trend detection (latency drift, error rate trends)
 * - Auto-adaptive routing weight adjustment hooks
 * - Forecast state persistence
 *
 * Safety: All functions are fail-open. Forecast failures never block routing.
 * No PII or prompt content is logged.
 */

import { clamp01 } from "./hybridRouter.ts";
import type { CostAwareWeights } from "./costAwareRouter.ts";

// ── Types ───────────────────────────────────────────────────────

export type SlaRiskLevel = 'low' | 'medium' | 'high';

export interface DailyCostRow {
  date: string;
  tenant_id: string;
  feature: string;
  provider: string;
  total_cost: number;
  total_calls: number;
  avg_cost_per_call: number;
}

export interface DailyPerformanceRow {
  date: string;
  provider: string;
  feature: string;
  avg_latency: number;
  error_rate: number;
  success_rate: number;
  total_calls: number;
}

export interface ForecastState {
  tenant_id: string;
  feature: string;
  projected_monthly_cost: number;
  burn_rate: number;
  sla_risk_level: SlaRiskLevel;
  performance_drift_score: number;
  last_updated: string;
}

export interface ForecastResult {
  burnRate: number;
  projectedMonthlyCost: number;
  smoothedDailyCost: number;
  budgetRisk: SlaRiskLevel;
}

export interface SlaTrendResult {
  latencyDrift: number;
  errorRateTrend: number;
  slaRiskLevel: SlaRiskLevel;
  performanceDriftScore: number;
}

export interface ForecastAdjustments {
  costWeightMultiplier: number;
  providerPenalty: number;
  explorationBoost: boolean;
  tsAlphaDecay: number;
  tsBetaDecay: number;
}

export interface AggregationParams {
  /** The date to aggregate (YYYY-MM-DD format) */
  targetDate: string;
}

// ── Constants ───────────────────────────────────────────────────

const BURN_RATE_WINDOW_DAYS = 7;
const EXP_SMOOTHING_ALPHA = 0.3;
const BUDGET_HIGH_THRESHOLD = 0.9;
const BUDGET_MEDIUM_THRESHOLD = 0.7;
const LATENCY_DRIFT_HIGH = 0.30;
const LATENCY_DRIFT_MEDIUM = 0.15;
const ERROR_RATE_TREND_THRESHOLD = 0.10;
const COST_WEIGHT_BOOST_FACTOR = 1.25;
const SLA_PENALTY_FACTOR = 0.8;
const TS_EXPLORATION_DECAY = 0.95;

// ── Cost Forecast Functions ─────────────────────────────────────

/**
 * Compute rolling 7-day burn rate and project monthly cost.
 */
export function computeBurnRate(dailyCosts: number[]): { burnRate: number; projectedMonthlyCost: number } {
  if (dailyCosts.length === 0) {
    return { burnRate: 0, projectedMonthlyCost: 0 };
  }

  const window = dailyCosts.slice(-BURN_RATE_WINDOW_DAYS);
  const totalInWindow = window.reduce((s, c) => s + c, 0);
  const burnRate = totalInWindow / Math.max(window.length, 1);
  const projectedMonthlyCost = burnRate * 30;

  return { burnRate, projectedMonthlyCost };
}

/**
 * Exponential smoothing for daily cost series.
 * smoothed_t = alpha * actual_t + (1 - alpha) * smoothed_(t-1)
 */
export function exponentialSmoothing(
  dailyCosts: number[],
  alpha: number = EXP_SMOOTHING_ALPHA,
): number {
  if (dailyCosts.length === 0) return 0;
  if (dailyCosts.length === 1) return dailyCosts[0];

  let smoothed = dailyCosts[0];
  for (let i = 1; i < dailyCosts.length; i++) {
    smoothed = alpha * dailyCosts[i] + (1 - alpha) * smoothed;
  }
  return smoothed;
}

/**
 * Determine budget risk level based on projected vs actual budget.
 */
export function computeBudgetRisk(
  projectedMonthlyCost: number,
  monthlyBudget: number,
): SlaRiskLevel {
  if (monthlyBudget <= 0) return 'low';
  const ratio = projectedMonthlyCost / monthlyBudget;
  if (ratio > BUDGET_HIGH_THRESHOLD) return 'high';
  if (ratio > BUDGET_MEDIUM_THRESHOLD) return 'medium';
  return 'low';
}

/**
 * Full cost forecast pipeline.
 */
export function computeCostForecast(
  dailyCosts: number[],
  monthlyBudget: number,
): ForecastResult {
  const { burnRate, projectedMonthlyCost } = computeBurnRate(dailyCosts);
  const smoothedDailyCost = exponentialSmoothing(dailyCosts);
  const budgetRisk = computeBudgetRisk(projectedMonthlyCost, monthlyBudget);

  return {
    burnRate,
    projectedMonthlyCost,
    smoothedDailyCost,
    budgetRisk,
  };
}

// ── SLA Trend Detection ─────────────────────────────────────────

/**
 * Compute latency drift between two periods.
 * drift = (current - previous) / previous
 */
export function computeLatencyDrift(
  currentPeriodLatencies: number[],
  previousPeriodLatencies: number[],
): number {
  if (previousPeriodLatencies.length === 0 || currentPeriodLatencies.length === 0) return 0;

  const currentMean = currentPeriodLatencies.reduce((s, v) => s + v, 0) / currentPeriodLatencies.length;
  const previousMean = previousPeriodLatencies.reduce((s, v) => s + v, 0) / previousPeriodLatencies.length;

  if (previousMean <= 0) return 0;
  return (currentMean - previousMean) / previousMean;
}

/**
 * Compute error rate trend between two periods.
 */
export function computeErrorRateTrend(
  currentErrorRate: number,
  previousErrorRate: number,
): number {
  return currentErrorRate - previousErrorRate;
}

/**
 * Determine SLA risk level from drift metrics.
 */
export function computeSlaRiskLevel(
  latencyDrift: number,
  errorRateTrend: number,
): SlaRiskLevel {
  if (latencyDrift > LATENCY_DRIFT_HIGH || errorRateTrend > ERROR_RATE_TREND_THRESHOLD) return 'high';
  if (latencyDrift > LATENCY_DRIFT_MEDIUM || errorRateTrend > ERROR_RATE_TREND_THRESHOLD / 2) return 'medium';
  return 'low';
}

/**
 * Composite performance drift score (0-1 scale, higher = worse).
 */
export function computePerformanceDriftScore(
  latencyDrift: number,
  errorRateTrend: number,
): number {
  // Normalize both to 0-1 and combine
  const normalizedLatencyDrift = clamp01(Math.abs(latencyDrift) / 0.5); // 50% drift = 1.0
  const normalizedErrorTrend = clamp01(Math.abs(errorRateTrend) / 0.2); // 20% error increase = 1.0
  return clamp01(0.6 * normalizedLatencyDrift + 0.4 * normalizedErrorTrend);
}

/**
 * Full SLA trend analysis pipeline.
 */
export function computeSlaTrend(
  currentLatencies: number[],
  previousLatencies: number[],
  currentErrorRate: number,
  previousErrorRate: number,
): SlaTrendResult {
  const latencyDrift = computeLatencyDrift(currentLatencies, previousLatencies);
  const errorRateTrend = computeErrorRateTrend(currentErrorRate, previousErrorRate);
  const slaRiskLevel = computeSlaRiskLevel(latencyDrift, errorRateTrend);
  const performanceDriftScore = computePerformanceDriftScore(latencyDrift, errorRateTrend);

  return { latencyDrift, errorRateTrend, slaRiskLevel, performanceDriftScore };
}

// ── Auto-Adaptive Routing Adjustments ───────────────────────────

/**
 * Compute routing adjustments based on forecast state.
 * These adjustments are applied on top of existing INT-02/INT-03 logic.
 */
export function computeForecastAdjustments(
  budgetRisk: SlaRiskLevel,
  slaRiskLevel: SlaRiskLevel,
  performanceDriftScore: number,
): ForecastAdjustments {
  let costWeightMultiplier = 1.0;
  let providerPenalty = 1.0;
  let explorationBoost = false;
  let tsAlphaDecay = 1.0;
  let tsBetaDecay = 1.0;

  // Budget risk → gradually increase cost weight
  if (budgetRisk === 'high') {
    costWeightMultiplier = COST_WEIGHT_BOOST_FACTOR;
  } else if (budgetRisk === 'medium') {
    costWeightMultiplier = 1.0 + (COST_WEIGHT_BOOST_FACTOR - 1.0) * 0.5; // half boost
  }

  // SLA risk → reduce quality weight for degraded providers
  if (slaRiskLevel === 'high') {
    providerPenalty = SLA_PENALTY_FACTOR;
  } else if (slaRiskLevel === 'medium') {
    providerPenalty = 1.0 - (1.0 - SLA_PENALTY_FACTOR) * 0.5; // half penalty
  }

  // Performance drift → boost exploration via Thompson prior decay
  if (performanceDriftScore > 0.5) {
    explorationBoost = true;
    tsAlphaDecay = TS_EXPLORATION_DECAY;
    tsBetaDecay = TS_EXPLORATION_DECAY;
  }

  return {
    costWeightMultiplier,
    providerPenalty,
    explorationBoost,
    tsAlphaDecay,
    tsBetaDecay,
  };
}

/**
 * Apply forecast-based cost weight adjustment to existing weights.
 * Renormalizes weights after adjustment.
 */
export function applyForecastCostAdjustment(
  weights: CostAwareWeights,
  costWeightMultiplier: number,
): CostAwareWeights {
  if (costWeightMultiplier === 1.0) return { ...weights };

  const adjusted = { ...weights };
  adjusted.w_cost *= costWeightMultiplier;

  // Renormalize
  const sum = adjusted.w_quality + adjusted.w_latency + adjusted.w_stability + adjusted.w_cost + adjusted.w_confidence;
  if (sum > 0) {
    adjusted.w_quality /= sum;
    adjusted.w_latency /= sum;
    adjusted.w_stability /= sum;
    adjusted.w_cost /= sum;
    adjusted.w_confidence /= sum;
  }

  return adjusted;
}

// ── Daily Aggregation Functions ─────────────────────────────────

/**
 * Aggregate yesterday's AI provider events into daily cost rows.
 * Idempotent: uses upsert on PK.
 */
export async function aggregateDailyCosts(
  supabase: any,
  targetDate: string,
): Promise<{ aggregated: number; errors: string[] }> {
  const errors: string[] = [];
  let aggregated = 0;

  try {
    // Query raw events for the target date
    const startOfDay = `${targetDate}T00:00:00Z`;
    const endOfDay = `${targetDate}T23:59:59.999Z`;

    const { data: events, error } = await supabase
      .from('ai_provider_events')
      .select('tenant_id, feature, provider, estimated_cost')
      .gte('created_at', startOfDay)
      .lte('created_at', endOfDay);

    if (error) {
      errors.push(`Failed to query events: ${error.message}`);
      return { aggregated, errors };
    }

    if (!events || events.length === 0) {
      return { aggregated: 0, errors };
    }

    // Group by (tenant_id, feature, provider)
    const groups = new Map<string, { totalCost: number; totalCalls: number }>();
    for (const e of events) {
      const key = `${e.tenant_id || 'global'}::${e.feature}::${e.provider}`;
      const existing = groups.get(key) || { totalCost: 0, totalCalls: 0 };
      existing.totalCost += e.estimated_cost || 0;
      existing.totalCalls += 1;
      groups.set(key, existing);
    }

    // Upsert aggregations
    for (const [key, value] of groups) {
      const [tenantId, feature, provider] = key.split('::');
      if (tenantId === 'global' || !tenantId) continue; // skip events without tenant_id

      const avgCost = value.totalCalls > 0 ? value.totalCost / value.totalCalls : 0;

      const { error: upsertErr } = await supabase
        .from('ai_cost_daily_agg')
        .upsert(
          {
            date: targetDate,
            tenant_id: tenantId,
            feature,
            provider,
            total_cost: value.totalCost,
            total_calls: value.totalCalls,
            avg_cost_per_call: avgCost,
          },
          { onConflict: 'date,tenant_id,feature,provider' },
        );

      if (upsertErr) {
        errors.push(`Upsert failed for ${key}: ${upsertErr.message}`);
      } else {
        aggregated++;
      }
    }
  } catch (err) {
    errors.push(`Unexpected error: ${err instanceof Error ? err.message : 'unknown'}`);
  }

  return { aggregated, errors };
}

/**
 * Aggregate yesterday's performance metrics into daily rows.
 * Idempotent: uses upsert on PK.
 */
export async function aggregateDailyPerformance(
  supabase: any,
  targetDate: string,
): Promise<{ aggregated: number; errors: string[] }> {
  const errors: string[] = [];
  let aggregated = 0;

  try {
    const startOfDay = `${targetDate}T00:00:00Z`;
    const endOfDay = `${targetDate}T23:59:59.999Z`;

    const { data: events, error } = await supabase
      .from('ai_provider_events')
      .select('provider, feature, latency_ms, success')
      .gte('created_at', startOfDay)
      .lte('created_at', endOfDay);

    if (error) {
      errors.push(`Failed to query events: ${error.message}`);
      return { aggregated, errors };
    }

    if (!events || events.length === 0) {
      return { aggregated: 0, errors };
    }

    // Group by (provider, feature)
    const groups = new Map<string, { latencies: number[]; successes: number; total: number }>();
    for (const e of events) {
      const key = `${e.provider}::${e.feature}`;
      const existing = groups.get(key) || { latencies: [], successes: 0, total: 0 };
      existing.latencies.push(e.latency_ms || 0);
      if (e.success) existing.successes++;
      existing.total++;
      groups.set(key, existing);
    }

    for (const [key, value] of groups) {
      const [provider, feature] = key.split('::');
      const avgLatency = value.latencies.reduce((s, v) => s + v, 0) / Math.max(value.latencies.length, 1);
      const successRate = value.total > 0 ? value.successes / value.total : 1;
      const errorRate = 1 - successRate;

      const { error: upsertErr } = await supabase
        .from('ai_performance_daily_agg')
        .upsert(
          {
            date: targetDate,
            provider,
            feature,
            avg_latency: avgLatency,
            error_rate: errorRate,
            success_rate: successRate,
            total_calls: value.total,
          },
          { onConflict: 'date,provider,feature' },
        );

      if (upsertErr) {
        errors.push(`Upsert failed for ${key}: ${upsertErr.message}`);
      } else {
        aggregated++;
      }
    }
  } catch (err) {
    errors.push(`Unexpected error: ${err instanceof Error ? err.message : 'unknown'}`);
  }

  return { aggregated, errors };
}

/**
 * Update forecast state for all tenants with recent activity.
 */
export async function updateForecastState(
  supabase: any,
  targetDate: string,
): Promise<{ updated: number; errors: string[] }> {
  const errors: string[] = [];
  let updated = 0;

  try {
    // Get distinct tenant+feature combos from recent cost data (last 14 days)
    const fourteenDaysAgo = new Date(new Date(targetDate).getTime() - 14 * 86400000)
      .toISOString().split('T')[0];

    const { data: recentCosts, error: costErr } = await supabase
      .from('ai_cost_daily_agg')
      .select('tenant_id, feature, date, total_cost')
      .gte('date', fourteenDaysAgo)
      .lte('date', targetDate)
      .order('date', { ascending: true });

    if (costErr) {
      errors.push(`Failed to query cost data: ${costErr.message}`);
      return { updated, errors };
    }

    // Group by tenant+feature
    const tenantFeatureMap = new Map<string, number[]>();
    for (const row of (recentCosts || [])) {
      const key = `${row.tenant_id}::${row.feature}`;
      const existing = tenantFeatureMap.get(key) || [];
      existing.push(row.total_cost);
      tenantFeatureMap.set(key, existing);
    }

    // Get performance data for SLA analysis
    const { data: perfData } = await supabase
      .from('ai_performance_daily_agg')
      .select('provider, feature, date, avg_latency, error_rate')
      .gte('date', fourteenDaysAgo)
      .lte('date', targetDate)
      .order('date', { ascending: true });

    // Split perf data into current (last 7 days) and previous (7 days before that)
    const sevenDaysAgo = new Date(new Date(targetDate).getTime() - 7 * 86400000)
      .toISOString().split('T')[0];

    const currentPerf: DailyPerformanceRow[] = [];
    const previousPerf: DailyPerformanceRow[] = [];
    for (const row of (perfData || [])) {
      if (row.date >= sevenDaysAgo) {
        currentPerf.push(row);
      } else {
        previousPerf.push(row);
      }
    }

    // Compute SLA trend (global, per feature)
    const featureSlaTrends = new Map<string, SlaTrendResult>();
    const featureSet = new Set<string>();
    for (const r of [...currentPerf, ...previousPerf]) featureSet.add(r.feature);

    for (const feature of featureSet) {
      const curLatencies = currentPerf.filter(r => r.feature === feature).map(r => r.avg_latency);
      const prevLatencies = previousPerf.filter(r => r.feature === feature).map(r => r.avg_latency);
      const curErrorRates = currentPerf.filter(r => r.feature === feature).map(r => r.error_rate);
      const prevErrorRates = previousPerf.filter(r => r.feature === feature).map(r => r.error_rate);

      const curErrorRate = curErrorRates.length > 0 ? curErrorRates.reduce((s, v) => s + v, 0) / curErrorRates.length : 0;
      const prevErrorRate = prevErrorRates.length > 0 ? prevErrorRates.reduce((s, v) => s + v, 0) / prevErrorRates.length : 0;

      featureSlaTrends.set(feature, computeSlaTrend(curLatencies, prevLatencies, curErrorRate, prevErrorRate));
    }

    // Get budget configs for risk calculation
    const tenantIds = [...new Set([...tenantFeatureMap.keys()].map(k => k.split('::')[0]))];
    let budgetMap = new Map<string, number>();
    if (tenantIds.length > 0) {
      const { data: budgets } = await supabase
        .from('tenant_ai_budget_config')
        .select('tenant_id, monthly_budget')
        .in('tenant_id', tenantIds);

      for (const b of (budgets || [])) {
        budgetMap.set(b.tenant_id, b.monthly_budget);
      }
    }

    // Update forecast state for each tenant+feature
    for (const [key, dailyCosts] of tenantFeatureMap) {
      const [tenantId, feature] = key.split('::');
      const monthlyBudget = budgetMap.get(tenantId) || 0;
      const costForecast = computeCostForecast(dailyCosts, monthlyBudget);
      const slaTrend = featureSlaTrends.get(feature) || {
        latencyDrift: 0, errorRateTrend: 0, slaRiskLevel: 'low' as SlaRiskLevel, performanceDriftScore: 0,
      };

      // Overall risk = max of budget risk and SLA risk
      const riskLevels: SlaRiskLevel[] = [costForecast.budgetRisk, slaTrend.slaRiskLevel];
      const riskOrder: Record<SlaRiskLevel, number> = { low: 0, medium: 1, high: 2 };
      const overallRisk = riskLevels.reduce((max, r) => riskOrder[r] > riskOrder[max] ? r : max, 'low' as SlaRiskLevel);

      const { error: upsertErr } = await supabase
        .from('ai_forecast_state')
        .upsert(
          {
            tenant_id: tenantId,
            feature,
            projected_monthly_cost: costForecast.projectedMonthlyCost,
            burn_rate: costForecast.burnRate,
            sla_risk_level: overallRisk,
            performance_drift_score: slaTrend.performanceDriftScore,
            last_updated: new Date().toISOString(),
          },
          { onConflict: 'tenant_id,feature' },
        );

      if (upsertErr) {
        errors.push(`Forecast upsert failed for ${key}: ${upsertErr.message}`);
      } else {
        updated++;
      }
    }
  } catch (err) {
    errors.push(`Unexpected error: ${err instanceof Error ? err.message : 'unknown'}`);
  }

  return { updated, errors };
}

// ── Forecast-Aware Routing Hook ─────────────────────────────────

/**
 * Fetch forecast state for a tenant+feature and compute routing adjustments.
 * Fail-open: returns neutral adjustments on any error.
 */
export async function getForecastAdjustments(
  supabase: any,
  tenantId: string | null,
  feature: string,
): Promise<ForecastAdjustments> {
  const neutral: ForecastAdjustments = {
    costWeightMultiplier: 1.0,
    providerPenalty: 1.0,
    explorationBoost: false,
    tsAlphaDecay: 1.0,
    tsBetaDecay: 1.0,
  };

  if (!tenantId) return neutral;

  try {
    const { data, error } = await supabase
      .from('ai_forecast_state')
      .select('projected_monthly_cost, burn_rate, sla_risk_level, performance_drift_score')
      .eq('tenant_id', tenantId)
      .eq('feature', feature)
      .maybeSingle();

    if (error || !data) return neutral;

    // Get budget for risk context
    const { data: budgetData } = await supabase
      .from('tenant_ai_budget_config')
      .select('monthly_budget')
      .eq('tenant_id', tenantId)
      .maybeSingle();

    const monthlyBudget = budgetData?.monthly_budget || 0;
    const budgetRisk = computeBudgetRisk(data.projected_monthly_cost, monthlyBudget);

    return computeForecastAdjustments(
      budgetRisk,
      data.sla_risk_level as SlaRiskLevel,
      data.performance_drift_score,
    );
  } catch {
    return neutral;
  }
}

/**
 * Hybrid Provider Router — PR-AI-INT-01C
 *
 * Ranks AI provider candidates using blended global+tenant EWMA metrics.
 * Supports OpenAI, Gemini, Anthropic.
 *
 * FinalScore = alpha * GlobalScore + beta * TenantScore
 * alpha/beta depend on tenant (feature,purpose) sample_count.
 *
 * No PII or prompt content is logged.
 */

// ── Types ───────────────────────────────────────────────────────

export type HybridProvider = 'openai' | 'gemini' | 'anthropic';

export interface ProviderCandidate {
  provider: HybridProvider;
  model: string;
}

export interface MetricsRow {
  scope: 'global' | 'tenant';
  provider: string;
  model: string;
  ewma_latency_ms: number;
  ewma_quality: number;
  ewma_cost_per_1k: number;
  ewma_success_rate: number;
  sample_count: number;
}

export interface RoutingResult {
  ranked: ProviderCandidate[];
  selected: ProviderCandidate;
  mode: 'explore' | 'exploit';
  alpha: number;
  beta: number;
  epsilon: number;
  tenantFpSamples: number;
  scores: ScoredCandidate[];
}

export interface ScoredCandidate {
  provider: string;
  model: string;
  finalScore: number;
  globalScore: number;
  tenantScore: number;
}

// ── Constants ───────────────────────────────────────────────────

const SCORE_WEIGHTS = {
  wq: 0.40, // quality
  ws: 0.30, // success
  wl: 0.20, // latency (inverted — lower is better)
  wc: 0.10, // cost (inverted — lower is better)
};

const LATENCY_CAP_MS = 5000;
const COST_CAP = 0.01;

/** EWMA smoothing factor */
export const EWMA_LAMBDA = 0.2;

// ── Helpers ─────────────────────────────────────────────────────

export function clamp01(v: number): number {
  return Math.max(0, Math.min(1, v));
}

/** Compute alpha/beta based on tenant (feature,purpose) sample count */
export function computeAlphaBeta(tenantSamples: number): { alpha: number; beta: number } {
  if (tenantSamples < 20) return { alpha: 0.85, beta: 0.15 };
  if (tenantSamples <= 100) return { alpha: 0.60, beta: 0.40 };
  return { alpha: 0.35, beta: 0.65 };
}

/** Compute exploration epsilon based on tenant (feature,purpose) sample count */
export function computeEpsilon(tenantSamples: number): number {
  if (tenantSamples < 20) return 0.20;
  if (tenantSamples <= 100) return 0.10;
  return 0.05;
}

/** Score a single metrics row into a 0-1 composite */
export function computeScore(m: MetricsRow | null): number {
  if (!m || m.sample_count === 0) return 0.5; // neutral default

  const latencyScore = clamp01(1 - m.ewma_latency_ms / LATENCY_CAP_MS);
  const costScore = clamp01(1 - m.ewma_cost_per_1k / COST_CAP);
  const successScore = clamp01(m.ewma_success_rate);
  // quality is 0..100 in DB
  const qualityScore = clamp01(m.ewma_quality / 100);

  return (
    SCORE_WEIGHTS.wq * qualityScore +
    SCORE_WEIGHTS.ws * successScore +
    SCORE_WEIGHTS.wl * latencyScore +
    SCORE_WEIGHTS.wc * costScore
  );
}

/** Deterministic seeded random for testing (xorshift32) */
export function seededRandom(seed: number): () => number {
  let s = seed | 0;
  return () => {
    s ^= s << 13;
    s ^= s >> 17;
    s ^= s << 5;
    return ((s >>> 0) / 4294967296);
  };
}

// ── EWMA Update ─────────────────────────────────────────────────

export interface UpdateParams {
  scope: 'global' | 'tenant';
  tenantId: string | null;
  feature: string;
  purpose: string;
  provider: string;
  model: string;
  latencyMs: number;
  costPer1k: number;
  qualityAvg: number;
  success: boolean;
}

export function computeEwmaUpdate(
  existing: { ewma_latency_ms: number; ewma_quality: number; ewma_cost_per_1k: number; ewma_success_rate: number; sample_count: number } | null,
  params: { latencyMs: number; costPer1k: number; qualityAvg: number; success: boolean },
): { ewma_latency_ms: number; ewma_quality: number; ewma_cost_per_1k: number; ewma_success_rate: number; sample_count: number } {
  const lambda = EWMA_LAMBDA;
  const successVal = params.success ? 1 : 0;

  if (!existing || existing.sample_count === 0) {
    return {
      ewma_latency_ms: params.latencyMs,
      ewma_quality: params.qualityAvg,
      ewma_cost_per_1k: params.costPer1k,
      ewma_success_rate: successVal,
      sample_count: 1,
    };
  }

  return {
    ewma_latency_ms: lambda * params.latencyMs + (1 - lambda) * existing.ewma_latency_ms,
    ewma_quality: lambda * params.qualityAvg + (1 - lambda) * existing.ewma_quality,
    ewma_cost_per_1k: lambda * params.costPer1k + (1 - lambda) * existing.ewma_cost_per_1k,
    ewma_success_rate: lambda * successVal + (1 - lambda) * existing.ewma_success_rate,
    sample_count: existing.sample_count + 1,
  };
}

// ── Main Ranking Function ───────────────────────────────────────

export interface RankParams {
  tenantId: string | null;
  feature: string;
  purpose: string;
  candidates: ProviderCandidate[];
  /** Override for testing */
  _randomFn?: () => number;
}

/**
 * Rank providers using hybrid global+tenant scoring.
 * Fetches metrics from DB via supabase service client.
 */
export async function rankProvidersHybrid(
  supabase: any,
  params: RankParams,
): Promise<RoutingResult> {
  const { tenantId, feature, purpose, candidates, _randomFn } = params;

  // Fetch global + tenant metrics in parallel
  const globalQuery = supabase
    .from('ai_provider_metrics_agg')
    .select('scope, provider, model, ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count')
    .eq('scope', 'global')
    .eq('feature', feature)
    .eq('purpose', purpose);

  const tenantQuery = tenantId
    ? supabase
        .from('ai_provider_metrics_agg')
        .select('scope, provider, model, ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count')
        .eq('scope', 'tenant')
        .eq('tenant_id', tenantId)
        .eq('feature', feature)
        .eq('purpose', purpose)
    : Promise.resolve({ data: [] });

  const [globalRes, tenantRes] = await Promise.all([globalQuery, tenantQuery]);
  const globalRows: MetricsRow[] = globalRes.data || [];
  const tenantRows: MetricsRow[] = tenantRes.data || [];

  // Build lookup maps
  const globalMap = new Map<string, MetricsRow>();
  for (const r of globalRows) globalMap.set(`${r.provider}::${r.model}`, r);

  const tenantMap = new Map<string, MetricsRow>();
  for (const r of tenantRows) tenantMap.set(`${r.provider}::${r.model}`, r);

  // Compute tenant (feature,purpose) total sample count
  const tenantFpSamples = tenantRows.reduce((sum, r) => sum + r.sample_count, 0);
  const { alpha, beta } = computeAlphaBeta(tenantFpSamples);
  const epsilon = computeEpsilon(tenantFpSamples);

  // Score each candidate
  const scored: ScoredCandidate[] = candidates.map(c => {
    const key = `${c.provider}::${c.model}`;
    const globalScore = computeScore(globalMap.get(key) ?? null);
    const tenantScore = computeScore(tenantMap.get(key) ?? null);
    const finalScore = alpha * globalScore + beta * tenantScore;
    return { provider: c.provider, model: c.model, finalScore, globalScore, tenantScore };
  });

  // Sort best-first
  scored.sort((a, b) => b.finalScore - a.finalScore);

  // Exploit vs explore
  const rng = _randomFn ?? Math.random;
  const isExplore = rng() < epsilon;
  let selected: ProviderCandidate;

  if (isExplore && scored.length > 1) {
    const top3 = scored.slice(0, Math.min(3, scored.length));
    const idx = Math.floor(rng() * top3.length);
    selected = { provider: top3[idx].provider as HybridProvider, model: top3[idx].model };
  } else {
    selected = { provider: scored[0].provider as HybridProvider, model: scored[0].model };
  }

  const ranked = scored.map(s => ({ provider: s.provider as HybridProvider, model: s.model }));

  return {
    ranked,
    selected,
    mode: isExplore ? 'explore' : 'exploit',
    alpha,
    beta,
    epsilon,
    tenantFpSamples,
    scores: scored.slice(0, 3), // telemetry: top 3 only
  };
}

/**
 * Update EWMA metrics for a provider after a call completes.
 * Fail-open: logs warning on error, never throws.
 */
export async function updateProviderAgg(
  supabase: any,
  params: UpdateParams,
): Promise<void> {
  try {
    const { scope, tenantId, feature, purpose, provider, model, latencyMs, costPer1k, qualityAvg, success } = params;

    // Fetch existing row
    let query = supabase
      .from('ai_provider_metrics_agg')
      .select('ewma_latency_ms, ewma_quality, ewma_cost_per_1k, ewma_success_rate, sample_count')
      .eq('scope', scope)
      .eq('feature', feature)
      .eq('purpose', purpose)
      .eq('provider', provider)
      .eq('model', model);

    if (scope === 'tenant' && tenantId) {
      query = query.eq('tenant_id', tenantId);
    } else {
      query = query.is('tenant_id', null);
    }

    const { data: existing } = await query.maybeSingle();

    const updated = computeEwmaUpdate(existing, { latencyMs, costPer1k, qualityAvg, success });

    if (existing) {
      // Update existing row
      let updateQuery = supabase
        .from('ai_provider_metrics_agg')
        .update({
          ...updated,
          last_updated: new Date().toISOString(),
        })
        .eq('scope', scope)
        .eq('feature', feature)
        .eq('purpose', purpose)
        .eq('provider', provider)
        .eq('model', model);

      if (scope === 'tenant' && tenantId) {
        updateQuery = updateQuery.eq('tenant_id', tenantId);
      } else {
        updateQuery = updateQuery.is('tenant_id', null);
      }

      await updateQuery;
    } else {
      // Insert new row
      await supabase
        .from('ai_provider_metrics_agg')
        .insert({
          scope,
          tenant_id: scope === 'tenant' ? tenantId : null,
          feature,
          purpose,
          provider,
          model,
          ...updated,
          last_updated: new Date().toISOString(),
        });
    }

    // Also insert raw event (fire-and-forget)
    supabase
      .from('ai_provider_events')
      .insert({
        tenant_id: tenantId,
        feature,
        purpose,
        provider,
        model,
        latency_ms: latencyMs,
        estimated_cost: costPer1k,
        quality_avg: qualityAvg,
        success,
      })
      .then(() => {})
      .catch(() => {});
  } catch (err) {
    console.warn('updateProviderAgg failed (fail-open):', err instanceof Error ? err.message : 'unknown');
  }
}

