};

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    // ── Auth guard ──────────────────────────────────────────────────
    const authHeader = req.headers.get("Authorization");
    if (!authHeader?.startsWith("Bearer ")) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY")!;

    const authClient = createClient(supabaseUrl, supabaseAnonKey, {
      global: { headers: { Authorization: authHeader } },
    });

    const { data: { user }, error: authError } = await authClient.auth.getUser();
    if (authError || !user) {
      return new Response(JSON.stringify({ error: "Unauthorized" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }
    // ── End auth guard ──────────────────────────────────────────────

    const { prompt, model = "google/gemini-3-flash-preview", useExpertKnowledge, selectedFrameworkIds = [], selectedFrameworks = [], documentSummaries = "" } = await req.json();

    if (!prompt || prompt.trim().length < 10) {
      return new Response(JSON.stringify({ error: "Prompt too short" }), {
        status: 400,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const LOVABLE_API_KEY = Deno.env.get("LOVABLE_API_KEY");
    if (!LOVABLE_API_KEY) {
      return new Response(JSON.stringify({ error: "AI service not configured" }), {
        status: 500,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // Fetch framework descriptions from DB if IDs provided (use service role for DB access)
    let expertContext = "";
    if (useExpertKnowledge) {
      if (selectedFrameworkIds && selectedFrameworkIds.length > 0) {
        const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const { data: frameworks } = await supabase
          .from("reference_frameworks")
          .select("name, description")
          .in("id", selectedFrameworkIds)
          .eq("is_active", true)
          .is("deleted_at", null);

        if (frameworks && frameworks.length > 0) {
          const frameworkList = frameworks
            .map((f: any) => `- ${f.name}: ${f.description || ''}`)
            .join("\n");

          expertContext = `You have deep expertise in the following selected international standards and frameworks:\n${frameworkList}\n\nWhen rewriting, reference ONLY these selected frameworks where relevant and ensure the prompt is grounded in evidence-based psychometric principles aligned with them.`;
        }
      } else if (selectedFrameworks && selectedFrameworks.length > 0) {
        const frameworkDescriptions: Record<string, string> = {
          ISO45003: "ISO 45003 (Psychological Health & Safety at Work)",
          ISO10018: "ISO 10018 & ISO 30414 (People Engagement & HR Reporting)",
          COPSOQ: "COPSOQ III (Copenhagen Psychosocial Questionnaire)",
          UWES: "UWES (Utrecht Work Engagement Scale)",
          WHO: "WHO Guidelines (Mental Health at Work)",
          Gallup: "Gallup Q12 (Employee Needs Hierarchy)",
        };
        const frameworkList = selectedFrameworks
          .filter((id: string) => frameworkDescriptions[id])
          .map((id: string) => `- ${frameworkDescriptions[id]}`)
          .join("\n");

        expertContext = `You have deep expertise in the following selected international standards and frameworks:\n${frameworkList}\n\nWhen rewriting, reference ONLY these selected frameworks where relevant and ensure the prompt is grounded in evidence-based psychometric principles aligned with them.`;
      }
    }

    let documentContext = "";
    if (documentSummaries && documentSummaries.trim().length > 0) {
      documentContext = `\n\nThe user has uploaded reference documents with the following content summaries. Incorporate relevant concepts from these documents into the rewritten prompt:\n${documentSummaries}`;
    }

    const systemPrompt = `You are an expert Industrial-Organizational Psychologist and Psychometrician who specializes in creating survey instruments.

${expertContext}${documentContext}

Your task is to take a user's rough prompt/instructions and rewrite it into a professional, detailed, expert-level prompt that will guide an AI to generate the highest quality survey questions.

Rules:
- Preserve the user's original intent and focus areas
- Add scientific rigor, proper terminology, and psychometric best practices
- Include guidance on question construction (avoiding double-barreled questions, leading language, etc.)
- Add relevant framework references if expert knowledge is enabled (only reference the selected frameworks)
- If document content was provided, weave in relevant concepts and terminology from those documents
- Keep the rewritten prompt clear and actionable
- Output ONLY the rewritten prompt text, no explanations or meta-commentary
- Write in the same language as the input prompt`;

    const response = await fetch("https://ai.gateway.lovable.dev/v1/chat/completions", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${LOVABLE_API_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: model,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: `Rewrite this prompt as an expert-level survey generation instruction:\n\n${prompt}` },
        ],
        temperature: 0.4,
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error("AI gateway error:", response.status, errorText);
      if (response.status === 429) {
        return new Response(JSON.stringify({ error: "Rate limit exceeded. Please wait a moment and try again." }), {
          status: 429,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }
      if (response.status === 402) {
        return new Response(JSON.stringify({ error: "Payment required. AI credits may be exhausted." }), {
          status: 402,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }
      return new Response(JSON.stringify({ error: "Failed to rewrite prompt" }), {
        status: 500,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const aiResponse = await response.json();
    const rewrittenPrompt = aiResponse.choices?.[0]?.message?.content || prompt;

    return new Response(JSON.stringify({ rewrittenPrompt, success: true }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error: unknown) {
    console.error("Error in rewrite-prompt:", error);
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    return new Response(JSON.stringify({ error: errorMessage }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version",
};

const MAX_BATCH_SIZE = 64;

interface SavedQuestion {
  question_text: string;
  question_text_ar: string | null;
  type: string;
  complexity?: string;
  tone?: string;
  explanation?: string;
  confidence_score?: number;
  bias_flag?: boolean;
  ambiguity_flag?: boolean;
  validation_status?: string;
  validation_details?: Record<string, unknown>;
  options?: { text: string; text_ar: string }[];
  mood_levels?: string[];
  category_id?: string | null;
  subcategory_id?: string | null;
  mood_score?: number | null;
  affective_state?: string | null;
  generation_period_id?: string | null;
  question_hash?: string | null;
}

interface SaveRequest {
  purpose: "wellness" | "survey";
  questions: SavedQuestion[];
  targetBatchId?: string;
  // Survey-specific fields
  model?: string;
  accuracyMode?: string;
  settings?: Record<string, unknown>;
  validationReport?: {
    overall_result: string;
    validation_results: Record<string, unknown>;
    critic_result?: unknown;
  } | null;
}

function mapToWellnessType(type: string): string {
  if (["scale", "multiple_choice", "text"].includes(type)) return type;
  if (type === "likert_5" || type === "numeric_scale") return "scale";
  if (type === "open_ended") return "text";
  return "scale";
}

function mapToQuestionType(type: string): string {
  if (["likert_5", "numeric_scale", "yes_no", "multiple_choice", "open_ended"].includes(type)) return type;
  if (type === "scale") return "likert_5";
  if (type === "text") return "open_ended";
  return "likert_5";
}

function formatDate(d: Date): string {
  const months = ["January","February","March","April","May","June","July","August","September","October","November","December"];
  return `${String(d.getDate()).padStart(2, "0")} ${months[d.getMonth()]} ${d.getFullYear()}`;
}

function formatMonth(d: Date): string {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-01`;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("Authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Missing authorization" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

    // Verify user with anon client
    const anonClient = createClient(supabaseUrl, Deno.env.get("SUPABASE_ANON_KEY")!, {
      global: { headers: { Authorization: authHeader } },
    });
    const { data: userData, error: authError } = await anonClient.auth.getUser();
    if (authError || !userData.user) {
      return new Response(JSON.stringify({ error: "Not authenticated" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }
    const userId = userData.user.id;

    // Use service role for all DB ops (atomic transaction context)
    const admin = createClient(supabaseUrl, serviceKey);

    // Get tenant_id
    const { data: tenantId } = await admin.rpc("get_user_tenant_id", { _user_id: userId });
    if (!tenantId) {
      return new Response(JSON.stringify({ error: "No organization found" }), {
        status: 400,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // Get profile name
    const { data: profile } = await admin
      .from("profiles")
      .select("full_name")
      .eq("user_id", userId)
      .single();
    const fullName = profile?.full_name || "Unknown";

    const body: SaveRequest = await req.json();
    const { purpose, questions, targetBatchId } = body;

    if (!questions || questions.length === 0) {
      return new Response(JSON.stringify({ error: "No questions provided" }), {
        status: 400,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const now = new Date();
    const batchName = `${formatDate(now)} - ${fullName}`;
    let savedCount = 0;

    if (purpose === "wellness") {
      let remaining = [...questions];

      // Append to existing batch if provided
      if (targetBatchId) {
        const { data: existingBatch, error: fetchErr } = await admin
          .from("question_generation_batches")
          .select("id, question_count")
          .eq("id", targetBatchId)
          .single();
        if (fetchErr) throw fetchErr;

        const currentCount = existingBatch.question_count || 0;
        const capacity = MAX_BATCH_SIZE - currentCount;
        const toAppend = remaining.splice(0, capacity);

        if (toAppend.length > 0) {
          const { error } = await admin.from("wellness_questions").insert(
            toAppend.map((q) => ({
              tenant_id: tenantId,
              batch_id: targetBatchId,
              question_text_en: q.question_text,
              question_text_ar: q.question_text_ar || null,
              question_type: mapToWellnessType(q.type),
              options: q.type === "multiple_choice" && q.options ? q.options : [],
              status: "draft",
            }))
          );
          if (error) throw error;

          await admin
            .from("question_generation_batches")
            .update({ question_count: currentCount + toAppend.length })
            .eq("id", targetBatchId);
          savedCount += toAppend.length;
        }
      }

      // Create new batch for remaining
      if (remaining.length > 0) {
        const periodId = remaining[0]?.generation_period_id || null;
        const { data: batch, error: batchError } = await admin
          .from("question_generation_batches")
          .insert({
            tenant_id: tenantId,
            target_month: formatMonth(now),
            question_count: remaining.length,
            status: "draft",
            created_by: userId,
            name: batchName,
            generation_period_id: periodId,
          })
          .select("id")
          .single();
        if (batchError) throw batchError;

        const { error } = await admin.from("wellness_questions").insert(
          remaining.map((q) => ({
            tenant_id: tenantId,
            batch_id: batch.id,
            question_text_en: q.question_text,
            question_text_ar: q.question_text_ar || null,
            question_type: mapToWellnessType(q.type),
            options: q.type === "multiple_choice" && q.options ? q.options : [],
            status: "draft",
          }))
        );
        if (error) throw error;
        savedCount += remaining.length;
      }

      // Also save to unified questions table
      await admin.from("questions").insert(
        questions.map((q) => ({
          tenant_id: tenantId,
          text: q.question_text,
          text_ar: q.question_text_ar || null,
          type: mapToQuestionType(q.type),
          options: q.options || [],
          mood_levels: q.mood_levels || [],
          is_active: true,
          is_global: false,
          ai_generated: true,
          created_by: userId,
          category_id: q.category_id || null,
          subcategory_id: q.subcategory_id || null,
          mood_score: q.mood_score || null,
          affective_state: q.affective_state || null,
        }))
      );
    } else {
      // Survey purpose
      let remaining = [...questions];

      if (targetBatchId) {
        const { data: targetBatch, error: fetchErr } = await admin
          .from("question_sets")
          .select("id, question_count")
          .eq("id", targetBatchId)
          .single();
        if (fetchErr) throw fetchErr;

        const currentCount = targetBatch.question_count || 0;
        const capacity = MAX_BATCH_SIZE - currentCount;
        const toAdd = remaining.splice(0, capacity);

        if (toAdd.length > 0) {
          const { error } = await admin.from("generated_questions").insert(
            toAdd.map((q) => ({
              question_set_id: targetBatchId,
              tenant_id: tenantId,
              question_text: q.question_text,
              question_text_ar: q.question_text_ar,
              type: q.type,
              complexity: q.complexity,
              tone: q.tone,
              explanation: q.explanation,
              confidence_score: q.confidence_score,
              bias_flag: q.bias_flag,
              ambiguity_flag: q.ambiguity_flag,
              validation_status: q.validation_status,
              validation_details: q.validation_details,
              options: q.options || [],
              category_id: q.category_id || null,
              subcategory_id: q.subcategory_id || null,
              mood_score: q.mood_score || null,
              affective_state: q.affective_state || null,
              generation_period_id: q.generation_period_id || null,
              question_hash: q.question_hash || null,
            }))
          );
          if (error) throw error;

          await admin
            .from("question_sets")
            .update({ question_count: currentCount + toAdd.length })
            .eq("id", targetBatchId);
          savedCount += toAdd.length;
        }
      }

      while (remaining.length > 0) {
        const chunk = remaining.splice(0, MAX_BATCH_SIZE);
        const { data: newBatch, error: setError } = await admin
          .from("question_sets")
          .insert({
            tenant_id: tenantId,
            user_id: userId,
            model_used: body.model || "unknown",
            accuracy_mode: body.accuracyMode || "standard",
            settings: body.settings || {},
            validation_result: body.validationReport?.validation_results || {},
            critic_pass_result: body.validationReport?.critic_result || null,
            status: body.validationReport?.overall_result === "passed" ? "validated" : "draft",
            name: batchName,
            question_count: chunk.length,
            generation_period_id: chunk[0]?.generation_period_id || null,
          })
          .select("id")
          .single();
        if (setError) throw setError;

        const { error } = await admin.from("generated_questions").insert(
          chunk.map((q) => ({
            question_set_id: newBatch.id,
            tenant_id: tenantId,
            question_text: q.question_text,
            question_text_ar: q.question_text_ar,
            type: q.type,
            complexity: q.complexity,
            tone: q.tone,
            explanation: q.explanation,
            confidence_score: q.confidence_score,
            bias_flag: q.bias_flag,
            ambiguity_flag: q.ambiguity_flag,
            validation_status: q.validation_status,
            validation_details: q.validation_details,
            options: q.options || [],
            category_id: q.category_id || null,
            subcategory_id: q.subcategory_id || null,
            mood_score: q.mood_score || null,
            affective_state: q.affective_state || null,
            generation_period_id: q.generation_period_id || null,
            question_hash: q.question_hash || null,
          }))
        );
        if (error) throw error;
        savedCount += chunk.length;
      }
    }

    return new Response(
      JSON.stringify({ success: true, savedCount, purpose }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("save-question-batch error:", error);
    return new Response(
      JSON.stringify({ error: error.message || "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface ScheduleRequest {
  scheduleId?: string;
  generateForDays?: number;
}

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, supabaseKey);

    const { scheduleId, generateForDays = 7 }: ScheduleRequest = await req.json().catch(() => ({}));

    // Get active schedules
    let schedulesQuery = supabase
      .from("question_schedules")
      .select("*")
      .eq("status", "active")
      .is("deleted_at", null)
      .eq("schedule_type", "survey"); // Only process survey schedules; daily check-ins use the mood pathway

    if (scheduleId) {
      schedulesQuery = schedulesQuery.eq("id", scheduleId);
    }

    const { data: schedules, error: schedulesError } = await schedulesQuery;

    if (schedulesError) {
      console.error("Error fetching schedules:", schedulesError);
      throw schedulesError;
    }

    if (!schedules?.length) {
      return new Response(JSON.stringify({ message: "No active schedules found", scheduled: 0 }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    let totalScheduled = 0;

    for (const schedule of schedules) {
      console.log(`Processing schedule: ${schedule.name} (${schedule.id})`);

      // Get target employees based on audience config
      const targetAudience = schedule.target_audience || { all: true };
      let employeesQuery = supabase
        .from("employees")
        .select("id")
        .eq("tenant_id", schedule.tenant_id)
        .eq("status", "active")
        .is("deleted_at", null);

      // Branch/Site Scoping
      if (schedule.branch_id) {
        employeesQuery = employeesQuery.eq("branch_id", schedule.branch_id);
      }
      if (schedule.site_id) {
        employeesQuery = employeesQuery.eq("site_id", schedule.site_id);
      }

      if (!targetAudience.all) {
        if (targetAudience.departments?.length) {
          employeesQuery = employeesQuery.in("department", targetAudience.departments);
        }
        if (targetAudience.specific_employees?.length) {
          employeesQuery = employeesQuery.in("id", targetAudience.specific_employees);
        }
      }

      const { data: employees, error: empError } = await employeesQuery;
      if (empError) {
        console.error("Error fetching employees:", empError);
        continue;
      }

      if (!employees?.length) {
        console.log(`No employees found for schedule ${schedule.id}`);
        continue;
      }

      // Get available questions - from linked batches or general pool
      const batchIds = (schedule.batch_ids || []) as string[];
      let questions: { id: string; _source: string }[] = [];

      if (batchIds.length > 0) {
        const { data: surveyQuestions, error: sqError } = await supabase
          .from("generated_questions")
          .select("id")
          .in("question_set_id", batchIds)
          .in("validation_status", ["published", "passed", "pending"]);

        if (sqError) {
          console.error("Error fetching survey batch questions:", sqError);
        } else if (surveyQuestions?.length) {
          questions = surveyQuestions.map(q => ({ ...q, _source: "generated_questions" }));
        }

        const { data: wellnessQuestions, error: wqError } = await supabase
          .from("wellness_questions")
          .select("id")
          .in("batch_id", batchIds)
          .eq("status", "published")
          .is("deleted_at", null);

        if (wqError) {
          console.error("Error fetching wellness batch questions:", wqError);
        } else if (wellnessQuestions?.length) {
          questions = [...questions, ...wellnessQuestions.map(q => ({ ...q, _source: "wellness_questions" }))];
        }

        console.log(`Found ${questions.length} questions from ${batchIds.length} linked batches`);
      } else {
        const activeCategories = schedule.active_categories || [];
        let questionsQuery = supabase
          .from("questions")
          .select("id")
          .eq("is_active", true)
          .is("deleted_at", null);

        if (activeCategories.length > 0) {
          questionsQuery = questionsQuery.in("category_id", activeCategories);
        }

        questionsQuery = questionsQuery.or(`tenant_id.eq.${schedule.tenant_id},is_global.eq.true`);

        const { data: poolQuestions, error: qError } = await questionsQuery;
        if (qError) {
          console.error("Error fetching questions:", qError);
          continue;
        }
        questions = (poolQuestions || []).map(q => ({ ...q, _source: "questions" }));
      }

      if (!questions.length) {
        console.log(`No questions found for schedule ${schedule.id}`);
        continue;
      }

      // DEDUP: Get ALL question_ids already assigned to each employee for THIS schedule
      const { data: allExistingAssignments } = await supabase
        .from("scheduled_questions")
        .select("employee_id, question_id")
        .eq("schedule_id", schedule.id);

      const assignedSet = new Set(
        (allExistingAssignments || []).map(a => `${a.employee_id}::${a.question_id}`)
      );

      const scheduledQuestions: any[] = [];

      // --- SURVEY: Deliver ALL questions at once ---
      // Use the schedule start_date as the single delivery timestamp.
      // No multi-day batching, no questions_per_delivery slicing.
      const surveyDeliveryDate = new Date(schedule.start_date || new Date());

      for (const employee of employees) {
        const employeeAssignedIds = new Set(
          (allExistingAssignments || [])
            .filter(a => a.employee_id === employee.id)
            .map(a => a.question_id)
        );

        const unassignedQuestions = questions.filter(q => !employeeAssignedIds.has(q.id));

        if (unassignedQuestions.length === 0) {
          console.log(`Employee ${employee.id} has received all questions in schedule ${schedule.id}, skipping`);
          continue;
        }

        // Assign ALL unassigned questions at once
        for (const question of unassignedQuestions) {
          const key = `${employee.id}::${question.id}`;
          if (assignedSet.has(key)) continue;

          scheduledQuestions.push({
            schedule_id: schedule.id,
            employee_id: employee.id,
            question_id: question.id,
            tenant_id: schedule.tenant_id,
            scheduled_delivery: surveyDeliveryDate.toISOString(),
            status: "pending",
            delivery_channel: "app",
            question_source: question._source,
          });

          assignedSet.add(key);
        }
      }

      if (scheduledQuestions.length > 0) {
        const { error: insertError } = await supabase
          .from("scheduled_questions")
          .insert(scheduledQuestions);

        if (insertError) {
          console.error("Error inserting scheduled questions:", insertError);
        } else {
          totalScheduled += scheduledQuestions.length;
          console.log(`Scheduled ${scheduledQuestions.length} questions for schedule ${schedule.id}`);
        }
      }
    }

    return new Response(JSON.stringify({ 
      success: true, 
      scheduled: totalScheduled,
      message: `Successfully scheduled ${totalScheduled} questions` 
    }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error: unknown) {
    console.error("Error in schedule-engine:", error);
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    return new Response(JSON.stringify({ error: errorMessage }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

